window.HADITH_CACHE["tirmidzi_3"] = {"1501":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَعِيدٍ الْكِنْدِيُّ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ إِسْرَائِيلَ عَنْ ثُوَيْرٍ عَنْ أَبِيهِ عَنْ عَلِيٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ كِسْرَى أَهْدَى لَهُ فَقَبِلَ وَأَنَّ الْمُلُوكَ أَهْدَوْا إِلَيْهِ فَقَبِلَ مِنْهُمْوَفِي الْبَاب عَنْ جَابِرٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَثُوَيْرُ بْنُ أَبِي فَاخِتَةَ اسْمُهُ سَعِيدُ بْنُ عِلَاقَةَ وَثُوَيْرٌ يُكْنَى أَبَا جَهْمٍ","id":"Telah menceritakan kepada kami [Ali bin Sa'id Al Kindi] berkata, telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Isra'il] dari [Tsuwair] dari [Bapaknya] dari [Ali] berkata, \"Raja Kisra memberikan hadiah kepada beliau lalu beliau menerimanya, dan Raja-raja juga memberikan hadiah kepada beliau lalu beliau menerimanya.\" Dalam bab ini ada serupa hadits dari Jabir, dan hadits ini derajatnya hasan gharib. Tsuwair bin Abi Fakhitah nama aslinya adalah Sa'id bin Ilaqah, dan julukan Tsuwair adalah Abu Jahm.\""},"1502":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ عَنْ عِمْرَانَ الْقَطَّانِ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ هُوَ ابْنُ الشِّخِّيرِ عَنْ عِيَاضِ بْنِ حِمَارٍأَنَّهُ أَهْدَى لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدِيَّةً لَهُ أَوْ نَاقَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمْتَ قَالَ لَا قَالَ فَإِنِّي نُهِيتُ عَنْ زَبْدِ الْمُشْرِكِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَعْنَى قَوْلِهِ إِنِّي نُهِيتُ عَنْ زَبْدِ الْمُشْرِكِينَ يَعْنِي هَدَايَاهُمْ وَقَدْ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْبَلُ مِنْ الْمُشْرِكِينَ هَدَايَاهُمْ وَذُكِرَ فِي هَذَا الْحَدِيثِ الْكَرَاهِيَةُ وَاحْتَمَلَ أَنْ يَكُونَ هَذَا بَعْدَ مَا كَانَ يَقْبَلُ مِنْهُمْ ثُمَّ نَهَى عَنْ هَدَايَاهُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud] dari [Imran Al Qaththan] dari [Qatadah] dari [Yazid bin Abdullah] -yaitu Ibnu Asy Syaikhkhir- dari [Iyadh bin Himar] Bahwasanya ia pernah memberikan hadiah, atau memberikan unta kepada beliau. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Apakah engkau telah Islam?\" ia menjawab, \"Belum.\" Beliau bersabda: \"Aku dilarang menerima pemberian orang-orang musyrik.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Sedangkan makna dari sabda Nabi 'Aku dilarang menerima pemberian orang-orang musyrik', yaitu menerima hadiah mereka.\" Telah diriwayatkan pula dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah menerima hadiah dari orang-orang musyrik. Dalam hadits tersebut disebutkan lafadz makruh, ini menunjukkan ada kemungkinan bahwa beliau pernah menerima pemberian mereka kemudian melarangnya setelah itu.\""},"1503":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا بَكَّارُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ عَنْ أَبِي بَكْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَاهُ أَمْرٌ فَسُرَّ بِهِ فَخَرَّ لِلَّهِ سَاجِدًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ بَكَّارِ بْنِ عَبْدِ الْعَزِيزِ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ رَأَوْا سَجْدَةَ الشُّكْرِ وَبَكَّارُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي بَكْرَةَ مُقَارِبُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] dari [Abu Ashim] berkata, telah menceritakan kepada kami [Bakar bin Abdul Aziz bin Abu Bakrah] dari [Bapaknya] dari [Abu Bakrah] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah mendapatkan perintah yang membuat beliau senang dan sujud syukur.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, dan kami tidak mengetahui kecuali dari hadits Bakkar bin Abdul Aziz dari jalur ini. kebanyakan para ulama` mengamalkan hadits ini, mereka melihat adanya anjuran sujud syukur. Bakkar bin Abdul Aziz bin Bakrah adalah seorang muqaribul hadits.\""},"1504":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَكْثَمَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ الْوَلِيدِ بْنِ رَبَاحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَرْأَةَ لَتَأْخُذُ لِلْقَوْمِ يَعْنِي تُجِيرُ عَلَى الْمُسْلِمِينَوَفِي الْبَاب عَنْ أُمِّ هَانِئٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَسَأَلْتُ مُحَمَّدًا فَقَالَ هَذَا حَدِيثٌ صَحِيحٌ وَكَثِيرُ بْنُ زَيْدٍ قَدْ سَمِعَ مِنْ الْوَلِيدِ بْنِ رَبَاحٍ وَالْوَلِيدُ بْنُ رَبَاحٍ سَمِعَ مِنْ أَبِي هُرَيْرَةَ وَهُوَ مُقَارِبُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Yahya bin Aktsam] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Katsir bin Zaid] dari [Al Walid bin Rabah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya seorang wanita dapat menjaga keamanan suatu kaum (muslimin).\" Dalam bab ini juga ada hadits dari Ummu Hani, dan hadits ini derajatnya hasan gharib. Aku pernah bertanya Muhammad tentang hadits ini, lalu ia menjawab, \"Ini adalah hadits shahih. Katsir bin Zaid telah mendengar dari Al Walid bin Rabah, dan Al Walid bin Rabah telah mendengar dari Abu Hurairah, sementara dia adalah seorang muqaribul hadits.\""},"1505":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ عَنْ أُمِّ هَانِئٍ أَنَّهَا قَالَتْأَجَرْتُ رَجُلَيْنِ مِنْ أَحْمَائِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَمَّنَّا مَنْ أَمَّنْتِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَجَازُوا أَمَانَ الْمَرْأَةِ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقُ أَجَازَ أَمَانَ الْمَرْأَةِ وَالْعَبْدِ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ وَأَبُو مُرَّةَ مَوْلَى عَقِيلِ بْنِ أَبِي طَالِبٍ وَيُقَالُ لَهُ أَيْضًا مَوْلَى أُمِّ هَانِئٍ أَيْضًا وَاسْمُهُ يَزِيدُ وَقَدْ رُوِيَ عَنْ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ أَجَازَ أَمَانَ الْعَبْدِ وَقَدْ رُوِيَ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذِمَّةُ الْمُسْلِمِينَ وَاحِدَةٌ يَسْعَى بِهَا أَدْنَاهُمْ قَالَ أَبُو عِيسَى وَمَعْنَى هَذَا عِنْدَ أَهْلِ الْعِلْمِ أَنَّ مَنْ أَعْطَى الْأَمَانَ مِنْ الْمُسْلِمِينَ فَهُوَ جَائِزٌ عَلَى كُلِّهِمْ","id":"Telah menceritakan kepada kami [Abul Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] berkata, telah mengabarkan kepadaku [Ibnu Abu Dzi`b] dari [Sa'id Al Maqburi] dari [Abu Murrah] -mantan budak (yang telah dimerdekakan oleh) Aqil bin Abu Thalib- dari [Ummu Hani] ia berkata, \"Aku memberi jaminan pengamanan kepada dua orang laki-laki dari kerabat suamiku. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Kami telah memberi keamanan kepada orang yang kamu jamin keamanannya.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Sebagian ahli ilmu beramal dengan hadits ini, mereka membolehkan jaminan keamanan yang diberikan oleh seorang wanita. Ini adalah pendapat Ahmad. Ishaq juga membolehkan jaminan keamanan yang diberikan oleh seorang wanita atau budak. Hadits ini diriwayatkan dengan banyak jalur. Abu Murrah mantan budak (yang telah dimerdekakan oleh) Aqil bin Abu Thalib sering dipanggil juga dengan nama Maula Ummu Hani, dan nama aslinya adalah Yazid. Diriwayatkan pula dari Umar Ibnul Khaththab, bahwasanya ia membolehkan jaminan keamanan yang diberikan oleh seorang budak. Diriwayatkan dari Ali bin Abu Thalib, dari Abdullah bin Amru, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jaminan seorang dari kaum muslimin itu bisa dilakukan oleh orang yang paling rendah dari mereka.\" Abu Isa berkata, \"Maksud dari hadits ini menurut para ulama` adalah, bahwa pemberian jaminan keamanan oleh kaum muslimin itu bisa dilakukan oleh siapa saja dari mereka.\""},"1506":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ أَخْبَرَنِي أَبُو الْفَيْضِ قَال سَمِعْتُ سُلَيْمَ بْنَ عَامِرٍ يَقُولُكَانَ بَيْنَ مُعَاوِيَةَ وَبَيْنَ أَهْلِ الرُّومِ عَهْدٌ وَكَانَ يَسِيرُ فِي بِلَادِهِمْ حَتَّى إِذَا انْقَضَى الْعَهْدُ أَغَارَ عَلَيْهِمْ فَإِذَا رَجُلٌ عَلَى دَابَّةٍ أَوْ عَلَى فَرَسٍ وَهُوَ يَقُولُ اللَّهُ أَكْبَرُ وَفَاءٌ لَا غَدْرٌ وَإِذَا هُوَ عَمْرُو بْنُ عَبَسَةَ فَسَأَلَهُ مُعَاوِيَةُ عَنْ ذَلِكَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ بَيْنَهُ وَبَيْنَ قَوْمٍ عَهْدٌ فَلَا يَحُلَّنَّ عَهْدًا وَلَا يَشُدَّنَّهُ حَتَّى يَمْضِيَ أَمَدُهُ أَوْ يَنْبِذَ إِلَيْهِمْ عَلَى سَوَاءٍ قَالَ فَرَجَعَ مُعَاوِيَةُ بِالنَّاسِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abu Dawud] ia berkata; telah memberitakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Abul Faidh] ia berkata; Aku mendengar [Sulaim bin Amir] berkata, \"Antara Mu'awiyah dan penduduk Romawi mempunyai perjanjian. Mu'awiyah kemudian melakukan perjalanan di negeri mereka, dengan harapan ketika masa perjanjian telah habis ia menyerang negeri tersebut. Namun tiba- tiba ada seorang laki-laki di atas kendaraan atau kuda seraya berkata, \"Allahu Akbar, hendaklah kalian penuhi perjanjian dan jangan berlaku curang.\" Dan ternyata laki-laki itu adalah [Amru bin Abasah], Mu'awiyah kemudian menanyakan hal itu kepada Amru bin Abasah, ia menjawab, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian mempunyai perjanjian dengan suatu kaum, maka jangan sekali-kali menghianati perjanjiannya hingga selesai masanya atau mengembalikan kepada mereka dengan cara yang baik (jujur).\" Mu'awiyah kemudian pulang bersama pasukannya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1507":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنِي صَخْرُ بْنُ جُوَيْرِيَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْغَادِرَ يُنْصَبُ لَهُ لِوَاءٌ يَوْمَ الْقِيَامَةِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَبِي سَعِيدٍ الْخُدْرِيِّ وَأَنَسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَسَأَلْتُ مُحَمَّدًا عَنْ حَدِيثِ سُوَيْدٍ عَنْ أَبِي إِسْحَقَ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِكُلِّ غَادِرٍ لِوَاءٌ فَقَالَ لَا أَعْرِفُ هَذَا الْحَدِيثَ مَرْفُوعًا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] ia berkata; telah menceritakan kepadaku [Shakhr bin Juwairiyah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari kiamat seorang penghianat akan diberi tanda dengan sebuah bendera.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Ali, Abdullah bin Mas'ud, Abu Said dan Anas.\" Abu Isa berkata; \"Hadits ini derajatnya hasan shahih. Aku pernah bertanya kepada Muhammad tentang hadits Suwaid, dari Abu Ishaq, dari Umarah bin Umair, dari Ali, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap penghianat diberi tanda dengan sebuah bendera.\"? ia menjawab, \"Aku tidak tahu; apakah hadits ini marfu'.\""},"1508":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُ قَالَرُمِيَ يَوْمَ الْأَحْزَابِ سَعْدُ بْنُ مُعَاذٍ فَقَطَعُوا أَكْحَلَهُ أَوْ أَبْجَلَهُ فَحَسَمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّارِ فَانْتَفَخَتْ يَدُهُ فَتَرَكَهُ فَنَزَفَهُ الدَّمُ فَحَسَمَهُ أُخْرَى فَانْتَفَخَتْ يَدُهُ فَلَمَّا رَأَى ذَلِكَ قَالَ اللَّهُمَّ لَا تُخْرِجْ نَفْسِي حَتَّى تُقِرَّ عَيْنِي مِنْ بَنِي قُرَيْظَةَ فَاسْتَمْسَكَ عِرْقُهُ فَمَا قَطَرَ قَطْرَةً حَتَّى نَزَلُوا عَلَى حُكْمِ سَعْدِ بْنِ مُعَاذٍ فَأَرْسَلَ إِلَيْهِ فَحَكَمَ أَنْ يُقْتَلَ رِجَالُهُمْ وَيُسْتَحْيَا نِسَاؤُهُمْ يَسْتَعِينُ بِهِنَّ الْمُسْلِمُونَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْتَ حُكْمَ اللَّهِ فِيهِمْ وَكَانُوا أَرْبَعَ مِائَةٍ فَلَمَّا فَرَغَ مِنْ قَتْلِهِمْ انْفَتَقَ عِرْقُهُ فَمَاتَقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَعَطِيَّةَ الْقُرَظِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Pada perang Ahzab Sa'd bin Mu'adz terkena anak panah hingga memutus urat nadi lengannya bagian luar, atau bagian dalam. Maka Rasulullah shallallahu 'alaihi wasallam menempelkan besi panas agar darahnya berhenti, tetapi tangannya justru membengkak dan mengeluarkan banyak darah. Rasulullah shallallahu 'alaihi wasallam kembali menempelkan besi panas agar darahnya berhenti. Ketika Sa'd melihat darahnya banyak keluar, ia pun berdoa, \"Ya Allah, janganlah engkau matikan aku hingga mataku menjadi sejuk dari (kekalahan) bani Quraizhah.\" Seketika itu urat nadinya berhenti dan tidak mengeluarkan setetes darah pun, hingga mereka (Bani Quraizhah) menyerahkan hukuman kepada keputusan Sa'd bin Mu'adz. Nabi pun mengutus seseorang menemui Sa'd. Saad putuskan agar tawanan laki-laki dibunuh sedang kaum perempuan dibiarkan hidup, dengan harapan kaum muslimin sewaktu-waktu membutuhkan pertolongannya. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Engkau telah memberlakukan mereka sesuai dengan hukum Allah.\" Jumlah mereka waktu itu adalah empat ratus orang, ketika selesai membunuh orang-orang kafir itu, urat nadi Sa'd kembali mengeluarkan darah hingga ia pun meninggal.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Abu Sa'id dan Athiyah Al Qurazhi.\" Abu Isa berkata, \"Ini adalah hadits shahih.\""},"1509":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو الْوَلِيدِ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ بَشِيرٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اقْتُلُوا شُيُوخَ الْمُشْرِكِينَ وَاسْتَحْيُوا شَرْخَهُمْ وَالشَّرْخُ الْغِلْمَانُ الَّذِينَ لَمْ يُنْبِتُواقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَرَوَاهُ الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ قَتَادَةَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdurrahman Abul Walid Ad Dimasyqi] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Sa'id bin Basyir] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bunuhlah orang-orang musyrik yang telah dewasa, dan biarkan yang masih remaja. Yaitu anak-anak yang belum tumbuh bulu kemaluannya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib. [Al Hajjaj bin Arthah] meriwayatkan dari [Qatadah] seperti hadits tersebut.\""},"1510":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَطِيَّةَ الْقُرَظِيِّ قَالَعُرِضْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ فَكَانَ مَنْ أَنْبَتَ قُتِلَ وَمَنْ لَمْ يُنْبِتْ خُلِّيَ سَبِيلُهُ فَكُنْتُ مِمَّنْ لَمْ يُنْبِتْ فَخُلِّيَ سَبِيلِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ بَعْضِ أَهْلِ الْعِلْمِ أَنَّهُمْ يَرَوْنَ الْإِنْبَاتَ بُلُوغًا إِنْ لَمْ يُعْرَفْ احْتِلَامُهُ وَلَا سِنُّهُ وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdul Malik bin Umair] dari [Athiyah Al Qurazhi] ia berkata; \"Pada perang bani Quraizhah kami dihadapkan kepada Nabi shallallahu 'alaihi wasallam, saat itu orang-orang yang telah tumbuh bulu kemaluannya dibunuh, sementara orang-orang yang belum tumbuh bulu kemaluannya dibiarkan hidup. Dan aku termasuk orang-orang yang belum tumbuh bulu kemaluannya, maka aku pun dibiarkan.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Sebagian ahli ilmu mengamalkan hadits ini, mereka berpendapat bahwa tumbuhnya bulu kemaluan adalah tanda baligh jika tidak diketahui kapan ia bermimpi basah, atau berapa umurnya.\" Ini adalah pendapat Ahmad bin Ishaq.\""},"1511":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي خُطْبَتِهِ أَوْفُوا بِحِلْفِ الْجَاهِلِيَّةِ فَإِنَّهُ لَا يَزِيدُهُ يَعْنِي الْإِسْلَامَ إِلَّا شِدَّةً وَلَا تُحْدِثُوا حِلْفًا فِي الْإِسْلَامِقَالَ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَأُمِّ سَلَمَةَ وَجُبَيْرِ بْنِ مُطْعِمٍ وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَقَيْسِ بْنِ عَاصِمٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Yazid bin Zurai'] berkata, telah menceritakan kepada kami [Husain Al Mu'allim] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda dalam khutbahnya: \"Penuhilah sumpah janji kalian di masa jahilliyah, sesungguhnya tidaklah Islam datang kecuali mengukuhkannya. Dan jangan membuat sumpah janji yang baru dalam Islam.\" Ia berkata, \"Dalam bab ini juga ada hadits dari 'Abdurrahman bin Auf, Ummu Salamah, Jubair bin Muth'im, Abu Hurairah, Ibnu Abbas dan Qais Abu Isa Ashim.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1512":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْحَجَّاجُ بْنُ أَرْطَاةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ بَجَالَةَ بْنِ عَبْدَةَقَالَ كُنْتُ كَاتِبًا لِجَزْءِ بْنِ مُعَاوِيَةَ عَلَى مَنَاذِرَ فَجَاءَنَا كِتَابُ عُمَرَ انْظُرْ مَجُوسَ مَنْ قِبَلَكَ فَخُذْ مِنْهُمْ الْجِزْيَةَ فَإِنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ أَخْبَرَنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ الْجِزْيَةَ مِنْ مَجُوسِ هَجَرَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al Hajjaj bin Arthah] dari [Amru bin Dinar] dari [Bajalah bin Abdah] ia berkata, \"Aku adalah sekertaris Jaza' bin Mu'awiyah, lalu datanglah surat [Umar] yang menyebutkan, \"Perhatikanlah orang-orang Majusi yang ada di sekitarmu, ambillah jizyah dari mereka. Sesungguhnya ['Abdurrahman bin Auf] telah mengabariku bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengambil jizyah dari orang-orang Majusi penduduk Hajar.\" Abu Isa berkata, \"Hadits ini derajatnya hasan.\""},"1513":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ بَجَالَةَأَنَّ عُمَرَ كَانَ لَا يَأْخُذُ الْجِزْيَةَ مِنْ الْمَجُوسِ حَتَّى أَخْبَرَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ الْجِزْيَةَ مِنْ مَجُوسِ هَجَرَ وَفِي الْحَدِيثِ كَلَامٌ أَكْثَرُ مِنْ هَذَا وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Bajalah] berkata, \"Umar tidak pernah mengambil Jizyah dari orang-orang Majusi hingga ['Abdurrahman bin Auf] memberinya kabar bahwa Nabi shallallahu 'alaihi wasallam pernah mengambil jizyah dari orang-orang Majusi penduduk Hajar.\" Sebenarnya redaksi hadits lebih panjang dari ini, dan ini adalah hadits hasan shahih.\""},"1514":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ أَبِي كَبْشَةَ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مَالِكٍ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجِزْيَةَ مِنْ مَجُوسِ الْبَحْرَيْنِوَأَخَذَهَا عُمَرُ مِنْ فَارِسَ وَأَخَذَهَا عُثْمَانُ مِنْ الْفُرْسِ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا فَقَالَ هُوَ مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Al Husain bin Abu Kabsyah Al Bashri] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Malik] dari [Az Zuhri] dari [As Sa`ib bin Yazid] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengambil jizyah dari orang-orang Majusi penduduk Bahrain, Umar mengambil dari penduduk Persia, dan Utsman mengambil dari Furs.\" Lalu aku tanyakan perawi hadits ini kepada Muhammad, maka ia menjawab, \"(Yaitu) Malik, dari Az Zuhri, dari Nabi shallallahu 'alaihi wasallam.\""},"1515":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَمُرُّ بِقَوْمٍ فَلَا هُمْ يُضَيِّفُونَا وَلَا هُمْ يُؤَدُّونَ مَا لَنَا عَلَيْهِمْ مِنْ الْحَقِّ وَلَا نَحْنُ نَأْخُذُ مِنْهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ أَبَوْا إِلَّا أَنْ تَأْخُذُوا كَرْهًا فَخُذُواقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَيْضًا وَإِنَّمَا مَعْنَى هَذَا الْحَدِيثِ أَنَّهُمْ كَانُوا يَخْرُجُونَ فِي الْغَزْوِ فَيَمُرُّونَ بِقَوْمٍ وَلَا يَجِدُونَ مِنْ الطَّعَامِ مَا يَشْتَرُونَ بِالثَّمَنِ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ أَبَوْا أَنْ يَبِيعُوا إِلَّا أَنْ تَأْخُذُوا كَرْهًا فَخُذُوا هَكَذَا رُوِيَ فِي بَعْضِ الْحَدِيثِ مُفَسَّرًا وَقَدْ رُوِيَ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ كَانَ يَأْمُرُ بِنَحْوِ هَذَا","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Abul Khair] dari [Uqbah bin Amir] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, sesungguhnya kami melewati suatu kaum; namun mereka tidak menjamu kami sebagai tamu dan tidak memberikan hak kami atas mereka dan tidak pula kami mengambil dari mereka?\" maka beliau bersabda: \"Jika mereka enggan memberi kecuali secara paksa, maka ambillah (dengan paksa).\" Abu Isa berkata, \"Hadits ini derajatnya hasan, [Al Laits bin Sa'id] juga meriwayatkannya dari [Yazid bin Abu Habib]. Makna dari hadits ini adalah, Bahwasanya para sahabat sedang melakukan safar untuk suatu peperangan, lalu mereka melewati suatu kaum, dan mereka tidak mendapatkan makanan apa pun meskipun dengan dibeli. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Jika mereka tidak mau menjual kecuali dengan paksaan, maka belilah dengan paksa.\" Seperti inilah diriwayatkan dalam beberapa hadits dengan keterangannya. Dan telah diriwayatkan bahwa Umar Ibnul Khaththab? radliallahu 'anhu pun pernah memerintahkan dengan hal yang serupa.\""},"1516":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَنْصُورُ بْنُ الْمُعْتَمِرِ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ لَا هِجْرَةَ بَعْدَ الْفَتْحِ وَلَكِنْ جِهَادٌ وَنِيَّةٌ وَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُواقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَبْدِ اللَّهِ بْنِ حُبْشِيٍّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ سُفْيَانُ الثَّوْرِيُّ عَنْ مَنْصُورِ بْنِ الْمُعْتَمِرِ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adh Dhabbi] berkata, telah menceritakan kepada kami [Ziyad bin Abdullah] berkata, telah menceritakan kepada kami [Manshur Ibnul Mu'tamir] dari [Mujahid] dari [Thawus] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ketika terjadi pembukaan (penaklukan) kota Makkah: \"Tidak ada hijrah setelah pembukaan kota Makkah, tetapi hanya ada jihad dan niat. Jika kalian diperintah untuk pergi (jihad) maka pergilah.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Abu Sa'id, Abdullah bin Amru dan Abdullah bin Hubsyi.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. [Sufyan Ats Tsauri] meriwayatkan dari [Manshur Ibnul Mu'tamir] seperti hadits tersebut.\""},"1517":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِفِي قَوْلِهِ تَعَالَى{ لَقَدْ رَضِيَ اللَّهُ عَنْ الْمُؤْمِنِينَ إِذْ يُبَايِعُونَكَ تَحْتَ الشَّجَرَةِ }قَالَ جَابِرٌ بَايَعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْ لَا نَفِرَّ وَلَمْ نُبَايِعْهُ عَلَى الْمَوْتِقَالَ وَفِي الْبَاب عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ وَابْنِ عُمَرَ وَعُبَادَةَ وَجَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عِيسَى بْنِ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ قَالَ جَابِرُ بْنُ عَبْدِ اللَّهِ وَلَمْ يُذْكَرْ فِيهِ أَبُو سَلَمَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir bin Abdullah] tentang firman Allah: '(Sesungguhnya Allah telah ridha terhadap orang-orang mu'min ketika mereka berjanji setia kepadamu di bawah pohon) ' -Qs. Al Fath: 18- Jabir berkata, \"Kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk tidak lari (dari medan perang), bukan baiat untuk mati.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Salamah Ibnul Akwa', Ibnu Umar, Ubadah dan Jarir bin Abdullah.\" Abu Isa berkata, \"Hadits ini diriwayatkan dari Isa bin Yunus dari Al Auza'I, dari Yahya bin Abu Katsir berkata; Jabir bin Abdullah berkata. Dan dalam hadits tersebut tidak disebut nama Abu Salamah.\""},"1518":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ قَالَ قُلْتُ لِسَلَمَةَ بْنِ الْأَكْوَعِعَلَى أَيِّ شَيْءٍ بَايَعْتُمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْحُدَيْبِيَةِ قَالَ عَلَى الْمَوْتِوَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Yazid bin Abu Ubaid] ia berkata; Aku bertanya kepada [Salamah Ibnul Akwa'], \"Atas apa kalian membaiat Rasulullah shallallahu 'alaihi wasallam pada hari Hudaibiyah?\" ia menjawab, \"Baiat untuk mati.\" Hadits ini derajatnya hasan shahih.\""},"1519":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نُبَايِعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّمْعِ وَالطَّاعَةِ فَيَقُولُ لَنَا فِيمَا اسْتَطَعْتُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ كِلَاهُمَا وَمَعْنَى كِلَا الْحَدِيثَيْنِ صَحِيحٌ قَدْ بَايَعَهُ قَوْمٌ مِنْ أَصْحَابِهِ عَلَى الْمَوْتِ وَإِنَّمَا قَالُوا لَا نَزَالُ بَيْنَ يَدَيْكَ حَتَّى نُقْتَلَ وَبَايَعَهُ آخَرُونَ فَقَالُوا لَا نَفِرُّ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata, \"Kami membaiat Rasulullah shallallahu 'alaihi wasallam untuk mendengar dan taat. Beliau bersabda kepada kami; \"Mendengar dan taat kepada kami semampu kalian.\" Abu Isa berkata, \"Kedua hadits ini derajatnya hasan shahih. Makna bahwa kedua hadits ini shahih yaitu, bahwa ada sekelompok orang dari sahabatnya telah berbaiat untuk mati. Mereka mengatakan, 'Kami akan selalu ada bersamamu hingga kami terbunuh'. Sedangkan yang lain mengatakan, 'Kami tidak akan kabur (dari peperangan) '."},"1520":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَلَمْ نُبَايِعْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمَوْتِ إِنَّمَا بَايَعْنَاهُ عَلَى أَنْ لَا نَفِرَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin mani'] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Kami tidak berbaiat kepada Rasulullah shallallahu 'alaihi wasallam untuk mati, tetapi kami berbaiat untuk tidak lari (dari medan perang).\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1521":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ رَجُلٌ بَايَعَ إِمَامًا فَإِنْ أَعْطَاهُ وَفَى لَهُ وَإِنْ لَمْ يُعْطِهِ لَمْ يَفِ لَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلَى ذَلِكَ الْأَمْرُ بِلَا اخْتِلَافٍ","id":"Telah menceritakan kepada kami [Abu Ammar] berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang pada hari kiamat tidak diajak berbicara oleh Allah, tidak dibersihkan dosanya dan baginya siksa yang pedih; seorang laki-laki yang berbaiat kepada seorang imam, jika imam tersebut memberikan sesuatu padanya maka akan ia tepati, namun jika tidak maka ia tidak menepati janjinya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, dan tidak ada perselisihan dalam perkara tersebut.\""},"1522":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُ قَالَجَاءَ عَبْدٌ فَبَايَعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْهِجْرَةِ وَلَا يَشْعُرُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ عَبْدٌ فَجَاءَ سَيِّدُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعْنِيهِ فَاشْتَرَاهُ بِعَبْدَيْنِ أَسْوَدَيْنِ وَلَمْ يُبَايِعْ أَحَدًا بَعْدُ حَتَّى يَسْأَلَهُ أَعَبْدٌ هُوَقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ أَبِي الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Seorang budak datang lalu berbaiat kepada Rasulullah shallallahu 'alaihi wasallam, sementara Nabi shallallahu 'alaihi wasallam tidak menyadari bahwa orang tersebut adalah budak. lalu tuannya datang, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Juallah budak itu kepadaku.\" dan Nabi Sallallahu 'alaihi Wasallam membelinya dengan dua orang budak yang hitam, akhirnya Nabi Sallallahu 'Alaihi Wasallam tidak membaiat seorang pun hingga beliau bertanya kepadanya; apakah dia seorang budak (atau bukan).\" Ia berkata, \"Dalam bab ini juga ada hadits dari Ibnu Abbas.\" Abu Isa berkata, \"Hadits Jabir ini derajatnya hasan gharib shahih, kami tidak mengetahuinya kecuali dari hadits Abu Az Zubair.\""},"1523":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ الْمُنْكَدِرِ سَمِعَ أُمَيْمَةَ بِنْتَ رُقَيْقَةَ تَقُولُبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نِسْوَةٍ فَقَالَ لَنَا فِيمَا اسْتَطَعْتُنَّ وَأَطَقْتُنَّ قُلْتُ اللَّهُ وَرَسُولُهُ أَرْحَمُ بِنَا مِنَّا بِأَنْفُسِنَا قُلْتُ يَا رَسُولَ اللَّهِ بَايِعْنَا قَالَ سُفْيَانُ تَعْنِي صَافِحْنَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا قَوْلِي لِمِائَةِ امْرَأَةٍ كَقَوْلِي لِامْرَأَةٍ وَاحِدَةٍقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَعَبْدِ اللَّهِ بْنِ عُمَرَ وَأَسْمَاءَ بِنْتِ يَزِيدَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَرَوَى سُفْيَانُ الثَّوْرِيُّ وَمَالِكُ بْنُ أَنَسٍ وَغَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ نَحْوَهُ قَالَ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَقَالَ لَا أَعْرِفُ لِأُمَيْمَةَ بِنْتِ رُقَيْقَةَ غَيْرَ هَذَا الْحَدِيثِ وَأُمَيْمَةُ امْرَأَةٌ أُخْرَى لَهَا حَدِيثٌ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnul Munkadir] ia mendengar [Umaimah binti Ruqaiqah] berkata, \"Aku berbaiat kepada Rasulullah shallallahu 'alaihi wasallam saat bersama beberapa wanita. Beliau lalu bersabda kepada kami: \"Terhadap apa saja yang kalian mampu dan sanggup (melaksanakannya).\" Aku berkata, \"Allah dan rasul-Nya lebih sayang kepada kami dari pada sayangnya kami terhadap diri kami sendiri.\" Aku berkata lagi, \"Wahai Rasulullah, baiatlah kami, Sufyan berkata, \"Maksudnya; jabatlah tangan kami.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \" sesungguhnya ucapanku untuk seratus wanita seperti ucapanku untuk seorang wanita.\" Ia berkata, \"Dalam bab ini juga ada hadits dari 'Aisyah, Abdullah bin Umar dan Asma binti Yazid.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, kami tidak mengetahuinya kecuali dari hadits Muhammad Ibnul Munkadir.\" [Sufyan Ats Tsauri], [Malik bin Anas] dan selain keduanya juga meriwayatkan dari [Muhammad Ibnul Munkadir] dengan hadits yang sama.\" Ia mengatakan, \"aku bertanya kepada Muhammad tentang hadits ini?\", Muhammad menjawab; \"Aku tidak mengetahui Umaimah binti Ruqaiqah mempunyai hadits kecuali hadits ini, dan Umaimah adalah wanita yang lain (berbeda), ia mempunyai (satu) hadits dari Rasulullah shallallahu 'alaihi wasallam.\""},"1524":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى الْكُوفِيُّ حَدَّثَنَا أَبُو بكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكُنَّا نَتَحَدَّثُ أَنَّ أَصْحَابَ بَدْرٍ يَوْمَ بَدْرٍ كَعِدَّةِ أَصْحَابِ طَالُوتَ ثَلَاثُ مِائَةٍ وَثَلَاثَةَ عَشَرَ رَجُلًاقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ الثَّوْرِيُّ وَغَيْرُهُ عَنْ أَبِي إِسْحَقَ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la Al Kufi] berkata, telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Kami memperbincangkan bahwa jumlah pasukan badar pada perang badar seperti jumlah pasukan Thaluth, yaitu tiga ratus tiga belas orang.\" Ia berkata, Dalam bab ini juga ada hadits dari Ibnu Abbas.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, [Ats Tsauri] dan selainnya telah meriwayatkannya dari [Abu Ishaq].\""},"1525":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلَّبِيُّ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِوَفْدِ عَبْدِ الْقَيْسِ آمُرُكُمْ أَنْ تُؤَدُّوا خُمُسَ مَا غَنِمْتُمْقَالَ وَفِي الْحَدِيثِ قِصَّةٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍ نَحْوَهُ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abbad bin Abbad Al Muhallabi] dari [Abu Jamrah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam berkata kepada utusan Abdu Qais: \"Aku perintahkan kepada kalian untuk menyerahkan seperlima dari ghanimah yang kalian dapatkan.\" Ia berkata, \"Dalam hadits terdapat kisah\". Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Abu Jamrah] dari [Ibnu Abbas] seperti hadits tersebut.\""},"1526":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَتَقَدَّمَ سَرْعَانُ النَّاسِ فَتَعَجَّلُوا مِنْ الْغَنَائِمِ فَاطَّبَخُوا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُخْرَى النَّاسِ فَمَرَّ بِالْقُدُورِ فَأَمَرَ بِهَا فَأُكْفِئَتْ ثُمَّ قَسَمَ بَيْنَهُمْ فَعَدَلَ بَعِيرًا بِعَشْرِ شِيَاهٍقَالَ أَبُو عِيسَى وَرَوَى سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِيهِ عَنْ عَبَايَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِيهِ حَدَّثَنَا بِذَلِكَ مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ وَهَذَا أَصَحُّ وَعَبَايَةُ بْنُ رِفَاعَةَ سَمِعَ مِنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ قَالَ وَفِي الْبَاب عَنْ ثَعْلَبَةَ بْنِ الْحَكَمِ وَأَنَسٍ وَأَبِي رَيْحَانَةَ وَأَبِي الدَّرْدَاءِ وَعَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ وَزَيْدِ بْنِ خَالِدٍ وَجَابِرٍ وَأَبِي هُرَيْرَةَ وَأَبِي أَيُّوبَ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Sa'id bin Masruq] dari [Abayah bin Rifa'ah] dari [Bapaknya] dari Kakeknya [Rafi' bin Khadij] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, orang-orang berjalan dengan cepat untuk mendapatkan harta ghanimah dengan segera, hingga mereka pun masak (hewan dari harta ghanimah). Sementara Rasulullah shallallahu 'alaihi wasallam masih di belakang bersama rombongan yang lain. Ketika beliau melewati mereka yang sedang masak-masak, beliau memerintahkan untuk membuang masakan tersebut, lalu mereka pun membuangnya. Setelah itu beliau membagi-bagikan harta ghanimah, dan beliau menyamakan satu unta dengan sepuluh kambing.\" Abu Isa berkata, \" [Sufyan At Tsauri] meriwayatkan dari [bapaknya], dari [Abayah], dari kakeknya [Rafi' bin Khadij], tetapi dalam hadits tersebut ia tidak menyebutkan 'dari bapaknya'. [Mahmud bin Ghailan] yang menceritakan hal itu kepada kami, ia berkata; [Waki'] menceritakan kepada kami dari [Sufyan], dan ini lebih shahih. Abayah bin Rifa'ah mendengar dari kakeknya, Rafi' bin Khadij.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Tsa'labah bin Al Hakam, Anas, Abu Raihanah, Abu Darda, 'Abdurrahman bin Samurah, Zaid bin Khalid, Jabir, Abu Hurairah dan Abu Ayyub.\""},"1527":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ انْتَهَبَ فَلَيْسَ مِنَّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ أَنَسٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Tsabit] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa merampas harta orang lain maka dia bukan dari golongan kami.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, dari hadits Anas.\""},"1528":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَبْدَءُوا الْيَهُودَ وَالنَّصَارَى بِالسَّلَامِ وَإِذَا لَقِيتُمْ أَحَدَهُمْ فِي الطَّرِيقِ فَاضْطَرُّوهُمْ إِلَى أَضْيَقِهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَنَسٍ وَأَبِي بَصْرَةَ الْغِفَارِيِّ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمَعْنَى هَذَا الْحَدِيثِ لَا تَبْدَءُوا الْيَهُودَ وَالنَّصَارَى قَالَ بَعْضُ أَهْلِ الْعِلْمِ إِنَّمَا مَعْنَى الْكَرَاهِيَةِ لِأَنَّهُ يَكُونُ تَعْظِيمًا لَهُمْ وَإِنَّمَا أُمِرَ الْمُسْلِمُونَ بِتَذْلِيلِهِمْ وَكَذَلِكَ إِذَا لَقِيَ أَحَدَهُمْ فِي الطَّرِيقِ فَلَا يَتْرُكْ الطَّرِيقَ عَلَيْهِ لِأَنَّ فِيهِ تَعْظِيمًا لَهُمْ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mendahului orang-orang Yahudi dan Nashrani dengan beruluk salam, jika di jalan kalian berjumpa dengan salah seorang dari mereka maka desaklah hingga ke bibir jalan.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Ibnu Umar, Anas dan Abu Bashrah Al Ghifari, sahabat Rasulullah shallallahu 'alaihi wasallam.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, dan maksud dari hadits ini adalah, janganlah kalian mendahului orang-orang Yahudi dan Nashrani dengan beruluk salam. Sebagian ulama` berkata, \"Maksud dari pelarangan itu karena hal tersebut bagian dari penghormatan kepada mereka, padahal kaum muslimin diperintahkan untuk menghinakan mereka. Hal ini juga berlaku saat bertemu salah seorang dari mereka di jalan; maka dianjurkan untuk tidak memberi jalan kepada mereka, sebab itu bagian dari pengagungan kepada mereka.\""},"1529":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْيَهُودَ إِذَا سَلَّمَ عَلَيْكُمْ أَحَدُهُمْ فَإِنَّمَا يَقُولُ السَّامُ عَلَيْكُمْ فَقُلْ عَلَيْكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"sesungguhnya orang-orang yahudi jika salah seorang dari mereka mengulukkan salam kepada kalian, maka ia hanya akan mengucapkan, 'As Saamu Alaikum (racun atas kalian). Maka ucapkanlah, \" 'Alaika (bahkan atas dirimu).\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1530":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً إِلَى خَثْعَمٍ فَاعْتَصَمَ نَاسٌ بِالسُّجُودِ فَأَسْرَعَ فِيهِمْ الْقَتْلَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُمْ بِنِصْفِ الْعَقْلِ وَقَالَ أَنَا بَرِيءٌ مِنْ كُلِّ مُسْلِمٍ يُقِيمُ بَيْنَ أَظْهُرِ الْمُشْرِكِينَ قَالُوا يَا رَسُولَ اللَّهِ وَلِمَ قَالَ لَا تَرَايَا نَارَاهُمَاحَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ مِثْلَ حَدِيثِ أَبِي مُعَاوِيَةَ وَلَمْ يَذْكُرْ فِيهِ عَنْ جَرِيرٍ وَهَذَا أَصَحُّ وَفِي الْبَاب عَنْ سَمُرَةَ قَالَ أَبُو عِيسَى وَأَكْثَرُ أَصْحَابِ إِسْمَعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً وَلَمْ يَذْكُرُوا فِيهِ عَنْ جَرِيرٍ وَرَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ الْحَجَّاجِ بْنِ أَرْطَاةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسٍ عَنْ جَرِيرٍ مِثْلَ حَدِيثِ أَبِي مُعَاوِيَةَ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ الصَّحِيحُ حَدِيثُ قَيْسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ وَرَوَى سَمُرَةُ بْنُ جُنْدَبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُسَاكِنُوا الْمُشْرِكِينَ وَلَا تُجَامِعُوهُمْ فَمَنْ سَاكَنَهُمْ أَوْ جَامَعَهُمْ فَهُوَ مِثْلُهُمْ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam mengutus ekspedisi kepada Khats'am, lalu ada beberapa orang (Khats'am) yang bersujud. Namun pasukan ekspedisi tersebut segera membunuh mereka. Kabar tersebut akhirnya sampai kepada Nabi shallallahu 'alaihi wasallam, lalu beliau pun memerintakan mereka untuk memberi setengah tebusan.\", kemudian Beliau bersabda: \"Aku berlepas diri dari setiap muslim yang tinggal bersama orang-orang musyrik.\" Para sahabat bertanya, \"Wahai Rasulullah, kenapa?\" beliau menjawab: \"Tidak pantas rumah mereka saling berhadapan.\" Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abdah] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] seperti hadits Abu Mu'awiyah, tetapi di dalamnya tidak disebutkan 'dari Jarir', dan ini lebih shahih.\" Dan dalam bab ini juga ada hadits dari Samurah, Abu Isa berkata; kebanyakan para sahabat Isma'il (meriwayatkannya) dari Qais bin Abi Hazim bahwasanya Rasulullah shallallahu 'alaihi wasallam mengutus sebuah ekspedisi, tanpa menyebutkan di dalamnya dari Jarir. Dan diriwayatkan oleh [Hammad bin Salamah] dari [Al Hajjaj bin Arthah] dari [Isma'il bin Abu Khalid] dari [Qais] dari [Jarir] semisal hadits Abu Mu'awiyah. Ia (Abu Isa) berkata; saya mendengar Muhammad mengatakan; yang benar hadits Qais dari Nabi shallallahu 'alaihi wasallam kedudukannya adalah mursal. Sedangkan Samurah bin Jundab meriwayatkan dari Nabi Shallahu 'alaihi Wasallam Beliau bersabda; \"janganlah kalian bertempat tinggal dengan orang-orang musyrik dan jangan pula bergaul dengan mereka, oleh karena itu barang siapa yang bertempat tinggal atau bergaul dengan mereka maka dia seperti mereka.\" "},"1531":{"ar":"حَدَّثَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْكِنْدِيُّ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ أَخْبَرَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ عُمَرَ بْنِ الْخَطَّابِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَئِنْ عِشْتُ إِنْ شَاءَ اللَّهُ لَأُخْرِجَنَّ الْيَهُودَ وَالنَّصَارَى مِنْ جَزِيرَةِ الْعَرَبِ","id":"Telah menceritakan kepada kami [Musa bin 'Abdurrahman Al Kindi] berkata, telah menceritakan kepada kami [Zaid Ibnul Hubab] berkata, telah mengabarkan kepada kami [Sufyan Ats Tsauri] dari [Abu Az Zubair] dari [Jabir] dari [Umar Ibnul Khaththab] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika aku masih hidup, sungguh -dengan izin Allah- aku akan keluarkan orang-orang Yahudi dan Nashrani dari Jazirah Arab.\""},"1532":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا أَبُو عَاصِمٍ وَعَبْدُ الرَّزَّاقِ قَالَا أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُ أَخْبَرَنِي عُمَرُ بْنُ الْخَطَّابِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَأُخْرِجَنَّ الْيَهُودَ وَالنَّصَارَى مِنْ جَزِيرَةِ الْعَرَبِ فَلَا أَتْرُكُ فِيهَا إِلَّا مُسْلِمًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Abu Ashim] dan [Abdurrazaq] keduanya berkata; telah mengabarkan kepada kami [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] bahwasanya ia mendengar [Jabir bin Abdullah] berkata; telah mengabarkan kepadaku [Umar Ibnul Kthaththab] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, akan aku keluarkan orang-orang Yahudi dan Nashrani dari Jazirah Arab. Aku tidak menyisakan di dalamnya kecuali orang muslim.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1533":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَتْ فَاطِمَةُ إِلَى أَبِي بَكْرٍ فَقَالَتْ مَنْ يَرِثُكَ قَالَ أَهْلِي وَوَلَدِي قَالَتْ فَمَا لِي لَا أَرِثُ أَبِي فَقَالَ أَبُو بَكْرٍ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا نُورَثُ وَلَكِنِّي أَعُولُ مَنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُولُهُ وَأُنْفِقُ عَلَى مَنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنْفِقُ عَلَيْهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَطَلْحَةَ وَالزُّبَيْرِ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَسَعْدٍ وَعَائِشَةَ وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ إِنَّمَا أَسْنَدَهُ حَمَّادُ بْنُ سَلَمَةَ وَعَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَقَالَ لَا أَعْلَمُ أَحَدًا رَوَاهُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ إِلَّا حَمَّادَ بْنَ سَلَمَةَ وَرَوَى عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ نَحْوَ رِوَايَةِ حَمَّادِ بْنِ سَلَمَةَ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abul Walid] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Fatimah datang kepada [Abu Bakar] dan bertanya, \"Siapa yang akan mewarisimu?\" Abu Bakar menjawab, \"Isteri dan anakku.\" Fatimah bertanya lagi, \"Kenapa aku tidak boleh mewarisi bapakku?\" Abu Bakar lalu berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami (para Nabi) tidak diwarisi.\" (Abu Bakar berkata) akan tetapi aku akan memenuhi kebutuhan siapa saja yang Rasulullah shallallahu 'alaihi wasallam penuhi kebutuhannya, dan aku akan memberikan nafkah kepada siapa saja yang Rasulullah shallallahu 'alaihi wasallam nafkahi.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Umar, Thalhah, Az Zubair, 'Abdurrahman bin Auf, Sa'd, dan 'Aisyah. Hadits Abu Hurairah ini derajatnya hasan gharib dari jalur ini. Hanya saja Hammad bin Salamah dan Abdul Wahhab bin Atha` menyandarkan sanadnya dari Muhammad bin Amru, dari Abu Salamah, dari Abu Hurairah. Aku pernah bertanya kepada Muhammad tentang hadits ini, ia menjawab, \"Aku tidak mengetahui seorang pun yang meriwayatkan hadits ini dari Muhammad bin Amru, dari Abu Salamah, dari Abu Hurairah selain Hammad bin Salamah.\" Abdul Wahhab meriwayatkan dari Muhammad bin Amru, dari Abu Salamah, dari Abu Hurairah seperti riwayat Hammad bin Salamah.\""},"1534":{"ar":"حَدَّثَنَا بِذَلِكَ عَلِيُّ بْنُ عِيسَى قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ فَاطِمَةَ جَاءَتْ أَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا تَسْأَلُ مِيرَاثَهَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَا سَمِعْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنِّي لَا أُورَثُ قَالَتْ وَاللَّهِ لَا أُكَلِّمُكُمَا أَبَدًا فَمَاتَتْ وَلَا تُكَلِّمُهُمَاقَالَ عَلِيُّ بْنُ عِيسَى مَعْنَى لَا أُكَلِّمُكُمَا تَعْنِي فِي هَذَا الْمِيرَاثِ أَبَدًا أَنْتُمَا صَادِقَانِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"[Ali bin Isa] telah menceritakan kepada kami seperti itu, ia berkata; telah menceritakan kepada kami [Abdul Wahhab bin Atha`] berkata, telah menceritakan kepada kami [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] berkata, \"Bahwasanya Fatimah mendatangi [Abu Bakar] dan [Umar]? radliallahu 'anhuma menanyakan tentang warisan yang harus ia terima dari Rasulullah shallallahu 'alaihi wasallam. Keduanya lalu berkata, \"Kami mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku tidak diwarisi.\" Fatimah lalu berkata, \"Demi Allah, aku tidak akan berbicara dengan kalian selamanya.\" Akhirnya Fatimah pun meninggal dan tidak pernah berbicara dengan keduanya.\" Ali bin Musa berkata, \"Maksud dari ucapan Fatimah, 'aku tidak akan berbicara dengan kalian', yaitu dalam masalah warisan, apa yang kalian berdua katakan benar adanya.\" Hadits ini diriwayatkan dari Abu Bakar As Shiddieq, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1535":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ أَخْبَرَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَالَدَخَلْتُ عَلَى عُمَرَ بْنِ الْخَطَّابِ وَدَخَلَ عَلَيْهِ عُثْمَانُ بْنُ عَفَّانَ وَالزُّبَيْرُ بْنُ الْعَوَّامِ وَعَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ وَسَعْدُ بْنُ أَبِي وَقَّاصٍ ثُمَّ جَاءَ عَلِيٌّ وَالْعَبَّاسُ يَخْتَصِمَانِ فَقَالَ عُمَرُ لَهُمْ أَنْشُدُكُمْ بِاللَّهِ الَّذِي بِإِذْنِهِ تَقُومُ السَّمَاءُ وَالْأَرْضُ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ قَالُوا نَعَمْ قَالَ عُمَرُ فَلَمَّا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو بَكْرٍ أَنَا وَلِيُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجِئْتَ أَنْتَ وَهَذَا إِلَى أَبِي بَكْرٍ تَطْلُبُ أَنْتَ مِيرَاثَكَ مِنْ ابْنِ أَخِيكَ وَيَطْلُبُ هَذَا مِيرَاثَ امْرَأَتِهِ مِنْ أَبِيهَا فَقَالَ أَبُو بَكْرٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نُورَثُ مَا تَرَكْنَا صَدَقَةٌ وَاللَّهُ يَعْلَمُ إِنَّهُ صَادِقٌ بَارٌّ رَاشِدٌ تَابِعٌ لِلْحَقِّقَالَ أَبُو عِيسَى وَفِي الْحَدِيثِ قِصَّةٌ طَوِيلَةٌ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ مَالِكِ بْنِ أَنَسٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah mengabarkan kepada kami [Bisyr bin Umar] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Malik bin Aus bin Al Hadatsan] ia berkata; Aku menemui Umar Ibnul Khaththab, lalu datanglah [Utsman bin Affan], [Az Zubair Ibnul Awwam], ['Abdurrahman bin Auf] dan [Sa'd bin Waqash]. Setelah itu [Ali] dan [Al Abbas] datang berselisih (tentang warisan Nabi). [Umar] lalu berkata kepada mereka, \"Aku bersumpah atas kalian dengan nama Allah yang dengan izin-Nya langit dan bumi tercipta. Kalian semua tahu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"kami (para Nabi) tidak diwarisi, adapun apa yang kami tinggalkan sebagai shadaqah.\" Para sahabat menjawab, \"Benar.\" Umar berkata lagi, \"Ketika Rasulullah shallallahu 'alaihi wasallam wafat, Abu Bakar berkata, \"Aku adalah penerima wasiat Rasulullah shallallahu 'alaihi wasallam.\" Umar melanjutkan, \"Lantas dirimu wahai (Al Abbas) dan dia ini (Ali) datang menemui Abu Bakar dan menuntut warisan keponakanmu (Rasulullah), sedangkan dia ini (Ali) datang menuntut warisan isterinya (Fatimah) dari bapaknya (Rasulullah).\" [Abu Bakar] berkata, \"Sungguh Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami (para Nabi) tidak diwarisi, Segala yang kami tinggalkan sebagai sedekah.\" (Umar melanjutkan) padahal Allah tahu bahwa Abu Bakar adalah seorang yang jujur, baik, lurus, dan selalu mengikuti kebenaran.\" Abu Isa berkata, \"Dalam hadits ini sebenarnya ada kisah yang panjang sekali, hadits ini derajatnya hasan shahih gharib, dari hadits Malik bin Anas.\""},"1536":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا زَكَرِيَّا بْنُ أَبِي زَائِدَةَ عَنْ الشَّعْبِيِّ عَنْ الْحَارِثِ بْنِ مَالِكِ بْنِ الْبَرْصَاءِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ يَقُولُ لَا تُغْزَى هَذِهِ بَعْدَ الْيَوْمِ إِلَى يَوْمِ الْقِيَامَةِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَسُلَيْمَانَ بْنِ صُرَدٍ وَمُطِيعٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ حَدِيثُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ الشَّعْبِيِّ فَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Zakariya bin Abu Zaidah] dari [Asy Sya'bi] dari [Al Harits bin Malik bin Al Barsha`] ia berkata, \"Saat pembukaan kota Makkah aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Setelah hari ini kota ini tidak akan diserang hingga hari kiamat.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ibnu Abbas, Sulaiman bin Shurad, dan Muthi'. Hadits ini derajatnya hasan shahih, ini adalah hadits Zakariya bin Abu Zaidah, dari Asy Sya'bi, kami tidak mengetahuinya kecuali dari hadits yang diriwayatkannya.\" "},"1537":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ قَالَغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا طَلَعَ الْفَجْرُ أَمْسَكَ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ قَاتَلَ فَإِذَا انْتَصَفَ النَّهَارُ أَمْسَكَ حَتَّى تَزُولَ الشَّمْسُ فَإِذَا زَالَتْ الشَّمْسُ قَاتَلَ حَتَّى الْعَصْرِ ثُمَّ أَمْسَكَ حَتَّى يُصَلِّيَ الْعَصْرَ ثُمَّ يُقَاتِلُ قَالَ وَكَانَ يُقَالُ عِنْدَ ذَلِكَ تَهِيجُ رِيَاحُ النَّصْرِ وَيَدْعُو الْمُؤْمِنُونَ لِجُيُوشِهِمْ فِي صَلَاتِهِمْقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ بِإِسْنَادٍ أَوْصَلَ مِنْ هَذَا وَقَتَادَةُ لَمْ يُدْرِكْ النُّعْمَانَ بْنَ مُقَرِّنٍ وَمَاتَ النُّعْمَانُ بْنُ مُقَرِّنٍ فِي خِلَافَةِ عُمَرَ بْنِ الْخَطَّابِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [An Nu'man bin Muqarrin] ia berkata, \"Aku pernah berperang bersama Nabi shallallahu 'alaihi wasallam, maka jika terbit fajar beliau menahan diri (tidak berperang) hingga matahari terbit. dan jika matahari telah terbit beliau menyerang, jika telah tiba pertengahan siang beliau berhenti hingga matahari condong ke arah barat, ketika matahari telah condong beliau kembali menyerang hingga tiba waktu asar, kemudian beliau berhenti hingga selesai melaksanakan shalat asar, dan setelah itu beliau kembali menyerang.\" Nu'man berkata, \"Maka pada saat itu dikatakan, 'Angin kemenangan telah berhembus, dan orang-orang beriman mendoakan tentaranya dalam shalat mereka.\" Abu Isa berkata, \"Hadits ini diriwayatkan dari An Nu'man bin Muqarrin dengan sanad lain yang lebih bersambung dari pada sanad ini. Dan Qatadah belum pernah ketemu An Nu'man bin Muqarrin, sebab Nu'man meninggal pada masa pemerintahan Umar Ibnul Khaththab.\""},"1538":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ وَالْحَجَّاجُ بْنُ مِنْهَالٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو عِمْرَانَ الْجَوْنِيُّ عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ مَعْقِلِ بْنِ يَسَارٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِ بَعَثَ النُّعْمَانَ بْنَ مُقَرِّنٍ إِلَى الْهُرْمُزَانِ فَذَكَرَ الْحَدِيثَ بِطُولِهِ فَقَالَ النُّعْمَانُ بْنُ مُقَرِّنٍشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ إِذَا لَمْ يُقَاتِلْ أَوَّلَ النَّهَارِ انْتَظَرَ حَتَّى تَزُولَ الشَّمْسُ وَتَهُبَّ الرِّيَاحُ وَيَنْزِلَ النَّصْرُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعَلْقَمَةُ بْنُ عَبْدِ اللَّهِ هُوَ أَخُو بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Affan bin Muslim] dan [Al Hajjaj bin Minhal] keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah menceritakan kepada kami [Abu Imran Al Jauni] dari [Alqamah bin Abdullah Al Muzanni] dari [Ma'qil bin Yasar] berkata, \"Umar Ibnul Khaththab mengutus [An Nu'man bin Muqarrin] menuju Hurmuzan…lalu ia menyebutkan hadits dengan panjang. An Nu'man bin Muqarrin berkata, \"Aku pernah mengikuti peperangan bersama Rasulullah shallallahu 'alaihi wasallam. Maka Jika di awal hari (pagi hari) beliau tidak memulai peperangan, beliau menunggu matahari condong dan angin bertiup, sehingga kemenangan pun turun.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Alqamah bin Abdullah adalah saudara Abu Bakar bin Abdullah Al Muzani.\""},"1539":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عِيسَى بْنِ عَاصِمٍ عَنْ زِرٍّ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطِّيَرَةُ مِنْ الشِّرْكِ وَمَا مِنَّا وَلَكِنَّ اللَّهَ يُذْهِبُهُ بِالتَّوَكُّلِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَحَابِسٍ التَّمِيمِيِّ وَعَائِشَةَ وَابْنِ عُمَرَ وَسَعْدٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سَلَمَةَ بْنِ كُهَيْلٍ وَرَوَى شُعْبَةُ أَيْضًا عَنْ سَلَمَةَ هَذَا الْحَدِيثَ قَالَ سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ كَانَ سُلَيْمَانُ بْنُ حَرْبٍ يَقُولُ فِي هَذَا الْحَدِيثِ وَمَا مِنَّا وَلَكِنَّ اللَّهَ يُذْهِبُهُ بِالتَّوَكُّلِ قَالَ سُلَيْمَانُ هَذَا عِنْدِي قَوْلُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَمَا مِنَّا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail bin Ashim] dari ['Isa bin 'Ashim] dari [Zirr] dari [Abdullah bin Mas'ud] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya thiyarah (pesimis) bagian dari syirik dan bukan bagian dari ajaran kami, justru Allah akan menghilangkan thiyarah (pesimis) itu dengan bertawakkal kepada-Nya.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Hurairah, Habis At Tamimi, 'Aisyah, Ibnu Umar dan Sa'd. Hadits ini derajatnya hasah shahih, kami tidak mengetahuinya kecuali dari hadits Salamah bin Kuhail. [Syu'bah] juga meriwayatkan dari [Salamah] dengan hadits yang sama. Ia berkata, \"Aku mendengar Muhammad bin Isma'il berkata, \"Sulaiman bin Harb berkata tentang hadits ini, 'dan bukan dari kita, justru Allah akan menghilangkan thiyarah (pesimis) itu dengan bertawakkal kepada-Nya', Sulaiman berkata, \"Ini menurut pendapatku, adalah perkataan Abdullah bin Mas'ud \"dan tidaklah (thiyarah) dari ajaran kami.\" "},"1540":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا طِيَرَةَ وَأُحِبُّ الْفَأْلَ قَالُوا يَا رَسُولَ اللَّهِ وَمَا الْفَأْلُ قَالَ الْكَلِمَةُ الطَّيِّبَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyayar] berkata, telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hisyam Ad Dastuwa`i] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada Adwa (keyakinan bahwa penyakit bisa menular, bukan karena takdir dari Allah) atau Thiyarah (rasa pesimis), tetapi aku menyukai sikap optimis.\" Para sahabat bertanya, \"Wahai Rasulullah, apa itu optimis?\" beliau menjawab: \"Kalimat yang baik.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\" "},"1541":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو عَامِرٍ الْعَقَدِيُّ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعْجِبُهُ إِذَا خَرَجَ لِحَاجَةٍ أَنْ يَسْمَعَ يَا رَاشِدُ يَا نَجِيحُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] berkata, telah menceritakan kepada kami [Abu Amir Al Aqadi] dari [Hammad bin Salamah] dari [Humaid] dari [Anas bin Malik] berkata, \"Sesuatu yang Nabi shallallahu 'alaihi wasallam sukai saat keluar menyelesaikan hajatnya adalah saat mendengar seserang memangil, 'Wahai Rasyid (orang yang mendapatkan jalan lurus), wahai Najih (orang yang sukses) '.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib shahih.\""},"1542":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ أَمِيرًا عَلَى جَيْشٍ أَوْصَاهُ فِي خَاصَّةِ نَفْسِهِ بِتَقْوَى اللَّهِ وَمَنْ مَعَهُ مِنْ الْمُسْلِمِينَ خَيْرًا وَقَالَ اغْزُوا بِسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ قَاتِلُوا مَنْ كَفَرَ بِاللَّهِ وَلَا تَغُلُّوا وَلَا تَغْدِرُوا وَلَا تُمَثِّلُوا وَلَا تَقْتُلُوا وَلِيدًا فَإِذَا لَقِيتَ عَدُوَّكَ مِنْ الْمُشْرِكِينَ فَادْعُهُمْ إِلَى إِحْدَى ثَلَاثِ خِصَالٍ أَوْ خِلَالٍ أَيَّتُهَا أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ وَادْعُهُمْ إِلَى الْإِسْلَامِ وَالتَّحَوُّلِ مِنْ دَارِهِمْ إِلَى دَارِ الْمُهَاجِرِينَ وَأَخْبِرْهُمْ أَنَّهُمْ إِنْ فَعَلُوا ذَلِكَ فَإِنَّ لَهُمْ مَا لِلْمُهَاجِرِينَ وَعَلَيْهِمْ مَا عَلَى الْمُهَاجِرِينَ وَإِنْ أَبَوْا أَنْ يَتَحَوَّلُوا فَأَخْبِرْهُمْ أَنَّهُمْ يَكُونُوا كَأَعْرَابِ الْمُسْلِمِينَ يَجْرِي عَلَيْهِمْ مَا يَجْرِي عَلَى الْأَعْرَابِ لَيْسَ لَهُمْ فِي الْغَنِيمَةِ وَالْفَيْءِ شَيْءٌ إِلَّا أَنْ يُجَاهِدُوا فَإِنْ أَبَوْا فَاسْتَعِنْ بِاللَّهِ عَلَيْهِمْ وَقَاتِلْهُمْ وَإِذَا حَاصَرْتَ حِصْنًا فَأَرَادُوكَ أَنْ تَجْعَلَ لَهُمْ ذِمَّةَ اللَّهِ وَذِمَّةَ نَبِيِّهِ فَلَا تَجْعَلْ لَهُمْ ذِمَّةَ اللَّهِ وَلَا ذِمَّةَ نَبِيِّهِ وَاجْعَلْ لَهُمْ ذِمَّتَكَ وَذِمَمَ أَصْحَابِكَ لِأَنَّكُمْ إِنْ تَخْفِرُوا ذِمَّتَكُمْ وَذِمَمَ أَصْحَابِكُمْ خَيْرٌ مِنْ أَنْ تَخْفِرُوا ذِمَّةَ اللَّهِ وَذِمَّةَ رَسُولِهِ وَإِذَا حَاصَرْتَ أَهْلَ حِصْنٍ فَأَرَادُوكَ أَنْ تُنْزِلَهُمْ عَلَى حُكْمِ اللَّهِ فَلَا تُنْزِلُوهُمْ وَلَكِنْ أَنْزِلْهُمْ عَلَى حُكْمِكَ فَإِنَّكَ لَا تَدْرِي أَتُصِيبُ حُكْمَ اللَّهِ فِيهِمْ أَمْ لَا أَوْ نَحْوَ هَذَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ وَحَدِيثُ بُرَيْدَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ نَحْوَهُ بِمَعْنَاهُ وَزَادَ فِيهِ فَإِنْ أَبَوْا فَخُذْ مِنْهُمْ الْجِزْيَةَ فَإِنْ أَبَوْا فَاسْتَعِنْ بِاللَّهِ عَلَيْهِمْ قَالَ أَبُو عِيسَى هَكَذَا رَوَاهُ وَكِيعٌ وَغَيْرُ وَاحِدٍ عَنْ سُفْيَانَ وَرَوَى غَيْرُ مُحَمَّدِ بْنِ بَشَّارٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ وَذَكَرَ فِيهِ أَمْرَ الْجِزْيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan] dari [Alqamah Martsad] dari [Sulaiman bin Buraidah] dari [Bapaknya] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengirim seorang pemimpin untuk suatu pasukan beliau memberi nasihat untuk selalu bertakwa kepada Allah, dan memberi nasihat kebaikan kepada kaum muslimin. Beliau bersabda: \"Berperanglah dengan nama Allah dan di jalan Allah, perangilah orang-orang yang kafir kepada Allah, jangan mencuri harta ghanimah, jangan menipu, jangan mencincang dan jangan membunuh anak kecil. Jika engkau bertemu dengan orang-orang musyrik musuhmu, maka serulah kepada tiga hal. Mana saja dari ketiga hal itu mereka lakukan maka terimalah dan jangan kalian perangi; serulah mereka untuk masuk Islam; pindah dari negeri mereka menuju negeri orang-orang yang hijrah (kaum muslimin); dan kabarkanlah kepada mereka, jika mereka mau melakukannya (hijrah) maka mereka akan mendapatkan apa yang akan didapatkan oleh orang-orang yang telah berhijrah, dan mereka akan dibebani kewajiban sebagaimana yang didapat oleh orang-orang yang telah hijrah. Tetapi jika mereka menolak untuk hijrah, maka setatus mereka seperti orang-orang Arab dusun, dan akan diberlakukan kepada mereka hukum yang diberlakukan kepada orang-orang Arab dusun. Mereka tidak mendapatkan ghanimah ataupun fai` kecuali jika mereka ikut berjihad, jika menolak maka mereka serta mintalah pertolongan kepada Allah atas mereka dan perangilah. dan Jika engkau mengepung suatu benteng, lalu mereka menginginkan agar engkau memberikan jaminan Allah dan rasul-Nya kepada mereka, maka jangan engkau lakukan. Tetapi berikanlah jaminanmu dan jaminan sahabatmu kepada mereka, sebab jika kalian membatalkan jaminan kalian atau jaminan sahabat kalian, maka itu lebih baik dari pada membatalkan jaminan Allah dan rasul-Nya. Jika engkau mengepung suatu benteng, lalu mereka menginginkan agar engkau menghukumi mereka dengan hukum Allah, maka jangan kamu lakukan. Tetapi hukumilah mereka dengan hukummu. Sebab engkau tidak tahu apakah engkau bisa menguhukumi mereka sesuai dengan hukum Allah atau tidak.\" Kurang lebih seperti ini (sabda Rasulullah Shallallahu 'Alahi Wasallam). Abu Isa berkata, \"Dalam bab ini juga ada hadits dari An Nu'man bin Muqarrin. dan Hadits Buraidah derajatnya hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Ahmad] dari [Sufyan] dari [Alqamah bin Martsad] seperti hadits tersebut dengan maknanya. namun ia menambahkan dalam hadits tersebut, 'Jika mereka menolak maka ambillah jizyah dari mereka, dan jika mereka menolak maka mintalah pertolongan kepada Allah atas mereka (perangilah) '.\" Abu Isa berkata, \"Seperti inilah [Waki'] dan selainnya meriwayatkan hadits tersebut dari [Sufyan]. Dan selain Muhammad bin Basysyar juga meriwayatkan dari 'Abdurrahman bin Mahdi, dan dalam hadits tersebut ia menyebutkan tentang jizyah.\" "},"1543":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُغِيرُ إِلَّا عِنْدَ صَلَاةِ الْفَجْرِ فَإِنْ سَمِعَ أَذَانًا أَمْسَكَ وَإِلَّا أَغَارَ فَاسْتَمَعَ ذَاتَ يَوْمٍ فَسَمِعَ رَجُلًا يَقُولُ اللَّهُ أَكْبَرُ اللَّهُ أَكْبَرُ فَقَالَ عَلَى الْفِطْرَةِ فَقَالَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ خَرَجْتَ مِنْ النَّارِقَالَ الْحَسَنُ وَحَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah menceritakan kepada kami [Tsabit] dari [Anas] ia berkata, \"Nabi shallallahu 'alaihi wasallam tidak pernah menyerang dengan tiba-tiba kecuali ketika fajar. Maka Jika mendengar suara adzan beliau menahan diri, akan tetapi jika tidak (mendengarkannya) beliau menyerangnya. Dan pada suatu hari beliau mencari dengar hingga akhirnya beliau mendengar seorang laki-laki mengucapkan Allahu Akbar Allahu Akbar, beliau lalu bersabda: \"Dia di atas fitrah (Iman dan tauhid).\" Laki-laki itu lalu mengucapkan, \"Asyhadu An Laa Ilaaha Illaallahu.\" Beliau bersabda: \"Engkau telah keluar dari neraka.\" Al Hasan berkata, \"Telah menceritakan kepada kami [Abul Walid] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dengan sanad ini, seperti hadits tersebut.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1544":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقِيلَ يَا رَسُولَ اللَّهِ مَا يَعْدِلُ الْجِهَادَ قَالَ إِنَّكُمْ لَا تَسْتَطِيعُونَهُ فَرَدُّوا عَلَيْهِ مَرَّتَيْنِ أَوْ ثَلَاثًا كُلُّ ذَلِكَ يَقُولُ لَا تَسْتَطِيعُونَهُ فَقَالَ فِي الثَّالِثَةِ مَثَلُ الْمُجَاهِدِ فِي سَبِيلِ اللَّهِ مَثَلُ الْقَائِمِ الصَّائِمِ الَّذِي لَا يَفْتُرُ مِنْ صَلَاةٍ وَلَا صِيَامٍ حَتَّى يَرْجِعَ الْمُجَاهِدُ فِي سَبِيلِ اللَّهِوَفِي الْبَاب عَنْ الشِّفَاءِ وَعَبْدِ اللَّهِ بْنِ حُبْشِيٍّ وَأَبِي مُوسَى وَأَبِي سَعِيدٍ وَأُمِّ مَالِكٍ الْبَهْزِيَّةِ وَأَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Ditanyakan kepada Rasulullah, \"Wahai Rasulullah, amalan apa yang bisa menyamai jihad?\" beliau menjawab: \"Kalian tidak akan mampu.\" Mereka lalu mengulangi pertanyaan tersebut hingga dua atau tiga kali. Dan setiap itu pula beliau menjawab: \"Kalian tidak akan mampu.\" Dan pada kali ketiganya beliau bersabda: \"Permisalan seorang mujahid di jalan Allah seperti seorang yang berdiri shalat dan puasa, ia tidak pernah berhenti dari shalat dan puasanya hingga orang yang berjihad di jalan Allah kembali dari medan perang.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Asy Syifa', Abdullah bin Hubsyi, Abu Musa, Abu Sa'id, Ummu Malik Al Bahziyah dan Anas. Dan hadits ini derajatnya hasan shahih. Hadits ini telah diriwayatkan dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1545":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيع�� حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ حَدَّثَنِي مَرْزُوقٌ أَبُو بَكْرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي يَقُولُ اللَّهُ عَزَّ وَجَلَّ الْمُجَاهِدُ فِي سَبِيلِ اللَّهِ هُوَ عَلَيَّ ضَامِنٌ إِنْ قَبَضْتُهُ أَوْرَثْتُهُ الْجَنَّةَ وَإِنْ رَجَعْتُهُ رَجَعْتُهُ بِأَجْرٍ أَوْ غَنِيمَةٍقَالَ هُوَ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Bazi'] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] berkata, telah menceritakan kepadaku [Marzuq Abu Bakr] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza Wa Jalla berfirman: \"Orang yang berjihad fi sabilillah menjadi tanggungan-Ku, jika Aku pengang (cabut) ruhnya maka akan Aku masukkan ke dalam surga, dan jika Aku kembalikan maka Aku kembalikan ia dengan membawa pahala dan ghanimah.\" Abu Isa berkata, \"Hadits ini derajatnya shahih gharib dari jalur periwayatan ini.\""},"1546":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّ عَمْرَو بْنَ مَالِكٍ الْجَنْبِيَّ أَخْبَرَهُ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ كُلُّ مَيِّتٍ يُخْتَمُ عَلَى عَمَلِهِ إِلَّا الَّذِي مَاتَ مُرَابِطًا فِي سَبِيلِ اللَّهِ فَإِنَّهُ يُنْمَى لَهُ عَمَلُهُ إِلَى يَوْمِ الْقِيَامَةِ وَيَأْمَنُ مِنْ فِتْنَةِ الْقَبْرِ وَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُجَاهِدُ مَنْ جَاهَدَ نَفْسَهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُقْبَةَ بْنِ عَامِرٍ وَجَابِرٍ وَحَدِيثُ فَضَالَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] berkata, telah mengabarkan kepada kami [Abdullah Ibnul Mubarak] berkata, telah mengabarkan kepada kami [Haiwah bin Syuraih] ia berkata; telah mengabarkan kepadaku [Abu Hani Al Khaulani] bahwa [Amru bin Malik Al Janbi] telah mendengar [Fadhalah bin Ubaid] menceritakan dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Setiap mayit ditutup berdasarkan amalnya kecuali orang yang mati saat berjaga di jalan Allah, maka amalnya akan tetap berkembang hingga hari kiamat, dan ia akan aman dari fitnah Dajjal.\" Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mujahid adalah orang yang bisa melawan dirinya sendiri.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Uqbah bin Amir dan Jabir. Dan hadits Fadhalah ini derajatnya hasan shahih.\""},"1547":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ وَسُلَيْمَانَ بْنِ يَسَارٍ أَنَّهُمَا حَدَّثَاهُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ زَحْزَحَهُ اللَّهُ عَنْ النَّارِ سَبْعِينَ خَرِيفًا أَحَدُهُمَا يَقُولُ سَبْعِينَ وَالْآخَرُ يَقُولُ أَرْبَعِينَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو الْأَسْوَدِ اسْمُهُ مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ الْأَسَدِيُّ الْمَدَنِيُّ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَأَنَسٍ وَعُقْبَةَ بْنِ عَامِرٍ وَأَبِي أُمَامَةَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abul Aswad] dari [Urwah bin Az Zubair] dan [Sulaiman bin Yasar] bahwa keduanya telah menceritakan kepadanya (Abul Aswad) dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berpuasa satu hari di jalan Allah, maka Allah akan menjauhkannya dari api neraka selama tujuh puluh musim.\" Salah seorang dari keduanya meriwayatkan dengan lafadz, 'Tujuh puluh', sementara yang lain dengan lafadz, 'empat puluh'.\" Abu Isa berkata, \"Hadits ini derajatnya gharib melalui jalur periwayatan ini. Dan Abul Aswad nama aslinya adalah Muhammad bin 'Abdurrahman bin Naufal Al Asadi? orang Madinah. Dan dalam bab ini juga ada hadits dari Abu Sa'id, Anas, Uqbah bin Amir dan Abu Umamah.\""},"1548":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْوَلِيدِ الْعَدَنِيُّ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ قَالَ و حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ الزُّرَقِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَصُومُ عَبْدٌ يَوْمًا فِي سَبِيلِ اللَّهِ إِلَّا بَاعَدَ ذَلِكَ الْيَوْمُ النَّارَ عَنْ وَجْهِهِ سَبْعِينَ خَرِيفًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sa'id bin 'Abdurrahman Al Makhzumi] berkata, telah menceritakan kepada kami [Abdullah bin Al Walid Al Adani] berkata, telah menceritakan kepada kami [Sufyan Ats Tsauri] ia berkata; dan Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Sufyan] dari [Suhail bin Abu Shalih] dari [An Nu'man bin Abu Ayyasy Az Zuraqi] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba berpuasa satu hari di jalan Allah, kecuali puasa satu hari itu akan menjauhkannya dari api neraka selama tujuh puluh musim (tahun).\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1549":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْوَلِيدُ بْنُ جَمِيلٍ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ الْبَاهِلِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ يَوْمًا فِي سَبِيلِ اللَّهِ جَعَلَ اللَّهُ بَيْنَهُ وَبَيْنَ النَّارِ خَنْدَقًا كَمَا بَيْنَ السَّمَاءِ وَالْأَرْضِهَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي أُمَامَةَ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] berkata, telah menceritakan kepada kami [Yazid bin harun] berkata, telah mengabarkan kepada kami [Al Walid bin Jamil] dari [Al Qasim Abu 'Abdurrahman] dari [Abu Umamah Al Bahili] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berpuasa satu hari di jalan Allah, maka Allah akan menjadikan antara dirinya dengan neraka sebuah parit sejauh langit dan bumi.\" Hadits ini derajatnya hasan gharib, dari hadits Abu Umamah.\""},"1550":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ الرُّكَيْنِ بْنِ الرَّبِيعِ عَنْ أَبِيهِ عَنْ يُسَيْرِ بْنِ عَمِيلَةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ كُتِبَتْ لَهُ بِسَبْعِ مِائَةِ ضِعْفٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ الرُّكَيْنِ بْنِ الرَّبِيعِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Al Husain bin Ali Al Ju'fi] dari [Zaidah] dari [Ar Rukain bin Ar Rabi'] dari [Bapaknya] dari [Yusair bin Amilah] dari [Khuraim bin Fatik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berinfak di jalan Allah maka akan dituliskan untuknya tujuh ratus lipat kebaikan.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Hurairah. Dan hadits ini derajatnya hasan, kami hanya mengetahuinya dari hadits Ar rukain bin Ar Rabi'.\""},"1551":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ كَثِيرِ بْنِ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَدِيِّ بْنِ حَاتِمٍ الطَّائِيِّأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الصَّدَقَةِ أَفْضَلُ قَالَ خِدْمَةُ عَبْدٍ فِي سَبِيلِ اللَّهِ أَوْ ظِلُّ فُسْطَاطٍ أَوْ طَرُوقَةُ فَحْلٍ فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ هَذَا الْحَدِيثُ مُرْسَلًا وَخُولِفَ زَيْدٌ فِي بَعْضِ إِسْنَادِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] berkata, telah menceritakan kepada kami [Zaid bin Hubab] berkata, telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Katsir Ibnul Harits] dari [Al Qasim bin 'Abdurrahman] dari [Adi bin Hatim Ath Tha`i] Bahwasanya ia pernah bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Sedekah apa yang paling utama?\" beliau menjawab: \"Memperbantukan seorang budak untuk jihad di jalan Allah, atau mendirikan kemah untuk berlindung seornag mujahid, atau memberikan seekor unta di jalan Allah.\" Abu Isa berkata, \"Hadits ini telah diriwayatkan dari Mu'awiyah bin Shalih secara mursal.\" Dan Zaid masih dipertentangkan dalam beberapa sanadnya."},"1552":{"ar":"قَالَ وَرَوَى الْوَلِيدُ بْنُ جَمِيلٍ هَذَا الْحَدِيثَ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْوَلِيدُ بْنُ جَمِيلٍ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصَّدَقَاتِ ظِلُّ فُسْطَاطٍ فِي سَبِيلِ اللَّهِ وَمَنِيحَةُ خَادِمٍ فِي سَبِيلِ اللَّهِ أَوْ طَرُوقَةُ فَحْلٍ فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَهُوَ أَصَحُّ عِنْدِي مِنْ حَدِيثِ مُعَاوِيَةَ بْنِ صَالِحٍ","id":"Ia berkata; [Al Walid bin Jamil] menceritakan hadits ini dari [Al Qasim Abu 'Abdurrahman] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam. seperti itu pula yang diceritakan oleh [Ziyad bin Ayyub] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Al Walid bin Jamil] dari [Al Qasim Abu 'Abdurrahman] dari [Abu Umamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sedekah yang paling utama adalah mendirikan kemah, memperbantukan seorang budak dan memberikan unta di jalan Allah.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, dan menurutku hadits ini lebih shahih dari hadits Mu'awiyah bin Shalih.\""},"1553":{"ar":"حَدَّثَنَا أَبُو زَكَرِيَّا يَحْيَى بْنُ دُرُسْتَ الْبَصْرِيُّ حَدَّثَنَا أَبُو إِسْمَعِيلَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ فَقَدْ غَزَا وَمَنْ خَلَفَ غَازِيًا فِي أَهْلِهِ فَقَدْ غَزَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Zakariya Yahya bin Durusta Al Bashri] berkata, telah menceritakan kepada kami [Abu Isma'il] berkata, telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menyediakan bekal kepada seorang mujahid di jalan Allah maka ia telah berjihad. Dan barangsiapa menanggung keluarga orang yang berjihad, maka ia telah berjihad.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, hadits ini juga telah diriwayatkan dari selain jalur ini.\""},"1554":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ أَوْ خَلَفَهُ فِي أَهْلِهِ فَقَدْ غَزَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ibnu Abu Laila] dari [Atha] dari [Zaid bin Khalid Al Juhani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberi bekal seorang mujahid di jalan Allah, atau menanggung keluarga yang ditinggalkannya, maka ia telah berjihad.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] dari [Atha] dari [Zaid bin Khalid Al Juhani] dari Nabi shallallahu 'alaihi wasallam, seperti hadits tersebut.\""},"1555":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ فَ��َدْ غَزَا وَمَنْ خَلَفَ غَازِيًا فِي أَهْلِهِ فَقَدْ غَزَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] berkata, telah menceritakan kepada kami [Harb bin Syaddad] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberi bekal kepada seorang mujahid di jalan Allah, maka ia telah berjihad. Dan barangsiapa menanggung keluarga seorang mujahid maka ia telah berjihad.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1556":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ يَزِيدَ بْنِ أَبِي مَرْيَمَ قَالَ لَحِقَنِي عَبَايَةُ بْنُ رِفَاعَةَ بْنِ رَافِعٍ وَأَنَا مَاشٍ إِلَى الْجُمُعَةِ فَقَالَ أَبْشِرْ فَإِنَّ خُطَاكَ هَذِهِ فِي سَبِيلِ اللَّهِ سَمِعْتُ أَبَا عَبْسٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اغْبَرَّتْ قَدَمَاهُ فِي سَبِيلِ اللَّهِ فَهُمَا حَرَامٌ عَلَى النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَأَبُو عَبْسٍ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ جَبْرٍ وَفِي الْبَاب عَنْ أَبِي بَكْرٍ وَرَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عِيسَى وَيَزِيدُ بْنُ أَبِي مَرْيَمَ رَجُلٌ شَامِيٌّ رَوَى عَنْهُ الْوَلِيدُ بْنُ مُسْلِمٍ وَيَحْيَى بْنُ حَمْزَةَ وَغَيْرُ وَاحِدٍ مِنْ أَهْلِ الشَّامِ وَبُرَيْدُ بْنُ أَبِي مَرْيَمَ كُوفِيٌّ أَبُوهُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاسْمُهُ مَالِكُ بْنُ رَبِيعَةَ وَبُرَيْدُ بْنُ أَبِي مَرْيَمَ سَمِعَ مِنْ أَنَسِ بْنِ مَالِكٍ وَرَوَى عَنْ يَزِيدِ بْنِ أَبِي مَرْيَمَ أَبُو إِسْحَقَ الْهَمْدَانِيُّ وَعَطَاءُ بْنُ السَّائِبِ وَيُونُسُ بْنُ أَبِي إِسْحَقَ وَشُعْبَةُ أَحَادِيثَ","id":"Telah menceritakan kepada kami [Abu Ammar Al Husain bin Huraits] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Yazid bin Abu Maryam] ia berkata, \" [Abayah bin Rifa'ah] menjumpaiku saat aku sedang berjalan menuju shalat jum'at, ia lalu berkata, \"Berbahagialah engkau, sebab langkah kakimu ini termasuk fi sabilillah. Aku mendengar [Abu Abas] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang kedua kakinya berdebu di jalan Allah, maka keduanya diharamkan untuk masuk neraka.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib shahih. Abu Abs nama aslinya adalah 'Abdurrahman bin Jabr. Dan dalam bab ini juga ada hadits dari Abu Bakar dan seorang laki-laki sahabat Nabi shallallahu 'alaihi wasallam.\" Abu Isa berkata, \"Yazid bin Abu Maryam adalah seorang yang berasal dari Syam, Al Walid bin Muslim, Yahya bin Hamzah dan beberapa orang dari penduduk Syam telah meriwayatkan darinya. Sementara Buraid bin Maryam adalah seorang yang berasal dari Kufah, bapaknya merupakan sahabat Nabi shallallahu 'alaihi wasallam. Nama asli (Buraid) adalah Malik bin Rabi'ah. Buraid bin Abu Maryam mendengar dari Anas bin Malik. Abu Ishaq Al Hamdani, Atha bin As Sa`ib, Yunus bin Abu Ishaq dan Syu'bah telah meriwayatkan beberapa hadits darinya.\""},"1557":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ الْمَسْعُودِيِّ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَلِجُ النَّارَ رَجُلٌ بَكَى مِنْ خَشْيَةِ اللَّهِ حَتَّى يَعُودَ اللَّبَنُ فِي الضَّرْعِ وَلَا يَجْتَمِعُ غُبَارٌ فِي سَبِيلِ اللَّهِ وَدُخَانُ جَهَنَّمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَمُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ هُوَ مَوْلَى أَبِي طَلْحَةَ مَدَنِيٌّ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dari ['Abdurrahman bin Abdullah Al Mas'udi] dari [Muhammad bin 'Abdurrahman] dari [Isa bin Thalhah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk ke dalam neraka seorang laki-laki yang menangis karena takut kepada Allah hingga susu kembali ke dalam kantungnya. Dan tidak akan berkumpul menjadi satu debu di jalan Allah dengan asap api neraka.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, dan Muhammad bin 'Abdurrahman adalah mantan budak (yang telah dimerdekakan oleh) Abu Thalhah, yang berasal dari madinah.\""},"1558":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ أَنَّ شُرَحْبِيلَ بْنَ السِّمْطِ قَالَ يَا كَعْبُ بْنَ مُرَّةَ حَدِّثْنَا عَنْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحْذَرْ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ شَابَ شَيْبَةً فِي الْإِسْلَامِ كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَةِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ فَضَالَةَ بْنِ عُبَيْدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَحَدِيثُ كَعْبِ بْنِ مُرَّةَ حَدِيثٌ حَسَنٌ هَكَذَا رَوَاهُ الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ وَأَدْخَلَ بَيْنَهُ وَبَيْنَ كَعْبِ بْنِ مُرَّةَ فِي الْإِسْنَادِ رَجُلًا وَيُقَالُ كَعْبُ بْنُ مُرَّةَ وَيُقَالُ مُرَّةُ بْنُ كَعْبٍ الْبَهْزِيُّ وَالْمَعْرُوفُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرَّةُ بْنُ كَعْبٍ الْبَهْزِيُّ وَقَدْ رَوَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Amru bin Murrah] dari [Salim bin Abul Ja'd] bahwa [Syurahbil bin As Samth] berkata, \"Wahai [Ka'b bin Murrah], ceritakanlah kepadaku sebuah hadits dari Rasulullah shallallahu 'alaihi wasallam, dan hati-hatilah (jangan menambah atau menguranginya).\" Ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tumbuh satu uban dalam Islam, maka uban tersebut akan menjadi cahaya baginya pada hari kiamat.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Fadhalah bin Ubaid dan Abdullah bin Amru. Dan hadits Ka'b bin Murrah derajatnya adalah hasan. Demikianlah Al A'masy meriwayatkan dari Amru bin Murrah. Hadits ini juga diriwayatkan dari [Manshur], dari [Salim bin Abul Ja'd]. Lalu ia memasukkan satu nama antara dia dengan Ka'b bin Murrah. Yaitu [seorang laki-laki] yang dipanggil dengan nama Ka'b bin Murrah, atau Murrah bin Ka'b Al Bahzi. Tetapi yang lebih masyhur di kalangan sahabat Nabi shallallahu 'alaihi wasallam adalah Murrah bin Ka'b Al Bahzi. Ia telah meriwayatkan beberapa hadits dari Nabi shallallahu 'alaihi wasallam.\""},"1559":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ الْمَرْوَزِيُّ أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ الْحِمْصِيُّ عَنْ بَقِيَّةَ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَمْرِو بْنِ عَبَسَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَابَ شَيْبَةً فِي سَبِيلِ اللَّهِ كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَحَيْوَةُ بْنُ شُرَيْحٍ ابْنُ يَزِيدَ الْحِمْصِيُّ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur Al Marwazi] berkata, telah mengabarkan kepada kami [Haiwah bin Syuraih Al Himshi] dari [Baqiyah] dari [bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah] dari [Amru bin Abasah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tumbuh satu bulu uban di jalan Allah, maka bulu uban tersebut akan menjadi cahaya baginya pada hari kiamat.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, dan Haiwah bin Syuraih adalah Ibnu Yazid Al Himshi.\""},"1560":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْخَيْلُ لِثَلَاثَةٍ هِيَ لِرَجُلٍ أَجْرٌ وَهِيَ لِرَجُلٍ سِتْرٌ وَهِيَ عَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي لَهُ أَجْرٌ فَالَّذِي يَتَّخِذُهَا فِي سَبِيلِ اللَّهِ فَيُعِدُّهَا لَهُ هِيَ لَهُ أَجْرٌ لَا يَغِيبُ فِي بُطُونِهَا شَيْءٌ إِلَّا كَتَبَ اللَّهُ لَهُ أَجْرًاوَفِي الْحَدِيثِ قِصَّةٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى مَالِكُ بْنُ أَنَسٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda tertulis kebaikan hingga hari kiamat. Dan kuda ada tiga; kuda yang menjadi pahala bagi seorang laki-laki, kuda yang akan menjadi satir bagi seorang laki-laki dan kuda yang akan menjadi dosa bagi seorang laki-laki. Adapun kuda yang bisa menjadi pahala adalah kuda yang digunakan untuk jihad di jalan Allah, maka ia mempersiapkan kuda tersebut akan menjadi pahala baginya. Tidak ada sesuatu yang masuk ke dalam perutnya kecuali Allah akan menuliskan pahala kepadanya.\" Dan dalam redaksi hadits tersebut terdapat kisah. Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. [Malik bin Anas] telah meriwayatkan hadits ini dari [Zaid bin Aslam], dari [Abu Shalih], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam.\""},"1561":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيُدْخِلُ بِالسَّهْمِ الْوَاحِدِ ثَلَاثَةً الْجَنَّةَ صَانِعَهُ يَحْتَسِبُ فِي صَنْعَتِهِ الْخَيْرَ وَالرَّامِيَ بِهِ وَالْمُمِدَّ بِهِ وَقَالَ ارْمُوا وَارْكَبُوا وَلَأَنْ تَرْمُوا أَحَبُّ إِلَيَّ مِنْ أَنْ تَرْكَبُوا كُلُّ مَا يَلْهُو بِهِ الرَّجُلُ الْمُسْلِمُ بَاطِلٌ إِلَّا رَمْيَهُ بِقَوْسِهِ وَتَأْدِيبَهُ فَرَسَهُ وَمُلَاعَبَتَهُ أَهْلَهُ فَإِنَّهُنَّ مِنْ الْحَقِّحَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَّامٍ عَنْ عَبْدِ اللَّهِ بْنِ الْأَزْرَقِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ كَعْبِ بْنِ مُرَّةَ وَعَمْرِو بْنِ عَبْسَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Abdullah bin 'Abdurrahman bin Abu Husain] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hanya dengan satu anak panah, Allah akan memasukkan tiga orang ke dalam surga; orang yang membuatnya dengan niat untuk suatu kebaikan; orang yang melemparkannya dan orang yang mempersiapkannya.\" Kemudian beliau bersabda: \"(gemarlah berlatih) melempar dan berkendara. Sungguh, kalian melempar lebih aku sukai dari pada kalian berkendaraan. Setiap permainan yang dilakukan oleh seorang laki-laki muslim adalah batil kecuali latihan dia melempar anak panah dengan busurnya, atau pengajarannya terhadap kuda tunggangannya, atau senda guraunya dengan isterinya, karena sesungguhnya itu semua termasuk kebenaran.\" Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katisr] dari [Abu Sallam] dari [Abdullah bin Al Azraq] dari [Uqbah bin Amir Al Juhani] dari Nabi shallallahu 'alaihi wasallam, seperti dalam hadits tersebut. Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ka'b bin Murrah dan Amru bin Abasah bin Amru. Dan hadits ini derajatnya hasan shahih.\""},"1562":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ عَنْ أَبِيهِ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي نَجِيحٍ السُّلَمِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ فَهُوَ لَهُ عَدْلُ مُحَرَّرٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَأَبُو نَجِيحٍ هُوَ عَمْرُو بْنُ عَبْسَةَ السُّلَمِيُّ وَعَبْدُ اللَّهِ بْنُ الْأَزْرَقِ هُوَ عَبْدُ اللَّهِ بْنُ زَيْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] dari [Bapaknya] dari [Qatadah] dari [Salim bin Abul Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Abu Najih As Sulami? radliallahu 'anhu] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melempar panah di jalan Allah, maka ia mendapatkan kebaikan seperti memerdekakan seorang budak.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Abu Najih nama aslinya adalah Amru bin Absah As Sulami, sementara Abdullah Al Azraq nama aslinya adalah Abdullah bin Zaid.\""},"1563":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا شُعَيْبُ بْنُ رُزَيْقٍ أَبُو شَيْبَةَ حَدَّثَنَا عَطَاءٌ الْخُرَاسَانِيُّ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَيْنَانِ لَا تَمَسُّهُمَا النَّارُ عَيْنٌ بَكَتْ مِنْ خَشْيَةِ اللَّهِ وَعَيْنٌ بَاتَتْ تَحْرُسُ فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُثْمَانَ وَأَبِي رَيْحَانَةَ وَحَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ شُعَيْبِ بْنِ رُزَيْقٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdhami] berkata, telah menceritakan kepada kami [Bisyr bin Umar] berkata, telah menceritakan kepada kami [Syu'aib bin Zuraiq Abu Syaibah] berkata, telah menceritakan kepada kami [Atha Al Khurasani] dari [Atha bin Abu Rabah] dari [Ibnu Abbas] ia berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda; \"Dua mata yang tidak akan disentuh oleh api neraka; mata yang menangis karena takut kepada Allah dan mata yang bergadang untuk berjaga di jalan Allah.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Utsman dan Abu Raihanah. Hadits Ibnu Abbas derajatnya hasan gharib, dan kami tidak mengetahui hadits ini kecuali dari hadits Syu'aib bin Zuraiq.\""},"1564":{"ar":"حَدَّثَنَا يَحْيَى بْنُ طَلْحَةَ الْيَرْبُوعِيُّ الْكُوفِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَتْلُ فِي سَبِيلِ اللَّهِ يُكَفِّرُ كُلَّ خَطِيئَةٍ فَقَالَ جِبْرِيلُ إِلَّا الدَّيْنَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الدَّيْنَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ كَعْبِ بْنِ عُجْرَةَ وَجَابِرٍ وَأَبِي هُرَيْرَةَ وَأَبِي قَتَادَةَ وَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أَبِي بَكْرٍ إِلَّا مِنْ حَدِيثِ هَذَا الشَّيْخِ قَالَ وَسَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ هَذَا الْحَدِيثِ فَلَمْ يَعْرِفْهُ و قَالَ أَرَى أَنَّهُ أَرَادَ حَدِيثَ حُمَيْدٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَيْسَ أَحَدٌ مِنْ أَهْلِ الْجَنَّةِ يَسُرُّهُ أَنْ يَرْجِعَ إِلَى الدُّنْيَا إِلَّا الشَّهِيدُ","id":"Telah menceritakan kepada kami [Yahya bin Thalhah Al Yarbu'I Al Kufi] berkata, telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Humaid] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"gugur di jalan Allah dapat menghapuskan setiap dosa.\" Jibril kemudian berkata, \"Kecuali hutang.\" Maka Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Kecuali hutang.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ka'b bin Ujrah, Jabir, Abu Hurairah dan Qatadah. Ini adalah hadits gharib, kami tidak mengetahui hadits ini diriwayatkan oleh Abu Bakr kecuali dari jalur syaikh ini. Ia berkata, \"Aku bertanya kepada Muhammad bin Isma'il tentang hadits ini, tetapi ia tidak mengetahuinya. Ia (Muhammad bin Isma'il) berkata, \"Menurutku yang ia (Yahya bin Thalhah) maksud adalah hadits Humaid, dari Anas, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak seorang pun dari penduduk surga yang senang untuk kembali ke dunia kecuali orang yang mati syahid.\""},"1565":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ الزُّهْرِيِّ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَرْوَاحَ الشُّهَدَاءِ فِي طَيْرٍ خُضْرٍ تَعْلُقُ مِنْ ثَمَرِ الْجَنَّةِ أَوْ شَجَرِ الْجَنَّةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Az Zuhri] dari [Ibnu Ka'b bin Malik] dari [bapaknya] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ruh para syuhada berada bersama burung-burung hijau yang menempel pada buah-buahan surga, atau beliau mengatakan, 'pepohonan surga'.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1566":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَامِرٍ الْعُقَيْلِيِّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُرِضَ عَلَيَّ أَوَّلُ ثَلَاثَةٍ يَدْخُلُونَ الْجَنَّةَ شَهِيدٌ وَعَفِيفٌ مُتَعَفِّفٌ وَعَبْدٌ أَحْسَنَ عِبَادَةَ اللَّهِ وَنَصَحَ لِمَوَالِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Utsman bin Umar] berkata, telah mengabarkan kepada kami [Ali Ibnul Mubarak] dari [Yahya bin Abu Katsir] dari [Amir Al Uqaili] dari [Bapaknya] dari [Abu Hurairah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperlihatkan tiga golongan yang akan masuk surga pertama kali; orang yang mati syahid, orang yang menjaga diri dari hal yang diharamkan, dan seorang budak yang baik dalam beribadah kepada Allah serta taat kepada tuannya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan.\""},"1567":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَا مِنْ عَبْدٍ يَمُوتُ لَهُ عِنْدَ اللَّهِ خَيْرٌ يُحِبُّ أَنْ يَرْجِعَ إِلَى الدُّنْيَا وَأَنَّ لَهُ الدُّنْيَا وَمَا فِيهَا إِلَّا الشَّهِيدُ لِمَا يَرَى مِنْ فَضْلِ الشَّهَادَةِ فَإِنَّهُ يُحِبُّ أَنْ يَرْجِعَ إِلَى الدُّنْيَا فَيُقْتَلَ مَرَّةً أُخْرَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ ابْنُ أَبِي عُمَرَ قَالَ سُفْيَانُ بْنُ عُيَيْنَةَ كَانَ عَمْرُو بْنُ دِينَارٍ أَسَنَّ مِنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang hamba meninggal dunia, ia mendapatkan kebaikan di sisi Allah, lalu merasa senang jika kembali ke dunia, padahal ia telah memiliki sesutu yang lebih baik dari dunia dan seisinya selain orang yang mati syahid. Hal itu karena ia merasakan akan keutamaan syahid hingga ia ingin kembali ke dunia hingga ia terbunuh lagi.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Ibnu Abu Umar berkata, \"Sufyan bin Uyainah menuturkan, \"Amru bin Dinar lebuh tua dari Az Zuhri.\""},"1568":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ عَطَاءِ بْنِ دِينَارٍ عَنْ أَبِي يَزِيدَ الْخَوْلَانِيِّ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ يَقُولُ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الشُّهَدَاءُ أَرْبَعَةٌ رَجُلٌ مُؤْمِنٌ جَيِّدُ الْإِيمَانِ لَقِيَ الْعَدُوَّ فَصَدَقَ اللَّهَ حَتَّى قُتِلَ فَذَلِكَ الَّذِي يَرْفَعُ النَّاسُ إِلَيْهِ أَعْيُنَهُمْ يَوْمَ الْقِيَامَةِ هَكَذَا وَرَفَعَ رَأْسَهُ حَتَّى وَقَعَتْ قَلَنْسُوَتُهُ قَالَ فَمَا أَدْرِي أَقَلَنْسُوَةَ عُمَرَ أَرَادَ أَمْ قَلَنْسُوَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَرَجُلٌ مُؤْمِنٌ جَيِّدُ الْإِيمَانِ لَقِيَ الْعَدُوَّ فَكَأَنَّمَا ضُرِبَ جِلْدُهُ بِشَوْكِ طَلْحٍ مِنْ الْجُبْنِ أَتَاهُ سَهْمٌ غَرْبٌ فَقَتَلَهُ فَهُوَ فِي الدَّرَجَةِ الثَّانِيَةِ وَرَجُلٌ مُؤْمِنٌ خَلَطَ عَمَلًا صَالِحًا وَآخَرَ سَيِّئًا لَقِيَ الْعَدُوَّ فَصَدَقَ اللَّهَ حَتَّى قُتِلَ فَذَلِكَ فِي الدَّرَجَةِ الثَّالِثَةِ وَرَجُلٌ مُؤْمِنٌ أَسْرَفَ عَلَى نَفْسِهِ لَقِيَ الْعَدُوَّ فَصَدَقَ اللَّهَ حَتَّى قُتِلَ فَذَلِكَ فِي الدَّرَجَةِ الرَّابِعَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَطَاءِ بْنِ دِينَارٍ قَالَ سَمِعْت مُحَمَّدًا يَقُولُ قَدْ رَوَى سَعِيدُ بْنُ أَبِي أَيُّوبَ هَذَا الْحَدِيثَ عَنْ عَطَاءِ بْنِ دِينَارٍ وَقَالَ عَنْ أَشْيَاخٍ مِنْ خَوْلَانَ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي يَزِيدَ و قَالَ عَطَاءُ بْنُ دِينَارٍ لَيْسَ بِهِ بَأْسٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Atha bin Dinar] dari [Abu Yazid Al Khaulani] Bahwasanya ia mendengar [Fadhalah bin Ubaid] berkata; Aku mendengar [Umar Ibnul Khaththab] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Syuhada itu ada empat; seorang mukmin yang istimewa keimanannya, ia bertemu musuh dan membenarkan Allah hingga ia terbunuh. Mukmin inilah yang kelak mata manusia tertuju kepadanya dengan penuh kekaguman pada hari kiamat.\" Nabi mengucapkan hal ini sembari mengangkat kepalanya hingga pecinya terjatuh. Ia katakana; 'Saya tidak tahu peci manakah yang dimaksud, peci Umarkah atau peci Nabi'. Beliau melanjutkan sabdanya; Dan Seorang mukmin yang istimewa keimanannya dan bertemu musuh, hanya sayang tubuhnya (maksudnya dirinya) seolah-olah terkena sedikit duri pohon karena sifat pengecutnya yang masih ada, ia terkena anak panah yang menyasar hingga menjadikannya terbantai, orang ini berada di tingkat kedua. dan seorang mukmin yang masih mencampuradukkan amal shalihnya dan amal buruknya, ia bertemu musuh dan membenarkan Allah hingga terbunuh. Orang ini berada di tingkat ketiga. Dan seorang mukmin yang melampui batas terhadap dirinya, ia bertemu musuh dan membenarkan Allah hingga ia terbunuh. Orang ini berada di tingkat keempat.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Atha bin Dinar. Ia berkata, \"Aku mendengar [Muhammad] berkata, \" [Sa'id bin Abu Ayyub] telah meriwayatkan hadits ini dari [Atha bin Dinar]. Ia berkata dari beberapa [syaikh] wilayah Khaulan, dan ia tidak menyebutkan dalam riwayatnya 'dari Abu Zayid'. namun Atha bin Dinar berkata, \"Tidak ada masalah dengan hal itu.\""},"1569":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ سَمِعَهُ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ عَلَى أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ فَتُطْعِمُهُ وَكَانَتْ أُمُّ حَرَامٍ تَحْتَ عُبَادَةَ بْنِ الصَّامِتِ فَدَخَلَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَأَطْعَمَتْهُ وَجَلَسَتْ تَفْلِي رَأْسَهُ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّه�� يَرْكَبُونَ ثَبَجَ هَذَا الْبَحْرِ مُلُوكٌ عَلَى الْأَسِرَّةِ أَوْ مِثْلَ الْمُلُوكِ عَلَى الْأَسِرَّةِ قُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا لَهَا ثُمَّ وَضَعَ رَأْسَهُ فَنَامَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ نَحْوَ مَا قَالَ فِي الْأَوَّلِ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَقَالَ فَرَكِبَتْ أُمُّ حَرَامٍ الْبَحْرَ فِي زَمَانِ مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ فَصُرِعَتْ عَنْ دَابَّتِهَا حِينَ خَرَجَتْ مِنْ الْبَحْرِ فَهَلَكَتْ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأُمُّ حَرَامٍ بِنْتُ مِلْحَانَ هِيَ أُخْتُ أُمِّ سُلَيْمٍ وَهِيَ خَالَةُ أَنَسِ بْنِ مَالِكٍ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] Bahwasanya ia pernah mendengarnya berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah masuk menemui Ummu Haram binti Milhan, lalu Ummu Haram menghidangkan makanan kepada beliau. Ummu Haram adalah isteri Ubadah bin Ash Shamit, suatu hari Rasulullah shallallahu 'alaihi wasallam menemuinya lalu ia memberi hidangan kepada beliau. Kemudian ia duduk menahan kepala beliau, Rasulullah shallallahu 'alaihi wasallam pun tidur. Setelah itu beliau bangun sambil tertawa, Ummu Haram berkata, \"Aku bertanya, \"Apa yang membuatmu tertawa ya Rasulullah?\" beliau menjawab: \"Telah ditampakkan kepadaku beberapa orang dari umatku yang berperang di jalan Allah, mereka unggul di atas lautan laksanana para raja di atas dipan.\" Aku berkata, \"Wahai Rasulullah, doakanlah agar aku termasuk dari mereka.\" beliau lantas mendoakan Ummu Haram dan kembali meletakkan kepalanya untuk tidur. Kemudian beliau bangun dan tertawa. Ummu Haram berkata, \"Aku bertanya, \"Wahai Rasulullah, apa yang membuatmu tertawa?\" Beliau menjawab: \"Telah ditampakkan kepadaku beberapa orang dari umatku yang berperang di jalan Allah…seperti yang beliau sebutkan di awal. Ummu Haram berkata, \"Aku berkata, \"Wahai Rasulullah, doakanlah agar aku termasuk dari mereka.\" beliau bersabda: \"Engkau termasuk orang-orang yang pertama (dari mereka).\" Ummu Haram lalu mengarungi lautan pada masa pemerintahan Mu'awiyah bin Abu Sufyan. Saat akan mendarat dari lautan ia terpental dari tunggannya hingga ia pun meninggal.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Ummu Haram binti Milhan adalah saudara wanita Ummu Sulaim, ia adalah bibi Anas bin Malik.\""},"1570":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ أَبِي مُوسَى قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُقَاتِلُ شَجَاعَةً وَيُقَاتِلُ حَمِيَّةً وَيُقَاتِلُ رِيَاءً فَأَيُّ ذَلِكَ فِي سَبِيلِ اللَّهِ قَالَ مَنْ قَاتَلَ لِتَكُونَ كَلِمَةُ اللَّهِ هِيَ الْعُلْيَا فَهُوَ فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq bin Salamah] dari [Abu Musa] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya tentang seorang laki-laki yang berperang agar disebut sebagai seorang yang gagah berani, dan seorang laki-laki yang berperang karena kelompok dan seorang laki-laki yang berperang karena riya, maka manakah yang termasuk fi sabilillah?\" beliau menjawab: \"Barangsiapa berperang untuk meninggikan kalimat Allah maka ia telah berperang fi sabilillah.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Umar. Dan hadits ini derajatnya hasan shahih.\""},"1571":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ اللَّيْثِيِّ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ إِلَى دُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ مَالِكِ بْنِ أَنَسٍ وَسُفْيَانَ الثَّوْرِيِّ وَغَيْرِ وَاحِدٍ مِنْ الْأَئِمَّةِ هَذَا عَنْ يَحْيَى بْنِ سَعِيدٍ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ قَالَ قَالَ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ يَنْبَغِي أَنْ نَضَعَ هَذَا الْحَدِيثَ فِي كُلِّ بَابٍ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari [Alqamah bin Waqash Al Laitsi] dari [Umar Ibnul Khaththab] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hanyasanya setiap amal itu tergantung dengan amalnya, dan setiap orang akan mendapatkan ganjaran sesuai dengan amalnya. Barangsiapa hijrahnya untuk Allah dan rasul-Nya, maka amalan hijrahnya akan sampai kepada Allah dan rasul-Nya. Dan barangsiapa hijrahnya untuk dunia atau wanita yang akan dinikahinya, maka hijrahnya akan sampai pada sesuatu yang ia hijrah kepadanya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Hadits ini juga telah diriwayatkan oleh [Malik bin Anas], [Sufyan Ats Tsauri] dan banyak imam lain dari [Yahya bin Sa'id]. Dan kami tidak mengetahuinya kecuali dari hadits Yahya bin Said Al Anshari. Ia berkata, \"'Abdurrahman bin Mahdi berkata, \"Selayaknya kita meletakkan hadits ini pada setiap bab.\""},"1572":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْعَطَّافُ بْنُ خَالِدٍ الْمَخْزُومِيُّ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدْوَةٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَمَوْضِعُ سَوْطٍ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَأَبِي أَيُّوبَ وَأَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Aththaf bin Khalid Al Makhzumi] dari [Abu Hazim] dari [Sahl bin Sa'd As Sa'idi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keluar pagi hari di jalan Allah lebih baik dari dunia dan seisinya, dan tempat cambuk salah seorang dari kalian di surga lebih baik dari dunia dan seisinya.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Hurairah, Ibnu Abbas, Abu Ayyub dan Anas. Hadits ini derajatnya hasan shahih.\""},"1573":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ ابْنِ عَجْلَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْحَجَّاجُ عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو حَازِمٍ الَّذِي رَوَى عَنْ سَهْلِ بْنِ سَعْدٍ هُوَ أَبُو حَازِمٍ الزَّاهِدُ وَهُوَ مَدَنِيٌّ وَاسْمُهُ سَلَمَةُ بْنُ دِينَارٍ وَأَبُو حَازِمٍ الَّذِي رَوَى عَنْ أَبِي هُرَيْرَةَ هُوَ أَبُو حَازِمٍ الْأَشْجَعِيُّ الْكُوفِيُّ وَاسْمُهُ سَلْمَانُ وَهُوَ مَوْلَى عَزَّةَ الْأَشْجَعِيَّةِ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Ibnu Ajlan] dari [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Dan [Al Hajjaj] dari [Al Hakam] dari [Miqsam] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Keluar di waktu sore atau pagi hari di jalan Allah lebih baik dari dunia dan seisinya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib. Abu Hazim yang meriwayatkan hadits dari Sahl bin Sa'd adalah Abu Hazim Az Zahid. Ia berasal dari kota Madinah, nama aslinya adalah Salamah bin Dinar. Sementara Abu Hazim yang meriwayatkan hadits dari Abu Hurairah adalah Abu Hazim Al Asyja'I Al Kufi, nama aslinya adalah Salman, mantan budak (yang telah dimerdekakan oleh) Azzah Al Asyja'iyah.\""},"1574":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ الْكُوفِيُّ حَدَّثَنَا أَبِي عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ ابْنِ أَبِي ذُبَابٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَرَّ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشِعْبٍ فِيهِ عُيَيْنَةٌ مِنْ مَاءٍ عَذْبَةٌ فَأَعْجَبَتْهُ لِطِيبِهَا فَقَالَ لَوْ اعْتَزَلْتُ النَّاسَ فَأَقَمْتُ فِي هَذَا الشِّعْبِ وَلَنْ أَفْعَلَ حَتَّى أَسْتَأْذِنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَفْعَلْ فَإِنَّ مُقَامَ أَحَدِكُمْ فِي سَبِيلِ اللَّهِ أَفْضَلُ مِنْ صَلَاتِهِ فِي بَيْتِهِ سَبْعِينَ عَامًا أَلَا تُحِبُّونَ أَنْ يَغْفِرَ اللَّهُ لَكُمْ وَيُدْخِلَكُمْ الْجَنَّةَ اغْزُو فِي سَبِيلِ اللَّهِ مَنْ قَاتَلَ فِي سَبِيلِ اللَّهِ فَوَاقَ نَاقَةٍ وَجَبَتْ لَهُ الْجَنَّةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ubaid bin Asbath bin Muhammad Al Qurasyi Al Kufi] berkata, telah menceritakan kepada kami [Bapakku] dari [Hisyam bin Sa'd] dari [Sa'id bin Abu Hilal] dari [Ibnu Abu Dzubab] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki dari sabahat Rasulullah shallallahu 'alaihi wasallam melewati sebuah lembah yang terdapat mata air yang jernih hingga membuatnya kagum karena bagusnya. Ia lalu berkata, \"Sekiranya aku tinggalkan manusia dan menetap di lembah ini. Tetapi sekali-kali aku tidak akan melakukannya hingga aku minta izin kepada Rasulullah shallallahu 'alaihi wasallam.\" Kemudian laki-laki itu menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu bersabda: \"Jangan kamu lakukan! Sungguh, tempat salah seorang dari kalian di jalan Allah (jihad) lebih utama dari ibadah selama enam puluh tahun di dalam rumahnya. Apakah kalian tidak suka jika Allah mengampuni dosa-dosa kalian dan memasukkan kalian ke dalam surga? Berperanglah kalian di jalan Allah, barangsiapa berperang di jalan Allah meskipun hanya sekadar orang memerah susu unta, maka telah wajib baginya masuk surga.\" Abu Isa berkata, \"Hadits ini derajatnya hasan.\""},"1575":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَغَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَلَقَابُ قَوْسِ أَحَدِكُمْ أَوْ مَوْضِعُ يَدِهِ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَلَوْ أَنَّ امْرَأَةً مِنْ نِسَاءِ أَهْلِ الْجَنَّةِ اطَّلَعَتْ إِلَى الْأَرْضِ لَأَضَاءَتْ مَا بَيْنَهُمَا وَلَمَلَأَتْ مَا بَيْنَهُمَا رِيحًا وَلَنَصِيفُهَا عَلَى رَأْسِهَا خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, keluar di sore atau pagi hari di jalan Allah adalah lebih baik dari pada dunia dan seisinya. Dan tempat busur panah salah seorang dari kalian atau tempat tangan salah seorang dari kalian di surga adalah lebih baik dari dunia dan seisinya. Sekiranya wanita penduduk surga melongok ke bumi maka maka seisi langit dan bumi akan menjadi terang serta penuh dengan semerbak harum, dan sungguh konde rambut wanita surga lebih baik dari dunia dan seisinya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1576":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّا��ٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ النَّاسِ رَجُلٌ مُمْسِكٌ بِعِنَانِ فَرَسِهِ فِي سَبِيلِ اللَّهِ أَلَا أُخْبِرُكُمْ بِالَّذِي يَتْلُوهُ رَجُلٌ مُعْتَزِلٌ فِي غُنَيْمَةٍ لَهُ يُؤَدِّي حَقَّ اللَّهِ فِيهَا أَلَا أُخْبِرُكُمْ بِشَرِّ النَّاسِ رَجُلٌ يُسْأَلُ بِاللَّهِ وَلَا يُعْطِي بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَيُرْوَى هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Bukair bin Abdullah bin Al Asyaj] dari [Atha bin Yasar] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Maukah aku kabarkan kepada kalian sebaik-baik manusia? Seorang laki-laki yang memegang tali kudanya di jalan Allah. Maukah aku kabarkan kepada kalian orang berikutnya? Seorang laki-laki yang menyepi di tempat pengembalaannya, lalu ia melaksanakan hak-hak Allah. Dan maukah aku kabarkan kepada kalian seburuk-buruk manusia? Seorang laki-laki yang diminta bantuan dengan nama Allah tetapi tidak mau memberi.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib dari jalur periwayatan ini, dan hadits ini juga diriwayatkan dari Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1577":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَهْلِ بْنِ عَسْكَرٍ الْبَغْدَادِيُّ حَدَّثَنَا الْقَاسِمُ بْنُ كَثِيرٍ الْمِصْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ أَنَّهُ سَمِعَ سَهْلَ بْنَ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ اللَّهَ الشَّهَادَةَ مِنْ قَلْبِهِ صَادِقًا بَلَّغَهُ اللَّهُ مَنَازِلَ الشُّهَدَاءِ وَإِنْ مَاتَ عَلَى فِرَاشِهِقَالَ أَبُو عِيسَى حَدِيثُ سَهْلِ بْنِ حُنَيْفٍ حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ شُرَيْحٍ وَقَدْ رَوَاهُ عَبْدُ اللَّهِ بْنُ صَالِحٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شُرَيْحٍ وَعَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ يُكْنَى أَبَا شُرَيْحٍ وَهُوَ إِسْكَنْدَرَانِيٌّ وَفِي الْبَاب عَنْ مُعَاذِ بْنِ جَبَلٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sahl bin Askar Al Baghdadi] berkata, telah menceritakan kepada kami [Al Qasim bin Katsir Al Mishri] berkata, telah menceritakan kepada kami ['Abdurrahman bin Syuraih] Bahwasanya ia mendengar [Sahl bin Abu Umamah bin Sahl bin Hunaif] ia menceritakan dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang memohon mati syahid kepada Allah dengan jujur dari dalam hatinya, maka Allah akan memberinya pahala syuhada meskipun ia meninggal di atas kasur.\" Abu Isa berkata, \"Hadits Sahl bin Hunaif derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits 'Abdurrahman bin Syuraih. [Abdullah bin Shalih] telah meriwayatkannya dari ['Abdurrahman bin Syuraih]. Dan 'Abdurrahman bin Syuraih berjuluk Abu Syuraih, ia berasal dari Iskadariya. Dalam bab ini juga ada hadits dari Mu'adz bin Jabal.\""},"1578":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَالِكِ بْنِ يُخَامِرَ السَّكْسَكِيِّ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ اللَّهَ الْقَتْلَ فِي سَبِيلِهِ صَادِقًا مِنْ قَلْبِهِ أَعْطَاهُ اللَّهُ أَجْرَ الشَّهِيدِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Sulaiman bin Musa] dari [Malik bin Yukhamir As Saksaki] dari [Mu'adz bin Jabal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memohon kepada Allah untuk mati di jalan-Nya, jujur dari dalam hatinya, maka Allah akan memberinya pahala mati syahid.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1579":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ حَقٌّ عَلَى اللَّهِ عَوْنُهُمْ الْمُجَاهِدُ فِي سَبِيلِ اللَّهِ وَالْمُكَاتَبُ الَّذِي يُرِيدُ الْأَدَاءَ وَالنَّاكِحُ الَّذِي يُرِيدُ الْعَفَافَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Ibnu Ajlan] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang pasti Allah tolong; orang yang berjihad di jalan Allah, budak yang ingin merdeka dari tuannya (dengan tebusan) dan orang yang ingin menikah agar dirinya terjaga dari dosa.\" Abu Isa berkata, \"Hadits ini derajatnya hasan.\""},"1580":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُكْلَمُ أَحَدٌ فِي سَبِيلِ اللَّهِ وَاللَّهُ أَعْلَمُ بِمَنْ يُكْلَمُ فِي سَبِيلِهِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ اللَّوْنُ لَوْنُ الدَّمِ وَالرِّيحُ رِيحُ الْمِسْكِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] ia berkata, 'Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seseorang terluka di jalan Allah -dan Allah lebih tahu dengan orang yang terluka di jalan Nya-, kecuali pada hari kiamat ia akan datang dengan luka berwarna darah dan berbau kesturi.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, hadits ini telah diriwayatkan dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1581":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ مَالِكِ بْنِ يُخَامِرَ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَاتَلَ فِي سَبِيلِ اللَّهِ مِنْ رَجُلٍ مُسْلِمٍ فُوَاقَ نَاقَةٍ وَجَبَتْ لَهُ الْجَنَّةُ وَمَنْ جُرِحَ جُرْحًا فِي سَبِيلِ اللَّهِ أَوْ نُكِبَ نَكْبَةً فَإِنَّهَا تَجِيءُ يَوْمَ الْقِيَامَةِ كَأَغْزَرِ مَا كَانَتْ لَوْنُهَا الزَّعْفَرَانُ وَرِيحُهَا كَالْمِسْكِهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Ibnu Juraij] dari [Sulaiman bin Musa] dari [Malik bin Yukhamir] dari [Mu'adz bin Jabal] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang muslim yang berperang di jalan Allah selama waktu perasaan susu unta, maka telah wajib baginya masuk surga. Dan barangsiapa terluka di jalan Allah, atau terkena sebuah lemparan maka pada hari kiamat ia akan datang dalam keadaan terluka, warnanya warna za'faran (nama tumbuhan yang berwarna kuning keemasan) dan baunya bau kesturi.\" Hadits ini derajatnya shahih.\""},"1582":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَفْضَلُ أَوْ أَيُّ الْأَعْمَالِ خَيْرٌ قَالَ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ قِيلَ ثُمَّ أَيُّ شَيْءٍ قَالَ الْجِهَادُ سَنَامُ الْعَمَلِ قِيلَ ثُمَّ أَيُّ شَيْءٍ يَا رَسُولَ اللَّهِ قَالَ ثُمَّ حَجٌّ مَبْرُورٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Muhammad bin Amru] berkata, telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya, \"Amal apa yang paling utama, atau ia mengatakan, \"Amal apa yang paling baik?\" beliau menjawab: \"Beriman kepada Allah dan Rasul-Nya.\" Dikatakan, \"Lalu apa lagi?\" beliau menjawab: \"Jihad, ia adalah puncak sebuah amal.\" Dikatakan, \"Wahai Rasulullah, lalu apa lagi?\" beliau menjawab: \"Haji mabrur.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Hadits ini telah diriwayatkan dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1583":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ أَبِي بَكْرِ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ قَال سَمِعْتُ أَبِي بِحَضْرَةِ الْعَدُوِّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبْوَابَ الْجَنَّةِ تَحْتَ ظِلَالِ السُّيُوفِ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ رَثُّ الْهَيْئَةِ أَأَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُهُ قَالَ نَعَمْ فَرَجَعَ إِلَى أَصْحَابِهِ فَقَالَ أَقْرَأُ عَلَيْكُمْ السَّلَامَ وَكَسَرَ جَفْنَ سَيْفِهِ فَضَرَبَ بِهِ حَتَّى قُتِلَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ جَعْفَرِ بْنِ سُلَيْمَانَ الضُّبَعِيِّ وَأَبُو عِمْرَانَ الْجَوْنِيُّ اسْمُهُ عَبْدُ الْمَلِكِ بْنُ حَبِيبٍ وَأَبُو بَكْرِ ابْنُ أَبِي مُوسَى قَالَ أَحْمَدُ بْنُ حَنْبَلٍ هُوَ اسْمُهُ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ja'far bin Sulaiman Adh Dhuba'i] dari [Abu Imran Al Jauni] dari [Abu Bakr bin Abu Musa Al Asy'ari] ia berkata; Aku mendengar [Bapakku] berkata di hadapan musuh, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pintu-pintu surga berada di bawah naungan pedang.\" Lalu ada seorang laki-laki yang buruk keadaannya berkata, \"Apakah kamu benar-banar mendengar hadits dari Rasulullah shallallahu 'alaihi wasallam yang menyebutnya?\" Bapakku menjawab, \"Ya.\" Laki-laki itu kemudian kembali kepada para sahabatnya dan berkata, \"Aku ucapkan salam (perpisahan) kepada kalian.\" Kemudian orang itu memecah sarung pedangnya dan berperang hingga terbunuh.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Ja'far bin Suliman Adh Dhubba'i. Abu Imran Al jauni nama aslinya adalah Abdul Malik bin Habib, dan Abu Bakar adalah Ibnu (anak) Abu Musa. Ahmad bin Hanbal berkata, \"Itu adalah nama dia.\""},"1584":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ حَدَّثَنَا الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النَّاسِ أَفْضَلُ قَالَ رَجُلٌ يُجَاهِدُ فِي سَبِيلِ اللَّهِ قَالُوا ثُمَّ مَنْ قَالَ ثُمَّ مُؤْمِنٌ فِي شِعْبٍ مِنْ الشِّعَابِ يَتَّقِي رَبَّهُ وَيَدَعُ النَّاسَ مِنْ شَرِّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Ammar] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] berkata, telah menceritakan kepada kami [Az Zuhri] dari [Atha bin Yazid Al Laitsi] dari [Abu Sa'id Al Kahudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya, \"Manusia mana yang paling utama?\" beliau bersabda: \"Seorang laki-laki yang berjihad di jalan Allah.\" Para sahabat bertanya, \"Lalu siapa lagi?\" beliau menjawab: \"Seorang mukmin yang berada di suatu lembah, ia beribadah kepada Allah dan menjauhi manusia agar terhindar dari keburukannya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1585":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ أَحَدٍ مِنْ أَهْلِ الْجَنَّةِ يَسُرُّهُ أَنْ يَرْجِعَ إِلَى الدُّنْيَا غَيْرُ الشَّهِيدِ فَإِنَّهُ يُحِبُّ أَنْ يَرْجِعَ إِلَى الدُّنْيَا يَقُولُ حَتَّى أُقْتَلَ عَشْرَ مَرَّاتٍ فِي سَبِيلِ اللَّهِ مِمَّا يَرَى مِمَّا أَعْطَاهُ مِنْ الْكَرَامَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepadaku [Bapakku] dari [Qatadah] ia berkata, telah menceritakan kepada kami [Anas bin Malik] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang pun dari penduduk surga yang senang untuk kembali lagi ke dunia selain orang yang mati syahid. Sesungguhnya ia suka untuk kembali lagi ke dunia, ia mengatakan 'hingga aku terbunuh sepuluh kali', di jalan Allah, hal itu karena ia melihat kemuliaan yang diberikan oleh Allah kepadanya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari Nabi shallallahu 'alaihi wasallam seperti itu dengan makna yang sama.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1586":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلشَّهِيدِ عِنْدَ اللَّهِ سِتُّ خِصَالٍ يُغْفَرُ لَهُ فِي أَوَّلِ دَفْعَةٍ وَيَرَى مَقْعَدَهُ مِنْ الْجَنَّةِ وَيُجَارُ مِنْ عَذَابِ الْقَبْرِ وَيَأْمَنُ مِنْ الْفَزَعِ الْأَكْبَرِ وَيُوضَعُ عَلَى رَأْسِهِ تَاجُ الْوَقَارِ الْيَاقُوتَةُ مِنْهَا خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَيُزَوَّجُ اثْنَتَيْنِ وَسَبْعِينَ زَوْجَةً مِنْ الْحُورِ الْعِينِ وَيُشَفَّعُ فِي سَبْعِينَ مِنْ أَقَارِبِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abdullah bin 'Abdurrahman] berkata, telah menceritakan kepada kami [Nu'aim bin Hammad] berkata, telah menceritakan kepada kami [Baqiyyah Ibnul Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'di Karib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang mati syahid di sisi Allah mempunyai enam keutamaan; dosanya akan diampuni sejak darahnya tertumpah di awal kali pertempuran, diperlihatkan tempat duduknya di surga, dijaga dari siksa kubur, diberi keamanan dari ketakutan yang besar saat dibangkitkan dari kubur, diberi mahkota kemuliaan yang satu permata darinya lebih baik dari dunia seisinya, dinikahkan dengan tujuh puluh dua bidadari dan diberi hak untuk memberi syafaat kepada tujuh puluh orang dari keluarganya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib.\""},"1587":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ حَدَّثَنَا أَبُو النَّضْرِ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَمَوْضِعُ سَوْطِ أَحَدِكُمْ فِي الْجَنَّةِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا وَلَرَوْحَةٌ يَرُوحُهَا الْعَبْدُ فِي سَبِيلِ اللَّهِ أَوْ لَغَدْوَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَاهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu An Nadhr] berkata, telah menceritakan kepada kami [Abu An Nadhr Al Baghdadi] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abdullah bin Dinar] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ribath satu hari di jalan Allah lebih baik dari dunia seisinya. Dan tempat cambuk salah seorang dari kalian di surga lebih baik dari dunia seisinya. Dan keluarnya seorang hamba di jalan Allah pada waktu pagi atau sore hari adalah lebih baik dari dunia dan seisinya.\" Hadits ini derajatnya hasan shahih. "},"1588":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُنْكَدِرِ قَالَمَرَّ سَلْمَانُ الْفَارِسِيُّ بِشُرَحْبِيلَ بْنِ السِّمْطِ وَهُوَ فِي مُرَابَطٍ لَهُ وَقَدْ شَقَّ عَلَيْهِ وَعَلَى أَصْحَابِهِ قَالَ أَلَا أُحَدِّثُكَ يَا ابْنَ السِّمْطِ بِحَدِيثٍ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَلَى قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ أَفْضَلُ وَرُبَّمَا قَالَ خَيْرٌ مِنْ صِيَامِ شَهْرٍ وَقِيَامِهِ وَمَنْ مَاتَ فِيهِ وُقِيَ فِتْنَةَ الْقَبْرِ وَنُمِّيَ لَهُ عَمَلُهُ إِلَى يَوْمِ الْقِيَامَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan Ats Tsauri] berkata, telah menceritakan kepada kami [Muhammad Ibnul Munkadir] ia berkata, \" [Salman Al Farisi] melewati Syurahbil bin As Simth yang sedang berada di tempat ribathnya, sementara dirinya dan para sahabatnya telah merasakan kebosanan. Salman berkata, \"Wahai Ibnu As Simth, maukah aku bacakan kepadamu sebuah hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab, \"Tentu.\" Salman berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ribath satu hari di jalan Allah lebih utama, dan barangkali ia menyebutkan, \"lebih baik dari puasa dan shalat selama sebulan. Dan barangsiapa meninggal saat ribath, maka ia akan terjaga dari fitnah kubur dan amalnya akan terus berkembang hingga datangnya hari kiamat.\" Abu Isa berkata, \"hadits ini derajatnya hasan.\""},"1589":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ ح��جْرٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ إِسْمَعِيلَ بْنِ رَافِعٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَقِيَ اللَّهَ بِغَيْرِ أَثَرٍ مِنْ جِهَادٍ لَقِيَ اللَّهَ وَفِيهِ ثُلْمَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ الْوَلِيدِ بْنِ مُسْلِمٍ عَنْ إِسْمَعِيلَ بْنِ رَافِعٍ وَإِسْمَعِيلُ بْنُ رَافِعٍ قَدْ ضَعَّفَهُ بَعْضُ أَهْلِ الْحَدِيثِ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ هُوَ ثِقَةٌ مُقَارِبُ الْحَدِيثِ وَقَدْ رُوِيَ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثُ سَلْمَانَ إِسْنَادُهُ لَيْسَ بِمُتَّصِلٍ مُحَمَّدُ بْنُ الْمُنْكَدِرِ لَمْ يُدْرِكْ سَلْمَانَ الْفَارِسِيَّ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ مَكْحُولٍ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ سَلْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah menceritakan kepada kami [Al Walid bin Muslim] dari [Isma'il bin Rafi'] dari [Sumay] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berjumpa dengan Allah sementara pada dirinya tidak ada bekas-bekas jihad di jalan Allah, maka ia berjumpa Allah dalam keadaan kurang sempurna (sumbing).\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, yaitu dari hadits Al Walid bin Muslim, dari Isma'il bin Rafi'. Sebagian ulama` telah mendha'ifkan Isma'il bin rafi'. Ia berkata, \"Aku mendengar Muhammad berkata, \"Ia orang tsiqah dan muqaribul hadits.\" Telah diriwayatkan pula dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam dengan jalur lain. Hadits Salman sanadnya tidak bersambung, sebab Muhammad Ibnul Munkadir belum pernah berjumpa dengan Salman Al Farisi. Hadits ini juga telah diriwayatkan dari [Ayyub bin Musa], dari [Makhul], dari [Syurahbil bin As Simth], dari [Salman], dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut.\""},"1590":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ حَدَّثَنِي أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ عَنْ أَبِي صَالِحٍ مَوْلَى عُثْمَانَ قَال سَمِعْتُ عُثْمَانَ وَهُوَ عَلَى الْمِنْبَرِ يَقُولُإِنِّي كَتَمْتُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَرَاهِيَةَ تَفَرُّقِكُمْ عَنِّي ثُمَّ بَدَا لِي أَنْ أُحَدِّثَكُمُوهُ لِيَخْتَارَ امْرُؤٌ لِنَفْسِهِ مَا بَدَا لَهُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ أَلْفِ يَوْمٍ فِيمَا سِوَاهُ مِنْ الْمَنَازِلِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ أَبُو صَالِحٍ مَوْلَى عُثْمَانَ اسْمُهُ تُرْكَانُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Hisyam bin Abdul Malik] berkata, telah menceritakan kepada kami [Al Laits bin Sa'd] berkata, telah menceritakan kepadaku [Abu Aqil Zuhrah bin Ma'bad] dari [Abu Shalih] -mantan budak (yang telah dimerdekakan oleh) Utsman- ia berkata, \"Aku mendengar [Utsman] berkata di atas mimbar, \"Aku telah menyembunyikan dari kalian sebuah hadits yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, karena aku kawatir kalian akan berselisih denganku. Setelah itu aku berniat menyampaikan hadits itu kepada kalian agar seseorang bisa memilih apa yang terbaik untuk dirinya sendiri. Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ribath (berjaga-jaga di perbatasan) satu hari di jalan Allah lebih baik dari seribu hari di tempat lain.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib. Muhammad bin Isma'il berkata, \"Abu Shalih -mantan budak (yang telah dimerdekakan oleh) Utsman- nama aslinya adalah Turkan.\""},"1591":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَأَحْمَدُ بْنُ نَصْرٍ النَّيْسَابُورِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَجِدُ الشَّهِيدُ مِنْ مَسِّ الْقَتْلِ إِلَّا كَمَا يَجِدُ أَحَدُكُمْ مِنْ مَسِّ الْقَرْصَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Ahmad bin Nashr An Naisaburi] dan banyak orang, mereka berkata; telah menceritakan kepada kami [Shafwan bin Isa] berkata, telah menceritakan kepada kami [Muhammad bin Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mujahid tidak merasakan sakitnya mati kecuali sebagaimana salah seorang dari kalian merasakan sakitnya digigit semut.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib.\""},"1592":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا الْوَلِيدُ بْنُ جَمِيلٍ الْفِلَسْطِينِيُّ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ شَيْءٌ أَحَبَّ إِلَى اللَّهِ مِنْ قَطْرَتَيْنِ وَأَثَرَيْنِ قَطْرَةٌ مِنْ دُمُوعٍ فِي خَشْيَةِ اللَّهِ وَقَطْرَةُ دَمٍ تُهَرَاقُ فِي سَبِيلِ اللَّهِ وَأَمَّا الْأَثَرَانِ فَأَثَرٌ فِي سَبِيلِ اللَّهِ وَأَثَرٌ فِي فَرِيضَةٍ مِنْ فَرَائِضِ اللَّهِقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah memberitakan kepada kami [Al Walid bin Jamil Al Filasthini] dari [Al Qasim bin 'Abdurrahman] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada sesuatu yang dicintai oleh Allah kecuali dua tetas air dan dua bekas; tetesan air mata karena takut kepada Allah dan tetesan darah yang tertumpah di jalan Allah. Adapun dua bekas itu adalah; bekas karena di jalan Allah dan bekas karena melaksanakan kewajiban Allah.\" Ia berkata, \"Hadits derajatnya hasan gharib.\""},"1593":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ائْتُونِي بِالْكَتِفِ أَوْ اللَّوْحِ فَكَتَبَ{ لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ }وَعَمْرُو بْنُ أُمِّ مَكْتُومٍ خَلْفَ ظَهْرِهِ فَقَالَ هَلْ لِي مِنْ رُخْصَةٍ فَنَزَلَتْ{ غَيْرُ أُولِي الضَّرَرِ }وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَجَابِرٍ وَزَيْدِ بْنِ ثَابِتٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهُوَ حَدِيثٌ غَرِيبٌ مِنْ حَدِيثِ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي إِسْحَقَ وَقَدْ رَوَى شُعْبَةُ وَالثَّوْرِيُّ عَنْ أَبِي إِسْحَقَ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al jahdhami] berkata, telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] dari [Bapaknya] dari [Abu Ishaq] dari [Al Barra` bin Azib] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berikan aku lembaran itu.\" Beliau kemudian menulis '(Tidaklah sama antara mu'min yang duduk (yang tidak ikut berperang)) ' -Qs. An Nisa: 95-, sementara Amru bin Ummi Maktum berada di belakang beliau. Amru berkata, \"Apakah ada keringanan untukku?\" lalu turunlah ayat: '(selain orang yang mempunyai 'uzur) ' -Qs. An Nisa: 95-Dalam bab ini juga ada hadits dari Ibnu Abbas, Jabir dan Zaid bin Tsabit. Hadits ini derajatnya hasan shahih, tetapi hadits ini termasuk hadits gharib riwayat Sulaiman At Taimi dari Abu Ishaq. [Syu'bah] dan [Ats Tsauri] juga meriwayatkan hadits ini dari [Abu Ishaq].\""},"1594":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ وَشُعْبَةَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي الْعَبَّاسِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَأْذِنُهُ فِي الْجِهَادِ فَقَالَ أَلَكَ وَالِدَانِ قَالَ نَعَمْ قَالَ فَفِيهِمَا فَجَاهِدْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو الْعَبَّاسِ هُوَ الشَّاعِرُ الْأَعْمَى الْمَكِّيُّ وَاسْمُهُ السَّائِبُ بْنُ فَرُّوخَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan bin Uyainah] dan [Syu'bah] dari [habib bin Abi Tsabit] dari [Abul Abbas] dari [Abdullah bin Amru] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam yang memohon izin untuk jihad, beliau lalu bersabda: \"Apakah kamu memiliki kedua orang tua?\" laki-laki itu menjawab, \"Ya.\" beliau bersabda: \"Hendaklah kami berjihad kepada keduanya (berbuat baik).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ibnu Abbas. Hadits ini derajatnya hasan shahih. Abul Abbas adalah seorang penyair buta dari Makkah, dan nama aslinya adalah As Sa`ib bin Farrukh.\""},"1595":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا الْحَجَّاجُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ جُرَيْجٍفِي قَوْلِهِ{ أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنْكُمْ }قَالَ عَبْدُ اللَّهِ بْنُ حُذَافَةَ بْنِ قَيْسِ بْنِ عَدِيٍّ السَّهْمِيُّ بَعَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى سَرِيَّةٍأَخْبَرَنِيهِ يَعْلَى بْنُ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ جُرَيْجٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata, telah menceritakan kepada kami [Al Hajjaj bin Muhammad] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, \"Firman Allah: '(ta'atilah Allah dan ta'atilah Rasul (Nya), dan ulil amri (pemimpin) di antara kamu) ' -Qs. An Nisa: 59- Abdullah bin Hudzafah bin Qais bin Adi As Sahmi diutus oleh Rasulullah shallallahu 'alaihi wasallam dalam sebuah ekspedisi, [Ya'la bin Muslim] mengabarkannya kepadaku dari [Sa'id bin Jubair], dari [Ibnu Abbas].\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, dan kami tidak mengetahuinya kecuali dari hadits Ibnu Juraij.\""},"1596":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ الْبَصْرِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَاصِمِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْ أَنَّ النَّاسَ يَعْلَمُونَ مَا أَعْلَمُ مِنْ الْوِحْدَةِ مَا سَرَى رَاكِبٌ بِلَيْلٍ يَعْنِي وَحْدَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adh Dhabbi Al Bashri] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ashim bin Muhammad] dari [Bapaknya] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya manusia mengetahui (bahayanya) sendiri sebagaimana yang aku ketahui, maka tidak seorang pun yang akan berjalan sendirian di waktu malam.\""},"1597":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حَرْمَلَةَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الرَّاكِبُ شَيْطَانٌ وَالرَّاكِبَانِ شَيْطَانَانِ وَالثَّلَاثَةُ رَكْبٌقَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ عَاصِمٍ وَهُوَ ابْنُ مُحَمَّدِ بْنِ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ مُحَمَّدٌ هُوَ ثِقَةٌ صَدُوقٌ وَعَاصِمُ بْنُ عُمَرَ الْعُمَرِيُّ ضَعِيفٌ فِي الْحَدِيثِ لَا أَرْوِي عَنْهُ شَيْئًا وَحَدِيثُ عَبْدِ اللَّهِ بْنِ عَمْرٍو حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik] dari ['Abdurrahman bin Harmalah] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu penunggang kuda adalah setan, dua penunggang kuda adalah setan dan tiga orang adalah rombongan.\" Abu Isa berkata, \"Hadits Ibnu Umar ini derajatnya hasan shahih, kami tidak mengetahui hadits ini kecuali dari jalur ini, yaitu dari hadits Ashim. Dan dia adalah Ibnu Muhammad bin Zaid bin Abdullah bin Umar. Muhammad berkata; ia adalah seorang yang tsiqah (dapat dipercaya) dan jujur, sementara Ashim bin Umar Al Umari yang seorang yang lemah dalam hadits, aku tidak pernah meriwayatkan sesuatu pun darinya. Dan hadits Abdullah bin Amru derajatnya hasan.\""},"1598":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ وَنَصْرُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَرْبُ خُدْعَةٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَزَيْدِ بْنِ ثَابِتٍ وَعَائِشَةَ وَابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَأَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ وَكَعْبِ بْنِ مَالِكٍ وَأَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] dan [Nashr bin Ali] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] ia mendengar [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"berperang itu bermain tipu muslihat (makar).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali, Zaid bin Tsabit, 'Aisyah, Ibnu Abbas, Abu Hurairah, Asma binti Yazid bin As Sakan, Ka'b bin Malik dan Anas. Dan hadits ini derajatnya hasah shahih.\""},"1599":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ وَأَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَكُنْتُ إِلَى جَنْبِ زَيْدِ بْنِ أَرْقَمَ فَقِيلَ لَهُ كَمْ غَزَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ غَزْوَةٍ قَالَ تِسْعَ عَشْرَةَ فَقُلْتُ كَمْ غَزَوْتَ أَنْتَ مَعَهُ قَالَ سَبْعَ عَشْرَةَ قُلْتُ أَيَّتُهُنَّ كَانَ أَوَّلَ قَالَ ذَاتُ الْعُشَيْرِ أَوْ الْعُشَيْرَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Wahb bin Jarir] dan [Abu Dawud Ath Thayalisi] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, \"Aku pernah berada di sisi [Zaid bin Arqam], lalu ditanyakan kepadanya, \"Berapa kali Nabi shallallahu 'alaihi wasallam ikut peperangan?\" ia menjawab, \"Sembilan belas kali.\" Aku bertanya kepadanya, \"Berapa kali kamu memgikuti peperangan beliau?\" ia menjawab, \"Tujuh belas kali.\" Aku bertanya lagi, \"Perang apa yang pertama kali kamu ikuti?\" ia menjawab, \"Perang Dzatul Usyaira atau Dzatul usyairah.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1600":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا سَلَمَةُ بْنُ الْفَضْلِ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَعَبَّأَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِبَدْرٍ لَيْلًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي أَيُّوبَ وَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَسَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ هَذَا الْحَدِيثِ فَلَمْ يَعْرِفْهُ وَقَالَ مُحَمَّدُ بْنُ إِسْحَقَ سَمِعَ مِنْ عِكْرِمَةَ وَحِينَ رَأَيْتُهُ كَانَ حَسَنَ الرَّأْيِ فِي مُحَمَّدِ بْنِ حُمَيْدٍ الرَّازِيِّ ثُمَّ ضَعَّفَهُ بَعْدُ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] berkata, telah menceritakan kepada kami [Salamah Ibnul Fadhl] dari [Muhammad bin Ishaq] dari [Ikrimah] dari [Ibnu Abbas] dari ['Abdurrahman bin Auf] ia berkata, \"Pada perang Badar Nabi shallallahu 'alaihi wasallam mempersiapkan kami di waktu malam.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Ayyub. Ini adalah hadits gharib, kami tidak mengetahuinya kecuali dari jalur ini. Aku pernah bertanya Muhammad bin Isma'il tentang hadits ini, tetapi ia juga tidak mengetahuinya. Ia berkata, \"Muhammad bin Ishaq mendengar dari Ikrimah, saat aku bersamanya ia masih menganggap Muhammad bin Humaid Ar Razi sebagai orang yang baik, namun setelah itu ia mendha'ifkannya.\""},"1601":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ ابْنِ أَبِي أَوْفَى قَالَسَمِعْتُهُ يَقُولُ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو عَلَى الْأَحْزَابِ فَقَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِس��ابِ اهْزِمْ الْأَحْزَابَ اللَّهُمَّ اهْزِمْهُمْ وَزَلْزِلْهُمْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Yazid Abu Isa harun] berkata, telah memberitakan kepada kami [Isma'il bin Abu Khalid] dari [Ibnu Abu Aufa] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam berdoa saat terjadi perang ahzab, beliau mengucapkan: \"ALLAHUMMA MUNZILAL KITAAB SARIE'UL HISAAB IHZIMIL AHZAAB, ALLAHUMMA IHZIMHUM WA ZALZILHUM\" (Ya Allah Yang menurunkan Al Kitab, Yang cepat hisabnya, hancurkanlah pasukan ahzab. Ya Allah, hancurkan dan goncanglah mereka).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ibnu Mas'ud. Dan hadits derajatnya hasan shahih.\""},"1602":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ الْوَلِيدِ الْكِنْدِيُّ الْكُوفِيُّ وَأَبُو كُرَيْبٍ وَمُحَمَّدُ بْنُ رَافِعٍ قَالُوا حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ شَرِيكٍ عَنْ عَمَّارٍ يَعْنِي الدُّهْنِيَّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ وَلِوَاؤُهُ أَبْيَضُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَحْيَى بْنِ آدَمَ عَنْ شَرِيكٍ قَالَ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَلَمْ يَعْرِفْهُ إِلَّا مِنْ حَدِيثِ يَحْيَى بْنِ آدَمَ عَنْ شَرِيكٍ و قَالَ حَدَّثَنَا غَيْرُ وَاحِدٍ عَنْ شَرِيكٍ عَنْ عَمَّارٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ قَالَ مُحَمَّدٌ وَالْحَدِيثُ هُوَ هَذَا قَالَ أَبُو عِيسَى وَالدُّهْنُ بَطْنٌ مِنْ بَجِيلَةَ وَعَمَّارٌ الدُّهْنِيُّ هُوَ عَمَّارُ بْنُ مُعَاوِيَةَ الدُّهْنِيُّ وَيُكْنَى أَبَا مُعَاوِيَةَ وَهُوَ كُوفِيٌّ وَهُوَ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Al Walid Al Kindi Al Kufi] dan [Abu Kuraib] dan [Muhammad bin Rafi'] mereka berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Syarik] dari [Ammar] -yaitu Ad Duhni- dari [Abu Az Zubair] dari [Jabir] berkata, \"Nabi shallallahu 'alaihi wasallam masuk kota Makkah dengan membawa bendara berwarna putih.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Yahya bin Adam, dari Syarik. Ia berkata, \"Aku bertanya Muhammad tentang hadits ini, tetapi ia juga tidak mengetahuinya kecuali dari hadits Yahya bin Adam Syarik. Muhammad berkata, \"Tidak hanya seorang yang telah meriwayatkan dari Syarik, dari Ammar, dari Abu Az Zubair, dari Jabir bahwa Nabi shallallahu 'alaihi wasallam masuk Makkah dengan mengenakan imamah berwarna hitam.\" Muhammad mengatakan, \"Hadits yang? sebenarnya adalah hadits ini.\" Abu Isa berkata, \"Ad Duhnu (nama kabilah) berasal dari Bajilah (nama kabilah). Dan Ammar Ad Duhni adalah Ammar bin Mu'awiyah Ad Duhni, julukannya Abu Mu'awiyah. Dia orang yang berasal dari Kufah dan tsiqah (dapat dipercaya) menurut ahli hadits.\""},"1603":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ حَدَّثَنَا أَبُو يَعْقُوبَ الثَّقَفِيُّ حَدَّثَنَا يُونُسُ بْنُ عُبَيْدٍ مَوْلَى مُحَمَّدِ بْنِ الْقَاسِمِ قَالَبَعَثَنِي مُحَمَّدُ بْنُ الْقَاسِمِ إِلَى الْبَرَاءِ بْنِ عَازِبٍ أَسْأَلُهُ عَنْ رَايَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَتْ سَوْدَاءَ مُرَبَّعَةً مِنْ نَمِرَةٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَالْحَارِثِ بْنِ حَسَّانَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ ابْنِ أَبِي زَائِدَةَ وَأَبُو يَعْقُوبَ الثَّقَفِيُّ اسْمُهُ إِسْحَقُ بْنُ إِبْرَاهِيمَ وَرَوَى عَنْهُ أَيْضًا عُبَيْدُ اللَّهِ بْنُ مُوسَى","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Yahya bin Zakariya bin Abu Zaidah] berkata, telah menceritakan kepada kami [Abu Ya'qub Ats Tsaqafi] berkata, telah menceritakan kepada kami [Yunus bin Ubaid] -mantan budak Muhammad bin Al Qasim- ia berkata, \"Muhammad Ibnul Qasim mengutusku kepada [Al bara` bin Azib] untuk bertanya tentang bendera Rasulullah shallallahu 'alaihi wasallam. Ia lalu menjawab, \"Bendera beliau berwarna hitam, bentuknya persegi empat dan terbuat dari kain wool yang bergaris.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali dari Al Harits bin Hassan dan Ibnu Abbas.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Ibnu Abu Zaidah. Abu Ya'qub Ats Tsaqafi nama aslinya adalah Ishaq bin Ibrahim. Ubaidullah bin Musa juga telah meriwayatkan darinya.\""},"1604":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا يَحْيَى بْنُ إِسْحَقَ وَهُوَ السَّالِحَانِيُّ حَدَّثَنَا يَزِيدُ بْنُ حَيَّانَ قَال سَمِعْتُ أَبَا مِجْلَزٍ لَاحِقَ بْنَ حُمَيْدٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَتْ رَايَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَوْدَاءَ وَلِوَاؤُهُ أَبْيَضَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] berkata, telah menceritakan kepada kami [Yahya bin Ishaq] -yaitu As Salihani- berkata, telah menceritakan kepada kami [Yazid bin Hayyan] ia berkata; Aku mendengar [Abu Mijlaz Lahiq bin Humaid] menceritakan dari [Ibnu Abbas] ia berkata, \"Bendera Rasulullah shallallahu 'alaihi wasallam berwarna hitam dan umbul-umbulnya berwarna putih.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib melalui jalur ini, dari Ibnu Abbas.\""},"1605":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ عَمَّنْسَمِعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنْ بَيَّتَكُمْ الْعَدُوُّ فَقُولُوا حم لَا يُنْصَرُونَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ وَهَكَذَا رَوَى بَعْضُهُمْ عَنْ أَبِي إِسْحَقَ مِثْلَ رِوَايَةِ الثَّوْرِيِّ وَرُوِيَ عَنْهُ عَنْ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Muhallab bin Abu Shufrah] dari [orang yang mendengar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kalian diserbu oleh musuh pada waktu malam maka bacalah, \"Haammiim laa yunsharuun (Demi Allah, mereka tidak akan menang).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Salamah bin Al Akwa'. Seperti inilah sebagian mereka meriwayatkan dari Abu Ishaq seperti riwayat Ats Tsauri. Diriwayatkan pula darinya (Abu Ishaq), dari Al Muhallab bin Abu Shufrah, dari Nabi shallallahu 'alaihi wasallam secara mursal.\""},"1606":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ شُجَاعٍ الْبَغْدَادِيُّ حَدَّثَنَا أَبُو عُبَيْدَةَ الْحَدَّادُ عَنْ عُثْمَانَ بْنِ سَعْدٍ عَنْ ابْنِ سِيرِينَ قَالَصَنَعْتُ سَيْفِي عَلَى سَيْفِ سَمُرَةَ بْنِ جُنْدَبٍ وَزَعَمَ سَمُرَةُ أَنَّهُ صَنَعَ سَيْفَهُ عَلَى سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ حَنَفِيًّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ تَكَلَّمَ يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ فِي عُثْمَانَ بْنِ سَعْدٍ الْكَاتِبِ وَضَعَّفَهُ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Syuja' Al Baghdadi] berkata, telah menceritakan kepada kami [Abu Ubaidah Al Haddad] dari [Utsman bin Sa'd] dari [Ibnu Sirin] ia berkata, \"Aku membuat pedangku mirip seperti pedang Samurah bin Jundub, sementara [Samurah] menyakini bahwa ia membuat pedangnya mirip seperti pedang Rasulullah shallallahu 'alaihi wasallam. Dan pedang Rasulullah shallallahu 'alaihi wasallam bentuknya bengkok ujungnya.\" Abu Isa berkata, \"Hadits ini derajatnya gharib, kami tidak mengetahuinya kecuali dari jalur ini. Yahya bin Sa'id Al Qaththan telah memperbincangkan profil Utsman bin Sa'd Al Katib (seorang sekretaris), Yahya bin Sa'id melemahkannya dari sisi hafalan.\""},"1607":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَنْبَأَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ عَطِيَّةَ بْنِ قَيْسٍ عَنْ قَزَعَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَلَمَّا بَلَغَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ مَرَّ الظَّهْرَانِ فَآذَنَنَا بِلِقَاءِ الْعَدُوِّ فَأَمَرَنَا بِالْفِطْرِ فَأَفْطَرْنَا أَجْمَعُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عُمَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa] berkata, telah memberitakan kepada kami [Abdullah Ibnul Mubarak] berkata, telah memberitakan kepada kami [Sa'id bin Abdul Aziz] dari [Athiyah bin Qais] dari [Qaza'ah] dari [Abu Sa'id Al Khudri] ia berkata, \"Pada saat pembukaan kota Makkah dan perjalanan telah sampai di Marra Zhahran (lembah antara Makkah dan Asfan), beliau memberi tahukan kepada kami bahwa musuh telah dekat. Beliau kemudian memerintahkan kepada kami untuk berbuka, hingga kami pun berbuka semua.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, dan dalam bab ini juga ada hadits dari Umar.\""},"1608":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ قَتَادَةَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَرَكِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا لِأَبِي طَلْحَةَ يُقَالُ لَهُ مَنْدُوبٌ فَقَالَ مَا كَانَ مِنْ فَزَعٍ وَإِنْ وَجَدْنَاهُ لَبَحْرًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عَمْرِو بْنِ الْعَاصِ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abu Dawud Ath Thayalisi] ia berkata; telah memberitakan kepada kami [Syu'bah] dari [Qatadah] berkata, telah menceritakan kepada kami [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam mengendarai kuda milik Abu Thalhah yang bernama Mandub, beliau lalu bersabda: \"Dia bukan kuda penakut, tetapi ia adalah kuda yang larinya kencang.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ibnu Amru bin Al Ash, dan hadits ini derajatnya hasan shahih.\""},"1609":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَابْنُ أَبِي عَدِيٍّ وَأَبُو دَاوُدَ قَالُوا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ فَزَعٌ بِالْمَدِينَةِ فَاسْتَعَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَسًا لَنَا يُقَالُ لَهُ مَنْدُوبٌ فَقَالَ مَا رَأَيْنَا مِنْ فَزَعٍ وَإِنْ وَجَدْنَاهُ لَبَحْرًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Ibnu Abu Adi] dan [Abu Dawud] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Madinah sedang dirundung oleh rasa takut, lalu Nabi shallallahu 'alaihi wasallam meminjam kuda milik kami yang bernama Mandub, beliau lalu bersabda: \"Kami tidak melihat kuda ini ketakutan, tetapi kami rasakan kuda ini berlari sangat kencang.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1610":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَحْسَنِ النَّاسِ وَأَجْوَدِ النَّاسِ وَأَشْجَعِ النَّاسِ قَالَ وَقَدْ فَزِعَ أَهْلُ الْمَدِينَةِ لَيْلَةً سَمِعُوا صَوْتًا قَالَ فَتَلَقَّاهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فَرَسٍ لِأَبِي طَلْحَةَ عُرْيٍ وَهُوَ مُتَقَلِّدٌ سَيْفَهُ فَقَالَ لَمْ تُرَاعُوا لَمْ تُرَاعُوا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدْتُهُ بَحْرًا يَعْنِي الْفَرَسَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] ia berkata, \"Nabi shallallahu 'alaihi wasallam adalah sebaik-baik manusia, paling bagus dan paling berani. Penduduk Madinah merasa ketakutan saat mendengar suara di waktu malam.\" Anas berkata, \"Nabi shallallahu 'alaihi wasallam lalu menemui mereka dengan mengendarai kuda milik Abu Thalhah tanpa pelana, sementara beliau waktu itu menenteng pedangnya. Beliau lalu bersabda: \"Kalian jangan takut, kalian jangan takut.\" Nabi shallallahu 'alaihi wasallam kemudian bersabda lagi: \"Kami mendapatinya (kuda) lari dengan cepat.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1611":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ الْبَرَاءِ بِنِ عَازِبٍ قَالَقَالَ لَنَا رَجُلٌ أَفَرَرْتُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا عُمَارَةَ قَالَ لَا وَاللَّهِ مَا وَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ وَلَّى سَرَعَانُ النَّاسِ تَلَقَّتْهُمْ هَوَازِنُ بِالنَّبْلِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَتِهِ وَأَبُو سُفْيَانَ بْنُ الْحَارِثِ بْنِ عَبْدِ الْمُطَّلِبِ آخِذٌ بِلِجَامِهَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عُمَرَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Sufyan Ats Tsauri] berkata, telah menceritakan kepada kami [Abu Ishaq] dari [Al Bara bin Azib] ia berkata, \"Seorang laki-laki berkata kepadaku, \"Wahai Abu Umarah, apakah kamu kabur dari Rasulullah shallallahu 'alaihi wasallam?\" Ia menjawab, \"Tidak. Demi Allah, Rasulullah shallallahu 'alaihi wasallam pantang melarikan diri (dari peperangan), justru sahabat-sahabatnya lah yang sedemikian cepatnya melarikan diri ketika bani Hawazin menghujani mereka dengan lemparan anak-anak panah, sedang Rasulullah shallallahu 'alaihi wasallam tetap teguh berada di atas bighalnya, dan Abu Sufyan bin Al Harits bin Abdul Muthallib memegangi tali kekangnya. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Aku seorang Nabi yang tak pernah dusta, aku anak Abdul Muthallib.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali dan Ibnu Umar. hadits ini derajatnya hasan shahih.\""},"1612":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيٍّ الْمُقَدَّمِيُّ الْبَصْرِيُّ حَدَّثَنِي أَبِي عَنْ سُفْيَانَ بْنِ حُسَيْنٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَقَدْ رَأَيْتُنَا يَوْمَ حُنَيْنٍ وَإِنَّ الْفِئَتَيْنِ لَمُوَلِّيَتَانِ وَمَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةُ رَجُلٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ عُبَيْدِ اللَّهِ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin 'Umar bin Ali Al Muqaddami Al Bashri] berkata, telah menceritakan kepadaku [Bapakku] dari [Sufyan bin Husain] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Pada saat perang Hunain aku melihat ada dua kelompok yang saling melarikan diri, sementara bersama Rasulullah shallallahu 'alaihi wasallam hanya ada seratus orang.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahui hadits tersebut berasal dari Ubaidullah kecuali dari jalur ini.\""},"1613":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ صُدْرَانَ أَبُو جَعْفَرٍ الْبَصْرِيُّ حَدَّثَنَا طَالِبُ بْنُ حُجَيْرٍ عَنْ هُودِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنْ جَدِّهِ مَزِيدَةَ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْفَتْحِ وَعَلَى سَيْفِهِ ذَهَبٌ وَفِضَّةٌ قَالَ طَالِبٌ فَسَأَلْتُهُ عَنْ الْفِضَّةِ فَقَالَ كَانَتْ قَبِيعَةُ السَّيْفِ فِضَّةًقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَجَدُّ هُودٍ اسْمُهُ مَزِيدَةُ الْعَصَرِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Shadran Abu Ja'far Al bashri] berkata, telah menceritakan kepada kami [Thalib bin Hujair] dari [Hud bin Abdullah bin Sa'd] dari kakeknya [Mazidah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk Makkah saat terjadi penaklukan, sementara pada pedang beliau terdapat emas dan perak.\" Thalib berkata, \"lalu aku bertanya kepada Hud bin Abdullah tentang perak tersebut, lantas ia menjawab, \"Ujung gagang pedang (beliau) terbuat dari perak.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Anas, dan hadits ini derajatnya hasan gharib. Kakek Hud namanya adalah Mazidah Al Ashri.\" "},"1614":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَتْ قَبِيعَةُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَهَكَذَا رُوِيَ عَنْ هَمَّامٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ وَقَدْ رَوَى بَعْضُهُمْ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي الْحَسَنِ قَالَ كَانَتْ قَبِيعَةُ سَيْفِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Wahb bin Jarir bin Hazim] berkata, telah menceritakan kepada kami [Bapakku] dari [Qatadah] dari [Anas] ia berkata, \"Gagang pedang Rasulullah shallallahu 'alaihi wasallam terbuat dari perak.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, seperti inilah diriwayatkan dari [Hammam], dari [Qatadah], dari [Anas]. Sebagian mereka meriwayatkan dari [Qatadah], dari [Sa'id bin Abul Hasan], ia berkata, \"Gagang pedang Rasulullah shallallahu 'alaihi wasallam terbuat dari perak.\""},"1615":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ عَنْ جَدِّهِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِ قَالَكَانَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْعَانِ يَوْمَ أُحُدٍ فَنَهَضَ إِلَى الصَّخْرَةِ فَلَمْ يَسْتَطِعْ فَأَقْعَدَ طَلْحَةَ تَحْتَهُ فَصَعِدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِ حَتَّى اسْتَوَى عَلَى الصَّخْرَةِ فَقَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَوْجَبَ طَلْحَةُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ صَفْوَانَ بْنِ أُمَيَّةَ وَالسَّائِبِ بْنِ يَزِيدَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ مُحَمَّدِ بْنِ إِسْحَقَ","id":"Telah menceritakan kepada kami [Abu Sa'id Al Asyaj] berkata, telah menceritakan kepada kami [Yunus bin Bukair] dari [Muhammad bin Ishaq] dari [Yahya bin Abbad bin Abdullah bin Az Zubair] dari [Bapaknya] dari kakeknya [Abdullah bin Az Zubair] dari [Az Zubair bin Al Awwam] ia berkata, \"Pada perang uhud Nabi shallallahu 'alaihi wasallam mengenakan dua baju perang, beliau lalu naik ke atas batu tetapi tidak bisa. Maka Thalhah pun jongkok di bawahnya hingga Nabi shallallahu 'alaihi wasallam dapat naik di atas batu tersebut.\" Zubair berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Telah wajib bagi Thalhah (masuk surga).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Shafwan bin Umayyah dan As Sa`ib bin Yazid, dan hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Muhammad bin Ishaq.\""},"1616":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ وَعَلَى رَأْسِهِ الْمِغْفَرُ فَقِيلَ لَهُ ابْنُ خَطَلٍ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَقَالَ اقْتُلُوهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُ كَبِيرَ أَحَدٍ رَوَاهُ غَيْرَ مَالِكٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam masuk Makkah dengan mengenakan mighfar (tameng penutup kepala) saat terjadi penaklukan, lalu dikatakan kepada beliau, \"Ibnu Khathal bergelayutan pada kain ka'bah?\" Beliau bersabda: \"Bunuhlah ia.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib, kami tidak mengetahui seorang imam yang meriwayatkannya selain Malik, dari Az Zuhri.\""},"1617":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْثَرُ بْنُ الْقَاسِمِ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْرُ مَعْقُودٌ فِي نَوَاصِي الْخَيْلِ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي سَعِيدٍ وَجَرِيرٍ وَأَبِي هُرَيْرَةَ وَأَسْمَاءَ بِنْتِ يَزِيدَ وَالْمُغِيرَةِ بْنِ شُعْبَةَ وَجَابِرٍ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَعُرْوَةُ هُوَ ابْنُ أَبِي الْجَعْدِ الْبَارِقِيُّ وَيُقَالُ هُوَ عُرْوَةُ بْنُ الْجَعْدِ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ وَفِقْهُ هَذَا الْحَدِيثِ أَنَّ الْجِهَادَ مَعَ كُلِّ إِمَامٍ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abtsar bin Al Qasim] dari [Hushain] dari [Asy Sya'bi] dari [Urwah Al Bariqi] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kebaikan akan selalu tertera pada ubun-ubun kuda hingga hari kiamat; yaitu pahala dan ghanimah.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ibnu Umar, Abu Sa'id, Jarir, Abu Hurairah, Asma binti Yazid, Al Mughirah bin Syu'bah dan Jabir.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, Urwah adalah Ibnu Abu Al Ja'd Al Bariqi, ia biasa dipanggil dengan nama Urwah Ibnul Ja'd. Ahmad bin Hambal berkata, \"Fikih dari hadits ini adalah, bahwa jihad bersama setiap imam (shalih atau jahat) akan tetap berlangsung hingga datangnya hari kiamat.\""},"1618":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ الْهَاشِمِيُّ الْبَصْرِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَيْبَانُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عِيسَى بْنُ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُمْنُ الْخَيْلِ فِي الشُّقْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ شَيْبَانَ","id":"Telah menceritakan kepada kami [Abdullah bin Ash Shabbah Al Hasyimi Al Bashri] berkata, telah menceritakan kepada kami [Yazid bin Harun] berkata, telah mengabarkan kepada kami [Syaiban] -yaitu Ibnu 'Abdurrahman- berkata, telah menceritakan kepada kami [Isa bin Ali bin Abdullah bin Abbas] dari [Bapaknya] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berkah kuda itu pada warna blonde (merah kekuning-kuningan).\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahui hadits ini dari hadits Syaiban kecuali dari jalur ini.\""},"1619":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَلِيِّ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الْخَيْلِ الْأَدْهَمُ الْأَقْرَحُ الْأَرْثَمُ ثُمَّ الْأَقْرَحُ الْمُحَجَّلُ طَلْقُ الْيَمِينِ فَإِنْ لَمْ يَكُنْ أَدْهَمَ فَكُمَيْتٌ عَلَى هَذِهِ الشِّيَةِحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] berkata, telah mengabarkan kepada kami [Abdullah Ibnul Mubarak] berkata, telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Ali bin Rabah] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik kuda adalah yang berwarna hitam pekat, pada wajahnya ada semburat warna putih, dan pada hidung serta bibir bagian atas berwarna putih. Kemudian kuda yang pada wajahnya ada semburat warna putih, pada kaki-kakinya berwarna putih, serta kaki kanannya ada warna putih. Jika tidak ada kuda yang berwarna hitam pekat, maka yang berwarna merah kehitaman seperti sifat-sifat tersebut.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Wahb bin Jarir] berkata, telah menceritakan kepada kami [Bapakku] dari [Yahya bin Ayyub] dari [Yazid bin Abu Habib] dengan sanad ini, seperti hadits tersebut secara makananya.\" Abu Isa berkata; \" Ini adalah hadits hasan gahrib shahih.\" "},"1620":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي سَلْمُ بْنُ عَبْدِ الرَّحْمَنِ النَّخَعِيُّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَرِهَ الشِّكَالَ مِنْ الْخَيْلِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَثْعَمِيِّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَأَبُو زُرْعَةَ بْنُ عَمْرِو بْنِ جَرِيرٍ اسْمُهُ هَرِمٌ حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا جَرِيرٌ عَنْ عُمَارَةَ بْنِ الْقَعْقَاعِ قَالَ قَالَ لِي إِبْرَاهِيمُ النَّخَعِيُّ إِذَا حَدَّثْتَنِي فَحَدِّثْنِي عَنْ أَبِي زُرْعَةَ فَإِنَّهُ حَدَّثَنِي مَرَّةً بِحَدِيثٍ ثُمَّ سَأَلْتُهُ بَعْدَ ذَلِكَ بِسِنِينَ فَمَا أَخْرَمَ مِنْهُ حَرْفًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Sufyan] ia berkata; telah menceritakan kepadaku [Salm bin 'Abdurrahman An Nakha'i] dari [Abu Zur'ah bin Amru bin Jarir] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau tidak menyukai warna putih pada sebagian kaki kuda.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. [Syu'bah] meriwayatkannya dari Abdullah bin Yazid Al Khats'ami dari Abu Zur'ah dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam, seperti hadits tersebut. Abu Zur'ah bin Amru bin Jarir nama aslinya adalah Harim.\" Telah menceritakan kepada kami Muhammad bin Huamid Ar Razi berkata, telah menceritakan kepada kami Umarah bin Al Qa'qa' ia berkata; Ibrahim An Nakha'I berkata kepadaku, \"Jika engkau membacakan hadits kepadaku maka bacakanlah kepadaku hadits dari Abu Zur'ah, sebab suatu ketika ia pernah membacakan hadits kepadaku. Kemudian setelah beberapa tahun hadits tersebut aku tanyakan kepadanya dan tidak satu huruf pun yang hilang (lupa).\" "},"1621":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ وَزِيرٍ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْرَى الْمُضَمَّرَ مِنْ الْخَيْلِ مِنْ الْحَفْيَاءِ إِلَى ثَنِيَّةِ الْوَدَاعِ وَبَيْنَهُمَا سِتَّةُ أَمْيَالٍ وَمَا لَمْ يُضَمَّرْ مِنْ الْخَيْلِ مِنْ ثَنِيَّةِ الْوَدَاعِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ وَبَيْنَهُمَا مِيلٌ وَكُنْتُ فِيمَنْ أَجْرَى فَوَثَبَ بِي فَرَسِي جِدَارًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَجَابِرٍ وَعَائِشَةَ وَأَنَسٍ وَهَذَا حَدِيثٌ صَحِيحٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ الثَّوْرِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Wazir Al Wasithi] berkata, telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] dari [Sufyan] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam mengadu kuda pacuan dari Hafya sampai Tsaniyatul Wada, dengan jarak tempuh enam mil. Sementara yang bukan termasuk kuda pacuan beliau adu dari Tsaniyatul Wada hingga masjid bani Zuraiq, dengan jarak tempuh satu mil. Dan aku termasuk orang yang mengikuti pacuan tersebut, lalu kudaku melompat tembok (setelah melewati batas finis).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Hurairah, Jabir, 'Aisyah dan Anas. Hadits dari Ats Tsauri ini derajatnya shahih hasan gharib.\""},"1622":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ نَافِعِ بْنِ أَبِي نَافِعٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا سَبَقَ إِلَّا فِي نَصْلٍ أَوْ خُفٍّ أَوْ حَافِرٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Waki'] dari [Ibnu Abu Dzi`b] dari [Nafi' bin Abu Nafi'] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada hadiah (lomba) kecuali pada panahan, balap unta dan kuda.\" Abu Isa berkata, \"Hadits ini derajatnya hasan.\""},"1623":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو جَهْضَمٍ مُوسَى بْنُ سَالِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدًا مَأْمُورًا مَا اخْتَصَّنَا دُونَ النَّاسِ بِشَيْءٍ إِلَّا بِثَلَاثٍ أَمَرَنَا أَنْ نُسْبِغَ الْوُضُوءَ وَأَنْ لَا نَأْكُلَ الصَّدَقَةَ وَأَنْ لَا نُنْزِيَ حِمَارًا عَلَى فَرَسٍقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى سُفْيَانُ الثَّوْرِيُّ هَذَا عَنْ أَبِي جَهْضَمٍ فَقَالَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ حَدِيثُ الثَّوْرِيِّ غَيْرُ مَحْفُوظٍ وَوَهِمَ فِيهِ الثَّوْرِيُّ وَالصَّحِيحُ مَا رَوَى إِسْمَعِيلُ ابْنُ عُلَيَّةَ وَعَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَبِي جَهْضَمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah menceritakan kepada kami [Abu Jahdham bin Musa bin Salim] dari [Abdullah bin Ubaidullah bin Abbas] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam adalah seorang hamba yang mendapat perintah (menjadi nabi), beliau tidak pernah mengkhususkan kami (ahli bait) atas semua manusia selain dari tiga hal; beliau memerintahkan kami untuk menyempurnakan wudhu, tidak makan harta sedekah serta memenangkan himar atas kuda.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali. Hadits ini derajatnya hasan shahih. [Sufyan bin Ats Tsauri] meriwayatkan hadits ini dari [Abu Jahdham], ia berkata; dari [Abdullah bin Ubaidullah bin Abbas], dari [Ibnu Abbas].\" Abu Isa berkata; Aku mendengar [Muhammad] berkata, \"Hadits Ats Tsauri tidak terjaga, dan Ats Tsauri sendiri masih merasa ragu. Yang lebih shahih adalah yang diriwayatkan oleh [Isma'il bin Ulayyah] dan [Abdul Warits bin Sa'id], dari [Abu Jahdham], dari [Abdullah bin Ubaidullah bin Abbas], dari [Ibnu Abbas].\""},"1624":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ بْنِ جَابِرٍ حَدَّثَنَا زَيْدُ بْنُ أَرْطَاةَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي الدَّرْدَاءِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ابْغُونِي ضُعَفَاءَكُمْ فَإِنَّمَا تُرْزَقُونَ وَتُنْصَرُونَ بِضُعَفَائِكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa] berkata, telah menceritakan kepada kami [Abdullah Ibnul Mubarak] ia berkata; telah mengabarkan kepada kami ['Abdurrahman bin Yazid bin Jabir] berkata, telah menceritakan kepada kami [Zaid bin Arthah] dari [Jubair bin Nufair] dari [Abu Darda] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tolonglah aku dengan perantaraan orang-orang jelata kalian, sebab kalian diberi rejeki dan diberi kemenangan melalui perantaraan mereka.\" Abu Isa berkata, \"hadits ini derajatnya hasan shahih.\" "},"1625":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا كَلْبٌ وَلَا جَرَسٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَعَائِشَةَ وَأُمِّ حَبِيبَةَ وَأُمِّ سَلَمَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malaikat tidak akan menyertai rombongan yang di dalamnya terdapat anjing atau lonceng.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Umar, 'Aisyah, Ummu Habibah dan Ummu Salamah. Hadits ini derajatnya hasan shahih.\""},"1626":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا الْأَحْوَصُ بْنُ الْجَوَّابِ أَبُو الْجَوَّابِ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ جَيْشَيْنِ وَأَمَّرَ عَلَى أَحَدِهِمَا عَلِيَّ بْنَ أَبِي طَالِبٍ وَعَلَى الْآخَرِ خَالِدَ بْنَ الْوَلِيدِ فَقَالَ إِذَا كَانَ الْقِتَالُ فَعَلِيٌّ قَالَ فَافْتَتَحَ عَلِيٌّ حِصْنًا فَأَخَذَ مِنْهُ جَارِيَةً فَكَتَبَ مَعِي خَالِدُ بْنُ الْوَلِيدِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشِي بِهِ فَقَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ الْكِتَابَ فَتَغَيَّرَ لَوْنُهُ ثُمَّ قَالَ مَا تَرَى فِي رَجُلٍ يُحِبُّ اللَّهَ وَرَسُولَهُ وَيُحِبُّهُ اللَّهُ وَرَسُولُهُ قَالَ قُلْتُ أَعُوذُ بِاللَّهِ مِنْ غَضَبِ اللَّهِ وَغَضَبِ رَسُولِهِ وَإِنَّمَا أَنَا رَسُولٌ فَسَكَتَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْأَحْوَصِ بْنِ جَوَّابٍ قَوْلُهُ يَشِي بِهِ يَعْنِي النَّمِيمَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Ziyad] berkata, telah menceritakan kepada kami [Abul Ahwash bin Al Jawwab Abul Jawwab] dari [Yunus bin Abu Ishaq] dari [Abu Ishaq] dari [Al Bara] berkata, \"Nabi shallallahu 'alaihi wasallam mengirim dua regu pasukan, satu regu beliau percayakan kepada Ali bin Abu Thalib dan yang lain kepada Khalid Ibnul Walid. Beliau lalu bersabda: \"Jika terjadi peperangan maka taatilah Ali.\" Al Bara berkata, \"Kemudian Ali dapat menaklukkan sebuah benteng dan mengambil seorang budak wanita untuk dirinya. Khalid Ibnul Walid lalu menulis surat pengaduan, lalu mengutusku untuk disampaikan kepada Nabi shallallahu 'alaihi wasallam. Maka akupun mendatangi Nabi shallallahu 'alaihi wasallam, beliau lalu membaca surat tersebut dan berubahlah rona wajahnya. Beliau bersabda: \"(kekurangan) apa yang kamu lihat diri seorang laki-laki yang mencintai Allah dan rasul-Nya, dan Allah dan rasul-Nya mencintainya!\" Al Bara berkata, \"Aku menjawab, \"Aku berlindung kepada Allah dari murka Allah dan murka rasul-Nya, aku ini hanyalah utusan.\" Beliau lalu diam.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ibnu Umar. Hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Al Ahwash bin Jawwab. Ucapan Al Bara, 'mengadukan', maksudnya adalah adu domba.\""},"1627":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ فَالْأَمِيرُ الَّذِي عَلَى النَّاسِ رَاعٍ وَمَسْئُولٌ عَنْ رَعِيَّتِهِ وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَهُوَ مَسْئُولٌ عَنْهُمْ وَالْمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ بَعْلِهَا وَهِيَ مَسْئُولَةٌ عَنْهُ وَالْعَبْدُ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ عَنْهُ أَلَا فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِقَالَ أَبُو عِيسَى وَفِي الْبَاب ع��نْ أَبِي هُرَيْرَةَ وَأَنَسٍ وَأَبِي مُوسَى وَحَدِيثُ أَبِي مُوسَى غَيْرُ مَحْفُوظٍ وَحَدِيثُ أَنَسٍ غَيْرُ مَحْفُوظٍ وَحَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ حَكَاهُ إِبْرَاهِيمُ بْنُ بَشَّارٍ الرَّمَادِيُّ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَنِي بِذَلِكَ مُحَمَّدٌ بِنِ إِبْرَاهِيمَ بْنِ بَشَّارٍ قَالَ وَرَوَى غَيْرُ وَاحِدٍ عَنْ سُفْيَانَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَهَذَا أَصَحُّ قَالَ مُحَمَّدٌ وَرَوَى إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ مُعَاذِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ سَائِلٌ كُلَّ رَاعٍ عَمَّا اسْتَرْعَاهُ قَالَ سَمِعْت مُحَمَّدًا يَقُولُ هَذَا غَيْرُ مَحْفُوظٍ وَإِنَّمَا الصَّحِيحُ عَنْ مُعَاذِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ketahuilah, setiap kalian adalah pemimpin dan setiap kalian bertanggung jawab dengan yang dipimpin. Maka seorang yang memerintah manusia adalah pemimpin dan bertanggung jawab atas yang dipimpinnya. Seorang laki-laki adalah pemimpin bagi ahli baitnya dan bertanggung jawab atas mereka semua. Seorang wanita adalah pemimpin untuk rumah suaminya, maka ia bertanggung jawab atas rumah suaminya. Dan seorang budak adalah pemimpin bagi harta tuannya, maka ia bertanggung jawab atasnya. Ketahuilah, setiap kalian adalah pemimpin, dan setiap kalian bertanggung jawab atas apa yang dipimpinnya.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Hurairah, Anas dan Abu Musa. Hadits Abu Musa dan Anas tidak terjaga. Sedangkan hadits Ibnu Umar derajatnya hasan shahih.\" Ia berkata, \" [Ibrahim bin Basysyar Ar Ramadi] menceritakan dari [Sufyan bin Uyainah], dari [Buraid bin Abdullah bin Abu Burdah], dari [Abu Burdah], dari [Abu Musa], dari Nabi shallallahu 'alaihi wasallam. [Muhammad bin Ibrahim bin basysyar] mengkabarkan seperti itu kepadaku. Ia berkata, \"Tidak seorang saja yang meriwayatkan dari Sufyan, dari Buraid, dari Abu Burdah, dari Nabi shallallahu 'alaihi wasallam secara mursal. Dan inilah yang lebih shahih. Muhammad berkata, \"Ishaq bin Ibrahim meriwayatkan dari Mu'adz bin Hisyam, dari bapaknya, dari Qatadah, dari Anas, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah akan menanyakan setiap pempin tentang yang dipimpinnya.\" Ia berkata, \"Aku mendengar Muhammad berkata, \"Hadits ini tidak terjaga, tetapi yang shahih adalah dari Mu'adz bin Hisyam, dari bapaknya, dari Qatadah, dari Al Hasan, dari Nabi shallallahu 'alaihi wasallam secara mursal.\""},"1628":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى النَّيْسَابُورِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ الْعَيْزَارِ بْنِ حُرَيْثٍ عَنْ أُمِّ الْحُصَيْنِ الْأَحْمَسِيَّةِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فِي حَجَّةِ الْوَدَاعِ وَعَلَيْهِ بُرْدٌ قَدْ الْتَفَعَ بِهِ مِنْ تَحْتِ إِبْطِهِ قَالَتْ فَأَنَا أَنْظُرُ إِلَى عَضَلَةِ عَضُدِهِ تَرْتَجُّ سَمِعْتُهُ يَقُولُ يَا أَيُّهَا النَّاسُ اتَّقُوا اللَّهَ وَإِنْ أُمِّرَ عَلَيْكُمْ عَبْدٌ حَبَشِيٌّ مُجَدَّعٌ فَاسْمَعُوا لَهُ وَأَطِيعُوا مَا أَقَامَ لَكُمْ كِتَابَ اللَّهِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعِرْبَاضِ بْنِ سَارِيَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أُمِّ حُصَيْنٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya An Naisaburi] berkata, telah menceritakan kepada kami [Muhammad bin Yusuf] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Al Aizar bin Huraits] dari [Ummul Hushain Al Ahmasiyah] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam berkhutbah saat haji wada', waktu itu beliau mengenakan selendang yang terlipat dari bawah ketiaknya.\" Ummul Hushain berkata, \"Aku melihat otot lengannya bergetar, aku mendengar beliau bersabda: \"Wahai sekalian manusia, hendaklah kalian bertakwa kepada Allah. Meskipun kalian dipimpin oleh budak dari habasyah (etopia) yang cacat hidung atau telinganya, maka dengar dan taatilah selama ia memimpin kalian dengan Kitabullah.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Abu Hurairah dan Irabdh bin Sariyah. Hadits ini derajatnya hasan shahih, dan tidak hanya diriwayatkan melalui satu jalur saja dari Ummu Hushain.\""},"1629":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّمْعُ وَالطَّاعَةُ عَلَى الْمَرْءِ الْمُسْلِمِ فِيمَا أَحَبَّ وَكَرِهَ مَا لَمْ يُؤْمَرْ بِمَعْصِيَةٍ فَإِنْ أُمِرَ بِمَعْصِيَةٍ فَلَا سَمْعَ عَلَيْهِ وَلَا طَاعَةَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَعِمْرَانَ بْنِ حُصَيْنٍ وَالْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah seorang muslim mendengar dan taat, baik dalam perkara yang disukai atau dibencinya selama tidak diperintahkan dalam kemaksiatan. Jika diperintahkan untuk melakukan kemaksiatan, maka tidak boleh mendengar dan taat.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali, Imran bin Hushain dan Al Hakam bin Amru Al Ghifari. Hadits ini derajatnya hasan shahih.\""},"1630":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ قُطْبَةَ بْنِ عَبْدِ الْعَزِيزِ عَنْ الْأَعْمَشِ عَنْ أَبِي يَحْيَى عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّحْرِيشِ بَيْنَ الْبَهَائِمِ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Yahya bin Adam] dari [Quthbah bin Abdul Aziz] dari [Al A'masy] dari [Abu Yahya] dari [Mujahid] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengadu (perkelahian) antara binatang.\""},"1631":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي يَحْيَى عَنْ مُجَاهِدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّحْرِيشِ بَيْنَ الْبَهَائِمِوَلَمْ يَذْكُرْ فِيهِ عَنْ ابْنِ عَبَّاسٍ وَيُقَالُ هَذَا أَصَحُّ مِنْ حَدِيثِ قُطْبَةَ وَرَوَى شَرِيكٌ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَبِي يَحْيَى حَدَّثَنَا بِذَلِكَ أَبُو كُرَيْبٍ عَنْ يَحْيَى بْنِ آدَمَ عَنْ شَرِيكٍ وَرَوَى أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ مُجَاهِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَأَبُو يَحْيَى هُوَ الْقَتَّاتُ الْكُوفِيُّ وَيُقَالُ اسْمُهُ زَاذَانُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ طَلْحَةَ وَجَابِرٍ وَأَبِي سَعِيدٍ وَعِكْرَاشِ بْنِ ذُؤَيْبٍ","id":"Telah menceritakan kepada kami [Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Sufyan] dari [Al A'masy] dari [Abu Yahya] dari [Mujahid] bahwa Nabi shallallahu 'alaihi wasallam melarang mengadu antara binatang. Dan ia tidak menyebutkan dalam hadits tersebut dari Ibnu Abbas. Dikatakan bahwa hadits ini derajatnya lebih shahih dari hadits Quthbah. [Syarik] meriwayatkan hadits ini dari [Al A'masy], dari [Mujahid], dari [Ibnu Abbas], dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. Tetapi dalam hadits tersebut ia tidak menyebutkan dari Abu Yahya. Seperti itulah [Abu Kuraib] menceritakan kepada kami dari [Yahya bin Adam], dari [Syarik]. [Abu Mu'awiyah] juga meriwayatkan dari [Al A'masy], dari [Mujahid], dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. Dan Abu Yahya adalah Al Qattat Al Kufi, ada yang mengatakan bahwa namanya adalah Zadzan. Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Thalhah, Jabir, Abu Sa'id dan Ikrasy bin Dzu`aib.\""},"1632":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْوَسْمِ فِي الْوَجْهِ وَالضَّرْبِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam melarang dari membuat wasam (membuat tanda dengan besi panas) di wajah (binatang) dan memukul.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1633":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْوَزِيرِ الْوَاسِطِيُّ حَدَّثَنَا إِسْحَقُ بْنُ يُوسُفَ الْأَزْرَقُ عَنْ سُفْيَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَعُرِضْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَيْشٍ وَأَنَا ابْنُ أَرْبَعَ عَشْرَةَ فَلَمْ يَقْبَلْنِي ثُمَّ عُرِضْتُ عَلَيْهِ مِنْ قَابِلٍ فِي جَيْشٍ وَأَنَا ابْنُ خَمْسَ عَشْرَةَ فَقَبِلَنِيقَالَ نَافِعٌ فَحَدَّثْتُ بِهَذَا الْحَدِيثِ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ فَقَالَ هَذَا حَدُّ مَا بَيْنَ الصَّغِيرِ وَالْكَبِيرِ ثُمَّ كَتَبَ أَنْ يُفْرَضَ لِمَنْ بَلَغَ الْخَمْسَ عَشْرَةَ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ نَحْوَهُ بِمَعْنَاهُ إِلَّا أَنَّهُ قَالَ قَالَ عُمَرُ بْنُ عَبْدِ الْعَزِيزِ هَذَا حَدُّ مَا بَيْنَ الذُّرِّيَّةِ وَالْمُقَاتِلَةِ وَلَمْ يَذْكُرْ أَنَّهُ كَتَبَ أَنْ يُفْرَضَ قَالَ أَبُو عِيسَى حَدِيثُ إِسْحَقَ بْنِ يُوسُفَ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ سُفْيَانَ الثَّوْرِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Wazir Al Wasithi] berkata, telah menceritakan kepada kami [Ishaq bin Yusuf Al Azraq] dari [Sufyan] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata, \"Aku pernah disiagakan di hadapan Rasulullah shallallahu 'alaihi wasallam dalam suatu barisan pasukan, waktu itu umurku masih empat belas tahun hingga beliau tidak menerimaku. Kemudian pada tahun berikutnya aku kembali disiagakan di hadapan beliau dalam suatu barisan pasukan yang sama, waktu itu umurku lima belas tahun hingga beliau pun menerimaku.\" Nafi' berkata, \"Hadits ini lalu aku sampaikan kepada Umar bin Abdul Aziz, ia lalu berkata, \"Ini adalah batas antara masa anak-anak dan dewasa.\" Kemudian ia menulis ketetapan agar anak-anak yang telah berumur lima belas tahun diwajibkan (mengikuti wajib militer).\" Telah menceritakan kepada kami [Ibnu Abi Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah] seperti hadits tersebut dan dengan makna yang sama. Hanya saja ia berkata, \"Umar bin Abdul Aziz berkata, \"Ini adalah batas antara anak-anak dan prajurit.\" Dan ia tidak menyebutkan tentang wajib (militer).\" Abu Isa berkata, \"Hadits Ishaq bin Yusuf ini derajatnya hasan shahih gharib, yaitu dari jalur Sufyan Ats Tsauri.\""},"1634":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَنَّهُ سَمِعَهُ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ فِيهِمْ فَذَكَرَ لَهُمْ أَنَّ الْجِهَادَ فِي سَبِيلِ اللَّهِ وَالْإِيمَانَ بِاللَّهِ أَفْضَلُ الْأَعْمَالِ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ يُكَفِّرُ عَنِّي خَطَايَايَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِنْ قُتِلْتَ فِي سَبِيلِ اللَّهِ وَأَنْتَ صَابِرٌ مُحْتَسِبٌ مُقْبِلٌ غَيْرُ مُدْبِرٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ قُلْتَ قَالَ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ أَيُكَفِّرُ عَنِّي خَطَايَايَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ وَأَنْتَ صَابِرٌ مُحْتَسِبٌ مُقْبِلٌ غَيْرُ مُدْبِرٍ إِلَّا الدَّيْنَ فَإِنَّ جِبْرِيلَ قَالَ لِي ذَلِكَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَمُحَمَّدِ بْنِ جَحْشٍ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَرَوَى يَحْيَى بْنُ سَعِيدٍ الْأَنْصَارِيُّ وَغَيْرُ وَاحِدٍ هَذَا عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا أَصَحُّ مِنْ حَدِيثِ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abdullah bin Abu Qatadah] dari [Bapaknya] Bahwasanya ia pernah mendengarnya menceritakan dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau pernah berdiri di hadapan mereka dan mengatakan bahwa jihad di jalan Allah dan beriman kepada Allah adalah sebaik-baik amalan. Lalu seorang laki-laki berdiri dan bertanya, \"Wahai Rasulullah, bagaimana pendapatmu jika aku terbunuh di jalan Allah, apakah dosa-dosaku akan terampuni?\" Rasulullah shallallahu 'alaihi wasallam lalu menjawab: \"Benar. Jika engkau terbunuh di jalan Allah sementara engkau sabar, mengharap palaha, berani dan tidak lari.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apa yang kamu katakan tadi?\" ia menjawab, \"Bagaimana pendapatmu jika aku terbunuh di jalan Allah, apakah dosa-dosaku akan termapuni?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Benar, jika engkau bersabar, mengharap pahala dan tidak lari (dari medan perang), kecuali hutang. karena Jibril memberitahu hal itu padaku.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Anas, Muhammad bin Jahsy dan Abvu Hurairah. Hadits ini derajatnya hasan shahih. sebagian ulama meriwayatkan hadits ini dari [Sa'id Al Maqburi], dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut. [Yahya bin Sa'id Al Anshari] dan banyak perawai lain meriwayatkan hadits ini dari [Sa'id Al Maqburi], dari [Abdullah bin Abu Qatadah], dari [bapaknya], dari Nabi shallallahu 'alaihi wasallam. Dan ini lebih shahih dari hadits Sa'id Al Maqburi dari Abu Hurairah.\""},"1635":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي الدَّهْمَاءِ عَنْ هِشَامِ بْنِ عَامِرٍ قَالَشُكِيَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجِرَاحَاتُ يَوْمَ أُحُدٍ فَقَالَ احْفِرُوا وَأَوْسِعُوا وَأَحْسِنُوا وَادْفِنُوا الِاثْنَيْنِ وَالثَّلَاثَةَ فِي قَبْرٍ وَاحِدٍ وَقَدِّمُوا أَكْثَرَهُمْ قُرْآنًا فَمَاتَ أَبِي فَقُدِّمَ بَيْنَ يَدَيْ رَجُلَيْنِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ خَبَّابٍ وَجَابِرٍ وَأَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى سُفْيَانُ الثَّوْرِيُّ وَغَيْرُهُ هَذَا الْحَدِيثَ عَنْ أَيُّوبَ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ هِشَامِ بْنِ عَامِرٍ وَأَبُو الدَّهْمَاءِ اسْمُهُ قِرْفَةُ بْنُ بُهَيْسٍ أَوْ بَيْهَسٍ","id":"Telah menceritakan kepada kami [Azhar bin Marwan Al Bashri] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Ayyub] dari [Humaid bin Hilal] dari [Abu Ad Dahma] dari [Hisyam bin Amir] ia berkata, \"Pernah dikeluhkan kepada Rasulullah shallallahu 'alaihi wasallam tentang orang-orang yang terbunuh pada perang uhud, beliau lalu bersabda: \"Buatlah lubang, luaskan, perbagus dan kuburkanlah mereka dua orang atau tiga orang dalam satu lubang. Dan dahulukanlah di antara mereka yang banyak bafalan Al-Qur'annya.\" Lalu bapakku meninggal, hingga ia pun didahulukan di antara dua orang yang ada.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Khabbab, Jabir dan Anas. Hadits ini derajatnya hasan shahih. [Sufyan Ats Tsauri] dan selainnya meriwayatkan hadits ini dari [Ayyub], dari [Humaid bin Hilal] dan dari [Hisyam bin Amir]. Abu Dahma nama aslinya adalah Qirfah bin Buhais, atau Baihas.\""},"1636":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِ قَالَلَمَّا كَانَ يَوْمُ بَدْرٍ وَجِيءَ بِالْأُسَارَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَقُولُونَ فِي هَؤُلَاءِ الْأُسَارَى فَذَكَرَ قِصَّةً فِي هَذَا الْحَدِيثِ طَوِيلَةًقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَأَبِي أَيُّوبَ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ وَأَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ وَيُرْوَى عَنْ أَبِي هُرَيْرَةَ قَالَ مَا رَأَيْتُ أَحَدًا أَكْثَرَ مَشُورَةً لِأَصْحَابِهِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Amru bin Murrah] dari [Abu Ubaidah] dari [Abdullah] ia berkata, \"Ketika perang badar usai dan para tawanan didatangkan, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa pendapat kalian mengenai pata tawanan itu…lalu perawi menyebutkan kisah yang panjang dalam hadits ini.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Umar, Abu Ayyub, Anas dan Abu Hurairah. Dan hadits ini derajatnya hasan. Abu Ubaidah belum pernah mendengar dari bapaknya. Telah diriwayatkan pula dari Abu Hurairah, ia berkata, \"Aku tidak pernah melihat seseorang yang paling sering bermusyawarah dengan para sahabat selain dari pada Rasulullah shallallahu 'alaihi wasallam.\" "},"1637":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْحَكَمِ عَنْ مِقْسَمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ الْمُشْرِكِينَ أَرَادُوا أَنْ يَشْتَرُوا جَسَدَ رَجُلٍ مِنْ الْمُشْرِكِينَ فَأَبَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَهُمْ إِيَّاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْحَكَمِ وَرَوَاهُ الْحَجَّاجُ بْنُ أَرْطَاةَ أَيْضًا عَنْ الْحَكَمِ و قَالَ أَحْمَدُ بْنُ حَنْبَلٍ ابْنُ أَبِي لَيْلَى لَا يُحْتَجُّ بِحَدِيثِهِ و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ ابْنُ أَبِي لَيْلَى صَدُوقٌ وَلَكِنْ لَا نَعْرِفُ صَحِيحَ حَدِيثِهِ مِنْ سَقِيمِهِ وَلَا أَرْوِي عَنْهُ شَيْئًا وَابْنُ أَبِي لَيْلَى صَدُوقٌ فَقِيهٌ وَرُبَّمَا يَهِمُ فِي الْإِسْنَادِ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ سُفْيَانَ الثَّوْرِيِّ قَالَ فُقَهَاؤُنَا ابْنُ أَبِي لَيْلَى عَبْدُ اللَّهِ بْنُ شُبْرُمَةَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abu Ahmad] berkata, telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Laila] dari [Al hakam] dari [Miqsam] dari [Ibnu Abbas] berkata, \"Orang-orang musyrik ingin membeli jasad seorang laki-laki dari kaum musyrikin, tetapi Nabi shallallahu 'alaihi wasallam menolak untuk menjualnya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami tidak mengetahuinya kecuali dari hadits Al Hakam. [Al Hajjaj bin Arthah] juga meriwayatkannya dari [Al Hakam]. Imam Ahmad bin Hambal berkata, \"Hadits Ibnu Abu Laila tidak bisa dijadikan sebagai hujah.\" Muhammad bin Isma'il berkata, \"Isma'il bin Abu Laila adalah seorang yang jujur, tetapi kami tidak bisa membedakan mana hadits yang shahih darinya dan mana yang bukan. Dan aku tidak pernah meriwayatkan darinya, Ibnu Abu Laila adalah seorang yang jujur dan fakih, namun barangkali ia kurang baik dalam hal sanad.\" Telah menceritakan kepada kami Nashr bin Ali, ia berkata, \"Abdullah bin Dawud menceritakan kepada kami dari Sufyan Ats Tsauri, ia berkata, \"Fuqaha kami mengatakan bahwa Ibnu Abu Laila adalah Abdullah bin Syubrumah.\""},"1638":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ بْنِ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ ابْنِ عُمَرَ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَحَاصَ النَّاسُ حَيْصَةً فَقَدِمْنَا الْمَدِينَةَ فَاخْتَبَيْنَا بِهَا وَقُلْنَا هَلَكْنَا ثُمَّ أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا يَا رَسُولَ اللَّهِ نَحْنُ الْفَرَّارُونَ قَالَ بَلْ أَنْتُمْ الْعَكَّارُونَ وَأَنَا فِئَتُكُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يَزِيدَ بْنِ أَبِي زِيَادٍ وَمَعْنَى قَوْلِهِ فَحَاصَ النَّاسُ حَيْصَةً يَعْنِي أَنَّهُمْ فَرُّوا مِنْ الْقِتَالِ وَمَعْنَى قَوْلِهِ بَلْ أَنْتُمْ الْعَكَّارُونَ وَالْعَكَّارُ الَّذِي يَفِرُّ إِلَى إِمَامِهِ لِيَنْصُرَهُ لَيْسَ يُرِيدُ الْفِرَارَ مِنْ الزَّحْفِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan] dari [Yazid bin Abu Ziyad] dari ['Abdurrahman bin Abu Laila] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutuskan kami dalam sebuah ekspedisi, lalu orang-orang melarikan diri dari peperangan. Katika sampai di Madinah, kami bersembunyi karena malu. Kami lalu berkata; \"Kita telah celaka.\" Setelah itu kami mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, kami adalah orang-orang yang telah lari dari peperangan!\" beliau menjawab: \"Bahkan kalian adalah orang-orang yang kembali pada kancah peperangan, dan aku berada pada kelompok kalian.\" Abu Isa berkata, \"Ini adalah hadits hasan, kami tidak mengetahuinya kecuali dari hadits Yazid bin Ziyad. Adapun makna dari ungkapan, 'orang-orang melarikan diri dari peperangan' adalah mundur mundur dari peperangan. Dan makna sabda Nabi, 'Bahkan kalian adalah orang-orang yang kembali pada kancah peperangan' adalah berlari kepada pemimpinnya agar ia menolongnya, bukan lari untuk kabur dari peperangan.\""},"1639":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ قَال سَمِعْتُ نُبَيْحًا الْعَنَزِيَّ يُحَدِّثُ عَنْ جَابِرٍ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ جَاءَتْ عَمَّتِي بِأَبِي لِتَدْفِنَهُ فِي مَقَابِرِنَا فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُدُّوا الْقَتْلَى إِلَى مَضَاجِعِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَنُبَيْحٌ ثِقَةٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah mengabarkan kepada kami [Syu'bah] dari [Al Aswad bin Qais] ia berkata; Aku mendengar [Nubaih Al Anazi] menceritakan dari [Jabir] ia berkata, \"Pada perang uhud bibiku datang dengan membawa jasad ayahku untuk dikuburkan di pekuburan kami. Tiba-tiba penyeru Rasulullah shallallahu 'alaihi wasallam berteriak, \"Kembalikanlah semua korban perang di tempatnya masing-masing.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, dan Nubaih adalah seorang yang tsiqah.\""},"1640":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ تَبُوكَ خَرَجَ النَّاسُ يَتَلَقَّوْنَهُ إِلَى ثَنِيَّةِ الْوَدَاعِ قَالَ السَّائِبُ فَخَرَجْتُ مَعَ النَّاسِ وَأَنَا غُلَامٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] dan [Sa'id bin 'Abdurrahman Al Makhzumi] keduanya berkata; telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [As Sa`ib bin Yazid] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam kembali dari perang Tabuk, orang-orang menyambut kedatangan beliau hingga Tsaniyatul Wada'.\" As Sa`ib berkata, \"Aku lalu keluar bersama orang-orang, sementara waktu itu masih seorang bocah.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1641":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ شِهَابٍ عَنْ مَالِكِ بْنِ أَوْسِ بْنِ الْحَدَثَانِ قَال سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُكَانَتْ أَمْوَالُ بَنِي النَّضِيرِ مِمَّا أَفَاءَ اللَّهُ عَلَى رَسُولِهِ مِمَّا لَمْ يُوجِفْ الْمُسْلِمُونَ عَلَيْهِ بِخَيْلٍ وَلَا رِكَابٍ وَكَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالِصًا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْزِلُ نَفَقَةَ أَهْلِهِ سَنَةً ثُمَّ يَجْعَلُ مَا بَقِيَ فِي الْكُرَاعِ وَالسِّلَاحِ عُدَّةً فِي سَبِيلِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى سُفْيَانُ بْنُ عُيَيْنَةَ هَذَا الْحَدِيثَ عَنْ مَعْمَرٍ عَنْ ابْنِ شِهَابٍ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Ibnu Syihab] dari [Malik bin Aus bin Al Hadatsan] ia berkata, \"Aku mendengar [Umar Ibnul Khaththab] berkata, \"Harta kekayaan bani Nadhir yang Allah berikan kepada rasul-Nya, (untuk mendapatkan itu semua) kaum muslimin tidak susah-susah mengerahkan seekor kuda atau unta, semuanya itu adalah milik Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam menyisakan nafkah untuk kebutuhan keluarganya selama satu tahun, kemudian sisanya beliau gunakan untuk memenuhi kebutuhan hewan tunggangan, peralatan senjata dan bekal untuk perang fi sabilillah.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. [Sufyan bin Uyainah] meriwayatkan hadits ini dari [Ma'mar], dari [Ibnu Syihab].\""},"1642":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُرِّمَ لِبَاسُ الْحَرِيرِ وَالذَّهَبِ عَلَى ذُكُورِ أُمَّتِي وَأُحِلَّ لِإِنَاثِهِمْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَعُقْبَةَ بْنِ عَامِرٍ وَأَنَسٍ وَحُذَيْفَةَ وَأُمِّ هَانِئٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعِمْرَانَ بْنِ حُصَيْنٍ وَعَبْدِ اللَّهِ بْنِ الزُّبَيْرِ وَجَابِرٍ وَأَبِي رَيْحَانَ وَابْنِ عُمَرَ وَالْبَرَاءِ وَوَاثِلَةَ بْنِ الْأَسْقَعِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah menceritakan kepada kami [Abdullah bin Numair] berkata, telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Nafi'] dari [Sa'id bin Abu Hind] dari [Abu Musa Al Asy'ari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pakaian sutera dan emas diharamkan bagi umatku yang laki-laki dan dihalalkan bagi yang perempuan.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Umar, Ali, Uqbah bin Amir, Anas, Hudzaifah, Ummu Hani, Abdullah bin Amru, Imran bin Hushain, Abdullah bin Az Zubair, Jabir, Abu Raihan, Ibnu Umar, Al Bara dan Watsilah Ibnul Asqa'.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1643":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ الشَّعْبِيِّ عَنْ سُوَيْدِ بْنِ غَفَلَةَ عَنْ عُمَرَ أَنَّهُ خَطَبَ بِالْجَابِيَةِ فَقَالَنَهَى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَرِيرِ إِلَّا مَوْضِعَ أُصْبُعَيْنِ أَوْ ثَلَاثٍ أَوْ أَرْبَعٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] berkata, telah menceritakan kepada kami [Bapakku] dari [Qatadah] dari [Asy Sya'bi] dari [Suwaid bin Ghafalah] dari [Umar] Bahwasanya ia berkhutbah di Jabiyah, ia mengatakan, \"Nabi shallallahu 'alaihi wasallam melarang mengenakan sutera kecuali sekadar dua, tiga atau empat jari.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1644":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ وَالزُّبَيْرَ بْنَ الْعَوَّامِ شَكَيَا الْقَمْلَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ لَهُمَا فَرَخَّصَ لَهُمَا فِي قُمُصِ الْحَرِيرِ قَالَ وَرَأَيْتُهُ عَلَيْهِمَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Abdu Ash Shamad bin Abdul Warits] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] berkata, \"bahwasanya Abdurrahman bin Auf dan Az Zubair Ibnul Awwam pada suatu peperangan pernah mengeluh kepada Nabi shallallahu 'alaihi wasallam tentang penyakit gatal yang dideritanya, lalu beliau memberi keringanan kepada keduanya untuk mengenakan kain sutera.\" Anas berkata, \"Dan aku melihat keduanya mengenakan kain tersebut.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1645":{"ar":"حَدَّثَنَا أَبُو عَمَّارٍ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنَا وَاقِدُ بْنُ عَمْرِو بْنِ سَعْدِ بْنِ مُعَاذٍ قَالَقَدِمَ أَنَسُ بْنُ مَالِكٍ فَأَتَيْتُهُ فَقَالَ مَنْ أَنْتَ فَقُلْتُ أَنَا وَاقِدُ بْنُ عَمْرِو بْنِ سَعْدِ بْنِ مُعَاذٍ قَالَ فَبَكَى وَقَالَ إِنَّكَ لَشَبِيهٌ بِسَعْدٍ وَإِنَّ سَعْدًا كَانَ مِنْ أَعْظَمِ النَّاسِ وَأَطْوَلِهِمْ وَإِنَّهُ بُعِثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُبَّةٌ مِنْ دِيبَاجٍ مَنْسُوجٌ فِيهَا الذَّهَبُ فَلَبِسَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعِدَ الْمِنْبَرَ فَقَامَ أَ��ْ قَعَدَ فَجَعَلَ النَّاسُ يَلْمِسُونَهَا فَقَالُوا مَا رَأَيْنَا كَالْيَوْمِ ثَوْبًا قَطُّ فَقَالَ أَتَعْجَبُونَ مِنْ هَذِهِ لَمَنَادِيلُ سَعْدٍ فِي الْجَنَّةِ خَيْرٌ مِمَّا تَرَوْنَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Ammar] berkata, telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Muhammad bin Amru] berkata, telah menceritakan kepada kami [Waqid bin Amru bin Sa'd bin Mu'adz] ia berkata, \"Saat [Anas bin Malik] tiba aku mendekatinya hingga ia pun bertanya, \"Siapa kamu?\" Aku menjawab, \"Aku Waqid bin Amru bin Sa'd bin Mu'adz.\" Waqid berkata, \"Anas lalu menangis dan berkata, \"Sungguh, engkau mirip sekali dengan Sa'd. Dahulu Sa'd adalah orang yang paling besar dan tinggi di antara yang lain. Pernah didatangkan kepada Nabi shallallahu 'alaihi wasallam selendang yang terbuat dari Dibaj bersulamkan benang emas. Rasulullah shallallahu 'alaihi wasallam kemudian mengenakan kain tersebut lalu naik ke atas mimbar, beliau lantas berdiri -atau duduk- hingga orang-orang pun saling meraba kain tersebut. Mereka berkata, \"Kami tidak pernah melihat kain sebagus hari ini!\" Beliau lalu bersabda: \"Apakah kalian takjub dengan kain ini? sungguh, sapu tangan Sa'd di surga lebih baik dari apa yang kalian lihat ini.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Asma binti Abu Bakar, dan hadits ini derajatnya hasan shahih.\""},"1646":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَمَا رَأَيْتُ مِنْ ذِي لِمَّةٍ فِي حُلَّةٍ حَمْرَاءَ أَحْسَنَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ شَعْرٌ يَضْرِبُ مَنْكِبَيْهِ بَعِيدُ مَا بَيْنَ الْمَنْكِبَيْنِ لَمْ يَكُنْ بِالْقَصِيرِ وَلَا بِالطَّوِيلِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جَابِرِ بْنِ سَمُرَةَ وَأَبِي رِمْثَةَ وَأَبِي جُحَيْفَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Aku tidak pernah melihat seorang laki-laki yang mempunyai rambut panjang saat mengenakan kain berwarna merah sebagus Rasulullah shallallahu 'alaihi wasallam. Rambut beliau panjangnya sebahu, tidak panjang dan tidak pendek.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Jabir bin Samurah, Abu Rimtsah dan Abu Juhaifah. Dan hadits ini derajatnya hasan shahih.\""},"1647":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسِ الْقَسِّيِّ وَالْمُعَصْفَرِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَحَدِيثُ عَلِيٍّ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Malik bin Anas] dari [Nafi'] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ali] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarangku memakai kain yang bersulam sutera dan kain yang dicelup dengan warna kuning (berwarna kuning kekuningan).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Anas dan Abdullah bin Amru. Dan hadits Ali ini derajatnya hasan shahih.\""},"1648":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ حَدَّثَنَا سَيْفُ بْنُ هَارُونَ الْبُرْجُمِيُّ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ سَلْمَانَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ السَّمْنِ وَالْجُبْنِ وَالْفِرَاءِ فَقَالَ الْحَلَالُ مَا أَحَلَّ اللَّهُ فِي كِتَابِهِ وَالْحَرَامُ مَا حَرَّمَ اللَّهُ فِي كِتَابِهِ وَمَا سَكَتَ عَنْهُ فَهُوَ مِمَّا عَفَا عَنْهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ الْمُغِيرَةِ وَهَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ هَذَا الْوَجْهِ وَرَوَى سُفْيَانُ وَغَيْرُهُ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ سَلْمَانَ قَوْلَهُ وَكَأَنَّ هَذَا الْحَدِيثَ الْمَوْقُوفَ أَصَحُّ وَسَأَلْتُ الْبُخَارِيَّ عَنْ هَذَا الْحَدِيثِ فَقَالَ مَا أُرَاهُ مَحْفُوظًا رَوَى سُفْيَانُ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ عَنْ سَلْمَانَ مَوْقُوفًا قَالَ الْبُخَارِيُّ وَسَيْفُ بْنُ هَارُونَ مُقَارِبُ الْحَدِيثِ وَسَيْفُ بْنُ مُحَمَّدٍ عَنْ عَاصِمٍ ذَاهِبُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Isma'il bin Musa Al Fazari] berkata, telah menceritakan kepada kami [Saif bin Harun Al Burjumi] dari [Sualiman At Taimi] dari [Abu Utsman] dari [Salman] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang mentega, keju dan Al Fara (sejenis baju dari kulit).\" Beliau lalu menjawab: \"Halal adalah sesuatu yang telah Allah halalkan dalam kitab-Nya, dan haram adalah sesuatu yang telah Allah haramkan dalam kitab-Nya. Adapun yang Allah diamkan, maka itu adalah sesutau yang Allah maafkan.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Al Mughirah. Ini adalah hadits gharib, dan kami tidak mengetahuinya diriwayatkan secara marfu' kecuali dari jalur ini. Sufyan dan selainnya meriwayatkan sabda beliau dari Sulaiman At Taimi, dari Abu Sufyan, dari Salman. Maka seakan-akan hadits ini mauquf dan ini lebih shahih. Aku pernah bertanya Imam Bukhari tentang setatus hadits ini, ia menjawab, \"Menurutku hadits ini tidak terjaga. Sufyan meriwayatkan dari Sulaiman At Taimi, dari Abu Utsman, dari Salman secara mauquf.\" Imam Bukhari berkata lagi, \"Saif bin Harun adalah seorang Muqaribul hadits (haditsnya bisa diterima), sedangkan Saif bin Muhammad dari Ashim adalah Dzhibul hadits (haditsnya tidak bisa diterima).\" "},"1649":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ قَال سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُمَاتَتْ شَاةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَهْلِهَا أَلَا نَزَعْتُمْ جِلْدَهَا ثُمَّ دَبَغْتُمُوهُ فَاسْتَمْتَعْتُمْ بِهِ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Atha bin Abu Rabah] ia berkata; Aku mendengar [Ibnu Abbas] berkata, \"Ada seekor kambing yang mati, lalu Nabi shallallahu 'alaihi wasallam berkata kepada pemiliknya: \"Tidakkah kamu ambil kulitnya, lalu kamu samak hingga kamu bisa menikmatinya?\" "},"1650":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ وَعَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا إِهَابٍ دُبِغَ فَقَدْ طَهُرَوَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ قَالُوا فِي جُلُودِ الْمَيْتَةِ إِذَا دُبِغَتْ فَقَدْ طَهُرَتْ قَالَ أَبُو عِيسَى قَالَ الشَّافِعِيُّ أَيُّمَا إِهَابِ مَيْتَةٍ دُبِغَ فَقَدْ طَهُرَ إِلَّا الْكَلْبَ وَالْخِنْزِيرَ وَاحْتَجَّ بِهَذَا الْحَدِيثِ و قَالَ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ إِنَّهُمْ كَرِهُوا جُلُودَ السِّبَاعِ وَإِنْ دُبِغَ وَهُوَ قَوْلُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ وَأَحْمَدَ وَإِسْحَقَ وَشَدَّدُوا فِي لُبْسِهَا وَالصَّلَاةِ فِيهَا قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ إِنَّمَا مَعْنَى قَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا إِهَابٍ دُبِغَ فَقَدْ طَهُرَ جِلْدُ مَا يُؤْكَلُ لَحْمُهُ هَكَذَا فَسَّرَهُ النَّضْرُ بْنُ شُمَيْلٍ و قَالَ إِسْحَقُ قَالَ النَّضْرُ بْنُ شُمَيْلٍ إِنَّمَا يُقَالُ الْإِهَابُ لِجِلْدِ مَا يُؤْكَلُ لَحْمُهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِ وَمَيْمُونَةَ وَعَائِشَةَ وَحَدِيثُ ابْنِ عَبَّاسٍ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا وَرُوِيَ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُوِيَ عَنْهُ عَنْ سَوْدَةَ و سَمِعْت مُحَمَّدًا يُصَحِّحُ حَدِيثَ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدِيثَ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ وَقَالَ احْتَمَلَ أَنْ يَكُونَ رَوَى ابْنُ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى ابْنُ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ فِيهِ عَنْ مَيْمُونَةَ قَالَ أَبُو عِيسَى وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ وَهُوَ قَوْلُ سُفْيَانَ الثَّوْرِيِّ وَابْنِ الْمُبَارَكِ وَالشَّافِعِيِّ وَأَحْمَدَ وَإِسْحَقَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dan [Abdul Aziz bin Muhammad] dari [Zaid bin Aslam] dari ['Abdurrahman bin Wa'lah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kulit apapun jika disamak, maka ia menjadi suci.\" Banyak ulama` yang menjadikan hadits ini sebagai pedoman amal, mereka berpendapat bahwa kulit bangkai Jika disamak maka ia menjadi suci.\" Abu Isa berkata, \"Imam Syafi'I berkata, \"Kulit bangkai apapun jika disamak, maka ia menjadi suci kecuali anjing dan babi.\" Ia berdalil dengan hadits ini. Sebagian ulama` dari kalangan sahabat Nabi shallallahu 'alaihi wasallam dan selain mereka tetap memakruhkan kulit binatang buas meskipun telah disamak. Ini adalah pendapat Abdullah Ibnul Mubarak, Ahmad dan Ishaq. Dan mereka bersikap tegas dalam memakainya serta mengenakannya dalam shalat. Ishaq bin Ibrahim berkata, \"Hanyasanya makna dari sabda Rasulullah shallallahu 'alaihi wasallam, 'Kulit apapun jika disamak, maka ia menjadi suci', maksudnya adalah kulit dari hewan yang boleh dimakan dagingnya. Demikianlah yang dijelaskan oleh An Nadhr bin Syumail.\" Ishaq berkata lagi, Nadhar bin Syumail mengatakan; ungkapan disamak, adalah untuk kulit dari binatang yang dagingnya boleh dimakan.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Salamah Ibnul Muhabbaq, Mainunah dan 'Aisyah. Hadits Ibnu Abbas derajatnya hasan shahih. Hadits seperti ini telah diriwayatkan dari Ibnu Abbas, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\" Telah diriwayatkan pula dari [Ibnu Abbas] dari [Maimunah] dari Nabi shallallahu 'alaihi wasallam, Dan telah diriwayatkan pula dari Ibnu Abbas, dari [Saudah]. Aku pernah mendengar Muhammad (bin Isma'il) menshahihkan hadits Ibnu Abbas dari Nabi shallallahu 'alaihi wasallam, serta hadits Ibnu Abbas dari Maimunah. Bisa jadi Ibnu Abbas meriwayatkan melalui Maimunah dari Nabi shallallahu 'alaihi wasallam, dan bisa pula Ibnu Abbas meriwayatkannya dari Nabi tetapi ia tidak menyebutkan dalam haditsnya 'dari Maimunah'. Abu Isa berkata, \"Kebanyakan ahli ilmu mengamalkan hadits ini, dan ini adalah pendapat Sufyan Ats Tsauri, Ibnul Mubarak, As Syafi'i. Ahmad dan Ishaq.\""},"1651":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ طَرِيفٍ الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْأَعْمَشِ وَالشَّيْبَانِيِّ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَأَتَانَا كِتَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَيُرْوَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ عَنْ أَشْيَاخٍ لَهُمْ هَذَا الْحَدِيثُ وَلَيْسَ الْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ أَنَّهُ قَالَ أَتَانَا كِتَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ وَفَاتِهِ بِشَهْرَيْنِ قَالَ و سَمِعْت أَحْمَدَ بْنَ الْحَسَنِ يَقُولُ كَانَ أَحْمَدُ بْنُ حَنْبَلٍ يَذْهَبُ إِلَى هَذَا الْحَدِيثِ لِمَا ذُكِرَ فِيهِ قَبْلَ وَفَاتِهِ بِشَهْرَيْنِ وَكَانَ يَقُولُ كَانَ هَذَا آخِرَ أَمْرِ النَّبِيِّ صَلَّى اللَّهُ ع��لَيْهِ وَسَلَّمَ ثُمَّ تَرَكَ أَحْمَدُ بْنُ حَنْبَلٍ هَذَا الْحَدِيثَ لَمَّا اضْطَرَبُوا فِي إِسْنَادِهِ حَيْثُ رَوَى بَعْضُهُمْ فَقَالَ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ عَنْ أَشْيَاخٍ لَهُمْ مِنْ جُهَيْنَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Tharif Al Kufi] berkata, telah menceritakan kepada kami [Muhammad bin Fudhail] dari [Al A'masy] dan [Asy Syaibani] dari [Al Hakam] dari ['Abdurrahman bin Abu Laila] dari [Abdullah bin Ukaim] ia berkata, \"Surat Rasulullah shallallahu 'alaihi wasallam datang kepada kami, isinya adalah, 'Janganlah kalian memanfaatkan bangkai dengan mengambil kulit atau tulangnya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan, hadits ini telah diriwayatkan dari Abdullah bin Ukaim, dari para syaikh mereka. Tetapi banyak dari kalangan ulama` yang tidak berpedoman amal dengan hadits ini. Hadits ini telah diriwayatkan dari Abdullah bin Ukaim, ia berkata, \"Surat Nabi shallallahu 'alaihi wasallam datang kepada kami dua bulan sebelum beliau meninggal.\" Ia berkata, \"Aku mendengar Ahmad Ibnul Hasan berkata, \"Ahmad bin hambal sependapat dengan hadits ini, sebab dalam hadits tersebut disebutkan bahwa surat itu datang dua bulan sebelum beliau meninggal.\" Ahmad bin hambal berkata, \"Ini adalah perintah terakhir Nabi shallallahu 'alaihi wasallam, \" setelah itu Ahmad bin Hambal meninggalkan hadits ini karena terjadi kejanggalan dalam sanadnya. Kejanggalan itu karena sebagian perawi menyebutkan; dari Abdullah bin Ukaim, dari para syaikh mereka yang berasal dari Juhainah.\""},"1652":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ وَعَبْدِ اللَّهِ بْنِ دِينَارٍ وَزَيْدِ بْنِ أَسْلَمَ كُلُّهُمْ يُخْبِرُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْظُرُ اللَّهُ يَوْمَ الْقِيَامَةِ إِلَى مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ حُذَيْفَةَ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَسَمُرَةَ وَأَبِي ذَرٍّ وَعَائِشَةَ وَهُبَيْبِ بْنِ مُغَفَّلٍ وَحَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Anshari] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Malik] dari [Nafi'] dan [Abdullah bin Dinar] dan [Zaid bin Aslam] semuanya mengabarkan dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"kelak pada hari kiamat Allah tidak akan melihat seseorang yang menjulurkan (menyapukan) bajunya dengan rasa sombong.\" Abu Isa berkata; dalam bab ini ada hadits serupa dari Hudzaifah, Abu Said, Abu Hurairah, Samurah, Abu Dzar, Aisyah dan Hubaib bin Mughaffal, dan hadits Ibnu Umar derajatnya hadits hasan shahih. "},"1653":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ فَقَالَتْ أُمُّ سَلَمَةَ فَكَيْفَ يَصْنَعْنَ النِّسَاءُ بِذُيُولِهِنَّ قَالَ يُرْخِينَ شِبْرًا فَقَالَتْ إِذًا تَنْكَشِفُ أَقْدَامُهُنَّ قَالَ فَيُرْخِينَهُ ذِرَاعًا لَا يَزِدْنَ عَلَيْهِقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah bersabda: \"Barangsiapa menjulurkan kainnya dengan rasa sombong, maka Allah tidak akan melihatnya pada hari kiamat.\" 'Aisyah bertanya, \"Lalu apa yang harus dilakukan kaum wanita dengan dzail (lebihan kain bagian bawah) mereka?\" beliau menjawab: \"Mereka boleh memanjangkannya satu jengkal.\" 'Aisyah kembali menyelah, \"Kalau begitu telapak kaki mereka akan terlihat!\" beliau bersabda: \"Mereka boleh memanjangkannya sehasta, dan jangan lebih.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1654":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أُمِّ الْحَسَنِ أَنَّ أُمَّ سَلَمَةَ حَدَّثَتْهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَّرَ لِفَاطِمَةَ شِبْرًا مِنْ نِطَاقِهَاقَالَ أَبُو عِيسَى وَرَوَى بَعْضُهُمْ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ الْحَسَنِ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ وَفِي هَذَا الْحَدِيثِ رُخْصَةٌ لِلنِّسَاءِ فِي جَرِّ الْإِزَارِ لِأَنَّهُ يَكُونُ أَسْتَرَ لَهُنَّ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Affan] berkata, telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Ummul Hasan] bahwa [Ummu Salamah] menceritakan kepada mereka, Nabi shallallahu 'alaihi wasallam memberi keringanan kepada Fatimah untuk memanjangkan satu jengkal pada kain pengikat pinggangnya.\" Abu Isa berkata, \"Sebagian ahli hadits meriwayatkan dari [Hammad bin Salamah], dari [Ali bin Zaid], dari [Al Hasan], dari [Ibunya], dari [Ummu Salamah]. Pada hadits ini terdapat keringanan bagi para wanita untuk memanjangkan kain sarungnya (hingga menyapu tanah), sebab hal itu lebih bisa menutup auratnya.\""},"1655":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ قَالَأَخْرَجَتْ إِلَيْنَا عَائِشَةُ كِسَاءً مُلَبَّدًا وَإِزَارًا غَلِيظًا فَقَالَتْ قُبِضَ رُوحُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَيْنِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ مَسْعُودٍ وَحَدِيثُ عَائِشَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Isma'il bin Ibrahim] berkata, telah menceritakan kepada kami [Ayyub] dari [Humaid bin Hilal] dari [Abu Burdah] ia berkata, \" ['Aisyah] menunjukkan kain tipis dan sarung kasar kepada kami seraya mengatakan, \"Rasulullah shallallahu 'alaihi wasallam meninggal dalam keadaan terbungkus dengan dua kain ini.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali dan Ibnu Mas'ud. Dan hadits 'Aisyah ini derajatnya hasan shahih.\""},"1656":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ ابْنِ مَسْعُودٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ عَلَى مُوسَى يَوْمَ كَلَّمَهُ رَبُّهُ كِسَاءُ صُوفٍ وَجُبَّةُ صُوفٍ وَكُمَّةُ صُوفٍ وَسَرَاوِيلُ صُوفٍ وَكَانَتْ نَعْلَاهُ مِنْ جِلْدِ حِمَارٍ مَيِّتٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ حُمَيْدٍ الْأَعْرَجِ وَحُمَيْدٌ هُوَ ابْنُ عَلِيٍّ الْكُوفِيُّ قَالَ سَمِعْت مُحَمَّدًا يَقُولُ حُمَيْدُ بْنُ عَلِيٍّ الْأَعْرَجُ مُنْكَرُ الْحَدِيثِ وَحُمَيْدُ بْنُ قَيْسٍ الْأَعْرَجُ الْمَكِّيُّ صَاحِبُ مُجَاهِدٍ ثِقَةٌ قَالَ أَبُو عِيسَى وَالْكُمَّةُ الْقَلَنْسُوَةُ الصَّغِيرَةُ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah menceritakan kepada kami [Khalaf bin Khalifah] dari [Humaid Al A'raj] dari [Abdullah Ibnul Harits] dari [Ibnu Mas'ud] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada hari ketika Rabbnya berbicara dengannya, Musa mengenakan kain wool, jubah wool, peci wool, dan celana panjang dari wool. Sementara kedua sandalnya terbuat dari kulit himar yang telah mati.\" Abu Isa berkata, \"Hadits ini derajatnya gharib, kami tidak mengetahuinya kecuali dari hadits Humaid Al A'raj. Dan Humaid adalah Ibnu Ali Al Kufi. Ia (Abu Isa) berkata, \"Aku mendengar Muhammad berkata, \"Humaid bin Ali Al A'raj seorang munkarul hadits. Sementara Humaid bin Qais Al A'raj Al Makki adalah sahabat Mujahid, seorang yang tsiqah.\" Abu Isa berkata, \"Al Kummah adalah peci kecil.\""},"1657":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ يَوْمَ الْفَتْحِ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعُمَرَ وَابْنِ حُرَيْثٍ وَابْنِ عَبَّاسٍ وَرُكَانَةَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dari [Hammad bin Salamah] dari [Abu Az Z ubair] dari [Jabir] ia berkata, \"Nabi shallallahu 'alaihi wasallam masuk Makkah saat terjadi penaklukan dengan mengenakan imamah (surban yang dililitkan kepala) berwarna hitam.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali, Umar, Ibnu Huraits, Ibnu Abbas dan Rukanah.\" Abu Isa berkata, \"Hadits Jabir ini derajatnya hasan shahih.\""},"1658":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا يَحْيَى بْنُ مُحَمَّدٍ الْمَدَنِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اعْتَمَّ سَدَلَ عِمَامَتَهُ بَيْنَ كَتِفَيْهِقَالَ نَافِعٌ وَكَانَ ابْنُ عُمَرَ يَسْدِلُ عِمَامَتَهُ بَيْنَ كَتِفَيْهِ قَالَ عُبَيْدُ اللَّهِ وَرَأَيْتُ الْقَاسِمَ وَسَالِمًا يَفْعَلَانِ ذَلِكَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَفِي الْبَاب عَنْ عَلِيٍّ وَلَا يَصِحُّ حَدِيثُ عَلِيٍّ فِي هَذَا مِنْ قِبَلِ إِسْنَادِهِ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani] berkata, telah menceritakan kepada kami [Yahya bin Muhammad Al Madani] dari [Abdul Aziz bin Muhammad] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam mengenakan imamah (surban yang dililitkan kepala), maka beliau mengurai imamahnya antara dua pundaknya.\" Nafi' berkata, \"Ibnu Umar mengurai imamahnya antara dua pundaknya.\" Ubaidullah berkata, \"Aku melihat Al Qasim dan Salim pun melakukan seperti itu.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib. Dalam bab ini juga ada hadits dari Ali, tetapi dalam bab ini hadits Ali tersebut tidak shahih dari sisi sanadnya.\""},"1659":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ وَالْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ قَالَنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّخَتُّمِ بِالذَّهَبِ وَعَنْ لِبَاسِ الْقَسِّيِّ وَعَنْ الْقِرَاءَةِ فِي الرُّكُوعِ وَالسُّجُودِ وَعَنْ لِبَاسِ الْمُعَصْفَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Salamah bin Syabib] dan [Al Hasan bin Ali Al Khallal] dan tidak hanya seorang, mereka berkata; telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ali bin Abu Thalib] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarang kami memakai cincin emas, memakai kain yang bersulam sutera, membaca Al-Qur'an saat rukuk dan sujud, serta kain yang dicelup dengan warna kuning kekuningan.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1660":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَبِي التَّيَّاحِ حَدَّثَنَا حَفْصٌ اللَّيْثِيُّ قَالَ أَشْهَدُ عَلَى عِمْرَانَ بْنِ حُصَيْنٍ أَنَّهُ حَدَّثَنَا أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّخَتُّمِ بِالذَّهَبِقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ وَمُعَاوِيَةَ قَالَ أَبُو عِيسَى حَدِيثُ عِمْرَانَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو التَّيَّاحِ اسْمُهُ يَزِيدُ بْنُ حُمَيْدٍ","id":"Telah menceritakan kepada kami [Yusuf bin Hammad Al Ma'ni Al Bashri] berkata, telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Abu At Tayyah] berkata, telah menceritakan kepada kami [Hafsh Al Laitsi] ia berkata, \"Aku bersaksi atas [Imran bin Hushain] bahwa ia pernah berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai cincin emas.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Ali, Ibnu Umar, Abu Hurairah dan Mu'awiyah.\" Abu Isa berkata, \"Hadits Imran ini derajatnya hasan shahih, sedangkan Abu At Tayyah nama aslinya adalah Yazid bin Humaid.\""},"1661":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَغَيْرُ وَاحِدٍ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍ قَالَكَانَ خَاتَمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ وَرِقٍ وَكَانَ فَصُّهُ حَبَشِيًّاقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَبُرَيْدَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah] dan banyak perwawi dari [Abdullah bin Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Anas] ia berkata, \"Cincin Nabi shallallahu 'alaihi wasallam terbuat dari perak, sedangkan mata cincinnya dari Habasyah.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Ibnu Umar dan Buraidah.\" Abu Isa berkata, \"hadits ini derajatnya hasan shahih gharib dari jalur ini.\""},"1662":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا حَفْصُ بْنُ عُمَرَ بْنِ عُبَيْدِ اللَّهِ الطَّنَافِسِيُّ حَدَّثَنَا زُهَيْرٌ أَبُو خَيْثَمَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ خَاتَمُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ فَصُّهُ مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] berkata, telah menceritakan kepada kami [Hafsh bin Umar bin Ubaidullah Ath Thanafisi] berkata, telah menceritakan kepada kami [Zuhair Abu Khaitsamah] dari [Humaid] dari [Anas] ia berkata, \"Cincin Rasulullah shallallahu 'alaihi wasallam terbuat dari perak, demikian juga dengan mata cincinnya.\" Abu Isa berkata, \"hadits ini derajatnya hasan shahih gharib melalui jalur ini.\""},"1663":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْمُحَارِبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ خَاتَمًا مِنْ ذَهَبٍ فَتَخَتَّمَ بِهِ فِي يَمِينِهِ ثُمَّ جَلَسَ عَلَى الْمِنْبَرِ فَقَالَ إِنِّي كُنْتُ اتَّخَذْتُ هَذَا الْخَاتَمَ فِي يَمِينِي ثُمَّ نَبَذَهُ وَنَبَذَ النَّاسُ خَوَاتِيمَهُمْقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَجَابِرٍ وَعَبْدِ اللَّهِ بْنِ جَعْفَرٍ وَابْنِ عَبَّاسٍ وَعَائِشَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ نَحْوَ هَذَا مِنْ غَيْرِ هَذَا الْوَجْهِ وَلَمْ يَذْكُرْ فِيهِ أَنَّهُ تَخَتَّمَ فِي يَمِينِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid Al Muharibi] berkata, telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam membuat cincin dari emas lalu memakainya di jari tangan kanan. Setelah itu beliau duduk di atas mimbar dan bersabda: \"Sesungguhnya Aku telah mengenakan cincin ini di jari tangan kananku.\" Kemudian beliau membuang cincinnya, lantas orang-orang ikut membuang cincin mereka.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Ali, Jabir, Abdullah bin Ja'far, Ibnu Abbas, 'Aisyah dan Anas.\" Abu Isa berkata, \"Hadits Ibnu Umar ini derajatnya hasan shahih. Telah diriwayatkan pula dari Nafi' dari Ibnu Umar dari jalur lain seperti hadits tersebut. Namun dia tidak menyebutkan bahwa Rasulullah mengenakan cincin pada jari tangan kanannya.\" "},"1664":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا جَرِيرٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الصَّلْتِ بْنِ عَبْدِ اللَّهِ بْنِ نَوْفَلٍ قَالَرَأَيْتُ ابْنَ عَبَّاسٍ يَتَخَتَّمُ فِي يَمِينِهِ وَلَا إِخَالُهُ إِلَّا قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَتَّمُ فِي يَمِينِهِقَالَ أَبُو عِيسَى قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدِيثُ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الصَّلْتِ بْنِ عَبْدِ اللَّهِ بْنِ نَوْفَلٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] berkata, telah menceritakan kepada kami [Jarir] dari [Muhammad bin Ishaq] dari [Ash Shult bin Abdullah bin Naufal] ia berkata, \"Aku melihat [Ibnu Abbas] mengenakan cincin pada jari tangan kanannya, dan aku tidak mempunyai perkiraan lainnya kecuali ia mengatakan, 'Aku melihat Rasulullah shallallahu 'alaihi wasallam memakai cincin pada jari tangan kanannya.\" Abu Isa berkata, \"Muhammad bin Isma'il berkata, \"Hadits Muhammad bin Ishaq, dari Ash Shalt bin Abdullah bin Naufal derajatnya hasan shahih.\""},"1665":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ قَالَكَانَ الْحَسَنُ وَالْحُسَيْنُ يَتَخَتَّمَانِ فِي يَسَارِهِمَاهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Hatim bin Isma'il] dari [Ja'far bin Muhammad] dari [Bapaknya] ia berkata, \"? [Hasan] dan [Husain] biasa memakai cincin pada tangan kirinya.\" Ini adalah hadits hasan shahih.\""},"1666":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ حَمَّادِ بْنِ سَلَمَةَ قَالَ رَأَيْتُ ابْنَ أَبِي رَافِعٍ يَتَخَتَّمُ فِي يَمِينِهِ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ رَأَيْتُ عَبْدَ اللَّهِ بْنَ جَعْفَرٍ يَتَخَتَّمُ فِي يَمِينِهِ وَقَالَ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَتَّمُ فِي يَمِينِهِقَالَ و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ هَذَا أَصَحُّ شَيْءٍ رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذَا الْبَابِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Yazid bin Harun] dari [Hammad bin Salamah] ia berkata, \"Aku melihat [Ibnu Abu Rafi'] memakai cincin pada jari tangan kanannya, maka hal itu aku tanyakan kepadanya. Ia menjawab, \"Aku melihat [Abdullah bin Ja'far] memakai cincin pada jari tangan kanannya.\" Abdullah bin Ja'far berkata, \"Nabi shallallahu 'alaihi wasallam biasa memakai cincin pada jari tangan kanannya.\" Ia (Abu Isa) berkata, \"Muhammad bin Isma'il berkata, \"Ini adalah hadits yang paling shahih dari apa yang pernah diriwayatkan dari Nabi shallallahu 'alaihi wasallam dalam bab ini.\""},"1667":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَنَعَ خَاتَمًا مِنْ وَرِقٍ فَنَقَشَ فِيهِ مُحَمَّدٌ رَسُولُ اللَّهِ ثُمَّ قَالَ لَا تَنْقُشُوا عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ حَسَنٌ وَمَعْنَى قَوْلِهِ لَا تَنْقُشُوا عَلَيْهِ نَهَى أَنْ يَنْقُشَ أَحَدٌ عَلَى خَاتَمِهِ مُحَمَّدٌ رَسُولُ اللَّهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Tsabit] dari [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam membuat cincin dari perak, lalu pada cincin tersebut beliau buat ukiran 'Muhammad Rasulullah'. Setelah itu beliau bersabda: \"Janganlah kalian membuat ukiran pada cincin.\" Abu Isa berkata, \"Hadits ini derajatnya shahih hasan. Sedangkan makna sabda Beliau 'Janganlah kalian membuat ukiran pada cincin', yaitu beliau melarang seseorang membuat ukiran pada cincinnya dengan tulisan 'Muhammad Rasulullah'.\""},"1668":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ وَالْحَجَّاجُ بْنُ مِنْهَالٍ قَالَا حَدَّثَنَا هَمَّامٌ عَنْ ابْنِ جُرَيْجٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْخَلَاءَ نَزَعَ خَاتَمَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Sa'id bin Amir] dan [Al Hajjaj bin Minhal] keduanya berkata; telah menceritakan kepada kami [Hammam] dari [Ibnu Juraij] dari [Az Zuhri] dari [Anas] beliau bersabda: \"Jika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam WC, beliau melepas cincinnya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib.\""},"1669":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنَا أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ نَقْشُ خَاتَمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحَمَّدٌ سَطْرٌ وَرَسُولُ سَطْرٌ وَاللَّهِ سَطْرٌقَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya] berkata, telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] berkata, telah menceritakan kepada kami [Bapakku] dari [Tsumamah] dari [Anas bin Malik] ia berkata, \"Ukiran pada cincin Nabi shallallahu 'alaihi wasallam 'Muhammad' dalam satu baris; 'Rasul' dalam satu baris; dan 'Allah' dalam satu baris.\" Abu Isa berkata, \"Hadits Anas ini derajatnya hasan shahih gharib.\""},"1670":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ يَحْيَى وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ حَدَّثَنِي أَبِي عَنْ ثُمَامَةَ عَنْ أَنَسٍ قَالَكَانَ نَقْشُ خَاتَمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَسْطُرٍ مُحَمَّدٌ سَطْرٌ وَرَسُولُ سَطْرٌ وَاللَّهِ سَطْرٌ وَلَمْ يَذْكُرْ مُحَمَّدُ بْنُ يَحْيَى فِي حَدِيثِهِ ثَلَاثَةَ أَسْطُرٍ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Muhammad bin Yahya] dan tidak hanya seorang saja, mereka berkata; telah menceritakan kepada kami [Muhammad bin Abdullah Al Anshari] berkata, telah menceritakan kepadaku [Bapakku] dari [Tsumamah] dari [Anas] ia berkata, \"Ukiran cincin Nabi shallallahu 'alaihi wasallam ada tiga baris; Muhammad dalam satu baris; Rasul dalam satu baris dan Allah dalam satu baris.\" Muhammad bin Yahya tidak menyebutkan dalam haditsnya 'tiga baris'. Dalam bab ini juga ada hadits dari Ibnu Umar.\""},"1671":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصُّورَةِ فِي الْبَيْتِ وَنَهَى أَنْ يُصْنَعَ ذَلِكَقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي طَلْحَةَ وَعَائِشَةَ وَأَبِي هُرَيْرَةَ وَأَبِي أَيُّوبَ قَالَ أَبُو عِيسَى حَدِيثُ جَابِرٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Rauh bin Ubadah] berkata, telah menceritakan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang gambar yang ada dalam rumah, beliau juga melarang membuat lukisannya.\" Perawi berkata; \"dan dalam bab yang sama ada riwayat dari Ali, Abu Thalhah, 'Aisyah, Abu Hurairah dan Abu Ayyub.\" Abu Isa berkata, \"Hadits Jabir ini derajatnya hasan shahih.\""},"1672":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَأَنَّهُ دَخَلَ عَلَى أَبِي طَلْحَةَ الْأَنْصَارِيِّ يَعُودُهُ قَالَ فَوَجَدْتُ عِنْدَهُ سَهْلَ بْنَ حُنَيْفٍ قَالَ فَدَعَا أَبُو طَلْحَةَ إِنْسَانًا يَنْزِعُ نَمَطًا تَحْتَهُ فَقَالَ لَهُ سَهْلٌ لِمَ تَنْزِعُهُ فَقَالَ لِأَنَّ فِيهِ تَصَاوِيرَ وَقَدْ قَالَ فِيهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدْ عَلِمْتَ قَالَ سَهْلٌ أَوَلَمْ يَقُلْ إِلَّا مَا كَانَ رَقْمًا فِي ثَوْبٍ فَقَالَ بَلَى وَلَكِنَّهُ أَطْيَبُ لِنَفْسِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik] dari [Abu An Nadhr] dari [Ubaidullah bin Abdullah bin Utbah] Bahwasanya ia pernah menjenguk [Abu Thalhah Al Anshari]. Ubaidullah berkata, \"Aku melihat Sahl bin Huanif berada di sisinya.\" Ubaidullah melanjutkan, \"Abu Thalhah lantas memanggil seseorang agar mengambil permadani yang ada di bawahnya. [Sahl] lalu bertanya, \"Kenapa harus diambil?\" Abu Thalhah menjawab, \"Sebab di dalamnya terdapat gambar. Dan Nabi shallallahu 'alaihi wasallam juga telah bersabda mengenai hal itu sebagaimana yang engkau ketahui.\" Sahl bertanya lagi, \"Bukankah Nabi mengatakan 'kecuali ukiran yang ada pada kain? ' Thalhah menjawab, \"Benar, tetapi hal itu menjadikan hatiku lebih nyaman.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1673":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَوَّرَ صُورَةً عَذَّبَهُ اللَّهُ حَتَّى يَنْفُخَ فِيهَا يَعْنِي الرُّوحَ وَلَيْسَ بِنَافِخٍ فِيهَا وَمَنْ اسْتَمَعَ إِلَى حَدِيثِ قَوْمٍ وَهُمْ يَفِرُّونَ بِهِ مِنْهُ صُبَّ فِي أُذُنِهِ الْآنُكُ يَوْمَ الْقِيَامَةِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ وَأَبِي جُحَيْفَةَ وَعَائِشَةَ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membuat lukisan, maka Allah akan menyiksanya hingga ia meniupkan -yakni ruh-, padahal ia tidak akan mampu. Dan siapa yang mencuri dengar pembicaraan suatu kaum padahal mereka telah berusaha menghindar untuk merahasiakannya, maka pada hari kiamat akan dituangkan cairan timah ke dalam telinganya.\" Perawi berkata, \"Dalam bab ini juga ada hadits dari Abdullah bin Mas'ud, Abu Hurairah, Abu Juhaifah, 'Aisyah dan Ibnu Umar.\" Abu Isa berkata, \"Hadits Ibnu Abbas ini derajatnya hasan shahih.\""},"1674":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيِّرُوا الشَّيْبَ وَلَا تَشَبَّهُوا بِالْيَهُودِقَالَ وَفِي الْبَاب عَنْ الزُّبَيْرِ وَابْنِ عَبَّاسٍ وَجَابِرٍ وَأَبِي ذَرٍّ وَأَنَسٍ وَأَبِي رِمْثَةَ وَالْجَهْدَمَةِ وَأَبِي الطُّفَيْلِ وَجَابِرِ بْنِ سَمُرَةَ وَأَبِي جُحَيْفَةَ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Umar bin Abu Salamah] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ubahlah warna bulu uban kalian dan jangan menyerupai orang-orang yahudi.\" Perawi berkata, \"Dalam bab ini juga ada hadits dari Az Zubair, Ibnu Abbas, Abu Dzar, Anas, Abu Rimtsah, Al Jahdamah, Abu Thufail, Jabir bin Samurah, Abu Juhaifah dan Ibnu Umar.\" Abu Isa berkata, \"Hadits Abu Hurairah ini derajatnya hasan shahih. Hadits ini juga diriwayatkan dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1675":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ الْأَجْلَحِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِي الْأَسْوَدِ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحْسَنَ مَا غُيِّرَ بِهِ الشَّيْبُ الْحِنَّاءُ وَالْكَتَمُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو الْأَسْوَدِ الدِّيلِيُّ اسْمُهُ ظَالِمُ بْنُ عَمْرِو بْنِ سُفْيَانَ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] berkata, telah mengabarkan kepada kami [Ibnul Mubarak] dari [Al Ajlah] dari [Abdullah bin Buraidah] dari [Abul Aswad] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesuatu yang paling baik untuk mengubah warna bulu uban adalah Al Hina (inai) dan Al katam (sejenis tumbuhan yang gelap warnanya).\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Abul Aswad Ad Dili nama aslinya adalah Zhalim bin Amru bin Sufyan.\""},"1676":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَبْعَةً لَيْسَ بِالطَّوِيلِ وَلَا بِالْقَصِيرِ حَسَنَ الْجِسْمِ أَسْمَرَ اللَّوْنِ وَكَانَ شَعْرُهُ لَيْسَ بِجَعْدٍ وَلَا سَبْطٍ إِذَا مَشَى يَتَوَكَّأُقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَالْبَرَاءِ وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ وَجَابِرٍ وَوَائِلِ بْنِ حُجْرٍ وَأُمِّ هَانِئٍ قَالَ أَبُو عِيسَى حَدِيثُ أَنَسٍ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ حُمَيْدٍ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah] berkata, telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Humaid] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam adalah seorang laki-laki yang sedang, tidak tinggi dan tidak pendek, postur tubuhnya bagus dan berkulit cokelat. Rambut beliau tidak keriting dan tidak lurus, jika berjalan tegap.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari 'Aisyah, Al Bara, Abu Hurairah, Ibnu Abbas, Abu Sa'id, Jabir, Wail bin Hujr dan Ummu Hani.\" Abu Isa berkata, \"Hadits Anas dari Humaid derajatnya hasan shahih gharib melalui jalur ini.\""},"1677":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ وَكَانَ لَهُ شَعْرٌ فَوْقَ الْجُمَّةِ وَدُونَ الْوَفْرَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ عَائِشَةَ أَنَّهَا قَالَتْ كُنْتُ أَغْتَسِلُ أَنَا وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ وَلَمْ يَذْكُرُوا فِيهِ هَذَا الْحَرْفَ وَكَانَ لَهُ شَعْرٌ فَوْقَ الْجُمَّةِ وَدُونَ الْوَفْرَةِ وَعَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ ثِقَةٌ كَانَ مَالِكُ بْنُ أَنَسٍ يُوَثِّقُهُ وَيَأْمُرُ بِالْكِتَابَةِ عَنْهُ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abu Az Zinad] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Aku dan Rasulullah shallallahu 'alaihi wasallam mandi bersama dalam satu bejana. Rambut beliau antara ujung daun telinga hingga kedua bahu.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih gharib melalui jalur ini. diriwayatkan pula dari 'Aisyah dengan jalur lain, ia berkata, \"Aku dan Rasulullah shallallahu 'alaihi wasallam mandi bersama dalam satu bejana…namun para perawi tidak menyebutkan 'rambut beliau antara ujung daun telinga hingga kedua bahu'.\" 'Abdurrahman bin Abu Az Zinad seorang yang tsiqah, Malik bin Anas menyatakan bahwa 'Abdurrahman seorang yang tsiqah, dan memerintahkan untuk menulis (hadits) darinya.\""},"1678":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامٍ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّرَجُّلِ إِلَّا غِبًّاحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ عَنْ الْحَسَنِ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Ali bin Khasyram] berkata, telah mengabarkan kepada kami [Isa bin Yunus] dari [Hisyam] dari [Al Hasan] dari [Abdullah bin Mughaffal] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menyisir dan merapikan rambut kecuali sesekali.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] dari [Al Hasan] dengan sanad ini, seperti hadits tersebut.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\" Ia berkata, \"Dalam bab ini juga ada hadits dari Anas.\""},"1679":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَبُو دَاوُدَ هُوَ الطَّيَالِسِيُّ عَنْ عَبَّادِ بْنِ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اكْتَحِلُوا بِالْإِثْمِدِ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعْرَ وَزَعَمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَتْ لَهُ مُكْحُلَةٌ يَكْتَحِلُ بِهَا كُلَّ لَيْلَةٍ ثَلَاثَةً فِي هَذِهِ وَثَلَاثَةً فِي هَذِهِقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عَبَّاسٍ حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ عَلَى هَذَا اللَّفْظِ إِلَّا مِنْ حَدِيثِ عَبَّادِ بْنِ مَنْصُورٍ حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ وَمُحَمَّدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ عَبَّادِ بْنِ مَنْصُورٍ نَحْوَهُ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَيْكُمْ بِالْإِثْمِدِ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعْرَ","id":"Telah menceritakan kepada kami [Muhammd bin Humaid] berkata, telah menceritakan kepada kami [Abu Dawud] -yaitu Ath Thayalisi- dari [Abbad bin Manshur] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian bercelak dengan Al Itsmid (jenis celak terbaik), sebab ia akan menguatkan pandangan dan menumbuhkan bulu.\" Ibnu Abbas berkeyakinan bahwa Nabi shallallahu 'alaihi wasallam mempunyai celak yang selalu beliau gunakan setiap malam (menjelang tidur); tiga kali di sebelah dan tiga kali di sebelah lain.\" Perawi berkata, \"Dalam bab ini juga ada hadits dari Jabir dan Ibnu Umar.\" Abu Isa berkata, \"Hadits Ibnu Abbas ini derajatnya hasan gharib, kami tidak mengenalnya dengan lafadz seperti ini kecuali dari hadits Abbad bin Manshur.\" Telah menceritakan kepada kami [Ali bin Hujr] dan [Muhammad bin Yahya] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] dari [Abbad bin Manshur] seperti hadits tersebut. Diriwayatkan pula dengan jalur lain, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Hendaklah kalian menggunakan Al Itsmid, sebab ia membuat pandangan kuat dan menumbuhkan bulu.\""},"1680":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ الْإِسْكَنْدَرَانِيُّ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لِبْسَتَيْنِ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ بِثَوْبِهِ لَيْسَ عَلَى فَرْجِهِ مِنْهُ شَيْءٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَلِيٍّ وَابْنِ عُمَرَ وَعَائِشَةَ وَأَبِي سَعِيدٍ وَجَابِرٍ وَأَبِي أُمَامَةَ وَحَدِيثُ أَبِي هُرَيْرَةَ حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman Al Iskandarani] dari [Suhail bin Abu Shalih] dari [Bapaknya] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam melarang dua cara berpakaian; Ash Shama (membungkus seluruh tuhuh hingga tidak ada yang terlihat) dan seorang laki-laki berihtiba (duduk di atas bokong dengan mendekap kedua kakinya menempel dada) dengan dua kain, lalu tidak ada sesuatu yang menutupi kemaluannya.\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Ali, Ibnu Umar, 'Aisyah, Abu Said, Jabir dan Abu Umamah. hadits Abu Hurairah derajatnya hasan shahih gharib melalui jalur ini. Hadits ini juga telah diriwayatkan dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam dengan banyak jalur.\""},"1681":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْوَاصِلَةَ وَالْمُسْتَوْصِلَةَ وَالْوَاشِمَةَ وَالْمُسْتَوْشِمَةَقَالَ نَافِعٌ الْوَشْمُ فِي اللِّثَةِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَابْنِ مَسْعُودٍ وَأَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَابْنِ عَبَّاسٍ وَمَعْقِلِ بْنِ يَسَارٍ وَمُعَاوِيَةَ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] berkata, telah mengabarkan kepada kami [Abdullah Ibnul Mubarak] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Allah melaknat wanita yang menggelung rambut dan wanita yang minta untuk digelung rambutnya, wanita yang mentato dan wanita yang minta untuk ditato.\" Nafi' menyebutkan, \"Tato di gusi.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Ia berkata, \"Dalam bab ini juga ada hadits dari 'Aisyah, Ibnu Mas'ud, Asma binti Abu Bakar, Ibnu Abbas, Ma'qil bin Yasar dan Mu'awiyah.\""},"1682":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا أَبُو إِسْحَقَ الشَّيْبَانِيُّ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ مُعَاوِيَةَ بْنِ سُوَيْدِ بْنِ مُقَرِّنٍ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رُكُوبِ الْمَيَاثِرِقَالَ وَفِي الْحَدِيثِ قِصَّةٌ قَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَمُعَاوِيَةَ وَحَدِيثُ الْبَرَاءِ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى شُعْبَةُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ نَحْوَهُ وَفِي الْحَدِيثِ قِصَّةٌ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Ali bin Mushir] berkata, telah menceritakan kepada kami [Abu Ishaq Asy Syaibani] dari [Asy'ats bin Abu Asy Sya'tsa] dari [Mu'awiyah bin Suwaid bin Muqarrin] dari [Al Bara bin Azib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kami menggunakan pelana yang terbuat dari kain bersulam emas.\" Perawi berkata, \"Dalam hadits ini terdapat kisah. Ia berkata, \"Dalam bab ini juga ada hadits dari Ali dan Mu'awiyah. Hadits Al Bara derajatnya hasan shahih. [Syu'bah] juga telah meriwayatkan dari [Asy'ats bin Abu Asy Sya'tsa] seperti hadits tersebut. Dan dalam hadits tersebut juga terdapat kisah.\""},"1683":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْإِنَّمَا كَانَ فِرَاشُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِي يَنَامُ عَلَيْهِ أَدَمٌ حَشْوُهُ لِيفٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ حَفْصَةَ وَجَابِرٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Ali bin Mushir] dari [Hisyam bin Urwah] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Kasur yang digunakan tidur oleh Nabi shallallahu 'alaihi wasallam terbuat dari kulit dan isinya dari serabut.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Dalam bab ini juga ada hadits dari Hafshah dan Jabir.\""},"1684":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ الرَّازِيُّ حَدَّثَنَا أَبُو تُمَيْلَةَ وَالْفَضْلُ بْنُ مُوسَى وَزَيْدُ بْنُ حُبَابٍ عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ أَحَبَّ الثِّيَابِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَمِيصُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ تَفَرَّدَ بِهِ وَهُوَ مَرْوَزِيٌّ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ أَبِي تُمَيْلَةَ عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Humaid Ar Razi] berkata, telah menceritakan kepada kami [Abu Tumailah] dan [Al Fadhl bin Musa] dan [Zaid bin Hubab] dari [Abdul Mukmin bin Khalid] dari [Abdullah bin Buraidah] dari [Ummu Salamah] ia berkata, \"Pakaian yang paling disukai oleh Nabi shallallahu 'alaihi wasallam adalah gamis.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami mengetahuinya dari hadits Abdul Mukmin bin Khalid dengan periwayatan tunggal, dan dia adalah seorang Marwazi. Sebagian mereka juga meriwayatkan hadits ini dari [Abu Tumailah], dari [Abdul Mukmin bin Khalid], dari [Abdullah bin Buraidah], dari [ibunya], dari [Ummu Salamah].\""},"1685":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ الْبَغْدَادِيُّ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ أَحَبَّ الثِّيَابِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَمِيصُقَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ حَدِيثُ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أُمِّهِ عَنْ أُمِّ سَلَمَةَ أَصَحُّ وَإِنَّمَا يُذْكَرُ فِيهِ أَبُو تُمَيْلَةَ عَنْ أُمِّهِ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub Al Baghdadi] berkata, telah menceritakan kepada kami [Abu Tumailah] dari [Abdul Mukmin bin Khalid] dari [Abdullah bin Buraidah] dari [Ibunya] dari [Ummu Salamah] ia berkata, \"Pakaian yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam adalah gamis.\" Abu Isa berkata, \"Aku mendengar Muhammad bin Isma'il berkata, \"Hadits Abdullah bin buraidah, dari ibunya, dari Ummu Salamah lebih shahih, hanya saja dalam hadits tersebut disebutkan 'dari Abu Tumailah, dari ibunya'.\""},"1686":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ أَحَبَّ الثِّيَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَمِيصُ","id":"Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah mengabarkan kepada kami [Al Fadhl bin Musa] dari [Abdul Mukmin bin Khalid] dari [Abdullah bin Buraidah] dari [Ummu Salamah] ia berkata, \"Pakaian yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam adalah gamis.\""},"1687":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ الْحَجَّاجِ الصَّوَّافُ الْبَصْرِيُّ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ الدَّسْتُوَائِيُّ حَدَّثَنِي أَبِي عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ الْعُقَيْلِيِّ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ الْأَنْصَارِي��َةِ قَالَتْكَانَ كُمُّ يَدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الرُّسْغِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Al Hajjaj Ash Shawwaf Al Bashri] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam Ad Dastuwa`i] berkata, telah menceritakan kepadaku [Bapakku] dari [Budail bin Maisarah Al Uqaili] dari [Syahr bin Hausyab] dari [Asma binti Yazid bin As Sakan Al Anshariyah] ia berkata, \"Lengan tangan baju Rasulullah shallallahu 'alaihi wasallam hingga pergelangan tangan.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib.\""},"1688":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَبِسَ قَمِيصًا بَدَأَ بِمَيَامِنِهِقَالَ أَبُو عِيسَى وَرَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ عَنْ أَبِي هُرَيْرَةَ مَوْقُوفًا وَلَا نَعْلَمُ أَحَدًا رَفَعَهُ غَيْرَ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ عَنْ شُعْبَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdhami] berkata, telah menceritakan kepada kami [Abdu Ash Shamad bin Abdul Warits] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengenakan baju, beliau selalu memulai dari yang kanan.\" Abu Isa berkata, \"Tidak hanya seorang yang telah meriwayatkan hadits ini dari Syu'bah -dengan sanad ini- dari Abu Hurairah secara mauquf. Dan kami tidak mengetahui seorang pun yang memarfu'kan hadits ini selain Abdu Ash Shamad bin Abdul Warits, dari Syu'bah.\""},"1689":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَجَدَّ ثَوْبًا سَمَّاهُ بِاسْمِهِ عِمَامَةً أَوْ قَمِيصًا أَوْ رِدَاءً ثُمَّ يَقُولُ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ كَسَوْتَنِيهِ أَسْأَلُكَ خَيْرَهُ وَخَيْرَ مَا صُنِعَ لَهُ وَأَعُوذُ بِكَ مِنْ شَرِّهِ وَشَرِّ مَا صُنِعَ لَهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُمَرَ وَابْنِ عُمَرَ حَدَّثَنَا هِشَامُ بْنُ يُونُسَ الْكُوفِيُّ حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ الْمُزَنِيُّ عَنْ الْجُرَيْرِيِّ نَحْوَهُ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr] berkata, telah mengabarkan kepada kami [Abdullah Ibnul Mubarak] dari [Sa'id Al Jurairi] dari [Abu Nadhrah] dari [Abu Sa'id] ia berkata, \"Jika Nabi shallallahu 'alaihi wasallam mengenakan pakaian baru beliau selalu menyebut namanya, baik itu imamah, gamis ataupun selendang. Setelah itu beliau bersabda: \"ALLAHUMMA LAKAL HAMDU ANTA KASAUTANIIHI AS`ALUKA KHAIRAHU WA KHAIRA MAA SHUNI'A LAHU WA A'UUDZU BIKA MIN SYARRIHI WA SYARRI MAA SHUNI'A LAHU (Ya Allah, segala puji hanya milik-Mu, Engkau telah mengenakan pakaian itu kepadaku. Maka aku meminta kebaikannya dan kebaikan apa yang dibuat untuknya. Dan aku berlindung kepadamu keburukannya dan keburukkan apa yang dibuat untuknya).\" Abu Isa berkata, \"Dalam bab ini juga ada hadits dari Umar dan Ibnu Umar. Telah menceritakan kepada kami [Hisyam bin Yunus Al Kufi] berkata, telah menceritakan kepada kami [Al Qasim bin Malik Al Muzani] dari [Al Jurairi] seperti hadits tersebut. Dan hadits ini derajatnya hasan gharib shahih.\""},"1690":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَبِسَ جُبَّةً رُومِيَّةً ضَيِّقَةَ الْكُمَّيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Yusuf bin Isa] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Asy Sya'bi] dari [Urwah Ibnul Mughirah bin Syu'bah] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam pernah mengenakan jubah dari Rum yang lubang lengannya sempit.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1691":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ الْحَسَنِ بْنِ عَيَّاشٍ عَنْ أَبِي إِسْحَقَ هُوَ الشَّيْبَانِيُّ عَنْ الشَّعْبِيِّ قَالَ قَالَ الْمُغِيرَةُ بْنُ شُعْبَةَأَهْدَى دِحْيَةُ الْكَلْبِيُّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُفَّيْنِ فَلَبِسَهُمَاقَالَ أَبُو عِيسَى و قَالَ إِسْرَائِيلُ عَنْ جَابِرٍ عَنْ عَامِرٍ وَجُبَّةً فَلَبِسَهُمَا حَتَّى تَخَرَّقَا لَا يَدْرِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذَكِيٌّ هُمَا أَمْ لَا وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو إِسْحَقَ اسْمُهُ سُلَيْمَانُ وَالْحَسَنُ بْنُ عَيَّاشٍ هُوَ أَخُو أَبِي بَكْرِ بْنِ عَيَّاشٍ","id":"Telah menceritakan kepada kami [Qutaibah] berkata, telah menceritakan kepada kami [Ibnu Abu Zaidah] dari [Al Hasan bin Ayyasy] dari [Abu Ishaq] -yaitu Asy Syaibani- dari [Asy Sya'biy] berkata; [Al Mughirah bin Syu'bah] berkata, \"Dihyah Al Kalbi memberi hadiah Rasulullah shallallahu 'alaihi wasallam sepasang sepatu, lalu beliau mengenakannya.\" Abu Isa berkata, \" [Isra'il] menyebutkan dari [Jabir], dari [Amir], '…dan jubah, lalu beliau mengenakannya hingga rusak, beliau tidak tahu apakah keduanya dari kulit binatang yang disembelih atau binatang yang telah mati'. Ini adalah hadits hasan gharib. Abu Ishaq nama aslinya Sulaiman, sementara Al Hasan bin Ayyasy adalah saudara Abu Bakr bin Ayyasy.\""},"1692":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمِ بْنِ الْبَرِيدِ وَأَبُو سَعْدٍ الصَّغَانِيُّ عَنْ أَبِي الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ عَنْ عَرْفَجَةَ بْنِ أَسْعَدَ قَالَأُصِيبَ أَنْفِي يَوْمَ الْكُلَابِ فِي الْجَاهِلِيَّةِ فَاتَّخَذْتُ أَنْفًا مِنْ وَرِقٍ فَأَنْتَنَ عَلَيَّ فَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتَّخِذَ أَنْفًا مِنْ ذَهَبٍحَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا الرَّبِيعُ بْنُ بَدْرٍ وَمُحَمَّدُ بْنُ يَزِيدَ الْوَاسِطِيُّ عَنْ أَبِي الْأَشْهَبِ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ وَقَدْ رَوَى سَلْمُ بْنُ زَرِيرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَ نَحْوَ حَدِيثِ أَبِي الْأَشْهَبِ وَقَدْ رَوَى غَيْرُ وَاحِدٍ مِنْ أَهْلِ الْعِلْمِ أَنَّهُمْ شَدُّوا أَسْنَانَهُمْ بِالذَّهَبِ وَفِي الْحَدِيثِ حُجَّةٌ لَهُمْ و قَالَ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ سَلْمُ بْنُ زَرِينٍ وَهُوَ وَهْمٌ وَزَرِيرٌ أَصَحُّ وَأَبُو سَعْدٍ الصَّغَانِيُّ اسْمُهُ مُحَمَّدُ بْنُ مُيَسِّرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Ali bin Hasyim bin Al Barid] dan [Abu Sa'd Ash Shaghani] dari [Abul Asy'hab] dari ['Abdurrahman bin Tharafah] dari [Arfajah bin As'ad] ia berkata, \"Saat terjadi perang Al Kulab pada masa Jahilliyah hidungku terluka, lalu aku mengganti hidungku dari perak, tetapi justru hidungku menjadi busuk. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan agar aku membuat hidung dari emas.\" Telah menceritakan kepada kami [Ali bin Hujr] berkata, telah menceritakan kepada kami [Ar Rabi' bin Badr] dan [Muhammad bin Yazid Al Wasithi] dari [Abul Asyhab] seperti hadits tersebut.\" Abu Isa berkata, \"Hadits ini derajatnya hasan gharib, kami hanya mengetahuinya dari hadits 'Abdurrahman bin Tharafah. [Salm bin Zarir] juga meriwayatkan dari ['Abdurrahman bin Tharafah] seperti hadits Abul Asyhab. Banyak di antara ulama' yang telah meriwayatkan bahwa mereka meperkokoh gigi mereka dengan emas. Mereka berhujah dengan hadits tersebut. 'Abdurrahman bin Mahdi berkata, \"nama Salm bin Razin masih meragukan, sementara (Salm bin) Razin lebih shahih. Abu Sa'd Ash Shaghani nama aslinya adalah Muhammad bin Muyassir.\""},"1693":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ وَمُحَمَّدُ بْنُ بِشْرٍ وَعَبْدُ اللَّهِ بْنُ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ أَنْ تُفْتَرَشَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ أَنَّهُ كَرِهَ جُلُودَ السِّبَاعِ قَالَ أَبُو عِيسَى وَلَا نَعْلَمُ أَحَدًا قَالَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ غَيْرَ سَعِيدِ بْنِ أَبِي عَرُوبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ الرِّشْكِ عَنْ أَبِي الْمَلِيحِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ جُلُودِ السِّبَاعِ وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Abu Kuraib] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dan [Muhammad bin Bisyr] dan [Abdullah bin Isma'il bin Abu Khalid] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Abul Malih] dari [Bapaknya] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarang berhampar dengan kulit binatang buas.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Abul Malih] dari [Bapaknya] bahwa Nabi shallallahu 'alaihi wasallam melarang penggunaan kulit binatang buas.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami Mu'adz bin Hisyam berkata, telah menceritakan kepadaku Bapakku dari [Qatadah] dari [Abul Malih] Bahwasanya beliau membenci penggunaan kulit binatang buas.\" Abu Isa berkata, \"Kami tidak mengetahui seorang pun yang menyebutkan dari Abu Malih, dari bapaknya selain Sa'id bin Abu Arubah. Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada kami [Syu'bah] dari [Yazid Ar Risyk] dari [Abul Malih] dari Nabi shallallahu 'alaihi wasallam, Bahwasanya beliau melarang penggunaan kulit binatang buas. Dan ini yang lebih shahih.\""},"1694":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍكَيْفَ كَانَ نَعْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُمَا قِبَالَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] ia berkata, \"Aku bertanya kepada [Anas], 'Sandal Rasulullah shallallahu 'alaihi wasallam itu seperti apa?\" ia menjawab, \"Sandalnya mempunyai dua tali.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih.\""},"1695":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ نَعْلَاهُ لَهُمَا قِبَالَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] berkata, telah mengabarkan kepada kami [Habban bin Hilal] berkata, telah menceritakan kepada kami [Hammam] berkata, telah menceritakan kepada kami [Qatadah] dari [Anas] berkata, \"Sandal Rasulullah shallallahu 'alaihi wasallam mempunyai dua tali.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih, dan dalam bab yang sama terdapat hadits dari Ibnu Abbas dan Abu Hurairah.\""},"1696":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ ح و حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْشِي أَحَدُكُمْ فِي نَعْلٍ وَاحِدَةٍ لِيُنْعِلْهُمَا جَمِيعًا أَوْ لِيُحْفِهِمَا جَمِيعًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Al Anshari] berkata, telah menceritakan kepada kami [Ma'n] berkata, telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian berjalan dengan satu sandal, namun hendaklah memakai semuanya atau melepas semuanya.\" Abu Isa berkata, \"Hadits ini derajatnya hasan shahih. Ia berkata, \"Dalam bab ini juga ada hadits dari Jabir.\""},"1697":{"ar":"حَدَّثَنَا أَزْهَرُ بْنُ مَرْوَانَ الْبَصْرِيُّ حَدَّثَنَا الْحَارِثُ بْنُ نَبْهَانَ عَنْ مَعْمَرٍ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْتَعِلَ الرَّجُلُ وَهُوَ قَائِمٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَرَوَى عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ هَذَا الْحَدِيثَ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ وَكِلَا الْحَدِيثَيْنِ لَا يَصِحُّ عِنْدَ أَهْلِ الْحَدِيثِ وَالْحَارِثُ بْنُ نَبْهَانَ لَيْسَ عِنْدَهُمْ بِالْحَافِظِ وَلَا نَعْرِفُ لِحَدِيثِ قَتَادَةَ عَنْ أَنَسٍ أَصْلًا","id":"Telah menceritakan kepada kami [Azhar bin Marwan Al Bashri] berkata, telah menceritakan kepada kami [Al Harits bin Nabhan] dari [Ma'mar] dari [Ammar bin Abu Ammar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seorang memakai sandal sambil berdiri.\" Abu Isa berkata, \"Hadits ini derajatnya gharib. Ubaidullah bin Amru Ar Raqqi juga meriwayatkan hadits ini dari Ma'mar, dari Qatadah, dari Anas. Tetapi kedua hadits ini menurut ahli hadits tidak shahih. Menurut mereka Al Harits bin Nabhan bukan seorang yang hafidz, dan kami juga tidak mengetahui hadits Qatadah dari Anas mempunyai sumber yang jelas.\""},"1698":{"ar":"حَدَّثَنَا أَبُو جَعْفَرٍ السِّمْنَانِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو الرَّقِّيُّ عَنْ مَعْمَرٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَنْتَعِلَ الرَّجُلُ وَهُوَ قَائِمٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ و قَالَ مُحَمَّدُ بْنُ إِسْمَعِيلَ وَلَا يَصِحُّ هَذَا الْحَدِيثُ وَلَا حَدِيثُ مَعْمَرٍ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Abu Ja'far As Simnani] berkata, telah menceritakan kepada kami [Sulaiman bin Ubaidullah Ar Raqqi] berkata, telah menceritakan kepada kami [Ubaidullah bin Umar Ar Raqqi] dari [Ma'mar] dari [Qatadah] dari [Anas] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seseorang memakai sandal sambil berdiri.\" Abu Isa berkata, \"Hadits ini derajatnya gharib. Muhammad bin Isma'il berkata, \"Hadits ini tidak shahih, hadits Ma'mar dari Ammar bin Abu Ammar, dari Abu Hurairah juga tidak shahih.\""},"1699":{"ar":"حَدَّثَنَا الْقَاسِمُ بْنُ دِينَارٍ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ السَّلُولِيُّ كُوفِيٌّ حَدَّثَنَا هُرَيْمُ بْنُ سُفْيَانَ الْبَجَلِيُّ الْكُوفِيُّ عَنْ لَيْثٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْرُبَّمَا مَشَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَعْلٍ وَاحِدَةٍ","id":"Telah menceritakan kepada kami [Al Qasim bin Dinar] berkata, telah menceritakan kepada kami [Ishaq bin Manshur As Saluli] -berasal dari Kufah- berkata, telah menceritakan kepada kami [Huraim bin Sufyan Al Bajali Al Kufi] dari [Laits] dari ['Abdurrahman Ibnul Qasim] dari [Bapaknya] dari ['Aisyah] ia berkata, \"Barangkali Nabi shallallahu 'alaihi wasallam berjalan dengan satu sandal.\""},"1700":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّهَا مَشَتْ بِنَعْلٍ وَاحِدَةٍ وَهَذَا أَصَحُّقَالَ أَبُو عِيسَى هَكَذَا رَوَاهُ سُفْيَانُ الثَّوْرِيُّ وَغَيْرُ وَاحِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ مَوْقُوفًا وَهَذَا أَصَحُّ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari ['Abdurrahman Ibnul Qasim] dari [Bapaknya] dari ['Aisyah] Bahwasanya ia berjalan dengan satu sandal.\" Dan ini lebih shahih.\" Abu Isa berkata, \"Seperti inilah [Sufyan Ats Tsauri] dan selainnya meriwayatkan hadits ini dari 'Abdurrahman Ibnul Qasim secara mauquf. Dan ini lebih shahih.\""},"1701":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا انْتَعَلَ أَحَدُكُمْ فَلْيَبْدَأْ بِالْيَمِينِ وَإِذَا نَزَعَ فَلْيَبْدَأْ بِالشِّمَالِ فَلْتَكُنْ الْيُمْنَى أَوَّلَهُمَا تُنْعَلُ وَآخِرَهُمَا تُنْزَعُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepadaku [Al Anshari], telah menceritakan kepadaku [Ma'n], telah menceritakan kepadaku [Malik] (dalam riwayat lain). Dan telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila sala h seorang dari kalian mengenakan sandal, hendaklah ia mendahulukan yang kanan. Dan jika ia ingin melepasnya, maka dahulukanlah yang kiri. Jadikanlah yang sebelah kanan adalah yang pertama saat memakai dan yang kiri pertama saat melepasnya.\" Abu Isa berkata, \"Ini adalah hadits hasan shahih.\""},"1702":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْوَرَّاقُ وَأَبُو يَحْيَى الْحِمَّانِيُّ قَالَا حَدَّثَنَا صَالِحُ بْنُ حَسَّانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَدْتِ اللُّحُوقَ بِي فَلْيَكْفِكِ مِنْ الدُّنْيَا كَزَادِ الرَّاكِبِ وَإِيَّاكِ وَمُجَالَسَةَ الْأَغْنِيَاءِ وَلَا تَسْتَخْلِقِي ثَوْبًا حَتَّى تُرَقِّعِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ صَالِحِ بْنِ حَسَّانَ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ صَالِحُ بْنُ حَسَّانَ مُنْكَرُ الْحَدِيثِ وَصَالِحُ بْنُ أَبِي حَسَّانَ الَّذِي رَوَى عَنْهُ ابْنُ أَبِي ذِئْبٍ ثِقَةٌ قَالَ أَبُو عِيسَى وَمَعْنَى قَوْلِهِ وَإِيَّاكِ وَمُجَالَسَةَ الْأَغْنِيَاءِ عَلَى نَحْوِ مَا رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ رَأَى مَنْ فُضِّلَ عَلَيْهِ فِي الْخَلْقِ وَالرِّزْقِ فَلْيَنْظُرْ إِلَى مَنْ هُوَ أَسْفَلَ مِنْهُ مِمَّنْ فُضِّلَ هُوَ عَلَيْهِ فَإِنَّهُ أَجْدَرُ أَنْ لَا يَزْدَرِيَ نِعْمَةَ اللَّهِ عَلَيْهِ وَيُرْوَى عَنْ عَوْنِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ صَحِبْتُ الْأَغْنِيَاءَ فَلَمْ أَرَ أَحَدًا أَكْبَرَ هَمًّا مِنِّي أَرَى دَابَّةً خَيْرًا مِنْ دَابَّتِي وَثَوْبًا خَيْرًا مِنْ ثَوْبِي وَصَحِبْتُ الْفُقَرَاءَ فَاسْتَرَحْتُ","id":"Telah menceritakan kepadaku [Yahya bin Musa], telah menceritakan kepadaku [Sa'id bin Muhammad Al Warraq] dan [Abu Yahya Al Himmani] keduanya berkata, Telah menceritakan kepadaku [Shalih bin Hassan] dari [Urwah] dari ['Aisyah] radliallahu 'anha berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Jika engkau ingin bersamaku (atau sederajat denganku) di surga, maka ambillah bekal dari dunia seperti bekalnya seorang musafir dan janganlah engkau bergaul dengan orang-orang kaya serta janganlah menganggap bajumu sudah lusuh (robek yaitu tidak layak pakai) sebelum engkau menambalnya.\" Abu Isa berkata; Ini merupakan hadits Gharib yang tidak kami ketahui kecuali dari haditnya Shalih bin Hassan. Dan aku mendengar Muhammad berkata, \"Shalih bin Hassan seorang munkarul hadits adapun Shalih bin Abi Hassan yang mana Ibnu Abi Dzuaib meriwayatkan darinya ialah seorang yang tsiqqah.\" Abu Isa berkata; Dan arti dari sabda Nabi shallallahu 'alaihi wasallam \"Dan janganlah kamu bergaul dengan orang-orang kaya\". Ialah sebagaimana dalam riwayatnya Abu Hurairah Rhadliyallahu 'Anhu dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Barang siapa yang melihat orang yang dilebihkan darinya dari segi rupa dan rezeki, maka hendaknya dia melihat orang yang lebih kurang darinya atas nikmat yang dilebihkan atasnya (baik dari segi rupa atau rezeki), karena hal itu akan mendorongnya untuk selalu mensyukuri nikmat Allah yang telah dikaruniakan kepadanya.\" Diriwayatkan dari 'Aun bin Abdullah berkata; \"Aku telah bergaul dengan orang-orang kaya, maka aku tidak melihat ada orang yang lebih memiliki kemauan dari pada aku, bersama mereka aku melihat ada onta yang lebih bagus dari ontaku dan aku melihat baju yang lebih bagus dari bajuku. Lantas aku bergaul dengan para faqir dan hatiku menjadi tenang.\""},"1703":{"ar":"حَدَّثَنِي ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍ قَالَتْقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَلَهُ أَرْبَعُ غَدَائِرَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ قَالَ مُحَمَّدٌ لَا أَعْرِفُ لِمُجَاهِدٍ سَمَاعًا مِنْ أُمِّ هَانِئٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ الْمَكِّيُّ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ أُمِّ هَانِئٍ قَالَتْ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ وَلَهُ أَرْبَعُ ضَفَائِرَ أَبُو نَجِيحٍ اسْمُهُ يَسَارٌ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَعَبْدُ اللَّهِ بْنُ أَبِي نَجِيحٍ مَكِّيٌّ","id":"Telah menceritakan kepadaku [Ibnu Abu Umar], telah menceritakan kepadaku [Sufyan bin Uyainah] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ummu Hani`] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam bersabda masuk Makkah dan beliau memiliki empat rambut yang dikepang.\" Abu Isa berkata; Ini merupakah hadits Gharib dan Muhammad berkata, \"Aku tidak mengetahui Mujahid memiliki sama' (pernah mendengar) dari Ummu Hani'.\" Telah menceritakan kepadaku [Muhammad bin Basysyar], telah menceritakan kepadaku [Abdurrahman bin Mahdi], telah menceritakan kepadaku [Ibrahim bin Nafi' Al Makki] dari [Abu Najih] dari [Mujahid] dari [Ummu Hani`] ia berkata; Rasulullah shallallahu 'alaihi wasallam datang ke Makkah, dan beliau memiliki empat rambut yang dikepang.\" Abu Najih adalah Yasar. Abu Isa berkata; Ini adalah hadits gharib. Sedangkan Abdullah bin Abu Najih adalah Makki."},"1704":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا مُحَمَّدُ بْنُ حُمْرَانَ عَنْ أَبِي سَعِيدٍ وَهُوَ عَبْدُ اللَّهِ بْنُ بُسْرٍ قَال سَمِعْتُ أَبَا كَبْشَةَ الْأَنْمَارِيَّ يَقُولُكَانَتْ كِمَامُ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُطْحًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُنْكَرٌ وَعَبْدُ اللَّهِ بْنُ بُسْرٍ بَصْرِيٌّ هُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ ضَعَّفَهُ يَحْيَى بْنُ سَعِيدٍ وَغَيْرُهُ وَبُطْحٌ يَعْنِي وَاسِعَةً","id":"Telah menceritakan kepadaku [Humaid bin Mas'adah], telah menceritakan kepadaku [Muhammad bin Humran] dari [Abu Sa'id] ia adalah Abdullah bin Busr. Ia berkata, saya mendengar [Abu Kabsyah Al Anmari] berkata; \"Kopiyah para sahabat Rasulullah shallallahu 'alaihi wasallam adalah luas (menutupi kepala).\" Abu Isa berkata; Ini adalah hadits Munkar. Abdullah binn Busr adalah seorang yang dla'if menurut para ahli hadits. Yahya bin Sa'id dan yang lainnya juga mendla'ifkannya. Dan Buthhun maknanya adalah waasi'ah (luas)."},"1705":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ مُسْلِمِ بْنِ نَذِيرٍ عَنْ حُذَيْفَةَ قَالَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَضَلَةِ سَاقِي أَوْ سَاقِهِ فَقَالَ هَذَا مَوْضِعُ الْإِزَارِ فَإِنْ أَبَيْتَ فَأَسْفَلَ فَإِنْ أَبَيْتَ فَلَا حَقَّ لِلْإِزَارِ فِي الْكَعْبَ��ْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ رَوَاهُ الثَّوْرِيُّ وَشُعْبَةُ عَنْ أَبِي إِسْحَقَ","id":"Telah menceritakan kepadaku [Qutaibah], telah menceritakan kepadaku [Abul Ahwash] dari [Abu Ishaq] dari [Muslim bin Nadzr] dari [Hudzaifah] Rhadhiyallaahu 'Anhu berkata; Rasulullah shallallaahu 'alaihi wa sallam memegang betisku dan bersabda: \"Ini adalah batas pakaian, jika engkau tidak mau (ingin menambah panjangnya) maka boleh dibawahnya sedikit, dan jika engkau tidak mau, maka tidak diperbolehkan pakaian melebihi mata kaki.\" Abu Isa berkata; \"Ini merupakan hadits hasan shahih, [Tsauri] dan [Syu'bah] meriwayatkannya dari [Abu Ishaq].\""},"1706":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ أَبِي الْحَسَنِ الْعَسْقَلَانِيِّ عَنْ أَبِي جَعْفَرِ بْنِ مُحَمَّدِ بْنِ رُكَانَةَ عَنْ أَبِيهِ أَنَّ رُكَانَةَ صَارَعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَرَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُكَانَةُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ فَرْقَ مَا بَيْنَنَا وَبَيْنَ الْمُشْرِكِينَ الْعَمَائِمُ عَلَى الْقَلَانِسِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَإِسْنَادُهُ لَيْسَ بِالْقَائِمِ وَلَا نَعْرِفُ أَبَا الْحَسَنِ الْعَسْقَلَانِيَّ وَلَا ابْنَ رُكَانَةَ","id":"Telah menceritakan kepadaku [Qutaibah], telah menceritakan kepadaku [Muhammad bin Rabi'ah] dari [Abu Hasan Al Asqalani] dari [Abu Ja'far bin Muhammad bin Rukanah] dari [bapaknya] bahwasanya; [Rukanah] pernah bergulat dengan Nabi shallallahu 'alaihi wasallam lalu Nabi shallallahu 'alaihi wasallam mengalahkannya. Rukanah berkata; Aku mendengar Rosulullah shallallaahu 'alaihi wa sallam bersabda: \"Perbedaan antara kami dan kaum musyrikin ialah Imamah di atas peci.\" Abu Isa berkakta; Ini merupakan hadits gharib dan sanadnya tidaklah kuat dan kami tidak mengetahui Abul Hasan Al 'Asqalani demikian pula Ibnu Rukanah."},"1707":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ وَأَبُو تُمَيْلَةَ يَحْيَى بْنُ وَاضِحٍ عَنْ عَبْدِ اللَّهِ بْنِ مُسْلِمٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ خَاتَمٌ مِنْ حَدِيدٍ فَقَالَ مَا لِي أَرَى عَلَيْكَ حِلْيَةَ أَهْلِ النَّارِ ثُمَّ جَاءَهُ وَعَلَيْهِ خَاتَمٌ مِنْ صُفْرٍ فَقَالَ مَا لِي أَجِدُ مِنْكَ رِيحَ الْأَصْنَامِ ثُمَّ أَتَاهُ وَعَلَيْهِ خَاتَمٌ مِنْ ذَهَبٍ فَقَالَ مَالِي أَرَى عَلَيْكَ حِلْيَةَ أَهْلِ الْجَنَّةِ قَالَ مِنْ أَيِّ شَيْءٍ أَتَّخِذُهُ قَالَ مِنْ وَرِقٍ وَلَا تُتِمَّهُ مِثْقَالًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَبْدُ اللَّهِ بْنُ مُسْلِمٍ يُكْنَى أَبَا طَيْبَةَ وَهُوَ مَرْوَزِيٌّ","id":"Telah menceritakan kepadaku [Muhammad bin Humaid], telah menceritakan kepadaku [Zaid bin Hubab] dan [Abu Tsumailah Yahya bin Wadlih] dari [Abdullah bin Muslim] dari [Abdullah bin Buraidah] dari [bapaknya], ia berkata; Seorang lelaki datang kepada Nabi shallallahu 'alaihi wasallam dengan memakai cincin dari besi, lantas Nabi shallallahu 'alaihi wasallam bersabda: \"Kenapa kamu memakai perhiasan penghuni neraka?\" kemudian laki-laki itu datang lagi dengan memakai cincin dari Shufr, maka beliau pun bersabda: \"Mengapa aku mendapatkan bau berhala darimu.?\" Lalu pada waktu yang lain, laki-laki itu datang dengan memakai cincin emas, maka beliau bersabda: \"Kenapa kamu memakai perhiasannya penduduk surga?\" kemudian laki-laki itu bertanya: \"Sebaiknya cincin apa yang harus kupakai?\" beliau menjawab: \"Pakailah cincin perak dan janganlah kamu menyempurnakannya hingga seberat mitsqal.\" Abu Isa berkata; Ini adalah hadits gharib. Di dalam bab tercantum; \"Dari Abdullah bin Amr dan Abdullah bin Muslim kuniyahnya adalah Abu Thaibah, yakni Marwazi.\""},"1708":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ ابْنِ أَبِي مُوسَى قَال سَمِعْتُ عَلِيًّا يَقُولُنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَسِّيِّ وَالْمِيثَرَةِ الْحَمْرَاءِ وَأَنْ أَلْبَسَ خَاتَمِي فِي هَذِهِ وَفِي هَذِهِ وَأَشَارَ إِلَى السَّبَّابَةِ وَالْوُسْطَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَابْنُ أَبِي مُوسَى هُوَ أَبُو بُرْدَةَ بْنُ أَبِي مُوسَى وَاسْمُهُ عَامِرُ بْنُ عَبْدِ اللَّهِ بْنِ قَيْسٍ","id":"Telah menceritakan kepadaku [Ibnu Abu Umar], telah menceritakan kepadaku [Sufyan] dari [Ashim bin Kulaib] dari [Ibnu Abu Musa] ia berkata; Saya mendengar [Ali] berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarangku untuk menggunakan Al Qassiy (pakaian yang bahannya bercampur dengan sutera) dan Al Mitsarah Al Hamra` (kasur merah yang terbuat dari kain sutera) serta mengenakan cincin pada jari telunjuk dan jari tengah.\" Abu Isa berkata; \"Ini adalah hadits hasan shahih. Ibnu Musa adalah Abu Burdah bin Abu Musa, namanya adalah Amir bin Abdullah bin Qais.\""},"1709":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ أَحَبَّ الثِّيَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْبَسُهَا الْحِبَرَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar], telah menceritakan kepadaku [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Anas] ia berkata; \"Pakaian yang paling disukai Rasulullah shallallahu 'alaihi wasallam adalah hibarah (pakaian yang berhiaskan katun).\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib."},"1710":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ يُونُسَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَمَا أَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خُوَانٍ وَلَا فِي سُكُرُّجَةٍ وَلَا خُبِزَ لَهُ مُرَقَّقٌ قَالَ فَقُلْتُ لِقَتَادَةَ فَعَلَامَ كَانُوا يَأْكُلُونَ قَالَ عَلَى هَذِهِ السُّفَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ قَالَ مُحَمَّدُ بْنُ بَشَّارٍ وَيُونُسُ هَذَا هُوَ يُونُسُ الْإِسْكَافُ وَقَدْ رَوَى عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar], telah menceritakan kepadaku [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Yunus] dari [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah makan di atas meja yang panjang, tidak pula dengan nampan yang besar. Dan beliau tidak pernah dibuatkan roti yang renyah.\" Maka aku pun bertanya kepada Qatadah, \"Lalu dengan alasan apa, sehingga mereka makan di atas meja ini?\" Abu Isa berkata; Ini adalah hadits hasan gharib. Muhammad bin Basysyar; Yunus di sini adalah Yunus Al Iskafi. Dan [Abdul Warits bin Sa'id] telah meriwayatkan dari [Sa'id bin Abu Arubah] dari [Qatadah], dari [Anas] dari Nabi shallallahu 'alaihi wasallam, dengan hadits semisalnya."},"1711":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ عَنْ هِشَامِ بْنِ زَيْدِ بْنِ أَنَسٍ قَال سَمِعْتُ أَنَسًا يَقُولُأَنْفَجْنَا أَرْنَبًا بِمَرِّ الظَّهْرَانِ فَسَعَى أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلْفَهَا فَأَدْرَكْتُهَا فَأَخَذْتُهَا فَأَتَيْتُ بِهَا أَبَا طَلْحَةَ فَذَبَحَهَا بِمَرْوَةٍ فَبَعَثَ مَعِي بِفَخِذِهَا أَوْ بِوَرِكِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَهُ قَالَ قُلْتُ أَكَلَهُ قَالَ قَبِلَهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ جَابِرٍ وَعَمَّارٍ وَمُحَمَّدِ بْنِ صَفْوَانَ وَيُقَالُ مُحَمَّدُ بْنُ صَيْفِيٍّ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْعَمَلُ عَلَى هَذَا عِنْدَ أَكْثَرِ أَهْلِ الْعِلْمِ لَا يَرَوْنَ بِأَكْلِ الْأَرْنَبِ بَأْسًا وَقَدْ كَرِهَ بَعْضُ أَهْلِ الْعِلْمِ أَكْلَ الْأَرْنَبِ وَقَالُوا إِنَّهَا تَدْمَى","id":"Telah menceritakan kepadaku [Mahmud bin Ghailan], telah menceritakan kepadaku [Abu Dawud], telah mengabarkan kepada kami [Syu'bah] dari [Hisyam bin Zaid bin Anas] ia berkata, saya mendengar [Anas] berkata; \"Kami menemukan kelinci di Marru Azh Zhahran, maka para sahabat Nabi shallallahu 'alaihi wasallam berjalan di belakangnya. Kemudian aku pun melihatnya dan menangkapnya lalu membawanya ke hadapan Abu Thalhah, maka Abu Thalhah menyembelihnya di Marwa. Kemudian ia mengutusku untuk mengirimkan pahanya atau pangkal pahanya kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun memakannya.\" Abu Isa berkata; Di dalam bab ini tercantum; Dari Jabir dan Muhammad bin Shafwan dan biasanya ia dipanggil Muhammad bin Shaifi, dan ini adalah hadits Hasan Shahih. Dan menurut kebanyakan Ahlul Ilmi, memakan daging kelinci tidaklah mengapa, namun sebagian dari mereka membencinya dan mereka berkata, \"Sesungguhnya kelinci itu mengeluarkan darah.\""},"1712":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ أَكْلِ الضَّبِّ فَقَالَ لَا آكُلُهُ وَلَا أُحَرِّمُهُقَالَ وَفِي الْبَاب عَنْ عُمَرَ وَأَبِي سَعِيدٍ وَابْنِ عَبَّاسٍ وَثَابِتِ بْنِ وَدِيعَةَ وَجَابِرٍ وَعَبْدِ الرَّحْمَنِ بْنِ حَسَنَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ اخْتَلَفَ أَهْلُ الْعِلْمِ فِي أَكْلِ الضَّبِّ فَرَخَّصَ فِيهِ بَعْضُ أَهْلِ الْعِلْمِ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَيْرِهِمْ وَكَرِهَهُ بَعْضُهُمْ وَيُرْوَى عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ أُكِلَ الضَّبُّ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّمَا تَرَكَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقَذُّرًا","id":"Telah menceritakan kepadaku [Qutaibah], telah menceritakan kepadaku [Malik bin Anas] dari [Abdullah bin Dinar] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai memakan daging biawak, maka beliau menjawab: \"Aku tidak memakannya dan tidak pula mengharamkannya.\" Dan di dalam bab tercantum; Dari Umar dan Abu Sa'id dan Ibnu Abbas dan Tsabit bin Wadi'ah dan Jabir bin Abdurrahman bin Hasanah. Abu Isa berkata; Ini adalah hadits Hasan Shahih. Para Ahlul Ilmi berselisih pendapat mengenai makan daging biawak. Sebagian ulama dari kalangan sahabat Nabi shallallahu 'alaihi wasallam memberikan keringanan, namun sebagian mereka membencinya. Dan telah diriwayatkan dari Ibnu Abbas, bahwa ia berkata, \"Daging biawak pernah dimakan di atas hidangan Rasulullah shallallahu 'alaihi wasallam. Dan beliau tidak memakannya hanya karena menganggapnya kotor.\""},"1713":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ابْنِ أَبِي عَمَّارٍ قَالَ قُلْتُ لِجَابِرٍالضَّبُعُ صَيْدٌ هِيَ قَالَ نَعَمْ قَالَ قُلْتُ آكُلُهَا قَالَ نَعَمْ قَالَ قُلْتُ لَهُ أَقَالَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ ذَهَبَ بَعْضُ أَهْلِ الْعِلْمِ إِلَى هَذَا وَلَمْ يَرَوْا بِأَكْلِ الضَّبُعِ بَأْسًا وَهُوَ قَوْلُ أَحْمَدَ وَإِسْحَقَ وَرُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثٌ فِي كَرَاهِيَةِ أَكْلِ الضَّبُعِ وَلَيْسَ إِسْنَادُهُ بِالْقَوِيِّ وَقَدْ كَرِهَ بَعْضُ أَهْلِ الْعِلْمِ أَكْلَ الضَّبُعِ وَهُوَ قَوْلُ ابْنِ الْمُبَارَكِ قَالَ يَحْيَى الْقَطَّانُ وَرَوَى جَرِيرُ بْنُ حَازِمٍ هَذَا الْحَدِيثَ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ جَابِرٍ عَنْ عُمَرَ قَوْلَهُ وَحَدِيثُ ابْنِ جُرَيْجٍ أَصَحُّ وَابْنُ أَبِي عَمَّارٍ هُوَ عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي عَمَّارٍ ��لْمَكِّيُّ","id":"Telah menceritakan kepadaku [Ahmad bin Mani'], telah menceritakan kepadaku [Isma'il bin Ibrahim] Telah mengabarkan kepada kami [Ibnu Juraij] dari [Abdullah bin Ubaid bin Umair] dari [Ibnu Abu Ammar] ia berkata; Aku pernah bertanya kepada [Jabir], \"Apakah biawak termasuk binatang buruan?\" Jabir menjawab, \"Ya.\" Aku bertanya lagi, \"Bolehkah aku memakannya?\" Jabir menjawab, \"Ya.\" Aku bertanya lagi, \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah mengatakannya?\" Jabir menjawab, \"Ya.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih dan sebagian Ahlul Ilmi berpendapat demikian. Menurut mereka, makan daging biawak tidaklah mengapa. Demikianlah pendapat Ahmad dan Ishaq. Dan telah diriwayatkan dari Nabi shallallahu 'alaihi wasallam suatu hadits mengenai makruhnya makan daging biawak, namun isnadnya tidaklah kuat. Sebagian ulama juga ada yang memakruhkan makan daging biawak, di antaranya adalah Ibnul Mubarak. Yahya Al Qaththan berkata; Jarir bin Hazim telah meriwayatkan hadits ini dari Abdullah bin Ubaid bin Umair dari Ibnu Abu Ammar dari Jabir dari Umar. Sedangkan hadits Ibnu Juraij adalah lebih Shahih. Ibnu Abu Ammar adalah Abdurrahman bin Abdullah bin Abu Ammar Al Makki."},"1714":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ عَبْدِ الْكَرِيمِ بْنِ أَبِي الْمُخَارِقِ أَبِي أُمَيَّةَ عَنْ حِبَّانَ بْنِ جَزْءٍ عَنْ أَخِيهِ خُزَيْمَةَ بْنِ جَزْءٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ الضَّبُعِ فَقَالَ أَوَ يَأْكُلُ الضَّبُعَ أَحَدٌ وَسَأَلْتُهُ عَنْ الذِّئْبِ فَقَالَ أَوَيَأْكُلُ الذِّئْبَ أَحَدٌ فِيهِ خَيْرٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِالْقَوِيِّ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ عَبْدِ الْكَرِيمِ أَبِي أُمَيَّةَ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْحَدِيثِ فِي إِسْمَعِيلَ وَعَبْدِ الْكَرِيمِ أَبِي أُمَيَّةَ وَهُوَ عَبْدُ الْكَرِيمِ بْنُ قَيْسِ بْنِ أَبِي الْمُخَارِقِ وَعَبْدُ الْكَرِيمِ بْنُ مَالِكٍ الْجَزَرِيُّ ثِقَةٌ","id":"Telah menceritakan kepadaku [Hannad], telah menceritakan kepadaku [Abu Mu'awiyah] dari [Isma'il bin Muslim] dari [Abdul Karim bin Abul Mukhariq Abu Mu'awiiyah] dari [Hibban bin Jaz`u] dari [saudaranya] Khuzaimah bin Jaz`u, ia berkata; Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang memakan daging biawak, maka beliau menjawab: \"Apakah ada seseorang yang makan daging biawak?\" kemudian aku tanyakan tentang makan daging serigala, maka beliau pun menjawab: \"Adakah kebaikan bagi seorang yang memakan daging serigala?\" Abu Isa berkata; Isnad hadits ini tidaklah kuat, kami tidak mengetahuinya kecuali dari haditsnya Isma'il bin Muslim dari Abdul Karim Abu Uamayyah. Dan sebagian Ahlul hadits telah memberikan komentara mengenai Isma'il dan Abdul Karim Abu Umayyah. Ia adalah Abdul Karim bin Qais bin Abu Al Mukhariq dan Abdul Karim bin Malik bin Malik Al Jazari adalah seorang yang tsiqqah."},"1715":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَنَصْرُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ قَالَأَطْعَمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لُحُومَ الْخَيْلِ وَنَهَانَا عَنْ لُحُومِ الْحُمُرِقَالَ وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ وَرَوَاهُ حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرٍ وَرِوَايَةُ ابْنِ عُيَيْنَةَ أَصَحُّ قَالَ و سَمِعْت مُحَمَّدًا يَقُولُ سُفْيَانُ بْنُ عُيَيْنَةَ أَحْفَظُ مِنْ حَمَّادِ بْنِ زَيْدٍ","id":"Telah menceritakan kepadaku [Qutaibah bin Sa'id] dan [Nashru bin Ali] keduanya berkata, Telah menceritakan kepadaku [Sufyan] dari [Amru bin Dinar] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam memberi kami makan daging kuda, namun beliau melarang kami untuk memakan daging himar (keledai). Di dalam bab terdapat; Dari Asma` binti Abu Bakar. Abu Isa berkata; Ini adalah hadits hasan shahih. Dan seperti inilah riwayatlan lain dari Amr bin Dinar, dari Habir. Dan [Hammad bin Yazid] dari [Amru bin Dinar] dari [Muhammad bin Ali] dari [Jabir] Sedangkan riwayat yang paling shahih adalah riwayatnya Ibnu Uyainah. Dan saya telah mendengar Muhammad berkata; \"Sufyan bin Uyainah adalah lebih kuat hafalannya daripada Hammad bin Zaid.\""},"1716":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ يَحْيَى بْنِ سَعِيدٍ الْأَنْصَارِيِّ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ وَالْحَسَنِ ابْنَىْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ أَبِيهِمَا عَنْ عَلِيٍّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُتْعَةِ النِّسَاءِ زَمَنَ خَيْبَرَ وَعَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِحَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ وَالْحَسَنِ هُمَا ابْنَا مُحَمَّدِ ابْنِ الْحَنَفِيَّةِ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدٍ يُكْنَى أَبَا هَاشِمٍ قَالَ الزُّهْرِيُّ وَكَانَ أَرْضَاهُمَا الْحَسَنُ بْنُ مُحَمَّدٍ فَذَكَرَ نَحْوَهُ و قَالَ غَيْرُ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ عُيَيْنَةَ وَكَانَ أَرْضَاهُمَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepadaku [Muhammad bin Basysyar], telah menceritakan kepadaku [Abdul Wahhab Ats Tsaqafi] dari [Yahya bin Sa'id Al Anshari] dari [Malik bin Anas] dari [Zuhri] (dalam riwayat lain). Dan telah menceritakan kepada kami [Ibnu Abu Umar] Telah menceritakan kepadaku [Sufyan bin Uyainah] dari [Zuhri] dari [Abdullah] dan [Al Hasan] keduanya adalah anak dari Muhammad bin Ali dari [bapak] keduanya, dari [Ali] ia berkata; \"Pada hari Khaibar, Rasulullah shallallahu 'alaihi wasallam melarang nikah mut'ah dan juga melarang memakan daging himar yang jinak.\" Telah menceritakan kepadaku [Sa'id bin Abdurrahman Al Makhzumi] Telah menceritakan kepadaku [Sufyan] dari [Az Zuhri] dari [Abdullah] dan [Al Hasan] keduanya adalah anak dari Muhammad bin Al Hanafiyah, dan Abdullah bin Muhamamd kuniahnya adalah Abu Hasyim. Az Zuhri berkata; \"Yang paling tsiqah di antara keduanya adalah Al Hasan bin Muhammad.\" Lalu ia pun ia menyebuatkan hadits semisalnya. Dan telah berkata selain Sa'id bin Abdurrahman, dari Ibnu Uyainah bahwa yang paling Tsiqah di antara keduanya adalah Abdullah bin Muhammad. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1717":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ يَوْمَ خَيْبَرَ كُلَّ ذِي نَابٍ مِنْ السِّبَاعِ وَالْمُجَثَّمَةَ وَالْحِمَارَ الْإِنْسِيَّقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَجَابِرٍ وَالْبَرَاءِ وَابْنِ أَبِي أَوْفَى وَأَنَسٍ وَالْعِرْبَاضِ بْنِ سَارِيَةَ وَأَبِي ثَعْلَبَةَ وَابْنِ عُمَرَ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ وَغَيْرُهُ عَنْ مُحَمَّدِ بْنِ عَمْرٍو هَذَا الْحَدِيثَ وَإِنَّمَا ذَكَرُوا حَرْفًا وَاحِدًا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah menceritakan kepadaku [Abu Kuraib], telah menceritakan kepadaku [Husain bin Ali Al Ju'fi] dari [Za`idah] dari [Muhammad bin Amr] dari [Abu Salamah] dari [Abu Hurairah] bahwasanya; \"Pada hari Khaibar, Rasulullah shallallahu 'alaihi wasallam mengharamkan setiap hewan buas dan hewan yang dijadikan sasaran tembakan serta keledai yang jinak.\" Di dalam bab ini, juga terdapat riwayat dari Ali, Ali, Jabir, Ibnu Abu Aufa, Anas, Al 'Irbadl bin Sariyah, Abu Tsa'labah dan Ibnu Abu Sa'id. Abu Isa berkata; Ini adalah hadits Hasan Shahih. [Abdul Aziz bin Muhammad] dan selainnya telah meriwayatkan hadits ini dari [Muhammad bin Amr], namun mereka menyebutkan satu kalimat yaitu; \"Nabi shallallahu 'alaihi wasallam melarang makan daging setiap hewan buas.\""},"1718":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ الطَّائِيُّ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ حَ��َّثَنَا شُعْبَةُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي ثَعْلَبَةَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قُدُورِ الْمَجُوسِ فَقَالَ أَنْقُوهَا غَسْلًا وَاطْبُخُوا فِيهَا وَنَهَى عَنْ كُلِّ سَبْعٍ ذِي نَابٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مَشْهُورٌ مِنْ حَدِيثِ أَبِي ثَعْلَبَةَ وَرُوِيَ عَنْهُ مِنْ غَيْرِ هَذَا الْوَجْهِ وَأَبُو ثَعْلَبَةَ اسْمُهُ جُرْثُومٌ وَيُقَالُ جُرْهُمٌ وَيُقَالُ نَاشِبٌ وَقَدْ ذُكِرَ هَذَا الْحَدِيثُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ أَبِي ثَعْلَبَةَ","id":"Telah menceritakan kepadaku [Zaid bin Ahzam Ath Tha`i], telah menceritakan kepadaku [Salmu bin Qutaibah] Telah menceritakan kepadaku [Syu'bah] dari [Ayyub] dari [Abu Qilabah] dari [Abu Tsa'labah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang bejana-bejana milik orang-orang Majusi, maka beliau menjawab: \"Cucilah (berjana-bejana milik mereka) itu, dan pergunakanlah untuk memasak.\" Kemudian beliau juga melarang untuk memakan setiap daging binatang buas. Abu Isa berkata; Ini adalah hadits Masyhur, yakni dari hadits Abu Tsa'labah. Dan telah diriwayatkan pula darinya selain jalur ini. Abu Tsa'labah namanya adalah Jurtsum, dan biasa juga dipanggil Jurhum dan Nasyib. Hadits ini juga pernah disebutkan dari Abu Qilabah, dari Asma` Ar Rahabi, dari Abu Tsa'labah."},"1719":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عِيسَى بْنِ يَزِيدَ الْبَغْدَادِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُحَمَّدٍ الْعَيْشِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ وَقَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ الرَّحَبِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ أَهْلِ الْكِتَابِ فَنَطْبُخُ فِي قُدُورِهِمْ وَنَشْرَبُ فِي آنِيَتِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ لَمْ تَجِدُوا غَيْرَهَا فَارْحَضُوهَا بِالْمَاءِ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضِ صَيْدٍ فَكَيْفَ نَصْنَعُ قَالَ إِذَا أَرْسَلْتَ كَلْبَكَ الْمُكَلَّبَ وَذَكَرْتَ اسْمَ اللَّهِ فَقَتَلَ فَكُلْ وَإِنْ كَانَ غَيْرَ مُكَلَّبٍ فَذُكِّيَ فَكُلْ وَإِذَا رَمَيْتَ بِسَهْمِكَ وَذَكَرْتَ اسْمَ اللَّهِ فَقَتَلَ فَكُلْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepadaku [Ali bin Isa bin Yazid Al Baghdadi], telah menceritakan kepadaku [Ubaidullah bin Muhammad Al 'Aisyi], telah menceritakan kepadaku [Hammad bin Salamah] dari [Ayyub] dan [Qatadah] dari [Abu Qilabah] dari [Abu Asma` Ar Rahabi] dari [Abu Tsa'labah Al Khusyanni] bahwa ia pernah berkata, \"Wahai Rasulullah, kami bertempat tinggal di kediaman Ahli Kitab sehingga kami memasak dengan periuk-periuk dan juga minum dengan bejana-bejana mereka.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian tidak mendapatkan selainnya, maka cucilah dengan air.\" Kemudian Abu Tsa'labah berkata lagi, \"Wahai Rasulullah, sesungguhnya kami tinggal di kawasan perburuan.\" Beliau bersabda: \"Jika kalian melepaskan anjing kalian yang telah terlatih dengan terlebih dahulu menyebut nama Allah, lalu anjing itu membunuhnya, maka makanlah. Namun, jika anjingmu bukan anjing yang terlatih tetapi kamu sempat menyembelihnya, maka makanlah. Begitu pula jika kamu melepaskan anak panahmu dengan menyebut nama Allah lalu hewan buruannya terbunuh, maka makanlah.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih."},"1720":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ وَأَبُو عَمَّارٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ فَأْرَةً وَقَعَتْ فِي سَمْنٍ فَمَاتَتْ فَسُئِلَ عَنْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلْقُوهَا وَمَا حَوْلَهَا وَكُلُوهُقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ مَيْمُونَةَ وَحَدِيثُ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ أَصَحُّ وَرَوَى مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَهُوَ حَدِيثٌ غَيْرُ مَحْفُوظٍ قَالَ و سَمِعْت مُحَمَّدَ بْنَ إِسْمَعِيلَ يَقُولُ وَحَدِيثُ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَكَرَ فِيهِ أَنَّهُ سُئِلَ عَنْهُ فَقَالَ إِذَا كَانَ جَامِدًا فَأَلْقُوهَا وَمَا حَوْلَهَا وَإِنْ كَانَ مَائِعًا فَلَا تَقْرَبُوهُ هَذَا خَطَأٌ أَخْطَأَ فِيهِ مَعْمَرٌ قَالَ وَالصَّحِيحُ حَدِيثُ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ","id":"Telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Makhzumi] dan [Abu Ammar] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidullah] dari [Ibnu Abbas] dari [Maimunah] ia berkata; Bahwa ada seekor tikus yang terjatus di atas mentega hingga mati, lalu hal itu pun ditanyakan kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Buanglah tikus itu beserta mentega yang ada di sekelilingnya dan makanlah sisanya.\" Di dalam bab ini, juga terdapat riwayat dari Abu Hurairah. Abu Isa berkata; Ini adalah hadits Hasan Shahih. Dan hadits ini juga telah diriwayatkan dari Az Zuhri dari Ubaidullah dari Ibnu Abbas bahwasanya Nabi shallallahu 'alaihi wasallam pernah ditanya. Namun mereka tidak menyebutkan di dalamnya, \"Dari Maimunah.\" Haditsnya Ibnu Abbas dari Maimunah adalah lebih shahih. [Ma'mar] telah meriwayatkan dari [Az Zuhri], dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semisalnya, namun hadits tersebut adalah hadits ghairu mahfuzh (tidak terjaga). Ia berkata; Dan saya mendengar Muhammad bin Isma'il berkata; Haditsnya Ma'mar dari Zuhri dari Sa'id bin Al Musayyab dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam. Kemudian ia menyebutkan di dalamnya; Bahwa beliau ditanya tentangnya (yakni tikus yang terjatuh dalam mentega), maka beliau bersabda: \"Jika menteganya kering, maka buanglah tikusnya serta mentega yang berada di sekelilingnya. Namun jika mentegasah basah berair, maka janganlah kalian mendekatinya.\" Ini adalah salah. Ma'mar telah berbuat kesalahan di dalamnya. Yang Shahih adalah haditsnya Az Zuhri dari Ubaidullah dari Ibnu Abbas dari Maimunah."},"1721":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَأْكُلْ أَحَدُكُمْ بِشِمَالِهِ وَلَا يَشْرَبْ بِشِمَالِهِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِشِمَالِهِقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَعُمَرَ بْنِ أَبِي سَلَمَةَ وَسَلَمَةَ بْنِ الْأَكْوَعِ وَأَنَسِ بْنِ مَالِكٍ وَحَفْصَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَهَكَذَا رَوَى مَالِكٌ وَابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عُبَيْدِ اللَّهِ عَنْ ابْنِ عُمَرَ وَرَوَى مَعْمَرٌ وَعُقَيْلٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ وَرِوَايَةُ مَالِكٍ وَابْنُ عُيَيْنَةَ أَصَحُّ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur], telah mengabarkan kepada kami [Abdullah bin Numair] Telah menceritakan kepada kami [Ubaidullah bin Umar] dari [Ibnu Syihab] dari [Abu Bakr bin Ubaidullah bin Umar] dari [Abdullah bin Umar] bahwa Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Janganlah salah seorang dari kalian makan dengan tangan kirinya dan jangan pula minum dengan tangan kirinya, karena sesungguhnya setan makan dan minum dengan tangan kirinya.\" Di dalam bab ini, juga terdapat riwayat dari Jabir, Umar bin Salamah bin Al Akwa', Anas bin Malik dan Hafshah. Abu Isa berkata; Ini adalah hadits Hasan Shahih. Demikian pula yang diriwayatkan oleh [Malik] dan [Ibnu Uyainah] dari [Az Zuhri] dari [Abu Bakr bin Ubaidullah], dari [Ibnu Umar]. [Ma'mar] dan [Uqail] juga telah meriwayatkan dari [Az Zuhri] dari [Salim] dari [Ibnu Umar]. Namun riwayat Malik dan Ibnu Uyainah adalah lebih shahih."},"1722":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَأْكُلْ بِيَمِينِهِ وَلْيَشْرَبْ بِيَمِينِهِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِشِمَالِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Abdurrahman] ia berkata, Telah menceritakan kepada kami [Ja'far bin Aun] dari [Sa'id bin Abu Arubah] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian makan, hendaklah ia makan dengan tangan kanannya dan juga minum dengan tangan kanannya. Sebab, setan makan dan minum dengan tangan kirinya.\""},"1723":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي الشَّوَارِبِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَلْعَقْ أَصَابِعَهُ فَإِنَّهُ لَا يَدْرِي فِي أَيَّتِهِنَّ الْبَرَكَةُقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَكَعْبِ بْنِ مَالِكٍ وَأَنَسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ سُهَيْلٍ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ فَقَالَ حَدِيثُ عَبْدِ الْعَزِيزِ مِنْ الْمُخْتَلِفِ لَا يُعْرَفُ إِلَّا مِنْ حَدِيثِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Malik bin Abu Asy Syawarib], telah menceritakan kepada kami [Abdul Aziz bin Al Mukhtar] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] ia berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian makan, maka hendaklah ia menjilati jari-jari tangannya, karena ia tidak tahu manakah di antara (makanan itu) yang mengandung barakah.\" Di dalam bab ini juga terdapat riwayat dari Jabir, Ka'ab bin Malik dan Anas. Abu Isa berkata; Ini adalah hadits Hasan Gharib, kami tidak mengetahuinya kecuali dari jalur ini, yakni dari haditsnya Suhail. Dan saya telah bertanya kepada Muhammad mengenai hadits ini, maka ia pun menjawab, \"Haditsnya Abdullah adalah termasuk mukhtaliful hadits, kami tidak mengetahuinya kekduali dari haditsnya.\""},"1724":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ طَعَامًا فَسَقَطَتْ لُقْمَةٌ فَلْيُمِطْ مَا رَابَهُ مِنْهَا ثُمَّ لِيَطْعَمْهَا وَلَا يَدَعْهَا لِلشَّيْطَانِقَالَ وَفِي الْبَاب عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Abu Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seseorang memakan makanan lalu sebagiannya jatuh, hendaknya dia menghilangkan debu yang mencampurinya kemudian memakannya, dan janganlah dia membiarkannya untuk setan.\" Hadits semakna juga diriwayatkan dari Anas."},"1725":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَكَلَ طَعَامًا لَعِقَ أَصَابِعَهُ الثَّلَاثَ وَقَالَ إِذَا مَا وَقَعَتْ لُقْمَةُ أَحَدِكُمْ فَلْيُمِطْ عَنْهَا الْأَذَى وَلْيَأْكُلْهَا وَلَا يَدَعْهَا لِلشَّيْطَانِ وَأَمَرَنَا أَنْ نَسْلِتَ الصَّحْفَةَ وَقَالَ إِنَّكُمْ لَا تَدْرُونَ فِي أَيِّ طَعَامِكُمْ الْبَرَكَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal], telah menceritakan kepada kami [Affan bin Muslim], telah menceritakan kepada kami [Hammad bin Salamah], telah menceritakan kepada kami [Tsabit] dari [Anas] bahwasanya; Apabila Nabi shallallahu 'alaihi wasallam memakan makanan, maka beliau menjilati tiga jari tangannya. Dan beliau bersabda: \"Jika seseorang memakan makanan lalu sebagiannya jatuh maka hendaknya dia menghilangkan debu yang mencampurinya kemudian memakannya dan janganlah dia membiarkannya untuk setan.\" Kemudian beliau juga memerintahkan kami untuk mengusap piring, dan beliau bersabda: \"Sesungguhnya kalian tidak tahu, manakah di antara butiran makanan kalaian yang mengandung barakah.\" Abu Isa berkata; Ini adalah hadits Hasan Gharib Shahih."},"1726":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ أَخْبَرَنَا أَبُو الْيَمَانِ الْمُعَلَّى بْنُ رَاشِدٍ قَالَ حَدَّثَتْنِي جَدَّتِي أُمُّ عَاصِمٍ وَكَانَتْ أُمَّ وَلَدٍ لِسِنَانِ بْنِ سَلَمَةَ قَالَتْدَخَلَ عَلَيْنَا نُبَيْشَةُ الْخَيْرِ وَنَحْنُ نَأْكُلُ فِي قَصْعَةٍ فَحَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ فِي قَصْعَةٍ ثُمَّ لَحِسَهَا اسْتَغْفَرَتْ لَهُ الْقَصْعَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْمُعَلَّى بْنِ رَاشِدٍ وَقَدْ رَوَى يَزِيدُ بْنُ هَارُونَ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ عَنْ الْمُعَلَّى بْنِ رَاشِدٍ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami], telah mengabarkan kepada kami [Abul Yaman Al Mu'alla bin Rasyid] ia berkata, telah menceritakan kepadaku [nenekku] Ummu Ashim -beliau ialah ummu waladnya Sinan bin Salamah, beliau berkata; Telah datang kepada kami [Nubaisyatul Khair] dan kami sedang makan dengan satu piring besar, lalu beliau bercerita kepada kami; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barang siapa yang makan dengan satu piring besar kemudian menjilatinya hingga bersih, niscaya piring itu akan meminta ampun untuknya.\" Berkata Abu 'Isa; Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari haditsnya Al Mu'alla bin Rasyid, dan [Yazid bin Harun] dan banyak para ulama yang meriwayatkan hadits ini dari [Mu'alla bin Rasyid]."},"1727":{"ar":"حَدَّثَنَا أَبُو رَجَاءٍ حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَرَكَةُ تَنْزِلُ وَسَطَ الطَّعَامِ فَكُلُوا مِنْ حَافَتَيْهِ وَلَا تَأْكُلُوا مِنْ وَسَطِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ إِنَّمَا يُعْرَفُ مِنْ حَدِيثِ عَطَاءِ بْنِ السَّائِبِ وَقَدْ رَوَاهُ شُعْبَةُ وَالثَّوْرِيُّ عَنْ عَطَاءِ بْنِ السَّائِبِ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Abu Raja`], telah menceritakan kepada kami [Jarir] dari [Atha` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barakah itu turun di tengah-tengah makanan, maka mulailah makan dari pinggirnya dan janganlah makan dari tengahnya.\" Berkata Abu Isa; Ini merupakan hadits hasan shahih yang hanya kami ketahui dari haditsnya Atha' bin Sa`ib. [Syu'bah] dan [Ats Tsauri] telah meriwayatkan hadits ini dari [Atha' bin Sa`ib]. Hadits semakna juga diriwayatkan dari Ibnu Umar."},"1728":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنَا عَطَاءٌ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ مِنْ هَذِهِ قَالَ أَوَّلَ مَرَّةٍ الثُّومِ ثُمَّ قَالَ الثُّومِ وَالْبَصَلِ وَالْكُرَّاثِ فَلَا يَقْرَبْنَا فِي مَسْجِدِنَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عُمَرَ وَأَبِي أَيُّوبَ وَأَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ وَجَابِرِ بْنِ سَمُرَةَ وَقُرَّةَ بْنِ إِيَاسٍ الْمُزَنِيِّ وَابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur], telah mengabarkan kepada kami [Yahya bin Sa'id Al Qaththan] dari [Ibnu Juraij], telah menceritakan kepada kami [Atha`] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang telah memakan bawang putih ini, bawang putih ini, bawang merah, maka janganlah sekali-kali ia mendekati masjid kami ini.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Di dalam bab ini juga terdapat riwayat dari Umar, Abu Ayyub, Abu Hurairah, Abu Sa'id, Jabir bin Samurah, Qurrah bin Iyas dan Ibnu Umar."},"1729":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَنْبَأَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ سَمِعَ جَابِرَ بْنَ سَمُرَةَ يَقُولُنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَيُّوبَ وَكَانَ إِذَا أَكَلَ طَعَامًا بَعَثَ إِلَيْهِ بِفَضْلِهِ فَبَعَثَ إِلَيْهِ يَوْمًا بِطَعَامٍ وَلَمْ يَأْكُلْ مِنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَتَى أَبُو أَيُّوبَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ ثُومٌ فَقَالَ يَا رَسُولَ اللَّهِ أَحَرَامٌ هُوَ قَالَ لَا وَلَكِنِّي أَكْرَهُهُ مِنْ أَجْلِ رِيحِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Dawud], telah memberitakan kepada kami [Syu'bah] dari [Simak bin Harb] bahwa ia mendengar [Jabir bin Samurah] berkata; Rasulullah shallallahu 'alaihi wasallam singgah di kediaman Ayyub. Biasanya, jika Ayyub memakan suatu makanan, maka selebihnya ia kirimkan kepada beliau. Kemudian pada suatu hari, ia mengirimkan makanan kepada beliau, namun Nabi shallallahu 'alaihi wasallam tidak memakannya. Maka ketika Ayyub mendatangi Nabi shallallahu 'alaihi wasallam, ia pun menuturkan hal itu pada beliau, akhirnya Nabi shallallahu 'alaihi wasallam bersabda: \"Di dalam makanan itu terdapat bawang putih.\" Ayyub berkata, \"Wahai Rasulullah, apakah bawang itu haram?\" beliau menjawab: \"Tidak, akan tetapi saya membencinya karena baunya yang tajam.\" Abu Isa berkata; Ini adalah hasan shahih."},"1730":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَدُّوَيْهِ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْجَرَّاحُ بْنُ مَلِيحٍ وَالِدُ وَكِيعٍ عَنْ أَبِي إِسْحَقَ عَنْ شَرِيكِ بْنِ حَنْبَلٍ عَنْ عَلِيٍّ أَنَّهُ قَالَنُهِيَ عَنْ أَكْلِ الثُّومِ إِلَّا مَطْبُوخًا","id":"Telah menceritakan kepada kami [Muhammad bin Mudduwaih], telah menceritakan kepada kami [Musaddad], telah menceritakan kepada kami [Al Jarrah binn Malik] bapaknya Waki', dari [Abu Ishaq] dari [Syarik bin Hanbal] dari [Ali] bahwa ia berkata; \"Telah dilarang untuk memakan bawang kecuali jika dimasak.\""},"1731":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ شَرِيكِ بْنِ حَنْبَلٍ عَنْ عَلِيٍّ قَالَلَا يَصْلُحُ أَكْلُ الثُّومِ إِلَّا مَطْبُوخًاقَالَ أَبُو عِيسَى هَذَا الْحَدِيثُ لَيْسَ إِسْنَادُهُ بِذَلِكَ الْقَوِيِّ وَقَدْ رُوِيَ هَذَا عَنْ عَلِيٍّ قَوْلُهُ وَرُوِي عَنْ شَرِيكِ بْنِ حَنْبَلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا قَالَ مُحَمَّدٌ الْجَرَّاحُ بْنُ مَلِيحٍ صَدُوقٌ وَالْجَرَّاحُ بْنُ الضَّحَّاكِ مُقَارِبُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Waki'] dari [bapaknya] dari [Abu Ishaq] dari [Syarik bin Hanbal] dari [Ali] bahwa ia pernah berkata, \"Memakan bawang putih tidaklah baik, kecuali setelah dimasak.\" Abu Isa berkata; Hadits ini dengan isnad tersebut tidaklah kuat. Dan hadits ini juga telah driwayatkan dari Ali, yakni ungkapannya. Dan telah diriwayatkan pula dari Syarik bin Hanbal, dari Nabi shallallahu 'alaihi wasallam secara mursal. Muhammad berkata, \"Al Jarrah bin Malih adalah seorang yang Shaduq. Sedangkan Al Jarrah bin Adl Dlahak Muqaribul Hadits."},"1732":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ الصَّبَّاحِ الْبَزَّارُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ أَنَّ أُمَّ أَيُّوبَ أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ عَلَيْهِمْ فَتَكَلَّفُوا لَهُ طَعَامًا فِيهِ مِنْ بَعْضِ هَذِهِ الْبُقُولِ فَكَرِهَ أَكْلَهُ فَقَالَ لِأَصْحَابِهِ كُلُوهُ فَإِنِّي لَسْتُ كَأَحَدِكُمْ إِنِّي أَخَافُ أَنْ أُوذِيَ صَاحِبِيقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَأُمُّ أَيُّوبَ هِيَ امْرَأَةُ أَبِي أَيُّوبَ الْأَنْصَارِيِّ","id":"Telah menceritakan kepada kami [Al Hasan bin Ash Shabbah Al Bazzar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ubaidullah bin Abu Yazid] dari [bapaknya] bahwa [Ummu Ayyub], telah mengabarkan kepadanya, bahwasanya; Nabi shallallahu 'alaihi wasallam pernah singgah di kediaman mereka, lalu mereka berlomba-lomba memberi beliau makanan dari jenis bawang-bawangan, namun Nabi shallallahu 'alaihi wasallam tidak suka untuk memakannya, maka beliau pun bersabda kepada para sahabatnya: \"Makanlah, karena aku tidak sama dengan salah seorang dari kalian, aku takut untuk menyakiti temanku.\" Abu Isa berkata; Ini merupakan hadits hasan shahih gharib dan Ummu Ayyub ialah istrinya Abu Ayyub Al Anshari."},"1733":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُمَيْدٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ عَنْ أَبِي خَلْدَةَ عَنْ أَبِي الْعَالِيَةِ قَالَالثُّومُ مِنْ طَيِّبَاتِ الرِّزْقِوَأَبُو خَلْدَةَ اسْمُهُ خَالِدُ بْنُ دِينَارٍ وَهُوَ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ وَقَدْ أَدْرَكَ أَنَسَ بْنَ مَالِكٍ وَسَمِعَ مِنْهُ وَأَبُو الْعَالِيَةِ اسْمُهُ رُفَيْعٌ هُوَ الرِّيَاحِيُّ قَالَ عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ كَانَ أَبُو خَلْدَةَ خِيَارًا مُسْلِمًا","id":"Telah menceritakan kepada kami [Muhammad bin Humaid], telah menceritakan kepada kami [Zaid bin Al Hubab] dari [Abu Khaldah] dari [Abul Aliyah] ia berkata; \"Bawang itu termasuk dari rizki yang baik.\" Abu Khaldah bernama Khalid bin Dinar dan dia seorang yang tsiqah menurut ahlul hadits, dia juga telah bertemu dengan Anas bin Malik dan mendengar hadits darinya. Abul 'Aliyah bernama Rufai'. Abdurrahman bin Mahdi berkata; Abu Khaldah seorang muslim yang baik."},"1734":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَغْلِقُوا الْبَابَ وَأَوْكِئُوا السِّقَاءَ وَأَكْفِئُوا الْإِنَاءَ أَوْ خَمِّرُوا الْإِنَاءَ وَأَطْفِئُوا الْمِصْبَاحَ فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ غَلَقًا وَلَا يَحِلُّ وِكَاءً وَلَا يَكْشِفُ آنِيَةً وَإِنَّ الْفُوَيْسِقَةَ تُضْرِمُ عَلَى النَّاسِ بَيْتَهُمْقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik bin Anas] dari [Abu Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutuplah pintu, ikatlah penutup tempat minum, tumpahkanlah atau tutuplah bejana-bejana, dan padamkanlah lampu karena setan itu tidak akan membuka yang tertutup, tidak pula yang terikat dan juga tidak akan membuka bejana. Dan tikus terkadang bisa membakar rumah manusia.\" Di dalam bab ini juga terdapat riwayat dari Ibnu Umar, Abu Hurairah dan Ibnu Abbas. Abu Isa berkata; Ini adalah hadits hasan shahih. Dan juga telah diriwayatkan dalam beberapa jalur dari Jabirr."},"1735":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتْرُكُوا النَّارَ فِي بُيُوتِكُمْ حِينَ تَنَامُونَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] (tidak hanya satu) mereka berkata, Telah menceritakan kepada kami [Sufyan] dari [Zuhri] dari [Salim] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian meninggalkan api (tidak mematikannya) di rumah-rumah kalian saat kalian tidur.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1736":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ وَعُبَيْدُ اللَّهِ عَنْ الثَّوْرِيِّ عَنْ جَبَلَةَ بْنِ سُحَيْمٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْرَنَ بَيْنَ التَّمْرَتَيْنِ حَتَّى يَسْتَأْذِنَ صَاحِبَهُقَالَ وَفِي الْبَاب عَنْ سَعْدٍ مَوْلَى أَبِي بَكْرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Ahmad Az Zubairi] dan [Ubaidullah] dari [Ats Tsauri] dari [Jabalah bin Suhaim] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang seseorang untuk mengambil dua butir kurma hingga ia meminta izin kepada pemiliknya. Di dalam bab juga terdapat riwayat dari Sa'd Maula Abu Bakr. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1737":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَهْلِ بْنِ عَسْكَرٍ الْبَغْدَادِيُّ وَعَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّ��ُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْتٌ لَا تَمْرَ فِيهِ جِيَاعٌ أَهْلُهُقَالَ وَفِي الْبَاب عَنْ سَلْمَى امْرَأَةِ أَبِي رَافِعٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ هِشَامِ بْنِ عُرْوَةَ إِلَّا مِنْ هَذَا الْوَجْهِ قَالَ وَسَأَلْتُ الْبُخَارِيَّ عَنْ هَذَا الْحَدِيثِ فَقَالَ لَا أَعْلَمُ أَحَدًا رَوَاهُ غَيْرَ يَحْيَى بْنِ حَسَّانَ","id":"Telah menceritakan kepada kami [Muhammad bin Sahl bin Askar Al Baghdadi] dan [Abdullah bin Abdurrahman] keduanya berkata, Telah menceritakan kepada kami [Yahya bin Hassan] Telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Rumah yang di dalamnya tidak terdapat korma berarti penghuninya kelaparan (bagi yang makanan pokoknya ialah korma).\" Hadits semakna diriwayatkan dari Salma istrinya Abu Rafi'. Abu Isa berkata; Ini merupakan hadits hasan gharib tidak kami ketahui dari haditsnya Hisyam bin Urwah kecuali dari jalur ini. Dan aku bertanya kepada Al Bukhari tentang hadits ini, maka ia menjawab, \"Aku tidak mengetahui seorangpun yang meriwayatkannya selain Yahya bin Hassan.\""},"1738":{"ar":"حَدَّثَنَا هَنَّادٌ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ لَيَرْضَى عَنْ الْعَبْدِ أَنْ يَأْكُلَ الْأَكْلَةَ أَوْ يَشْرَبَ الشَّرْبَةَ فَيَحْمَدَهُ عَلَيْهَاقَالَ وَفِي الْبَاب عَنْ عُقْبَةَ بْنِ عَامِرٍ وَأَبِي سَعِيدٍ وَعَائِشَةَ وَأَبِي أَيُّوبَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ نَحْوَهُ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ","id":"Telah menceritakan kepada kami [Hannad] dan [Mahmud bin Ghailan] keduanya berkata, Telah menceritakan kepada kami [Abu Usamah] dari [Zakariya bin Abu Za`idah] dari [Sa'id bin Abu Burdah] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah benar-benar akan meridhai seorang hamba yang apabila makan atau minum lalu ia memuji-Nya.\" Di dalam bab juga terdapat riwayat dari Uqbah bin Amir, Abu Sa'id, Aisyah, Abu Ayyub dan Abu Hurairah. Abu Isa berkata; Ini adalah hadits hasan. Dan telah diriwayatkan pula oleh lebih dari satu rawi dari Zakaria bin Abu Za`idah dengan hadits semisalnya, dan kami tidak mengetahuinya kecuali dari haditsnya Zakariya bin Abu Za`idah."},"1739":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْأَشْقَرُ وَإِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَا حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِ مَجْذُومٍ فَأَدْخَلَهُ مَعَهُ فِي الْقَصْعَةِ ثُمَّ قَالَ كُلْ بِسْمِ اللَّهِ ثِقَةً بِاللَّهِ وَتَوَكُّلًا عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ يُونُسَ بْنِ مُحَمَّدٍ عَنْ الْمُفَضَّلِ بْنِ فَضَالَةَ وَالْمُفَضَّلُ بْنُ فَضَالَةَ هَذَا شَيْخٌ بَصْرِيٌّ وَالْمُفَضَّلُ بْنُ فَضَالَةَ شَيْخٌ آخَرُ بَصْرِيٌّ أَوْثَقُ مِنْ هَذَا وَأَشْهَرُ وَقَدْ رَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ ابْنِ بُرَيْدَةَ أَنَّ ابْنَ عُمَرَ أَخَذَ بِيَدِ مَجْذُومٍ وَحَدِيثُ شُعْبَةَ أَثْبَتُ عِنْدِي وَأَصَحُّ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Asyqar] dan [Ibrahim bin Ya'qub] keduanya berkata, Telah menceritakan kepada kami [Yunus bin Muhammad], telah menceritakan kepada kami [Al Mufadldlal bin Fadlalah] dari [Habib bin Asy Syahid] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] bahwasanya Rasulullah shallallahu 'alaihi wasallam memegang tangan orang yang terkena kusta dan memasukkannya ke dalam piring bersamanya (untuk makan), kemudian beliau bersabda: \"Makanlah dengan menyebut nama Allah (basmalah), tsiqah (keyakinan yang mantap) kepada Allah, dan penuh rasa tawakkal pada-Nya.\" Abu Isa berkata; Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari haditsnya Yunus bin Muhammad dari Mufadldlal bin Fadlalah, dia seorang syaikh dari Bashrah dan Mufadldlal bin Fadlalah syaikh Bashrah yang lain, ia lebih tsiqah dari yang pertama dan lebih terkenal. Dan Syu'bah juga telah meriwayatkan hadits ini Hubaib bin Syahid dari Ibnu Buraidah bahwasanya; \"Ibnu Umar memegang tangan orang yang terkena kusta.\" Dan menurutku hadits Syu'bah lebih shahih."},"1740":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ وَالْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ وَأَبِي بَصْرَةَ الْغِفَارِيِّ وَأَبِي مُوسَى وَجَهْجَاهٍ الْغِفَارِيِّ وَمَيْمُونَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Yahya bin Sa'id], telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang kafir itu makan dengan tujuh usus, sementara seorang mukmin hanya makan dengan satu usus.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Di dalam bab ini, juga terdapat riwayat dari Abu Hurairah, Abu Sa'id, Abu Bashrah Al Ghifari, Jahjah Al Ghifari, Maimunah dan Abdullah bin Amr."},"1741":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَافَهُ ضَيْفٌ كَافِرٌ فَأَمَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ فَحُلِبَتْ فَشَرِبَ ثُمَّ أُخْرَى فَشَرِبَهُ ثُمَّ أُخْرَى فَشَرِبَهُ حَتَّى شَرِبَ حِلَابَ سَبْعِ شِيَاهٍ ثُمَّ أَصْبَحَ مِنْ الْغَدِ فَأَسْلَمَ فَأَمَرَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَاةٍ فَحُلِبَتْ فَشَرِبَ حِلَابَهَا ثُمَّ أَمَرَ لَهُ بِأُخْرَى فَلَمْ يَسْتَتِمَّهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ يَشْرَبُ فِي مَعْيٍ وَاحِدٍ وَالْكَافِرُ يَشْرَبُ فِي سَبْعَةِ أَمْعَاءٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ سُهَيْلٍ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari], telah menceritakan kepada kami [Ma'n], telah menceritakan kepada kami [Malik] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah kedatangan tamu seorang kafir, lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk didatangkan seekor kambing dan memeras susunya. Maka laki-laki kafir itu pun meminumnya, kemudian diperaskan lagi dan diminumnya lagi, diperaskan lagi dan diminumnya lagi hingga ia menghabisnya tujuh bejana susu. Lalu pada esok hari ia masuk Islam, kemudian Rasulullah shallallahu 'alaihi wasallam pun memerintahkan agar laki-laki itu diperaskan susu kambing. Maka laki-laki itu meminumnya, sesudah itu ditawarkan lagi padanya, namun tidak ia tidak sanggup untuk menghabiskannya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang mukmin itu hanya minum dengan satu usus, sementara orang kafir minum dengan tujuh usus.\" Abu Isa berkata; Ini adalah hadits shahih gharib dari haditsnya Suhail."},"1742":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ ح و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامُ الِاثْنَيْنِ كَافِي الثَّلَاثَةَ وَطَعَامُ الثَّلَاثَةِ كَافِي الْأَرْبَعَةَقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Anshari], telah menceritakan kepada kami [Ma'n], telah menceritakan kepada kami [Malik] -dalam riwayat lain-, dan telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanan untuk dua orang cukup untuk tiga orang, dan makanan yang seharusnya untuk tiga orang, cukup untuk empat orang.\" Dan di dalam bab, juga terdapat riwayat dari Jabir dan Ibnu Umar. Abu Isa berkata; \"Ini adalah hadits hasan shahih.\""},"1743":{"ar":"وَرَوَى جَابِرٌ وَابْنُ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ طَعَامُ الْوَاحِدِ يَكْفِي الِاثْنَيْنِ وَطَعَامُ الِاثْنَيْنِ يَكْفِي الْأَرْبَعَةَ وَطَعَامُ الْأَرْبَعَةِ يَكْفِي الثَّمَانِيَةَحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا","id":"Dan Jabir bin Abdullah dan Ibnu Umar telah meriwayatkan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Makanan jatah satu orang cukup untuk dua orang. Makanan jatah dua orang cukup untuk empat orang. Sedangkan makanan jatah empat orang cukup untuk delapan orang.\" Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini."},"1744":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي يَعْفُورٍ الْعَبْدِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىأَنَّهُ سُئِلَ عَنْ الْجَرَادِ فَقَالَ غَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ غَزَوَاتٍ نَأْكُلُ الْجَرَادَقَالَ أَبُو عِيسَى هَكَذَا رَوَى سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي يَعْفُورٍ هَذَا الْحَدِيثَ وَقَالَ سِتَّ غَزَوَاتٍ وَرَوَى سُفْيَانُ الثَّوْرِيُّ وَغَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ أَبِي يَعْفُورٍ فَقَالَ سَبْعَ غَزَوَاتٍ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Sufyan] dari [Abu Ya'fur Al Abdi] dari [Abdullah bin Abu Aufa] bahwa ia pernah ditanya tentang belalang. Maka ia pun menjawab, \"Aku telah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam sebanyak enam kali peperangan, dan saat itu kami memakan belalang.\" Abu Isa berkata; Seperti inilah yang diriwayatkan oleh Sufyan bin Uyainah dari Abu Ya'fur dan ia menyebutkan; Enam kali peperangan. Sufyan Ats Tsauri dan yang lainnya juga meriwayatkan hadits ini dari Abu Ya'fur dan ia menyebutkan; \"Tujuh kali peperangan.\""},"1745":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ وَالْمُؤَمَّلُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ أَبِي يَعْفُورٍ عَنْ ابْنِ أَبِي أَوْفَى قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ نَأْكُلُ الْجَرَادَقَالَ أَبُو عِيسَى وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ أَبِي يَعْفُورٍ عَنْ ابْنِ أَبِي أَوْفَى قَالَ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَوَاتٍ نَأْكُلُ الْجَرَادَ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ بِهَذَا قَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو يَعْفُورٍ اسْمُهُ وَاقِدٌ وَيُقَالُ وَقْدَانُ أَيْضًا وَأَبُو يَعْفُورٍ الْآخَرُ اسْمُهُ عَبْدُ الرَّحْمَنِ بْنُ عُبَيْدِ بْنِ نِسْطَاسَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Ahmad] dan [Al Mu`amal] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Abu Ya'fur] dari [Ibnu Abu Aufa] ia berkata; \"Kami telah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh kali peperangan, maka di saat itu pula kami makan belalang.\" Abu Isa berkakta; Syu'bah meriwayatkan hadits ini dari Abu Ya'fur dari Ibnu Abu Aufa, ia berkata; Aku telah berperang bersama-sama dengan Rasulullah shallallahu 'alaihi wasallam dalam beberapa kali peperangan, dan saat itu kami makan belalang. Demikian begitu pula, telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dengan ini. Dan di dalam bab juga terdapat riwayat dari Ibnu Umar dan Jabir. Abu Isa berkata; Ini adalah hadits Hasan Shahih. Abu Ya'fur namanya adalah Waqid, dan biasa juga dipanggil Waqdan. Abu Ya'fur yang lain namanya adalah Abdurrahman bin Ubaid bin Nisthas."},"1746":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو النَّضْرِ هَاشِمُ بْنُ الْقَاسِمِ قَالَ حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ بْنِ عُلَاثَةَ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ وَأَنَسِ بْنِ مَالِكٍ قَالَاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَا عَلَى الْجَرَادِ قَالَ اللَّهُمَّ أَهْلِكِ الْجَرَادَ اقْتُلْ كِبَارَهُ وَأَهْلِكْ صِغَارَهُ وَأَفْسِدْ بَيْضَهُ وَاقْطَعْ دَابِرَهُ وَخُذْ بِأَفْوَاهِهِمْ عَنْ مَعَاشِنَا وَأَرْزَاقِنَا إِنَّكَ سَمِيعُ الدُّعَاءِ قَالَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ كَيْفَ تَدْعُو عَلَى جُنْدٍ مِنْ أَجْنَادِ اللَّهِ بِقَطْعِ دَابِرِهِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا نَثْرَةُ حُوتٍ فِي الْبَحْرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَمُوسَى بْنُ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيُّ قَدْ تُكُلِّمَ فِيهِ وَهُوَ كَثِيرُ الْغَرَائِبِ وَالْمَنَاكِيرِ وَأَبُوهُ مُحَمَّدُ بْنُ إِبْرَاهِيمَ ثِقَةٌ وَهُوَ مَدَنِيٌّ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Nadlr Hasyim bin Al Qasim] ia berkata, Telah menceritakan kepada kami [Ziyad bin Abdullah bin Ulatsah] dari [Musa bin Muhammad bin Ibrahim At Taimi] dari [bapaknya] dari [Jabir bin Abdullah] dan [Anas bin Malik] keduanya berkata; Apabila Rasulullah shallallahu 'alaihi wasallam mendoakan binasa atas serangga (belalang), beliau berkata: \"Ya Allah, binasakanlah serangga bunuhlah yang dewasanya dan binasakanlah anak-anaknya serta rusaklah telurnya dan punahkanlah keturunannya. Hindarkanlah mulutnya dari merusak mata pencaharian kami dan rezeki kami, sesungguhnya Engkau Dzat Yang Maha Mendengarkan doa.\" Kemiudian seorang lelaki bertanya, \"Wahai Rasulullah, kenapa engkau mendoakan binasa atas salah satu tentara Allah?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dia adalah makanannya ikan hiu di laut.\" Ini merupakan hadits gharib, tidak kami ketahui kecuali dari jalur ini. Dan Musa bin Muhammad bin Ibrahim At taimi telah dicela dan dia memiliki hadits-hadits Gharib dan Munkar, adapun bapaknya Muhammad bin Ibrahim seorang yang tsiqah berasal dari Madinah."},"1747":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ الْجَلَّالَةِ وَأَلْبَانِهَاقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَى الثَّوْرِيُّ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abdah] dari [Muhammad bin Ishaq] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang untuk memakan al jallalah (hewan yang memakan kotoran) dan meminum susunya.\" Hadits semakna diriwayatkan dari Ibnu Abbas. Berkata Abu 'Isa; Ini merupakan hadits hasan gharib dan [Tsauri] meriwayatkan dari [Ibnu Abi Nujaih] dari [Mujahid] dari Nabi shallallahu 'alaihi wasallam."},"1748":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُجَثَّمَةِ وَلَبَنِ الْجَلَّالَةِ وَعَنْ الشُّرْبِ مِنْ فِي السِّقَاءِقَالَ مُحَمَّدُ بْنُ بَشَّارٍ وَحَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwasanya; \"Nabi shallallahu 'alaihi wasallam melarang al mujatstsamah (menjadikan hewan sebagai sasaran tembak untuk membunuhnya), Laban Jalalah (susu dari hewan yang memakan kotoran), dan minum langsung dari guci (tempat minum).\" Muhammad bin Basysyar berkata; Dan telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Ikrimah] dair [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam semisalnya. Abu Isa berkata; Ini adalah hadits hasan shahih. Di dalam bab ini juga terdapat riwayat dari Abdullah bin Amr."},"1749":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ الطَّائِيُّ حَدَّثَنَا أَبُو قُتَيْبَةَ عَنْ أَبِي الْعَوَّامِ عَنْ قَتَادَةَ عَنْ زَهْدَمٍ الْجَرْمِيِّ قَالَدَخَلْتُ عَلَى أَبِي مُوسَى وَهُوَ يَأْكُلُ دَجَاجَةً فَقَالَ ادْنُ فَكُلْ فَإِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ زَهْدَمٍ وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ زَهْدَمٍ وَأَبُو الْعَوَّامِ هُوَ عِمْرَانُ الْقَطَّانُ","id":"Telah menceritakan kepada kami [Zaid bin Ahzam Ath Tha`i], telah menceritakan kepada kami [Abu Qutaibah] dari [Abu Al Awwam] dari [Qatadah] dari [Zahdam Al Jarmi] ia berkata; Aku pernah menemui [Abu Musa], dan ternyata saat itu ia sedang makan daging ayam. Maka ia berkata, \"Mendekatlah, karena sungguh, aku telah melihat Rasulullah shallallahu 'alaihi wasallam memakannya.\" Abu Isa berkata; Ini adalah hadits Hasan. Dan hadits ini juga telah diriwayatkan lebih dari satu dari Zahdam, namun kami tidak mengetahuinya kecuali dari haditsnya Zahdam. Abu Al Awwam adalah Imran Al Qaththan."},"1750":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ زَهْدَمٍ عَنْ أَبِي مُوسَى قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ لَحْمَ دَجَاجٍقَالَ وَفِي الْحَدِيثِ كَلَامٌ أَكْثَرُ مِنْ هَذَا وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَى أَيُّوبُ السَّخْتِيَانِيُّ هَذَا الْحَدِيثَ أَيْضًا عَنْ الْقَاسِمِ التَّمِيمِيِّ وَعَنْ أَبِي قِلَابَةَ عَنْ زَهْدَمٍ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ayyub] dari [Abu Qilabah] dari [Zahdam] dari [Abu Musa] ia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam makan daging ayam.\" Di dalam hadits ini terdapat ungkapan yang lebih panjang daripada ini. Dan hadits ini adalah hadits hasan shahih. Ayyub As Sakhtiyani juga telah meriwayatkan hadits ini dari [Al Qasim At Tamimi] dan dari [Abu Qilabah] dari [Zahdam]."},"1751":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ سَهْلٍ الْأَعْرَجُ الْبَغْدَادِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ عَنْ إِبْرَاهِيمَ بْنِ عُمَرَ بْنِ سَفِينَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَكَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمَ حُبَارَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَإِبْرَاهِيمُ بْنُ عُمَرَ بْنِ سَفِينَةَ رَوَى عَنْهُ ابْنُ أَبِي فُدَيْكٍ وَيُقَالُ بُرَيْدُ بْنُ عُمَرَ بْنِ سَفِينَةَ","id":"Telah menceritakan kepada kami [Al Fadllu bin Sahl Al A'raj Al Al Baghdadi], telah menceritakan kepada kami [Ibrahim bin Abdurrahman bin Mahdi] dari [Ibrahiim bin Umar bin Safinah] dari [bapaknya] dari [kakeknya] ia berkata; \"Aku pernah makan daging hubara (sejenis burung berbadan besar berkaki panjang) bersama Rasulullah shallallahu 'alaihi wasallam.\" Abu Isa berkata; Ini adalah hadits gharib, kami tidak mengetahuinya kecuali dari jalur ini. Terkait dengan Ibrahim bin Umar bin Safinah, maka Ibnu Abu Fudaik pernah meriwayatkan darinya, biasanya ia dipanggil Buraidah bin Umar bin Safinah."},"1752":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي مُحَمَّدُ بْنُ يُوسُفَ أَنَّ عَطَاءَ بْنَ يَسَارٍ أَخْبَرَهُ أَنَّ أُمَّ سَلَمَةَ أَخْبَرَتْهُأَنَّهَا قَرَّبَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَنْبًا مَشْوِيًّا فَأَكَلَ مِنْهُ ثُمَّ قَامَ إِلَى الصَّلَاةِ وَمَا تَوَضَّأَقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ وَالْمُغِيرَةِ وَأَبِي رَافِعٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani], telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata; [Ibnu Juraijj] berkata, Telah mengabarkan kepadaku [Muhammad bin Yusuf] bahwa [Atha` bin Yasar], telah mengabarkan kepadanya bahwa [Ummu Salamah], telah mengabarkan kepadanya bahwasanya; \"Ia pernah menyuguhkan daging yang dipanggang kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun memakannya. Setelah itu, beliau langsung menunaikan shalat, dan beliau tidak lagi berwudlu.\" Dan hadits semakna juga diriwayatkan dari Abdullah bin Harits, Al Mughirah dan Abu Rafi'. Abu Isa berkata; Ini adalah hadits hasan shahih gharib bila ditinjau dari jalur ini."},"1753":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا شَرِيكٌ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ أَبِي جُحَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَنَا فَلَا آكُلُ مُتَّكِئًاقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَلِيِّ بْنِ الْأَقْمَرِ وَرَوَى زَكَرِيَّا بْنُ أَبِي زَائِدَةَ وَسُفْيَانُ بْنُ سَعِيدٍ الثَّوْرِيُّ وَغَيْرُ وَاحِدٍ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ هَذَا الْحَدِيثَ وَرَوَى شُعْبَةُ عَنْ سُفْيَانَ الثَّوْرِيِّ هَذَا الْحَدِيثَ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Syarik] dari [Ali bin Al Aqmar] dari [Abu Juhaifah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun saya, maka saya tidaklah makan dengan bersandar.\" Dan hadits semakna juga diriwayatkan dari Ali, Abdullah bin Amr dan Abdullah bin Abbas. Abu Isa berkata; Ini adalah hadits hasan shahih, dan kami tidak mengetahuinya kecuali dari haditsnya Ali bin Al Aqmar. Dan [Zakaria bin Abu Za`idah] dan [Sufyan bin Sa'id Ats Tsauri] dan lebih dari satu orang perawi dari [Ali bin Al Aqmar]. Kemudian [Syu'bah] juga telah meriwayatkan hadits ini dari [Sufyan Ats Tsauri] dari [Ali bin Al Aqmar]."},"1754":{"ar":"حَدَّثَنَا سَلَمَةُ بْنُ شَبِيبٍ وَمَحْمُودُ بْنُ غَيْلَانَ وَأَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَالْعَسَلَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَقَدْ رَوَاهُ عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ وَفِي الْحَدِيثِ كَلَامٌ أَكْثَرُ مِنْ هَذَا","id":"Telah menceritakan kepada kami [Sulaiman bin Syabib] dan [Mahmud bin Ghailan] dan [Ahmad bin Ibrahim Ad Dauraqi] mereka berkata, Telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkata; \"Nabi shallallahu 'alaihi wasallam menyukai manisan dan madu.\" Ini adalah hadits hasan shahih gharib. Dan [Ali bin Mushir] juga telah meriwayatkannya dari [Hisyam bin Urwah]. Dan di dalam hadits itu terdapat ungkapan yang lebih banyak dari pada hadits ini."},"1755":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُمَرَ بْنِ عَلِيٍّ الْمُقَدَّمِيُّ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ فَضَاءٍ حَدَّثَنِي أَبِي عَنْ عَلْقَمَةَ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ أَبِيهِ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اشْتَرَى أَحَدُكُمْ لَحْمًا فَلْيُكْثِرْ مَرَقَتَهُ فَإِنْ لَمْ يَجِدْ لَحْمًا أَصَابَ مَرَقَةً وَهُوَ أَحَدُ اللَّحْمَيْنِوَفِي الْبَاب عَنْ أَبِي ذَرٍّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ مِنْ حَدِيثِ مُحَمَّدِ بْنِ فَضَاءٍ وَمُحَمَّدُ بْنُ فَضَاءٍ هُوَ الْمُعَبِّرُ وَقَدْ تَكَلَّمَ فِيهِ سُلَيْمَانُ بْنُ حَرْبٍ وَعَلْقَمَةُ بْنُ عَبْدِ اللَّهِ هُوَ أَخُو بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Umar bin Ali Al Maqaddami], telah menceritakan kepada kami [Muslim bin Ibrahim], telah menceritakan kepada kami [Muhammad bin Qadla`], telah menceritakan kepadaku [bapakku] dari [Alqamah bin Abdullah Al Muzani] dari [bapaknya], ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian membeli daging perbanyaklah kuahnya dan jika dia tidak mendapatkan daging dia akan mendapatkan kuahnya dan itu merupakan salah satu dari dua daging.\" Hadits semakna juga diriwayatkan dari Abu Dzar. Abu 'Isa berkata; Ini merupakan hadits gharib tidak kami ketahui kecuali dari jalur ini dari haditsnya Muhammad bin Fadla` dan Muhammad bin Fadlaa` dialah yang mengungkapkan. Dan Sulaiman bin Harb telah mencelanya. Sedangkan Alqamah binn Abdullah adalah saudaranya Bakr bin Abdullah Al Muzani."},"1756":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ عَلِيِّ بْنِ الْأَسْوَدِ الْبَغْدَادِيُّ حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ الْعَنْقَزِيُّ حَدَّثَنَا إِسْرَائِيلُ عَنْ صَالِحِ بْنِ رُسْتُمَ أَبِي عَامِرٍ الْخَزَّازِ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحْقِرَنَّ أَحَدُكُمْ شَيْئًا مِنْ الْمَعْرُوفِ وَإِنْ لَمْ يَجِدْ فَلْيَلْقَ أَخَاهُ بِوَجْهٍ طَلِيقٍ وَإِنْ اشْتَرَيْتَ لَحْمًا أَوْ طَبَخْتَ قِدْرًا فَأَكْثِرْ مَرَقَتَهُ وَاغْرِفْ لِجَارِكَ مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ","id":"Telah menceritakan kepada kami [Husain bin Ali bin Al Aswad Al Baghdadi], telah menceritakan kepada kami [Amr bin Muhammad Al Anqazi], telah menceritakan kepada kami [Isra`il] dari [Shalih bin Rustum Abu Amir Al Khazzaz] dari [Abu Imran Al Jauni] dari [Abdullah bin Shamit] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah sekali-kali salah seorang dari kalian meremehkan sesuatu pun dari amal kebaikan. Jika ia tidak mendapatkan sesuatu (untuk berbuat baik), hendaklah ia berwajah ceria terhadap temannya. Apabila kamu membeli daging atau memasak makanan di atas periuk, maka perbanyaknya kuahnya dan berikanlah dari makanan itu untuk tetanggamu.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Dan [Syu'bah] juga telah meriwayatkannya dari [Abu Imran Al Jauni]."},"1757":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ مُرَّةَ الْهَمْدَانِيِّ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَمُلَ مِنْ الرِّجَالِ كَثِيرٌ وَلَمْ يَكْمُلْ مِنْ النِّسَاءِ إِلَّا مَرْيَمُ ابْنَةُ عِمْرَانَ وَآسِيَةُ امْرَأَةُ فِرْعَوْنَ وَفَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] dari [Murrah Al Hamdani] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Telah banyak dari kaum laki-laki yang mencapai titik kesempurnaan, namun dari kaum wanita tidak ada yang sempurna kecuali Maryam binti Imran dan Asiyah isteri Fir'aun. Dan keutamaan Aisyah di antara wanita-wanita yang lain adalah laksana keutamaan makanan bubur atas semua makanan.\" Hadits semakna juga diriwayatkan dari Aisyah dan Anas. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1758":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ أَبِي أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَ زَوَّجَنِي أَبِي فَدَعَا أُنَاسًا فِيهِمْ صَفْوَانُ بْنُ أُمَيَّةَ فَقَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْهَسُوا اللَّحْمَ نَهْسًا فَإِنَّهُ أَهْنَأُ وَأَمْرَأُقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الْكَرِيمِ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْعِلْمِ فِي عَبْدِ الْكَرِيمِ الْمُعَلِّمِ مِنْهُمْ أَيُّوبُ السَّخْتِيَانِيُّ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Karim Abu Umayyah] dari [Abdullah bin Al Harits] ia berkata; Bapakku menikahkanku, lalu ia pun mengundang orang-orang dan di antara mereka terdapat Shafwan bin Muhammad. Maka [Shafwan] pun berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Makanlah daging yang terdapat di ujung gigi, karena hal itu akan lebih sedap dan bermanfaat bagi tubuh.\" Hadits semakna juga diriwayatkan dari Aisyah dan Abu Hurairah. Abu Isa berkata; Kami tidak mengetahui hadits ini kecuali dari haditsnya Abdul Karim. Dan sebagian Ahlul Ilmi telah berkomentar tentang Abdul Karim Al Mu'allim, di antara mereka adalah Ayyub As Sakhtiyani yakni, terkait dengan hafalannya."},"1759":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ عَنْ أَبِيهِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَزَّ مِنْ كَتِفِ شَاةٍ فَأَكَلَ مِنْهَا ثُمَّ مَضَى إِلَى الصَّلَاةِ وَلَمْ يَتَوَضَّأْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abdurrazzaq], telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ja'far bin Amru bin Umayyah Adl Dlamri] dari [bapaknya] bahwasanya; \"Ia pernah melihat Nabi shallallahu 'alaihi wasallam memotong lengan kambing dan memakan dagingnya lalu beliau langsung menunaikan shalat dengan tidak berwudlu lagi.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Dan hadits semakna juga diriwayatkan dari Al Mughirah bin Syu'bah."},"1760":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ أَبِي حَيَّانَ التَّيْمِيِّ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَرُفِعَ إِلَيْهِ الذِّرَاعُ وَكَانَتْ تُعْجِبُهُ فَنَهَسَ مِنْهَاقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَعَائِشَةَ وَعَبْدِ اللَّهِ بْنِ جَعْفَرٍ وَأَبِي عُبَيْدَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو حَيَّانَ اسْمُهُ يَحْيَى بْنُ سَعِيدِ بْنِ حَيَّانَ وَأَبُو زَرْعَةَ بْنُ عَمْرِو بْنِ جَرِيرٍ اسْمُهُ هَرِمٌ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la], telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Abu Hayyan At Taimi] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata; \"Nabi shallallahu 'alaihi wasallam pernah diberikan daging, lalu daging itu pun diberikan kepadanya bagian tangannya dan beliau menyukainya lantas beliau mencicipinya.\" Hadits semakna diriwayatkan juga dari Ibnu Mas'ud, 'Aisyah, Abdullah bin Ja'far dan Abu Ubaidaah. Abu Isa berkata; Ini merupakan hadits Hasan Shahih dan Abu Hayyan bernama Yahya bin Sa'id bin Hayyan. Abu Zar'ah bin Amr bin Jarir bernama Harim."},"1761":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا يَحْيَى بْنُ عَبَّادٍ أَبُو عَبَّادٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عَبْدِ الْوَهَّابِ بْنِ يَحْيَى مِنْ وَلَدِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْمَا كَانَ الذِّرَاعُ أَحَبَّ اللَّحْمِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ كَانَ لَا يَجِدُ اللَّحْمَ إِلَّا غِبًّا فَكَانَ يَعْجَلُ إِلَيْهِ لِأَنَّهُ أَعْجَلُهَا نُضْجًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani], telah menceritakan kepada kami [Yahya bin Abbad Abu Abbad], telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Abdul Wahhab bin Yahya] anak dari Abbad bin Abdullah bin Zubair, dari [Abdullah bin Az Zubair] dari [Aisyah] ia berkata; \"Bukanlah bagian tangan hewan yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam akan tetapi karena beliau jarang sekali mendapatkan daging maka beliau segera memakannya karena bagian itu lebih cepat matang.\" Abu Isa berkata; Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari jalur ini."},"1762":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا مُبَارَكُ بْنُ سَعِيدٍ هُوَ أَخُو سُفْيَانَ بْنِ سَعِيدٍ الثَّوْرِيِّ عَنْ سُفْيَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْإِدَامُ الْخَلُّقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَأُمِّ هَانِئٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Arafah], telah menceritakan kepada kami [Mubarak bin Sa'id] ia adalah saudaranya Sufyan bin Sa'id Ats Tsauri, dari [Sufyan] dari [Abu Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Lauk yang paling nikmat adalah cuka.\" Hadits yang semakna juga diriwayatkan dari Aisyah dan Ummu Hani`."},"1763":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ الْبَصْرِيُّ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْإِدَامُ الْخَلُّقَالَ أَبُو عِيسَى هَذَا أَصَحُّ مِنْ حَدِيثِ مُبَارَكِ بْنِ سَعِيدٍ","id":"Telah menceritakan kepada kami [Abdah bin Abdullah Al Khuza'I Al Bashari], telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari [Muharib bin Ditsar] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Lauk yang paling nikmat adalah al khallu (cuka).\" Abu Isa berkata; Hadits ini lebih shahih daripada haditsnya Mubarak bin Sa'id."},"1764":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَهْلِ بْنِ عَسْكَرٍ الْبَغْدَادِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْإِدَامُ الْخَلُّحَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَّا أَنَّهُ قَالَ نِعْمَ الْإِدَامُ أَوْ الْأُدْمُ الْخَلُّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ لَا نَعْرِفُهُ مِنْ حَدِيثِ هِشَامِ بْنِ عُرْوَةَ إِلَّا مِنْ حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ","id":"Telah menceritakan kepada kami [Muhamamd bin Sahl bin Askar Al Baghdadi], telah menceritakan kepada kami [Yahya bin Hassan], telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik lauk pauk ialah cuka.\" Telah menceritakan kepada kami [Abdullah bin Abdurrahman], telah mengabarkan kepada kami [Yahya bin Hassan] dari [Sulaiman bin Bilal] dengan isnad ini semisalnya. Hanya saja ia menyebutkan; \"Ni'mal Idaamu atau Al Udumu Al Khallu.\" Abu Isa berkata; Ini merupakan hadits hasan shahih gharib dari jalur ini yang tidak kami ketahui dari haditsnya Hisyam bin Urwah kecuali dari haditsnya Sulaiman bin Bilal."},"1765":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حَمْزَةَ الثُّمَالِيِّ عَنْ الشَّعْبِيِّ عَنْ أُمِّ هَانِئٍ بِنْتِ أَبِي طَالِبٍ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ هَلْ عِنْدَكُمْ شَيْءٌ فَقُلْتُ لَا إِلَّا كِسَرٌ يَابِسَةٌ وَخَلٌّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرِّبِيهِ فَمَا أَقْفَرَ بَيْتٌ مِنْ أُدْمٍ فِيهِ خَلٌّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ لَا نَعْرِفُهُ مِنْ حَدِيثِ أُمِّ هَانِئٍ إِلَّا مِنْ هَذَا الْوَجْهِ وَأَبُو حَمْزَةَ الثُّمَالِيُّ اسْمُهُ ثَابِتُ بْنُ أَبِي صَفِيَّةَ وَأُمُّ هَانِئٍ مَاتَتْ بَعْدَ عَلِيِّ بْنِ أَبِي طَالِبٍ بِزَمَانٍ وَسَأَلْتُ مُحَمَّدًا عَنْ هَذَا الْحَدِيثِ قَالَ لَا أَعْرِفُ لِلشَّعْبِيِّ سَمَاعًا مِنْ أُمِّ هَانِئٍ فَقُلْتُ أَبُو حَمْزَةَ كَيْفَ هُوَ عِنْدَكَ فَقَالَ أَحْمَدُ بْنُ حَنْبَلٍ تَكَلَّمَ فِيهِ وَهُوَ عِنْدِي مُقَارِبُ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al Ala`], telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Abu Hamzah Ats Tsamali] dari [Asy Sya'bi] dari [Ummu Hani` binti Abu Thalib] ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku (di rumahku) dan beliau bertanya: \"Apakah kamu mempunyai sesuatu makanan.\" Aku menjawab, \"Tidak, kecuali hanya sepotong roti kering dan cuka.\" Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Bawalah kemari, tidaklah rumah itu sunyi dari lauk, bila di dalamnya terdapat cuka.\" Abu Isa berkata; Ini adalah hadits hasan gharib ditinjau dari jalur ini. Kami tidak mengetahuinya dari hadits Ummu Hani` kecuali melalui jalur ini. Abu Hamzah Ats Tsumali namanya adalah Tsabit bin Abu Shafiyyah. Ummu Hani` wafat setelah Ali bin Abu Thalib dengan selang waktu yang cukup panjang. Aku pernah bertanya kepada Muhammad mengenai hadits ini, maka ia menjawab, \"Aku tidak mengetahui bahwa Asy Sya'bi pernah mendengar hadits dari Ummu Hani`.\" Kemudian aku katakan, \"Terkait dengan Abu Hamzah, bagaimana menurutmu?\" Maka ia pun menjawab, \"Ahmad bin Hanbal telah memberi komentar tentangnya, dan menurutku, ia adalah seorang muqaribul hadits.\""},"1766":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْكُلُ الْبِطِّيخَ بِالرُّطَبِقَالَ وَفِي الْبَاب عَنْ أَنَسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَاهُ بَعْضُهُمْ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلٌ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَائِشَةَ وَقَدْ رَوَى يَزِيدُ بْنُ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdah bin Abdullah Al Khuza'i], telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan bin Hisyam] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwasanya; \"Rasulullah shallallahu 'alaihi wasallam sering makan mentimun dicampur dengan kurma basah.\" Hadits semakna juga diriwayatkan dari Anas. Abu Isa berkakta; Ini merupakan hadits hasan gharib. Dan sebagian mereka meriwayatkannya dari [Hisyam bin Urwah] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam secara mursal, dan ia tidak menyebutkan di dalamnya; Dari Aisyah. Kemudian [Yazid bin Ruman] juga telah meriwayatkan hadits ini dari [Aisyah]."},"1767":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ مُوسَى الْفَزَارِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْقِثَّاءَ بِالرُّطَبِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ إِبْرَاهِيمَ بْنِ سَعِدٍ","id":"Telah meriwayatkan kepada kami [Isma'il bin Musa Al Fazari], telah meriwayatkan kepada kami [Ibrahim bin Sa'd] dari [bapaknya] dari [Abdullah bin Ja'far] ia berkata; \"Biasanya Rasulullah shallallahu 'alaihi wasallam makan mentimun dengan buah kurma.\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib, kami tidak mengetahuinya kecuali dari hadits Ibrahim bin Sa'd."},"1768":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا حُمَيْدٌ وَثَابِتٌ وَقَتَادَةُ عَنْ أَنَسٍأَنَّ نَاسًا مِنْ عُرَيْنَةَ قَدِمُوا الْمَدِينَةَ فَاجْتَوَوْهَا فَبَعَثَهُمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلِ الصَّدَقَةِ وَقَالَ اشْرَبُوا مِنْ أَبْوَالِهَا وَأَلْبَانِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَنَسٍ رَوَاهُ أَبُو قِلَابَةَ عَنْ أَنَسٍ وَرَوَاهُ سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani], telah menceritakan kepada kami [Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Humaid] dan [Tsabit] dan [Qatadah] dari [Anas] bahwasanya; Sekelompok orang dari Urainah datang ke kota Madinah lalu mereka pun merasa berduka. Maka Nabi shallallahu 'alaihi wasallam pun mengutus mereka bersama unta-unta sedekah, kemudian beliau bersabda: \"Minumlah dari air seni dan air susunya.\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib bila ditinjau dari jalur ini. Dan hadits ini juga telah diriwatkan lebih dari satu dari Anas. [Abu Qilabah] telah meriwayatkannya dari [Anas]. [Sa'id bin Abu Arubah] juga telah meriwayatkan dari [Qatadah] dari [Anas]."},"1769":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا قَيْسُ بْنُ الرَّبِيعِ قَالَ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْكَرِيمِ الْجُرْجَانِيُّ عَنْ قَيْسِ بْنِ الرَّبِيعِ الْمَعْنَى وَاحِدٌ عَنْ أَبِي هَاشِمٍ يَعْنِي الرّ��مَّانِيَّ عَنْ زَاذَانَ عَنْ سَلْمَانَ قَالَقَرَأْتُ فِي التَّوْرَاةِ أَنَّ بَرَكَةَ الطَّعَامِ الْوُضُوءُ بَعْدَهُ فَذَكَرْتُ ذَلِكَ للنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِمَا قَرَأْتُ فِي التَّوْرَاةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرَكَةُ الطَّعَامِ الْوُضُوءُ قَبْلَهُ وَالْوُضُوءُ بَعْدَهُقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى لَا نَعْرِفُ هَذَا الْحَدِيثَ إِلَّا مِنْ حَدِيثِ قَيْسِ بْنِ الرَّبِيعِ وَقَيْسُ بْنُ الرَّبِيعِ يُضَعَّفُ فِي الْحَدِيثِ وَأَبُو هَاشِمٍ الرُّمَّانِيُّ اسْمُهُ يَحْيَى بْنُ دِينَارٍ","id":"Telah menceritakan kepada kami [Yahya bin Musa], telah menceritakan kepada kami [Abdullah bin Numair], telah menceritakan kepada kami [Qais bin Ar Rabi'] ia berkata; -dalam riwyat lain- Dan telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdul Karim Al Jurjani] dari [Qais bin Ar Rabi'] -dengan makna yang satu- dari [Abu Hasyim Ar Rumani] dari [Zadzan] dari [Salman] ia berkata; Aku membaca di dalam Taurat, \"Sesungguhnya barokah makanan itu dengan berwudlu sesudah memakannya.\" Lalu aku sampaikan hal itu kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Barakah makanan itu dengan berwudhu sebelum dan sesudah memakannya.\" Hadits semakna diriwayatkan dari Anas dan Abu Hurairah. Abu Isa berkata; Kami tidak mengetahui hadits ini kecuali dari haditsnya Qais bin Rasi' namun dia di-dha'if-kan dalam periwayatan hadits."},"1770":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْخَلَاءِ فَقُرِّبَ إِلَيْهِ طَعَامٌ فَقَالُوا أَلَا نَأْتِيكَ بِوَضُوءٍ قَالَ إِنَّمَا أُمِرْتُ بِالْوُضُوءِ إِذَا قُمْتُ إِلَى الصَّلَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ عَمْرُو بْنُ دِينَارٍ عَنْ سَعِيدِ بْنِ الْحُوَيْرِثِ عَنْ ابْنِ عَبَّاسٍ و قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ كَانَ سُفْيَانُ الثَّوْرِيُّ يَكْرَهُ غَسْلَ الْيَدِ قَبْلَ الطَّعَامِ وَكَانَ يَكْرَهُ أَنْ يُوضَعَ الرَّغِيفُ تَحْتَ الْقَصْعَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Ibnu Abbas] bahwa suatu ketika, Rasulullah shallallahu 'alaihi wasallam keluar dari kakus, lalu disuguhkanlah makanan kepada beliau, kemudian para sahabatpun bertanya, \"Maukah engkau kami ambilkan air untuk wudlu?\" Beliau menjawab: \"Sesungguhnya aku diperintahkan untuk berwudhu hanya ketika aku hendak menunaikan shalat.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Hadits ini juga telah diriwayatkan oleh [Amr bin Dinar] dari [Sa'id bin Al Huwairits] dan [Ibnu Abbas]. Dan Ali bin Al Madini berkata; Yahya bin Sa'id berkata, \"Sufyan Ats Tsauri tidak suka mencuci tangan sebelum makan. Dan ia juga tidak suka bila ada roti yang diletakkan di bahwa piring yang besar.\""},"1771":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا الْعَلَاءُ بْنُ الْفَضْلِ بْنِ عَبْدِ الْمَلِكِ بْنِ أَبِي سَوِيَّةَ أَبُو الْهُذَيْلِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عِكْرَاشٍ عَنْ أَبِيهِ عِكْرَاشِ بْنِ ذُؤَيْبٍ قَالَبَعَثَنِي بَنُو مُرَّةَ بْنِ عُبَيْدٍ بِصَدَقَاتِ أَمْوَالِهِمْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدِمْتُ عَلَيْهِ الْمَدِينَةَ فَوَجَدْتُهُ جَالِسًا بَيْنَ الْمُهَاجِرِينَ وَالْأَنْصَارِ قَالَ ثُمَّ أَخَذَ بِيَدِي فَانْطَلَقَ بِي إِلَى بَيْتِ أُمِّ سَلَمَةَ فَقَالَ هَلْ مِنْ طَعَامٍ فَأُتِينَا بِجَفْنَةٍ كَثِيرَةِ الثَّرِيدِ وَالْوَذْرِ وَأَقْبَلْنَا نَأْكُلُ مِنْهَا فَخَبَطْتُ بِيَدِي مِنْ نَوَاحِيهَا وَأَكَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ بَيْنِ يَدَيْهِ فَقَبَضَ بِيَدِهِ الْيُسْرَى عَلَى يَدِي الْيُمْنَى ثُمَّ قَالَ يَا عِكْرَاشُ كُلْ مِنْ مَوْضِعٍ وَاحِدٍ فَإِنَّهُ طَعَامٌ وَاحِدٌ ثُمَّ أُتِينَا بِطَبَقٍ فِيهِ أَلْوَانُ الرُّطَبِ أَوْ مِنْ أَلْوَانِ الرُّطَبِ عُبَيْدُ اللَّهِ شَكَّ قَالَ فَجَعَلْتُ آكُلُ مِنْ بَيْنِ يَدَيَّ وَجَالَتْ يَدُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الطَّبَقِ وَقَالَ يَا عِكْرَاشُ كُلْ مِنْ حَيْثُ شِئْتَ فَإِنَّهُ غَيْرُ لَوْنٍ وَاحِدٍ ثُمَّ أُتِينَا بِمَاءٍ فَغَسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ وَمَسَحَ بِبَلَلِ كَفَّيْهِ وَجْهَهُ وَذِرَاعَيْهِ وَرَأْسَهُ وَقَالَ يَا عِكْرَاشُ هَذَا الْوُضُوءُ مِمَّا غَيَّرَتْ النَّارُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْعَلَاءِ بْنِ الْفَضْلِ وَقَدْ تَفَرَّدَ الْعَلَاءُ بِهَذَا الْحَدِيثِ وَلَا نَعْرِفُ لِعِكْرَاشٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Al Ala` bin Al Fadl bin Abdul Malik bin Sawiyyah Abul Hudzail], telah menceritakan kepada kami [Ubaidullah bin Ikrasy] dari [bapaknya] Ikrasy bin Dzu`aib, ia berkata; Banu Murrah mengutusku untuk menyerahkan zakat harta mereka kepada Nabi shallallahu 'alaihi wasallam, lalu aku sampai di Madinah dan aku mendapati beliau sedang duduk diantara kaum Muhajirin dan Anshar. Kemudian Rasulullah shallallahu 'alaihi wasallam memegang tanganku dan membawaku menuju rumahnya Ummu Salamah, Nabi bertanya: \"Apakah kalian memiliki makanan?\" Kemudian dihidangkan kepada kami sepiring tsarid (makanan dari daging dan roti), lalu kami memakannya dan aku mengambil makanan dari semua sudut piring dan Rasulullah shallallahu 'alaihi wasallam makan tsarid yang dihadapan beliau, lantas tangannya yang kiri memegangi tangan kanan saya, Kemudian bersabda: \"Wahai Ikrasy, makanlah dari satu tempat karena dia hanya satu jenis makanan.\" Kemudian dihidangkan untuk kami dengan piring yang penuh dengan korma basah, lalu aku memakan hanya dari bagian yang ada dihadapanku namun tangan Rasulullah shallallaahu 'alaihi wa sallam mengambil dari semua bagian piring sambil berkata: \"Wahai 'Ikrasy, makanlah dari tempat yang kamu kehendaki karena dia bukan satu jenis makanan.\" Kemudian didatangkan air kepada kami lalu Rasulullah shallallaahu 'alaihi wa sallam mencuci tangannya dan membasuh telapak tangan, wajah, lengan dan kepalanya, lalu berkata: \"Wahai Ikrasy, wudhu ini (dilakukan) karena kita memakan makanan yang dibakar dengan api (dimasak).\" Berkata Abu Isa: Ini merupakan hadits gharib tidak kami ketahui kecuali dari haditsnya Al 'Allaa' bin Fadl dan 'Allaa' meriwayatkannya sendiri dan kami tidak mengtahui Ikrasy memiliki hadits dari Nabi shallallahu 'alaihi wasallam selain hadits ini."},"1772":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ أَبِي طَالُوتَ قَالَدَخَلْتُ عَلَى أَنَسِ بْنِ مَالِكٍ وَهُوَ يَأْكُلُ الْقَرْعَ وَهُوَ يَقُولُ يَا لَكِ شَجَرَةً مَا أَحَبَّكِ إِلَيَّ لِحُبِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِيَّاكِقَالَ وَفِي الْبَاب عَنْ حَكِيمِ بْنِ جَابِرٍ عَنْ أَبِيهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Laits] dari [Mu'awiyah bin Shalih] dari [Abu Thalut] ia berkata; Aku pernah menemui [Anas bin Malik]. Saat itu, ia sedang makan buah labu seraya berkata, \"Wahai buah, sungguh aku begitu menyukaimu, karena kesukaan Rasulullah shallallahu 'alaihi wasallam terhadapmu.\" Hadits semakna juga diriwayatkan dari Hakim bin Jabir, dari bapaknya. Abu Isa berkata; Ini adalah hadits gharib ditinjau dari jalur ini."},"1773":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَيْمُونٍ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنِي مَالِكُ بْنُ أَنَسٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ فِي الصَّحْفَةِ يَعْنِي الدُّبَّاءَ فَلَا أَزَالُ أُحِبُّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَنَسٍ وَرُوِيَ أَنَّهُ رَأَى الدُّبَّاءَ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ مَا هَذَا قَالَ هَذَا الدُّبَّاءُ نُكَثِّرُ بِهِ طَعَامَنَا","id":"Telah menceritakan kepada kami [Muhammad bin Maimun Al Makki], telah menceritakan kepada kami [Sufyan bin Uyainah], telah menceritakan kepadaku [Malik bin Anas] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] ia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam mencari-cari labu di dalam shahfah (piring besar), hingga aku pun menyukainya.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Hadits ini juga telah diriwayatkan oleh lebih dari satu jalur dari Anas. Dan telah diriwayatkan bahwasanya; Ia pernah melihat buah labu di hadapan Rasulullah shallallahu 'alaihi wasallam, maka ia pun bertanya, \"Apa ini?\" beliau menjawab: \"Ini adalah buah labu. Kami menggunakannnya untuk memperbanyak makanan kami.\""},"1774":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا الزَّيْتَ وَادَّهِنُوا بِهِ فَإِنَّهُ مِنْ شَجَرَةٍ مُبَارَكَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّزَّاقِ عَنْ مَعْمَرٍ وَكَانَ عَبْدُ الرَّزَّاقِ يَضْطَرِبُ فِي رِوَايَةِ هَذَا الْحَدِيثِ فَرُبَّمَا ذَكَرَ فِيهِ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُبَّمَا رَوَاهُ عَلَى الشَّكِّ فَقَالَ أَحْسَبُهُ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُبَّمَا قَالَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا حَدَّثَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ مَعْبَدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعَمَرٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ عُمَرَ","id":"Telah menceritakan kepada kami [Yahya bin Musa], telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Zaid bin Aslam] dari [bapaknya] dari [Umar bin Al Khaththab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Makanlah minyak zaitun dan berminyaklah dengannya (pergunakan untuk selain makan), karena dia dihasilkan dari pohon yang diberkahi.\" Berkata Abu 'Isa: Ini merupakan hadits yang tidak kami ketahui kecuali dari haditsnya Abdurrazzaq dari Ma'mar, dan Abdurrazzaq mengalami Idlthirab dalam meriwayatkan hadis ini, terkadang dia menyebutkan dari Umar dari Nabi shallallahu 'alaihi wasallam dan terkadang meriwayatkannya dengan ragu-ragu dengan berkata, \"Pekiraan saya, diriwayatkan dari Umar dari Nabi shallallahu 'alaihi wasallam.\" Atau ia berkata: \"Dari Zaid bin Aslam dari bapaknya dari Nabi shallallahu 'alaihi wasallam secara mursal. Telah menceritakan kepada kami [Abu Dawud Sulaiman bin Ma'bad], telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Zaid bin Aslam] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam semisalnya, namun di dalam sanadnya ia tidak menyebutkan; Dari Umar."},"1775":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ رَجُلٍ يُقَالُ لَهُ عَطَاءٌ مِنْ أَهْلِ الشَّامِ عَنْ أَبِي أَسِيدٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا الزَّيْتَ وَادَّهِنُوا بِهِ فَإِنَّهُ مِنْ شَجَرَةٍ مُبَارَكَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Ahmad Az Zubairi] dan [Abu Nu'aim] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Abdullahh bin Isa] dari [seorang laki-laki] yang biasa dipanggil Atha, dan ia berasal dari Syam, dari [Abu Sa'id] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah Az Zait dan minyakilah (rambut kalian) dengannya, karena ia berasal dari pohon yang diberkahi.\" Abu Isa berkata; Ini adalah hadits gharib ditinjau dari jalur ini. Kami hanya mengetahuinya dari haditsnya Sufyan, dari Abdullah bin Isa."},"1776":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ يُخْبِرُهُمْ ذَاكَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَفَى أَحَدَكُمْ خَادِمُهُ طَعَامَهُ حَرَّهُ وَدُخَانَهُ فَلْيَأْخُذْ بِيَدِهِ فَلْيُقْعِدْهُ مَعَهُ فَإِنْ أَبَى فَلْيَأْخُذْ لُقْمَةً فَلْيُطْعِمْهَا إِيَّاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو خَالِدٍ وَالِدُ إِسْمَعِيلَ اسْمُهُ سَعْدٌ","id":"Telah menceritakan kepada kami [Nashr bin Ali], telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Abu Khalid] dari [bapaknya] dari [Abu Hurairah] ia mengabarkan kepadanya dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika pelayan salah seorang dari kalian telah menyediakan makanan untuknya, dan makanan itu masih hangat dan berasap, maka hendaklah ia mengambil tangan pelayannya dan duduk bersamanya, jika pelayan itu tidak mau, hendaklah ia mengambil bagian dari makanan itu lalu memberikan kepadanya.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Abu Khalid adalah bapaknya Isma'il, namanya adalah Sa'd."},"1777":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ حَمَّادٍ الْمَعْنِيُّ الْبَصْرِيُّ حَدَّثَنَا عُثْمَانُ بْنُ عَبْدِ الرَّحْمَنِ الْجُمَحِيُّ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ وَاضْرِبُوا الْهَامَ تُورَثُوا الْجِنَانَقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عُمَرَ وَأَنَسٍ وَعَبْدِ اللَّهِ بْنِ سَلَامٍ وَعَبْدِ الرَّحْمَنِ بْنِ عَائِشَ وَشُرَيْحِ بْنِ هَانِئٍ عَنْ أَبِيهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Yusuf bin Hammad Al Ma'niy Al Bashari], telah menceritakan kepada kami [Utsman bin Abdurrahman Al Jumahi] dari [Muhammad bin Ziyad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tebarkanlah salam, berilah makanan dan tebaslah leher-leher orang kafir (berjihad), niscaya kalian akan mewarisi Al Janan (surga yang dijanjikan bagi orang-orang yang bertakwa).\" Hadits semakna juga diriwayatkan dari Abdullah bin Amru, Ibnu Umar, Anas, Abdullah bin Salam, Abdurrahman bin A`isy dan Syuraih bin Hani` dari bapaknya. Abu Isa berkata; Ini adalah hadits Hasan Gharib dari haditsnya Ibnu Ziyad dari Abu Hurairah."},"1778":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْبُدُوا الرَّحْمَنَ وَأَطْعِمُوا الطَّعَامَ وَأَفْشُوا السَّلَامَ تَدْخُلُوا الْجَنَّةَ بِسَلَامٍقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abul Ahwash] dari [Atha` bin Sa`ib] dari [bapaknya] dari [Abdullahbin Amru] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beribadahlah kalian kepada Ar Rahman, berilah makanan, dan tebarkanlah salam, niscaya kalian akan masuk surga dengan selamat.\" Ini adalah hadits hasan shahih."},"1779":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا مُحَمَّدُ بْنُ يَعْلَى الْكُوفِيُّ حَدَّثَنَا عَنْبَسَةُ بْنُ عَبْدِ الرَّحْمَنِ الْقُرَشِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عَلَّاقٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَشَّوْا وَلَوْ بِكَفٍّ مِنْ حَشَفٍ فَإِنَّ تَرْكَ الْعَشَاءِ مَهْرَمَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ مُنْكَرٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَعَنْبَسَةُ يُضَعَّفُ فِي الْحَدِيثِ وَعَبْدُ الْمَلِكِ بْنِ عَلَّاقٍ مَجْهُولٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa], telah menceritakan kepada kami [Muhammad bin Ya'la Al Kufi], telah menceritakan kepada kami [Anbasah bin Abdurrahman Al Qurasyi] dari [Abdul Malik bin Allaq] dari [Anas bin Malik] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Makan malamlah meskipun hanya dengan segenggam korma jelek, karena meninggalkan makan malam dapat melemahkan badan.\" Berkata Abu 'Isa: Ini merupakan hadits Munkar tidak kami ketahui kecuali dari jalur ini dan Anbasah didla'ifkan dalam periwayatan hadits serta Abdul Malik bin 'Allaq adalah seorang yang majhul (tidak diketahui)."},"1780":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ الْهَاشِمِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَأَنَّهُ دَخَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ طَعَامٌ قَالَ ادْنُ يَا بُنَيَّ وَسَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَقَالَ أَبُو عِيسَى وَقَدْ رُوِيَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِي وَجْزَةَ السَّعْدِيِّ عَنْ رَجُلٍ مِنْ مُزَيْنَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ وَقَدْ اخْتَلَفَ أَصْحَابُ هِشَامِ بْنِ عُرْوَةَ فِي رِوَايَةِ هَذَا الْحَدِيثِ وَأَبُو وَجْزَةَ السَّعْدِيُّ اسْمُهُ يَزِيدُ بْنُ عُبَيْدٍ","id":"Telah menceritakan kepada kami [Abdullah bin Ash Shabah Al Hasyimi], telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Hisyam bin Urwah] dari [bapaknya] dari [Umar bin Abu Salamah] bahwa ia pernah menemui Rasulullah shallallahu 'alaihi wasallam dan pada saat itu, di sisi beliau terdapat makanan. Beliau pun bersabda: \"Mendekatlah wahai anakku, sebutlah nama Allah dan makanlah dengan tangan kananmu, serta mulailah menyantap makanan yang terdekat (dari kamu).\" Abu Isa berkata; Dan juga telah diriwayatkan dari [Hisyam bin Urwah] dari [Abu Wajzah As Sa'di] dari [seorang laki] dari Muzainah, dari [Umar bin Abu Salamah]. Dan para sahabat Hisyam bin Urwah telah berselisih mengenai periwayatan hadits ini. Abu Wajzah As Sa'di namanya adalah Yazid bin Ubaid."},"1781":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ الْعُقَيْلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أُمِّ كُلْثُومٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَحَدُكُمْ طَعَامًا فَلْيَقُلْ بِسْمِ اللَّهِ فَإِنْ نَسِيَ فِي أَوَّلِهِ فَلْيَقُلْ بِسْمِ اللَّهِ فِي أَوَّلِهِ وَآخِرِهِوَبِهَذَا الْإِسْنَادِ عَنْ عَائِشَةَ قَالَتْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ طَعَامًا فِي سِتَّةٍ مِنْ أَصْحَابِهِ فَجَاءَ أَعْرَابِيٌّ فَأَكَلَهُ بِلُقْمَتَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ لَوْ سَمَّى لَكَفَاكُمْ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأُمُّ كُلْثُومٍ هِيَ بِنْتُ مُحَمَّدِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Muhammad bin Aban], telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Hisyam Ad Dastuwa`i] dari [Budail bin Maisarah Al Uqaili] dari [Abdullah bin Ubaid bin Umair] dari [Ummu Kultsum] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian memakan makanan, maka ucapkanlah, 'BISMILLAH (Dengan menyebut nama Allah).' Dan jika ia lupa (mengucapkannya) di awal, maka hendaklah ia mengucapkan: 'BISMILLAHI FI AWWALIHI WA AKHIRIHI (Dengan menyebut Nama Allah, di awal dan di akhirnya).'\" Dengan isnad ini juga telah diriwayatkan dari Aisyah, ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah makan makanan berserta enam orang dari para sahabatnya. Lalu datanglah seorang badui, dan langsung makan dua suap, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya ia menyebut nama Allah, niscaya makanan itu akan cukup bagi kalian.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Ummu Kultsum adalah anak perempuan Muhammad bin Abu Bakar Ash Shiddiq radliallahu 'anhu."},"1782":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَعْقُوبُ بْنُ الْوَلِيدِ الْمَدَنِيُّ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّيْطَانَ حَسَّاسٌ لَحَّاسٌ فَاحْذَرُوهُ عَلَى أَنْفُسِكُمْ مَنْ بَاتَ وَفِي يَدِهِ رِيحُ غَمَرٍ فَأَصَابَهُ شَيْءٌ فَلَا يَلُومَنَّ إِلَّا نَفْسَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ مِنْ حَدِيثِ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Ya'qub bin Al Walid Al Madani] dari [Ibnu Abu Dzi`b] dari [Al Maqburi] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setan itu adalah perasa dan penjilat, karena itu berhati-hati dan jagalah diri kalian darinya. Siapa yang di tangannya masih terdapat bau lemak daging, lalu ia tertimpa sesuatu, maka janganlah ia mencela siapa pun kecuali kepada dirinya sendirinya.\" Abu Isa berkata; Ini adalah hadits hasan gharib bila ditinjau dari jalur ini. Dan telah diriwayatkan pula dari haditsnya [Suhail bin Abu Shalih], dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"1783":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ إِسْحَقَ الْبَغْدَادِيُّ الصَّاغَانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ الْمَدَائِنِيُّ حَدَّثَنَا مَنْصُورُ بْنُ أَبِي الْأَسْوَدِ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاتَ وَفِي يَدِهِ رِيحُ غَمَرٍ فَأَصَابَهُ شَيْءٌ فَلَا يَلُومَنَّ إِلَّا نَفْسَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ الْأَعْمَشِ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Bakr Muhammad bin Ishaq Al Baghdadi Ash Shaghani], telah menceritakan kepada kami [Muhammad bin Ja'far Al Mada`ini], telah menceritakan kepada kami [Manshur bin Abul Aswad] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang bermalam sementara di tangannya masih terdapat bau lemak daging, sehingga ia tertimpa sesuatu, maka janganlah ia mencela siapa pun kecuali dirinya sendiri.\" Abu Isa berkata; Ini adalah hadits hasan gharib, kami tidak mengetahuinya dari hadits Al A'masy kecuali dari jalur ini."},"1784":{"ar":"حَدَّثَنَا أَبُو زَكَرِيَّا يَحْيَى بْنُ دُرُسْتَ الْبَصْرِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ مُسْكِرٍ حَرَامٌ وَمَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا فَمَاتَ وَهُوَ يُدْمِنُهَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عَبَّاسٍ وَعُبَادَةَ وَأَبِي مَالِكٍ الْأَشْعَرِيِّ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُمَرَ حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ مَوْقُوفًا فَلَمْ يَرْفَعْهُ","id":"Telah menceritakan kepada kami [Abu Zakariya Yahya bin Duursta Al Bashari], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayub] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah khamer, dan setiap yang memabukkan itu adalah haram. Siapa yang meminum khamer lalu ia meninggal dalam keadaan kecanduan khamer, maka ia tidak akan meminumnya di akhirat.\" Hadits semakna juga diriwayatkan dari Abu Hurairah, Abu Sa'id, Abdullah bin Amr, Ibnu Abbas, Ubadah dan Abu Malik Al Asy'ari. Abu Isa berkata; Haditsnya Ibnu Umar adalah hasan shahih. Dan telah diriwayatkan pula oleh lebih dari satu dari Nafi' dari Ibnu Umar, dari Nabi shallallahu 'alaihi wasallam. Dan telah diriwayatkan oleh Malik bin Anas dari Nafi', dari Ibnu Umar secara Mauquf, dan ia tidak memarfu'kannya."},"1785":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أَبِيهِ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَرِبَ الْخَمْرَ لَمْ يَقْبَلْ اللَّهُ لَهُ صَلَاةً أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَإِنْ عَادَ لَمْ يَقْبَلْ اللَّهُ لَهُ صَلَاةً أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَإِنْ عَادَ لَمْ يَقْبَلْ اللَّهُ لَهُ صَلَاةً أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَإِنْ عَادَ الرَّابِعَةَ لَمْ يَقْبَلْ اللَّهُ لَهُ صَلَاةً أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ لَمْ يَتُبْ اللَّهُ عَلَيْهِ وَسَقَاهُ مِنْ نَهْرِ الْخَبَالِ قِيلَ يَا أَبَا عَبْدِ الرَّحْمَنِ وَمَا نَهْرُ الْخَبَالِ قَالَ نَهْرٌ مِنْ صَدِيدِ أَهْلِ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ نَحْوُ هَذَا عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Atha` bin As Sa`ib] dari [Abdullah bin Umair] dari [bapaknya] ia berkata; [Abdullah bin Umar] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang meminum khamer, maka Allah tidak akan menerima shalatnya selama empat puluh hari, jika ia bertaubat, maka Allah akan menerima taubatnya. Akan tetapi, jika ia kembali melakukannya, maka Allah tidak akan menerima shalatnya selama empat puluh hari, jika ia bertaubat, maka Allah akan menerima taubatnya, namun jika ia kembali lagi melakukannya, maka Allah tidak akan menerima lagi shalatnya selama empat puluh hari, bila ia bertaubat Allah akan menerima taubatnya. Apabila ia kembali melakukannya pada kali keempat, maka Allah tidak menerima shalatnya selama empat puluh hari. Dan setelah itu, jika ia bertaubat, Allah tidak akan menerima taubatnya, dan ia akan diberi minum dari sungai Khabal.\" kemudian ditanyakan, \"Wahai Abu Abdurrahman, apakah itu sungai Al Khabal?\" ia menjawab, \"Yaitu sungai nanah dari penghuni neraka.\" Abu Isa berkata; Ini adalah hadits Hasan. Dan telah diriwayatkan pula semisal hadits ini dari Abdullah bin Amr dan Ibnu Abbas dari Nabi shallallahu 'alaihi wasallam."},"1786":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْبِتْعِ فَقَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Musa Al Anshari], telah menceritakan kepada kami [Ma'n], telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Abu Salamah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam pernah ditanya tentang Al Bit (sejenis minuman yang terbuat dari madu), maka beliau menjawab: \"Setiap minuman yang dapat memabukkan adalah haram.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1787":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ الْكُوفِيُّ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ مُسْكِرٍ حَرَامٌقَالَ وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَابْنِ مَسْعُودٍ وَأَنَسٍ وَأَبِي سَعِيدٍ وَأَبِي مُوسَى وَالْأَشَجِّ الْعُصَرِيِّ وَدَيْلَمَ وَمَيْمُونَةَ وَابْنِ عَبَّاسٍ وَقَيْسِ بْنِ سَعْدٍ وَالنُّعْمَانِ بْنِ بَشِيرٍ وَمُعَاوِيَةَ وَوَائِلِ بْنِ حُجْرٍ وَقُرَّةَ الْمُزَنِيِّ وعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ وَأُمِّ سَلَمَةَ وَبُرَيْدَةَ وَأَبِي هُرَيْرَةَ وَعَائِشَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رُوِيَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَكِلَاهُمَا صَحِيحٌ رَوَاهُ غَيْرُ وَاحِدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَعَنْ أَبِي سَلَمَةَ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ubaid bin Asbath bin Muhammad Al Qurasyi Al Kufi] dan [Abu Sa'id Al Asyaj] keduanya berkata, Telah menceritakan kepada kami [Abdullah bin Idris] dri [Muhammad bin Amr] dari [Abu Salamah] dari [Ibnu Umar] ia berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram.\" Hadits semakna juga diriwayatkan dari Amr, Ali, Ibnu Mas'ud, Anas, Abu Sa'id, Abu Musa Al Asyajj Al Ushari, Dailam, Maimunah, Ibnu Abbas, Qais bin Sa'd, An Nu'man bin Basyir, dan Mu'awiyah, Wa`il bin Hujr, Qurrah Al Muzani, Abdullah bin Mughaffal, Ummu Salamah, Buraidah, Abu Hurairah dan Aisyah. Abu Isa berkata; Ini adalah hadits Hasan, dan telah diriwayatkan pula dari Abu Salamah dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam semisalnya, dan keduanya adalah Shahih. Dan hadits ini telah diriwayatkan pula lebih dari seorang dari Muhammad bin Amru dari Abu Salamah dari Abu Hurairah, dari Nabi shallallahu 'alaihi wasallam semisalnya. Dan dari Abu Salamah dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam."},"1788":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ دَاوُدَ بْنِ بَكْرِ بْنِ أَبِي الْفُرَاتِ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَسْكَرَ كَثِيرُهُ فَقَلِيلُهُ حَرَامٌقَالَ وَفِي الْبَاب عَنْ سَعْدٍ وَعَائِشَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَابْنِ عُمَرَ وَخَوَّاتِ بْنِ جُبَيْرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ جَابِرٍ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Isma'il bin Ja'far] -dalam riwayat lain- Dan telah menceritakan kepada kami [Ali bin Hujr], telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Dawud bin Bakr bin Abul Furat] dari [Ibnul Munkadir] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang memabukkan, maka sedikit dan banyaknya adalah haram.\" Hadits semakna juga diriwayatkan dari Sa'd, Aisyah, Abdullah bin Amru, Ibnu Umar dan Khawwat bin Jubair. Abu Isa berkata; Ini adalah hadits hasan gharib dari haditsnya Jabir."},"1789":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مَهْدِيِّ بْنِ مَيْمُونٍ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُعَاوِيَةَ الْجُمَحِيُّ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ الْمَعْنَى وَاحِدٌ عَنْ أَبِي عُثْمَانَ الْأَنْصَارِيِّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ حَرَامٌ مَا أَسْكَرَ الْفَرَقُ مِنْهُ فَمِلْءُ الْكَفِّ مِنْهُ حَرَامٌقَالَ أَبُو عِيسَى قَالَ أَحَدُهُمَا فِي حَدِيثِهِ الْحَسْوَةُ مِنْهُ حَرَامٌ قَالَ هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَاهُ لَيْثُ بْنُ أَبِي سُلَيْمٍ وَالرَّبِيعُ بْنُ صَبِيحٍ عَنْ أَبِي عُثْمَانَ الْأَنْصَارِيِّ نَحْوَ رِوَايَةِ مَهْدِيِّ بْنِ مَيْمُونٍ وَأَبُو عُثْمَانَ الْأَنْصَارِيُّ اسْمُهُ عَمْرُو بْنُ سَالِمٍ وَيُقَالُ عُمَرُ بْنُ سَالِمٍ أَيْضًا","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] dari [Hisyam bin Hassan] dari [Mahdi bin Maimun] -dalam riwayat lain- Dan telah menceritakan kepada kami [Abdullah bin Mu'awiyah Al Jumahi], telah menceritakan kepada kami [Mahdi bin Maimun] maknanya satu, dari [Abu Utsman Al Anshari] dari [Al Qasim bin Muhammad] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap yang memabukkan adalah haram, jika satu Faraq (tiga sha' atau enam belas liter) darinya memabukkan, maka sepenuh telapak tangannya juga haram.\" Abu Isa berkata; Salah seorang dari keduanya berkata di dalam haditsnya; \"Seteguk darinya adalah haram.\" Hadits ini adalah Hasan. Dan telah diriwayatkan pula oleh [Al Laits bin Abu Sulaim] dan [Ar Rabi' bin Shabih] dari [Abu Utsman Al Anshari] sebagaimana riwayatnya Mahdi bin Maimun dan Abu Utsman Al Anshari namanya adalah Amr bin Salim, dan dipanggil pula dengan nama Umar bin Salim."},"1790":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا ابْنُ عُلَيَّةَ وَيَزِيدُ بْنُ هَارُونَ قَالَا أَخْبَرَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ طَاوُسٍأَنَّ رَجُلًا أَتَى ابْنَ عُمَرَ فَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ نَعَمْفَقَالَ طَاوُسٌ وَاللَّهِ إِنِّي سَمِعْتُهُ مِنْهُ قَالَ وَفِي الْبَاب عَنْ ابْنِ أَبِي أَوْفَى وَأَبِي سَعِيدٍ وَسُوَيْدٍ وَعَائِشَةَ وَابْنِ الزُّبَيْرِ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Ibnu Ulayyah] dan [Yazid bin Harun] keduanya berkata, Telah mengabarkan kepada kami [Sulaiman At Taimi] dari [Thawus] bahwa seorang laki-laki mendatangi [Ibnu Umar] dan bertanya, \"Apakah Nabi shallallahu 'alaihi wasallam melarang Nabidz Al Jarr?\" Ibnu Umar menjawab, \"Ya.\" Thawus berkata, \"Demi Allah, aku telah mendengarnya darinya.\" Hadits semakna juga diriwayatkan dari Ibnu Abu Aufa, Abu Sa'id, Suwaid, Aisyah, Ibnu Zubair dan Ibnu Abbas. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1791":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَال سَمِعْتُ زَاذَانَ يَقُولُسَأَلْتُ ابْنَ عُمَرَ عَمَّا نَهَى عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَوْعِيَةِ أَخْبِرْنَاهُ بِلُغَتِكُمْ وَفَسِّرْهُ لَنَا بِلُغَتِنَا فَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَنْتَمَةِ وَهِيَ الْجَرَّةُ وَنَهَى عَنْ الدُّبَّاءِ وَهِيَ الْقَرْعَةُ وَنَهَى عَنْ النَّقِيرِ وَهُوَ أَصْلُ النَّخْلِ يُنْقَرُ نَقْرًا أَوْ يُنْسَجُ نَسْجًا وَنَهَى عَنْ الْمُزَفَّتِ وَهِيَ الْمُقَيَّرُ وَأَمَرَ أَنْ يُنْبَذَ فِي الْأَسْقِيَةِقَالَ وَفِي الْبَاب عَنْ عُمَرَ وَعَلِيٍّ وَابْنِ عَبَّاسٍ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَعَبْدِ الرَّحْمَنِ بْنِ يَعْمَرَ وَسَمُرَةَ وَأَنَسٍ وَعَائِشَةَ وَعِمْرَانَ بْنِ حُصَيْنٍ وَعَائِذِ بْنِ عَمْرٍو وَالْحَكَمِ الْغِفَارِيِّ وَمَيْمُونَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abu Dawud Ath Thayalisi], telah menceritakan kepada kami [Syu'bah] dari [Amr bin Murrah] ia berkata, saya mendengar [Zadzan] berkata; Aku pernah bertanya kepada [Ibnu Umar] tentang jenis minuman yang telah dilarang Rasulullah shallallahu 'alaihi wasallam, \"Kabarkanlah kepada kami dengan bahasa kalian, dan jelaskanlah kepada kami dengan bahasa kami.\" Ibnu Umar berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang, al hantamah yakni bejana (yang terbuat dari tanah dicampur gandum dan darah) untuk menaruh khamr, ad duba` yakni tengkorak kepala, an naqir yakni pohon kurma yang dipahat (hingga mati), dan beliau juga melarang al muzaffat tempat yang terbuat dari aspal dan memerintahkan untuk membuat nabidz pada bejana-bejana. Ia (Abu Isa) berkata dalam bab ini dari Umar, Ali, Ibnu Abbas, Abu Said, Abu Hurairah, Abdurrahman bin Ya'mar, Samurah, Anas, Aisyah, Imran bin Hushain, A`idz bin Amr, Hakam Al Ghifari, dan Maimunah. Abu Isa berkata, Hadits ini hasan shahih."},"1792":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَالْحَسَنُ بْنُ عَلِيٍّ وَمَحْمُودُ بْنُ غَيْلَانَ قَالُوا حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي كُنْتُ نَهَيْتُكُمْ عَنْ الظُّرُوفِ وَإِنَّ ظَرْفًا لَا يُحِلُّ شَيْئًا وَلَا يُحَرِّمُهُ وَكُلُّ مُسْكِرٍ حَرَامٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dan [Al Hasan bin Ali] dan [Mahmud bin Ghailan] mereka berkata; Telah menceritakan kepada kami [Abu Ashim] Telah menceritakan kepada kami [Sufyan] dari [Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku dahulu melarang kalian meminum nabidz yang disimpan dalam bejana-bajana terbuat dari kulit (yaitu dari Dubbaa', hantam dan Naqir) dan sesungguhnya bejana itu tidak dapat menghalalkan tidak juga dapat mengharamkan sesuatu. Dan setiap minuman yang memabukkan itu haram.\" Berkata Abu Isa: ini merupakan hadits hasan shahih."},"1793":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الظُّرُوفِ فَشَكَتْ إِلَيْهِ الْأَنْصَارُ فَقَالُوا لَيْسَ لَنَا وِعَاءٌ قَالَ فَلَا إِذَنْقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Dawud Al Hafari] dari [Sufyan] dari [Manshur] dari [Salim bin Abul Ja'd] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang untuk memakai bejana-bejana dari kulit, lantas kalangan Anshar mengadu kepada beliau seraya berkata, \"Kami tidak memiliki bejana selainnya.\" Beliau bersabda: \"Kalau begitu tidak dilarang.\" Hadits semakna diriwayatkan dari Ibnu Mas'ud, Abu Sa'id, Abu Hurairah dan Abdullah bin Umar. Berkata Abu 'Isa: Ini merupakan hadits hasan shahih."},"1794":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ الْبَصْرِيِّ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكُنَّا نَنْبِذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سِقَاءٍ تُوكَأُ فِي أَعْلَاهُ لَهُ عَزْلَاءُ نَنْبِذُهُ غُدْوَةً وَيَشْرَبُهُ عِشَاءً وَنَنْبِذُهُ عِشَاءً وَيَشْرَبُهُ غُدْوَةًقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَأَبِي سَعِيدٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ يُونُسَ بْنِ عُبَيْدٍ مِنْ غَيْرِ هَذَا الْوَجْهِ عَنْ عَائِشَةَ أَيْضًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Yunus bin Ubaid] dari [Al Hasan Al Bashri] dari [Ibunya] dari [Aisyah] ia berkata; \"Dahulu kami suka membuat nabidz untuk Rasulullah shallallaahu 'alaihi wa sallam di dalam sebuah bejana, bagian atasnya diikat dan dia memiliki lubang untuk keluar air. Kami membuatnya pada pagi hari lalu beliau meminumnya pada malam hari atau kami membuatnya di malam hari dan beliau meminumnya pada pagi hari.\" Hadits semakna diriwayatkan dari Jabir, Abu Sa'id dan Ibnu Abbas. Berkata Abu Isa: Ini merupakan hadits gharib tidak kami ketahui kecuali dari haditsnya Yunus bin Ubaid dari 'Aisyah juga namun melalui selain jalur ini."},"1795":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا إِسْرَائِيلُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُهَاجِرٍ عَنْ عَامِرٍ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْحِنْطَةِ خَمْرًا وَمِنْ الشَّعِيرِ خَمْرًا وَمِنْ التَّمْرِ خَمْرًا وَمِنْ الزَّبِيبِ خَمْرًا وَمِنْ الْعَسَلِ خَمْرًاقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ إِسْرَائِيلَ نَحْوَهُ وَرَوَى أَبُو حَيَّانَ التَّيْمِيُّ هَذَا الْحَدِيثَ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَ إِنَّ مِنْ الْحِنْطَةِ خَمْرًا فَذَكَرَ هَذَا الْحَدِيثَ حَدَّثَنَا بِذَلِكَ أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ أَبِي حَيَّانَ التَّيْمِيِّ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِ إِنَّ مِنْ الْحِنْطَةِ خَمْرًا بِهَذَا وَهَذَا أَصَحُّ مِنْ حَدِيثِ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ و قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ لَمْ يَكُنْ إِبْرَاهِيمُ بْنُ مُهَاجِرٍ بِالْقَوِيِّ الْحَدِيثِ وَقَدْ رُوِيَ مِنْ غَيْرِ وَجْهٍ أَيْضًا عَنْ النُّعْمَانِ بْنِ بَشِيرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Muhammad bin Yusuf] Telah menceritakan kepada kami [Isra`il], telah menceritakan kepada kami [Ibrahim bin Muhajir] dari [Amir Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya dari gandum yang bagus dan putih, dari gandum biasa, dari korma dan dari anggur, serta dari madu dapat dibuat khamr (arak).\" Hadits semakna juga diriwayatkan dari Abu Hurairah. Abu Isa berkata; Ini merupakan hadits gharib. Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal], telah menceritakan kepada kami [Yahya bin Adam] dari [Isra`il] semisalnya. [Abu Hayyan] juga telah meriwayatkan hadits ini dari [Asy Sya'bi] dari [Ibnu Umar] dari [Umar] ia berkata; \"Sesungguhnya dari biji gandum dapat dibuat khamr.\" Lalu menuturkan hadits ini. Demikian pula, telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Abdullah bin Idris] dari [Abu Hayyan At Taimi] dari [Asy Sya'bi] dari [Ibnu Umar] dari [Umar bin Al Khaththab] ia berkata; \"Sesungguhnya dari biji gandum dapat dibuat khamr.\" Hadits ini lebih shahih daripada haditsnya Ibrahim bin Muhajir. Ali Al Madini berkata; Yahya bin Sa'id berkata; Ibrahim bin Muhajir bukan orang yang kuat dalam periwayatan hadits. Hadits ini telah diriwayatkan juga dari Nu'man bin Basyir melalui banyak jalur."},"1796":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا الْأَوْزَاعِيُّ وَعِكْرِمَةُ بْنُ عَمَّارٍ قَالَا حَدَّثَنَا أَبُو كَثِيرٍ السُّحَيْمِيُّ قَال سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةُ وَالْعِنَبَةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو كَثِيرٍ السُّحَيْمِيُّ هُوَ الْغُبَرِيُّ وَاسْمُهُ يَزِيدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ غُفَيْلَةَ وَرَوَى شُعْبَةُ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abu Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] Telah menceritakan kepada kami [Al Auza'i] dan [Ikrimah bin Ammar] keduanya berkata, Telah menceritakan kepada kami [Abu Katsir As Suhaimi] ia berkata, saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer itu berasal dari dua pohon ini, yaitu pohon kurma dan anggur.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Abu Katsir As Suhaimi adalah Al Ghubari, namanya adalah Yazid bin Abdurrahman bin Ghufailah. [Syu'bah] telah meriwayatkan hadits ini dari [Ikrimah bin Ammar]."},"1797":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُنْبَذَ الْبُسْرُ وَالرُّطَبُ جَمِيعًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Atha` bin Abu Rabah] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang untuk mencampuradukkan antara kurma yang belum masak dan kurma yang baru masak. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1798":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا جَرِيرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْبُسْرِ وَالتَّمْرِ أَنْ يُخْلَطَ بَيْنَهُمَا وَنَهَى عَنْ الزَّبِيبِ وَالتَّمْرِ أَنْ يُخْلَطَ بَيْنَهُمَا وَنَهَى عَنْ الْجِرَارِ أَنْ يُنْبَذَ فِيهَاقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَأَنَسٍ وَأَبِي قَتَادَةَ وَابْنِ عَبَّاسٍ وَأُمِّ سَلَمَةَ وَمَعْبَدِ بْنِ كَعْبٍ عَنْ أُمِّهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'], telah menceritakan kepada kami [Jarir] dari [Sulaiman At Taimi] dari [Abu Nadlrah] dari [Abu Sa'id] bahwa Nabi shallallahu 'alaihi wasallam melarang untuk mencampur antara buah kurma yang belum masak dengan kurma kering, demikian pula buah anggur dan kurma. Dan beliau juga melarang untuk mendiamkan (kurma atau anggur) dalam Al Jirar (tempayan air). Hadits semakna juga telah diriwayatkan dari Jabir, Anas, Abu Qatadah, Ibnu Abbas, Ummu Salamah dan Ma'bad bin Ka'b dari ibunya. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1799":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَال سَمِعْتُ ابْنَ أَبِى لَيْلَى يُحَدِّثُ أَنَّ حُذَيْفَةَاسْتَسْقَى فَأَتَاهُ إِنْسَانٌ بِإِنَاءٍ مِنْ فِضَّةٍ فَرَمَاهُ بِهِ وَقَالَ إِنِّي كُنْتُ قَدْ نَهَيْتُهُ فَأَبَى أَنْ يَنْتَهِيَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشُّرْبِ فِي آنِيَةِ الْفِضَّةِ وَالذَّهَبِ وَلُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَقَالَ هِيَ لَهُمْ فِي الدُّنْيَا وَلَكُمْ فِي الْآخِرَةِقَالَ وَفِي الْبَاب عَنْ أُمِّ سَلَمَةَ وَالْبَرَاءِ وَعَائِشَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata, saya mendengar [Ibnu Abu Laila] menceritakan bahwasanya; [Hudzaifah] menimba air, lalu seorang laki-laki membawakannya bejana yang terbuat dari perak, maka Huzaifah pun segera membuangnya kemudian ia berkata, \"Sungguh, saya telah melarangnya, namun ia enggan. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang minum dengan menggunakan bejana yang terbuat dari emas dan perak, kemudian beliau juga melarang untuk mengenakan kain sutera dan Ad Dibaj (pakaian yang terbuat kain sutera yang halus). Beliau bersabda: \"Sesungguhya kain sutera itu adalah untuk mereka (orang-orang kafir) di dunia, dan bagi kalian nanti kelak di akhirat.\" Hadits yang semakna juga diriwayatkan dari Ummu Salamah, Al Barra` dan Aisyah. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1800":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَشْرَبَ الرَّجُلُ قَائِمًا فَقِيلَ الْأَكْلُ قَالَ ذَاكَ أَشَدُّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sa'id bin Arubah] dari [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam telah melarang seseorang minum dalam keadaan berdiri. Kemudian ditanyakan kepada beliau, \"Bagaimana dengan makan?\" Beliau menjawab: \"Terlebih lagi dalam makan.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1801":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي مُسْلِمٍ الْجَذْمِيِّ عَنْ الْجَارُودِ بْنِ الْمُعَلَّىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشُّرْبِ قَائِمًاقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ وَأَنَسٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ حَسَنٌ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي مُسْلِمٍ عَنْ الْجَارُودِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرُوِيَ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ أَبِي مُسْلِمٍ عَنْ الْجَارُودِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ضَالَّةُ الْمُسْلِمِ حَرَقُ النَّارِ وَالْجَارُودُ هُوَ ابْنُ الْمُعَلَّى الْعَبْدِيُّ صَاحِبُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُقَالُ الْجَارُودُ بْنُ الْعَلَاءِ أَيْضًا وَالصَّحِيحُ ابْنُ الْمُعَلَّى","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Khalid bin Al Harits] dari [Sa'id] dari [Qatadah] dari [Abu Muslim Al Jadzmi] dari [Al Jarud bin Al Mu'alli] bahwa Nabi shallallahu 'alaihi wasallam melarang minum sambil berdiri. Hadits semakna juga diriwayatkan dari Abu Sa'id, Abu Hurairah dan Anas. Abu Isa berkata; Ini adalah hadits gharib hasan. Demikian juga yang diriwayatkan oleh lebih dari satu orang dari Sa'id dari Qatadah dari Muslim dari Al Jarud dari Nabi shallallahu 'alaihi wasallam. Dan telah diriwayatkan pula dari [Qatadah] dari [Yazid bin Abdullah bin Asy Syikhkhir] dari [Abu Muslim] dari [Al Jarud] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Harta benda seorang mukmin yang hilang, adalah bahan bakarnya api neraka.\" Al Jarud adalah Ibnul Mu'alla Al Abdi, yakni salah seorang sahabat Nabi shallallahu 'alaihi wasallam. Dan ia juga dipanggil Al Jarud bin Al 'Ala`, namun yang shahih adalah Ibnul Mu'alla."},"1802":{"ar":"حَدَّثَنَا أَبُو السَّائِبِ سَلْمُ بْنُ جُنَادَةَ الْكُوفِيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكُنَّا نَأْكُلُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَمْشِي وَنَشْرَبُ وَنَحْنُ قِيَامٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَرَوَى عِمْرَانُ بْنُ حُدَيْرٍ هَذَا الْحَدِيثَ عَنْ أَبِي الْبَزَرِيِّ عَنْ ابْنِ عُمَرَ وَأَبُو الْبَزَرِيِّ اسْمُهُ يَزِيدُ بْنُ عُطَارِدٍ","id":"Telah menceritakan kepada kami [Abu Sa`ib Salm bin Junadah Al Kufi], telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] ia berkata; Kami dahulu makan pada zaman Nabi shallallahu 'alaihi wasallam sambil berjalan dan kami minum sambil berdiri. Berkata Abu 'Isa: Ini merupakan hadits shahih gharib dari haditsnya Ubaidullah bin Umar dari Nafi' dari Ibnu Umar. Dan [Imran bin Hudair] meriwayatkan hadits ini dari [Abil Bazari] dari [Ibnu Umar] dan Abul Bazari bernama Yazid bin 'Utharid."},"1803":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ وَمُغِيرَةُ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ مِنْ زَمْزَمَ وَهُوَ قَائِمٌقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَسَعْدٍ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَائِشَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Husyaim] Telah menceritakan kepada kami [Ashim Al Ahwal] dan [Al Mughirah] dari [Asy Sya'bi] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam pernah minum air zamzam sambil berdiri. Hadits semakna juga diriwayatkan Ali, Sa'd, Abdullah bin Amr dan Aisyah. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1804":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ حُسَيْنٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْرَبُ قَائِمًا وَقَاعِدًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Husain Al Mu'allim] dari [Amr bin Syu'aib] dari [bapaknya] dari [kakeknya] ia berkata; Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam minum sambil berdiri dan juga pernah sambil duduk. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1805":{"ar":"حَدَّثَنَا قُتَيْبَةُ وَيُوسُفُ بْنُ حَمَّادٍ قَالَا حَدَّثَنَا عَبْدُ الْوَارِثِ بْنُ سَعِيدٍ عَنْ أَبِي عِصَامٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ ثَلَاثًا وَيَقُولُ هُوَ أَمْرَأُ وَأَرْوَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَاهُ هِشَامٌ الدَّسْتُوَائِيُّ عَنْ أَبِي عِصَامٍ عَنْ أَنَسٍ وَرَوَى عَزْرَةُ بْنُ ثَابِتٍ عَنْ ثُمَامَةَ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ ثَلَاثًا","id":"Telah menceritakan kepada kami [Qutaibah] dan [Yusuf bin Hammad] keduanya berkata, Telah menceritakan kepada kami [Abdul Warits bin Sa'id] dari [Abu Ashim] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bernafas tiga kali dalam bejana dan beliau bersabda: \"Yang demikian itu adalah lebih mudah mengalir (masuk) ke lambung dan juga lebih memuaskan.\" Abu Isa berkata; Ini adalah hadits hasan gharib. Dan juga telah diriwayatkan oleh [Ad Dastuwa`i], dari [Abu 'Isham] dari [Anas]. Dan 'Azrah bin Tsabit telah meriwayatkan dari Tsumamah, dari Anas bahwa Nabi shallallahu 'alaihi wasallam bernafas sebanyak tiga kali dalam bejana."},"1806":{"ar":"حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ الْأَنْصَارِيُّ عَنْ ثُمَامَةَ بْنِ أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ ثَلَاثًاقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Azrah bin Tsabit Al Anshari] dari [Tsumamah bin Anas] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bernafas sebanyak tiga kali dalam bejana. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1807":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ يَزِيدَ بْنِ سِنَانٍ الْجَزَرِيِّ عَنْ ابْنٍ لِعَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَشْرَبُوا وَاحِدًا كَشُرْبِ الْبَعِيرِ وَلَكِنْ اشْرَبُوا مَثْنَى وَثُلَاثَ وَسَمُّوا إِذَا أَنْتُمْ شَرِبْتُمْ وَاحْمَدُوا إِذَا أَنْتُمْ رَفَعْتُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَيَزِيدُ بْنُ سِنَانٍ الْجَزَرِيُّ هُوَ أَبُو فَرْوَةَ الرُّهَاوِيُّ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Waki'] dari [Yazid bin Sinan Al Jazari] dari [Ibnu Atha` bin Abu Rabah] dari [bapaknya] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian minum dengan sekali tegukan sekaligus seperti minumnya unta, akan tetapi minumlah dengan dua atau tiga kali tegukan dan bacalah basmalah jika kalian minum, serta (bacalah) hamdalah jika kalian mengangkat bejananya.\" Abu Isa berkata; Ini merupakan hadits gharib dan Yazid bin Sinan Al Jazari dia adalah Farwah Ar Ruhawi."},"1808":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ رِشْدِينَ بْنِ كُرَيْبٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا شَرِبَ تَنَفَّسَ مَرَّتَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ رِشْدِينَ بْنِ كُرَيْبٍ قَالَ وَسَأَلْتُ أَبَا مُحَمَّدٍ عَبْدَ اللَّهِ بْنَ عَبْدِ الرَّحْمَنِ عَنْ رِشْدِينَ بْنِ كُرَيْبٍ قُلْتُ هُوَ أَقْوَى أَمْ مُحَمَّدُ بْنُ كُرَيْبٍ فَقَالَ مَا أَقْرَبَهُمَا وَرِشْدِينُ بْنُ كُرَيْبٍ أَرْجَحُهُمَا عِنْدِي قَالَ وَسَأَلْتُ مُحَمَّدَ بْنَ إِسْمَعِيلَ عَنْ هَذَا فَقَالَ مُحَمَّدُ بْنُ كُرَيْبٍ أَرْجَحُ مِنْ رِشْدِينَ بْنِ كُرَيْبٍ وَالْقَوْلُ عِنْدِي مَا قَالَ أَبُو مُحَمَّدٍ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ رِشْدِينُ بْنُ كُرَيْبٍ أَرْجَحُ وَأَكْبَرُ وَقَدْ أَدْرَكَ ابْنَ عَبَّاسٍ وَرَآهُ وَهُمَا أَخَوَانِ وَعِنْدَهُمَا مَنَاكِيرُ","id":"Telah menceritakan kepada kami [Ali bin Khasyram], telah menceritakan kepada kami [Isa bin Yunus] dari [Risydin bin Kuraib] dari [bapaknya] dari [Ibnu Abbas] bahwasanya; \"Apabila Nabi shallallahu 'alaihi wasallam minum, beliau bernafas dua kali.\" Berkata Abu Isa; Ini merupakan hadits gharib tidak kami ketahui kecuali dari haditsnya Rusydin bin Kuraib. Dia berkata; Aku bertanya kepada Abu Muhammad, \"Apakah Abdullah bin Abdurrahman dari Rusydin bin Kuraib yang lebih kuat atau Muhammad bin Kuraib?\" Ia menjawab, \"Keduanya sangat berdekatan dan Rusydin bin Kuraib lebih rajih menurutku.\" Dan aku bertanya kepada Muhammad bin Isma'il tentang ini, dia menjawab, \"Muhammad bin Kuraib lebih rajih dari Rusydin bin Kuraib.\" Perkataan yang lebih kuat menurutku ialah apa yang dikatakan oleh Abu Muhammad Abdullah bin Abdurrahman bahwa Rusydin bin Kuraib lebih rajih dan lebih tua dan dia juga telah bertemu dengan Ibnu Abbas serta melihatnya, namun keduanya memiliki hadits-hadits munkar."},"1809":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَيُّوبَ وَهُوَ ابْنُ حَبِيبٍ أَنَّهُ سَمِعَ أَبَا الْمُثَنَّى الْجُهَنِيَّ يَذْكُرُ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّفْخِ فِي الشُّرْبِ فَقَالَ رَجُلٌ الْقَذَاةُ أَرَاهَا فِي الْإِنَاءِ قَالَ أَهْرِقْهَا قَالَ فَإِنِّي لَا أَرْوَى مِنْ نَفَسٍ وَاحِدٍ قَالَ فَأَبِنْ الْقَدَحَ إِذَنْ عَنْ فِيكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ali bin Khasyram], telah mengabarkan kepada kami [Isa bin Yunus] dari [Malik bin Anas] dari [Ayyub bin Habib] bahwa mendengar [Abu Al Mutsanna Al Juhanni] menyebutkan dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam melarang untuk meniup ke dalam minuman. Kemudian seroang laki-laki berkata, \"Lalu bagaimana bila aku melihat kotoran di dalam bejana?\" Beliau bersabda: \"Kalau begitu, tumpahkanlah.\" Ia berkata lagi, \"Sungguh, aku tidaklah puasa dengan sekali tarikan nafas.\" Beliau bersabda: \"Kalau begitu, jauhkanlah bejana (tempat untuk minum) dari mulutmu.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1810":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُتَنَفَّسَ فِي الْإِنَاءِ أَوْ يُنْفَخَ فِيهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abdul Karim Al Jazari] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam melarang untuk bernafas dalam bejana atau meniupnya. Berkata Abu 'Isa; Ini merupakan hadits hasan shahih."},"1811":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّه�� عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَرِبَ أَحَدُكُمْ فَلَا يَتَنَفَّسْ فِي الْإِنَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur], telah menceritakan kepada kami [Abdush Shamad bin Abdul Warits], telah menceritakan kepada kami [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian minum, maka janganlah ia bernafas di dalam bejana.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1812":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ رِوَايَةًأَنَّهُ نَهَى عَنْ اخْتِنَاثِ الْأَسْقِيَةِقَالَ وَفِي الْبَاب عَنْ جَابِرٍ وَابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Abu Sa'id] secara Riwayah, bahwa ia melarang Ikhtinatsul Asqiyah (menempelkan kedua bibir pada tepi bejana dan minum darinya). Hadits semakna juga diriwayatkan dari Jabir, Ibnu Abbas dan Abu Hurairah. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1813":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ عَنْ عِيسَى بْنِ عَبْدِ اللَّهِ بْنِ أُنَيْسٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ إِلَى قِرْبَةٍ مُعَلَّقَةٍ فَخَنَثَهَا ثُمَّ شَرِبَ مِنْ فِيهَاقَالَ وَفِي الْبَاب عَنْ أُمِّ سُلَيْمٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ لَيْسَ إِسْنَادُهُ بِصَحِيحٍ وَعَبْدُ اللَّهِ بْنُ عُمَرَ الْعُمَرِيُّ يُضَعَّفُ فِي الْحَدِيثِ وَلَا أَدْرِي سَمِعَ مِنْ عِيسَى أَمْ لَا","id":"Telah menceritakan kepada kami [Yahya bin Musa], telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Abdullah bin Umar] dari [Isa bin Abdullah bin Unais] dari [bapaknya] ia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berjalan mengambil ghirbah (bejana air terbuat dari kulit) yang tergantung kemudian mengeluarkan mulut bejana tersebut dan meminum langsung dari mulutnya.\" Hadits semakna diriwayatkan dari Ummu Sulaim. Berkata Abu Isa; Hadits ini sanadnya tidak shahih dan Abdullah bin Umar Al Umari seorang yang dha'if dalam periwayatan hadits dan aku tidak tahu apakah dia mendengar dari Isa apa tidak? "},"1814":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ بْنِ جَابِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمْرَةَ عَنْ جَدَّتِهِ كَبْشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَرِبَ مِنْ فِي قِرْبَةٍ مُعَلَّقَةٍ قَائِمًا فَقُمْتُ إِلَى فِيهَا فَقَطَعْتُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَيَزِيدُ بْنُ يَزِيدَ بْنِ جَابِرٍ هُوَ أَخُو عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ وَهُوَ أَقْدَمُ مِنْهُ مَوْتًا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Yazid bin Jabir] dari [Abdurrahman bin Abu Amrah] dari [neneknya] Kabsyah, berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah masuk ke rumahku dan minum dari mulut bejana yang tergantung sambil berdiri lalu aku mengambilnya dan memotong mulut bejana tersebut.\" Abu Isa berkata; Ini merupakan hadits hasan shahih gharib dan Yazid bin Yazid bin Jabir ialah saudaranya Abdurrahman bin Yazid bin Jabir dan dia lebih dahulu meninggal dari saudaranya."},"1815":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ قَالَ و حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَبَنٍ قَدْ شِيبَ بِمَاءٍ وَعَنْ يَمِينِهِ أَعْرَابِيٌّ وَعَنْ يَسَارِهِ أَبُو بَكْرٍ فَشَرِبَ ثُمَّ أَعْطَى الْأَعْرَابِيَّ وَقَالَ الْأَيْمَنَ فَالْأَيْمَنَقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَسَهْلِ بْنِ سَعْدٍ وَابْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ بُسْرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Anshari], telah menceritakan kepada kami [Ma'n] telah menceritakan kepada kami [Malik] ia berkata, Dan telah menceritakan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah disuguhkan susu yang telah dicampur dengan air. Di sebelah kanan beliau ada seorang A'rabi, dan di sebelah kiri ada Abu Bakar. Maka beliau pun meminum susu tersebut lalu memberikannya kepada laki-laki A'rabi itu seraya bersabda: \"Mulailah dari sebelah kanan dan ke sebelah kanan.\" Hadits semakna juga diriwayatkan dari Ibnu Abbas, Sahl bin Sa'd, Ibnu Umar dan Abdullah bin Busr. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1816":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَاقِي الْقَوْمِ آخِرُهُمْ شُرْبًاقَالَ وَفِي الْبَاب عَنْ ابْنِ أَبِي أَوْفَى قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit Al Bunani] dari [Abdullah bin Rabah] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang memberi minum suatu kaum, maka dialah yang terakhir kali minum.\" Hadits semakna diriwayatkan pula dari Ibnu Abu Aufa. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1817":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ أَحَبُّ الشَّرَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحُلْوَ الْبَارِدَقَالَ أَبُو عِيسَى هَكَذَا رَوَى غَيْرُ وَاحِدٍ عَنْ ابْنِ عُيَيْنَةَ مِثْلَ هَذَا عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ وَالصَّحِيحُ مَا رُوِيَ عَنْ الزُّهْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Ma'mar] dari [Zuhri] dari [Urwah] dari [Aisyah] ia berkata; Sesungguhnya minuman yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam adalah Al Hulwa Al Barid (manisan yang dingin). Abu Isa berkata; Beginilah yang diriwayatkan oleh lebih dari satu Rawi dari Az Zuhri dari Nabi shallallahu 'alaihi wasallam secara mursal."},"1818":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَعْمَرٌ وَيُونُسُ عَنْ الزُّهْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الشَّرَابِ أَطْيَبُ قَالَ الْحُلْوُ الْبَارِدُقَالَ أَبُو عِيسَى وَهَكَذَا رَوَى عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا وَهَذَا أَصَحُّ مِنْ حَدِيثِ ابْنِ عُيَيْنَةَ رَحِمَهُ اللَّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] Telah mengabarkan kepada kami [Ma'mar] dan [Yunus] dari [Az Zuhri] bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya, \"Minuman apakah yang paling baik?\" Beliau menjawab: \"Al Hulwa Al Barid (manisan yang dingin).\" Demikian pula yang telah diriwatkan oleh [Abdurrazzaq] dari [Ma'mar], dari [Az Zuhri], dari Nabi shallallahu 'alaihi wasallam, dan ini lebih shahih daripada haditsnya Ibnu Uyainah Rahimahullah."},"1819":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَخْبَرَنَا بَهْزُ بْنُ حَكِيمٍ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ أَبَرُّ قَالَ أُمَّكَ قَالَ قُلْتُ ثُمَّ مَنْ قَالَ أُمَّكَ قَالَ قُلْتُ ثُمَّ مَنْ قَالَ أُمَّكَ قَالَ قُلْتُ ثُمَّ مَنْ قَالَ ثُمَّ أَبَاكَ ثُمَّ الْأَقْرَبَ فَالْأَقْرَبَقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَائِشَةَ وَأَبِي الدَّرْدَاءِ قَالَ أَبُو عِيسَى وَبَهْزُ بْنُ حَكِيمٍ هُوَ أَبُو مُعَاوِيَةَ بْنُ حَيْدَةَ الْقُشَيْرِيُّ وَهَذَا حَدِيثٌ حَسَنٌ وَقَدْ تَكَلَّمَ شُعْبَةُ فِي بَهْزِ بْنِ حَكِيمٍ وَهُوَ ثِقَةٌ عِنْدَ أَهْلِ الْحَدِيثِ وَرَوَى عَنْهُ مَعْمَرٌ وَالثَّوْرِيُّ وَحَمَّادُ بْنُ سَلَمَةَ وَغَيْرُ وَاحِدٍ مِنْ الْأَئِمَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah mengabarkan kepada kami [Yahya bin Sa'id], telah mengabarkan kepada kami [Bahz bin Hakim], telah menceritakan kepadaku [bapakku] dari [kakekku] ia berkata; Aku bertanya, \"Wahai Rasulullah, siapakah yang lebih berhak aku pergauli dengan baik?\" beliau menjawab: \"Ibumu.\" Kutanyakan lagi, \"Lalu siapa lagi?\" beliau menjawab: \"Ibumu.\" Aku bertanya lagi, \"Siapakah lagi?\" beliau menjawab: \"Ibumu.\" Aku bertanya lagi, \"Siapakah lagi?\" beliau menjawab: \"Ibumu.\" Aku bertanya lagi, \"Siapakah lagi?\" beliau baru menjawab: \"Kemudian barulah bapakmu, kemudian kerabat yang paling terdekat yang terdekat.\" Hadits semakna juga diriwayatkan dari Abu Hurairah, Abdullah bin Amr, Aisyah dan Abu Darda`. Abu Isa berkata; Ini adalah hadits hasan. Syu'bah telah memberikan komentar tentang Bahz bin Hakim bahwa ia adalah seorang yang Tsiqqah menurut para Ahli hadits. Ma'mar, Ats Tsauri dan Ma'mar bin Salamah serta imam-imam yang lain telah meriwayatkan hadits darinya."},"1820":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ الْمَسْعُودِيِّ عَنْ الْوَلِيدِ بْنِ الْعَيْزَارِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ ابْنِ مَسْعُودٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ الصَّلَاةُ لِمِيقَاتِهَا قُلْتُ ثُمَّ مَاذَا يَا رَسُولَ اللَّهِ قَالَ بِرُّ الْوَالِدَيْنِ قُلْتُ ثُمَّ مَاذَا يَا رَسُولَ اللَّهِ قَالَ الْجِهَادُ فِي سَبِيلِ اللَّهِ ثُمَّ سَكَتَ عَنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ اسْتَزَدْتُهُ لَزَادَنِيقَالَ أَبُو عِيسَى وَأَبُو عَمْرٍو الشَّيْبَانِيُّ اسْمُهُ سَعْدُ بْنُ إِيَاسٍ وَهُوَ حَدِيثٌ حَسَنٌ صَحِيحٌ رَوَاهُ الشَّيْبَانِيُّ وَشُعْبَةُ وَغَيْرُ وَاحِدٍ عَنْ الْوَلِيدِ بْنِ الْعَيْزَارِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ مِنْ غَيْرِ وَجْهٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ ابْنِ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Al Mas'udi] dari [Al Walid bin Al 'Aizar] dari [Abi Amru Asy Syaibani] dari [Ibnu Mas'ud] ia berkata; Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, amalan apakah yang paling mulia?\" beliau menjawab: \"Shalat tepat pada waktunya.\" Aku bertanya lagi, \"Kemudian apakah lagi wahai Rasulullah?\" beliau menjawab: \"Kemudian berbakti kepada kedua orang tua.\" Aku bertanya lagi, \"Apa lagi wahai Rasulullah?\" beliau menjawab: \"Kemudian berjihad di jalan Allah.\" Lalu Rasulullah shallallahu 'alaihi wasallam diam, sekiranya aku bertanya lagi, niscaya beliau akan menjawabnya. Abu Isa berkata; Abu Amr Asy Syaibani namanya adalah Sa'd bin Iyas. Dan ini adalah hadits hasan shahih, dan telah diriwayatkan pula oleh [Asy Syaibani] dan [Syu'bah] serta lebih dari satu orang rawi dari [Al Walid bin Al Aizar]. Hadits ini juga telah diriwayatkan oleh lebih dari satu jalur dari Abu Amr Asy Syaibani dari Ibnu Mas'ud."},"1821":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عُمَرُ بْنُ عَلِيٍّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رِضَى الرَّبِّ فِي رِضَى الْوَالِدِ وَسَخَطُ الرَّبِّ فِي سَخَطِ الْوَالِدِحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو نَحْوَهُ وَلَمْ يَرْفَعْهُ وَهَذَا أَصَحُّ قَالَ أَبُو عِيسَى وَهَكَذَا رَوَى أَصْحَابُ شُعْبَةَ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو مَوْقُوفًا وَلَا نَعْلَمُ أَحَدًا رَفَعَهُ غَيْرَ خَالِدِ بْنِ الْحَارِثِ عَنْ شُعْبَةَ وَخَالِدُ بْنُ الْحَارِثِ ثِقَةٌ مَأْمُونٌ قَالَ سَمِعْت مُحَمَّدَ بْنَ الْمُثَنَّى يَقُولُ مَا رَأَيْتُ بِالْبَصْرَةِ مِثْلَ خَالِدِ بْنِ الْحَارِثِ وَلَا بِالْكُوفَةِ مِثْلَ عَبْدِ اللَّهِ بْنِ إِدْرِيسَ قَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Abu Hafsh, Umar bin Ali] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin Atha'] [Bapaknya] dari [Abdullah bin Amr] radliallahu 'anhuma dari Nabi shallallaahu 'alaihi wa sallam, beliau bersabda: \"Ridha Allah terdapat pada ridha seorang bapak, dan murka Allah juga terdapat pada murkanya seorang bapak.\" Bercerita kepada Kami Muhammad bin Basysyar, berkata: Bercerita kepada kami Muhammad bin Ja'far dari Syu'bah dari Ya'la bin Atha' dari bapaknya dari Abdullah bin Amr seperti hadits diatas namun tidak memarfu'kannya dan riwayat ini lebih shohih. Berkata Abu Isa: Demikian shahabat-shahabat Syu'bah meriwayatkan dari Syu'bah dari Ya'la bin Atha' dari bapaknya dari Abdullah bin Amr secara mauquf dan kami tidak mengetahui seorangpun yang memarfu'kannya selain Khalid bin Harits dari Syu'bah dan Khalid bin Harits seorang yang tsiqah dan dipercaya. Dia berkata: aku mendengar Muhammad bin Al Mutsanna berkata: Aku tidak melihat seorang pun di Bashrah seperti Khalid bin Harits dan tidak juga di Kufah seperti Abdullah bin Idris. Hadits semakna diriwayatkan dari Abdullah bin Mas'ud."},"1822":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ أَبِي الدَّرْدَاءِأَنَّ رَجُلًا أَتَاهُ فَقَالَ إِنَّ لِيَ امْرَأَةً وَإِنَّ أُمِّي تَأْمُرُنِي بِطَلَاقِهَا قَالَ أَبُو الدَّرْدَاءِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْوَالِدُ أَوْسَطُ أَبْوَابِ الْجَنَّةِ فَإِنْ شِئْتَ فَأَضِعْ ذَلِكَ الْبَابَ أَوْ احْفَظْهُقَالَ ابْنُ أَبِي عُمَرَ رُبَّمَا قَالَ سُفْيَانُ إِنَّ أُمِّي وَرُبَّمَا قَالَ أَبِي وَهَذَا حَدِيثٌ صَحِيحٌ وَأَبُو عَبْدِ الرَّحْمَنِ السُّلَمِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ حَبِيبٍ","id":"Telah meriwayatkan kepada kami [Ibnu Abu Umar], telah meriwayatkan kepada kami [Sufyan bin Uyainah] dari [Atha` bin As Sa`ib] dari [Abu Abdurrahman As Sulami] dari [Abu Darda`] bahwa seorang laki-laki mendatanginya dan berkata, \"Sesungguhnya aku memiliki seorang isteri, sedang ibuku menyuruhku untuk menceraikannya.\" Abu Darda` berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang tua adalah pintu surga yang paling tengah. Jika kamu mampu, letakkanlah pintu tersebut atau jagalah.\" Ibnu Abu Umar berkata; Sepertinya Sufyan menyebutkan; \"Sesungguhnya ibuku.\" Dan sepertinya juga ia menyebutkan; \"Sesungguhnya bapakku.\" Dan ini adalah hadits shahih. Dan Abu Abdurrahman As Sulami, namanya adalah Abdullah bin Habib."},"1823":{"ar":"حَدَّثَنَا حُمَيْدُ بنُ مَسْعَدَةَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُحَدِّثُكُمْ بِأَكْبَرِ الْكَبَائِرِ قَالُوا بَلَى يَا رَسُولَ اللَّهِ قَالَ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ قَالَ وَجَلَسَ وَكَانَ مُتَّكِئًا فَقَالَ وَشَهَادَةُ الزُّورِ أَوْ قَوْلُ الزُّورِ فَمَا زَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُهَا حَتَّى قُلْنَا لَيْتَهُ سَكَتَقَالَ وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو بَكْرَةَ اسْمُهُ نُفَيْعُ بْنُ الْحَارِثِ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], telah meriwayatkan kepada kami [Bisyr bin Al Mufadldlal] Telah meriwayatkan kepada kami [Al Jurairi] dari [Abdurrahman bin Abu Bakrah] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah kalian aku beritahukan tentang dosa yang paling besar?\" Mereka menjawab, \"Ya, wahai Rasulullah.\" beliau bersabda: \"Yaitu, berbuat syirik kepada Allah, dan durhaka kepada kedua orang tua.\" kemudian beliua terdiam sejenak sambil bersandar, kemudian beliau bersabda: \"Dan kesaksian palsu.\" Rasulullah shallallahu 'alaihi wasallam terus mengulanginya, hingga kami berkata, \"Seandainya beliau diam.\" Hadits semakna juga diriwayatkan dari Abu Sa'id. Abu Isa berkata; Ini adalah hadits hasan shahih. Abu Bakrah namanya adalah Nufai' bin Al Harits."},"1824":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ ابْنِ الْهَادِ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْكَبَائِرِ أَنْ يَشْتُمَ الرَّجُلُ وَالِدَيْهِ قَالُوا يَا رَسُولَ اللَّهِ وَهَلْ يَشْتُمُ الرَّجُلُ وَالِدَيْهِ قَالَ نَعَمْ يَسُبُّ أَبَا الرَّجُلِ فَيَشْتُمُ أَبَاهُ وَيَشْتُمُ أُمَّهُ فَيَسُبُّ أُمَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Ibnul Hadi] dari [Sa'd bin Ibrahim] dari [Humaid bin Abdurrahman] dari [Abdullah bin Amr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Termasuk Al Kaba`ir (dosa-dosa besar), yakni bila seseorang mencela kedua orang tuanya.\" Mereka para sahabat bertanya, \"Wahai Rasulullah, mungkinkah seseorang mencela kedua orang tuanya?\" beliau menjawab: \"Ya, bila ia mencaki bapak seseorang, maka orang itu pun akan mencaci bapaknya. Dan bila ia mencaci ibu seseorang, lalu orang itu pun akan mencaci ibunya.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1825":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا حَيْوَةُ بْنُ شُرَيْحٍ أَخْبَرَنِي الْوَلِيدُ بْنُ أَبِي الْوَلِيدِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَبَرَّ الْبِرِّ أَنْ يَصِلَ الرَّجُلُ أَهْلَ وُدِّ أَبِيهِقَالَ وَفِي الْبَاب عَنْ أَبِي أَسِيدٍ قَالَ أَبُو عِيسَى هَذَا إِسْنَادٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ ابْنِ عُمَرَ مِنْ غَيْرِ وَجْهٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], elah mengabarkan kepada kami [Abdullah bin Mubarak], telah mengabarkan kepada kami [Haiwah bin Syuraih], telah mengabarkan kepadaku [Al Walid bin Abul Walid] dari [Abdullah bin Dinar] dari [Ibnu Umar] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kebaikan yang paling utama adalah manakala seseorang menyambung hubungan silaturahmi kepada kerabat dan teman dekat bapaknya.\" Hadits semakna juga diriwayatkan dari Abu Sa'id. Abu Isa berkata; Ini adalah Isnad yang shahih. Dan hadits ini juga telah diriwayatkan dari Ibnu Umar lebih dari satu jalur."},"1826":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا أَبِي عَنْ إِسْرَائِيلَ ح قَالَ و حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ وَهُوَ ابْنُ مَدُّوَيْهِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ وَاللَّفْظُ لِحَدِيثِ عُبَيْدِ اللَّهِ عَنْ أَبِي إِسْحَقَ الْهَمْدَانِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَالَةُ بِمَنْزِلَةِ الْأُمِّوَفِي الْحَدِيثِ قِصَّةٌ طَوِيلَةٌ وَهَذَا حَدِيثٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Sufyan bin Waki'], telah menceritakan kepada kami [bapakku] dari [Isra`il] -dalam riwayat lain- Dan telah menceritakan kepada kami [Muhammad bin Ahmad] ia adalah Ibnu Madduwaih, telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Isra`il] -lafazh adalah milik haditsnya Ubaidullah- dari [Abu Ishaq Al Hamdani] dari [Al Barra` bin Azib] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Khalah (bibi dari ibu) itu kedudukannya sama dengan seorang ibu.\" Hadits ini memiliki kisah yang panjang dan ini merupakan hadits shahih."},"1827":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ ذَنْبًا عَظِيمًا فَهَلْ لِي تَوْبَةٌ قَالَ هَلْ لَكَ مِنْ أُمٍّ قَالَ لَا قَالَ هَلْ لَكَ مِنْ خَالَةٍ قَالَ نَعَمْ قَالَ فَبِرَّهَاوَفِي الْبَاب عَنْ عَلِيٍّ وَالْبَرَاءِ بْنِ عَازِبٍ حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ ابْنِ عُمَرَ وَهَذَا أَصَحُّ مِنْ حَدِيثِ أَبِي مُعَاوِيَةَ وَأَبُو بَكْرِ بْنُ حَفْصٍ هُوَ ابْنُ عُمَرَ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Muhammmad bin Suqah] dari [Abu Bakr bin Hafsh] dari [Ibnu Umar] bahwasanya; Seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sungguh, aku telah berbuat dosa besar, apakah aku masih mempunyai kesempatan untuk bertaubat?\" beliau balik bertanya: \"Apakah kamu masih mempunyai ibu?\" Laki-laki itu menjawab, \"Tidak.\" Kemudian beliau bertanya lagi: \"Apakah kamu mempunyai bibi?\" laki-laki itu menjawab, \"Ya.\" Beliau bersabda: \"Kalau begitu, berbaktilah kepadanya.\" Hadits semakna juga diriwayatkan dari Ali dan Al Barra` bin Azib. Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin Suqah] dari [Abu Bakr bin Hafsh] dari Nabi shallallahu 'alaihi wasallam semisalnya. Dan di dalamnya ia tidak menyebutkan; Dari Ibnu Umar. Dan ini adalah lebih shahih dari haditsnya Abu Mu'awiyah. Abu Bakr bin Hafsh adalah Ibnu Umar bin Sa'd bin Abu Waqash."},"1828":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ هِشَامٍ الدَّسْتُوَائِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي جَعْفَرٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثُ دَعَوَاتٍ مُسْتَجَابَاتٌ لَا شَكَّ فِيهِنَّ دَعْوَةُ الْمَظْلُومِ وَدَعْوَةُ الْمُسَافِرِ وَدَعْوَةُ الْوَالِدِ عَلَى وَلَدِهِقَالَ أَبُو عِيسَى وَقَدْ رَوَى الْحَجَّاجُ الصَّوَّافُ هَذَا الْحَدِيثَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ نَحْوَ حَدِيثِ هِشَامٍ وَأَبُو جَعْفَرٍ الَّذِي رَوَى عَنْ أَبِي هُرَيْرَةَ يُقَالُ لَهُ أَبُو جَعْفَرٍ الْمُؤَذِّنُ وَلَا نَعْرِفُ اسْمَهُ وَقَدْ رَوَى عَنْهُ يَحْيَى بْنُ أَبِي كَثِيرٍ غَيْرَ حَدِيثٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr], telah mengabarkan kepada kami [Isma'il bin Ibrahim] dari [Hisyam Ad Dastuwa`i] dari [Yahya bin Abu Katsir] dari [Abu Ja'far] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga macam doa yang akan dikabulkan yang tidak ada keraguan padanya; doa orang yang terzhalimi, doa musafir, dan doa orang tua (menimpakan keburukan) atas anaknya.\" Berkata Abu Isa: [Hajjaj Ash Shawwaf] meriwayatkan hadits ini dari [Yahya bin Abi Katsir] seperti haditsnya Hisyam dan Abu Ja'far yang meriwayatkan dari Abu Hurairah biasa dipanggil Abu Ja'far Al Muadzdzin dan kami tidak mengetahui namanya dan Yahya bin Abi Katsir telah meriwayatkan darinya lebih dari satu hadits."},"1829":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ مُوسَى أَخْبَرَنَا جَرِيرٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَجْزِي وَلَدٌ وَالِدًا إِلَّا أَنْ يَجِدَهُ مَمْلُوكًا فَيَشْتَرِيَهُ فَيُعْتِقَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سُهَيْلِ بْنِ أَبِي صَالِحٍ وَقَدْ رَوَى سُفْيَانُ الثَّوْرِيُّ وَغَيْرُ وَاحِدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ هَذَا الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Musa], telah mengabarkan kepada kami [Jarir] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang anak tidak akan mampu untuk membalas kebaikan orang tuanya, kecuali ia mendapatinya dalam keadaan budak, lalu ia membeli dan memerdekakannya.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Kami tidak mengetahuinya kecuali dari haditsnya Suhail bin Abu Shalih. Dan [Sufyan Ats Tsauri] dan lebih dari satu orang rawi telah meriwayatkan hadits ini dari [Suhail bin Abu Shalih]."},"1830":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ قَالَاشْتَكَى أَبُو الرَّدَّادِ اللَّيْثِيُّ فَعَادَهُ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فَقَالَ خَيْرُهُمْ وَأَوْصَلُهُمْ مَا عَلِمْتُ أَبَا مُحَمَّدٍ فَقَالَ عَبْدُ الرَّحْمَنِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ اللَّهُ تَبَارَكَ وَتَعَالَى أَنَا اللَّهُ وَأَنَا الرَّحْمَنُ خَلَقْتُ الرَّحِمَ وَشَقَقْتُ لَهَا مِنْ اسْمِي فَمَنْ وَصَلَهَا وَصَلْتُهُ وَمَنْ قَطَعَهَا بَتَتُّهُوَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَابْنِ أَبِي أَوْفَى وَعَامِرِ بْنِ رَبِيعَةَ وَأَبِي هُرَيْرَةَ وَجُبَيْرِ بْنِ مُطْعِمٍ قَالَ أَبُو عِيسَى حَدِيثُ سُفْيَانَ عَنْ الزُّهْرِيِّ حَدِيثٌ صَحِيحٌ وَرَوَى مَعْمَرٌ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ رَدَّادٍ اللَّيْثِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَمَعْمَرٍ كَذَا يَقُولُ قَالَ مُحَمَّدٌ وَحَدِيثُ مَعْمَرٍ خَطَأٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] dan [Sa'id bin Abdurrahman Al Makhzumi] keduanya berkata, Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abu Salamah] ia berkata; Suatu ketika Abu Ar Radad Al Laitsi jatuh sakit, lalu [Abdurrahman bin Auf] menjenguknya maka Abu Radad pun berkata, \"Sebaik-baik manusia -yang saya ketahui- dan yang paling kuat menyambung silaturrahim di antara mereka adalah Abu Muhammad.\" Kemudian berkatalah Abdurrahman; Aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Tabaraka wa Ta'ala berfiman: 'Akulah Allah, dan Aku adalah Ar Rahman. Aku telah menciptakan kasih sayang yang aku ambilkan dari nama-Ku. Maka siapa yang menyambungnya, akau akan menyambungnya, dan siapa yang memutuskannya, maka Aku akan memutuskan kasih sayang-Ku darinya.'\" Hadits semakna juga diriwayatkan dari Abu Sa'id, Ibnu Abu Aufa, Amir bin Rabi'ah, Abu Hurairah dan Jubair bin Muth'im. Abu Isa berkata; Haditsnya Sufyan dari Az Zuhri adalah hadits shahih. Dan Ma'mar juga meriwayatkan hadits ini dari Az Zuhri dari Abu Salamah, dari Raddad Al Laitsi dari Abdurrahman bin Auf dan Ma'mar dan ia berkata; Muhammad berkata, \"Haditsnya Ma'mar adalah salah.\""},"1831":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا بَشِيرٌ أَبُو إِسْمَعِيلَ وَفِطْرُ بْنُ خَلِيفَةَ عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ الْوَاصِلُ بِالْمُكَافِئِ وَلَكِنَّ الْوَاصِلَ الَّذِي إِذَا انْقَطَعَتْ رَحِمُهُ وَصَلَهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ سَلْمَانَ وَعَائِشَةَ وَعَبْدِ اللَّهِ بْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Basyir Abu Isma'il] dan [Fithr bin Khalifah] dari [Mujahid] dari [Abdullah bin Amru] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang yang dinamakan Al Washil (penyambung silaturrahim) bukanlah Al Mukafi`i (orang yang menyambung silaturrahim jika para kerabatnya menyambungnya, dan ia akan memustuskan bila mereka memutuskannya), akan tetapi yang disebut Al Washil itu adalah manakalah hubungan silaturrahminya terputus maka ia akan segera menyambungnya.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Hadits semakna juga diriwayatkan dari Salman, Aisyah dan Abdullah bin Umar."},"1832":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَنَصْرُ بْنُ عَلِيٍّ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ مُحَمَّدِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْجَنَّةَ قَاطِعٌقَالَ ابْنُ أَبِي عُمَرَ قَالَ سُفْيَانُ يَعْنِي قَاطِعَ رَحِمٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] dan [Nashr bin Ali] dan [Sa'id bin Abdurrahman] mereka berkata, Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Muhammad bin Jubair bin Muth'im] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga seorang yang memutus (silaturrahim).\" Ibnu Abu Umar berkata; Sufyan berkata, \"Yaitu pemutus silaturrrahmi.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1833":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ قَال سَمِعْتُ ابْنَ أَبِي سُوَيْدٍ يَقُولُ سَمِعْتُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ يَقُولُ زَعَمَتْ الْمَرْأَةُ الصَّالِحَةُ خَوْلَةُ بِنْتُ حَكِيمٍ قَالَتْخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَهُوَ مُحْتَضِنٌ أَحَدَ ابْنَيْ ابْنَتِهِ وَهُوَ يَقُولُ إِنَّكُمْ لَتُبَخِّلُونَ وَتُجَبِّنُونَ وَتُجَهِّلُونَ وَإِنَّكُمْ لَمِنْ رَيْحَانِ اللَّهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَالْأَشْعَثِ بْنِ قَيْسٍ قَالَ أَبُو عِيسَى حَدِيثُ ابْنِ عُيَيْنَةَ عَنْ إِبْرَاهِيمَ بْنِ مَيْس��رَةَ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِهِ وَلَا نَعْرِفُ لِعُمَرَ بْنِ عَبْدِ الْعَزِيزِ سَمَاعًا مِنْ خَوْلَةَ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Ibrahim bin Maisarah] ia berkata, saya mendengar [Ibnu Abu Suwaid] berkata, saya mendengar [Umar bin Abdul Aziz] berkata; Seorang wanita shalihah yaitu [Khaulah binti Hakim] berkata; Pada suatu hari Rasulullah shallallahu 'alaihi wasallam keluar dengan menggendong salah satu dari dua cucu dari anak perempuannya seraya bersabda: \"Sesungguhnya kalian benar-benar akan menjadikan seseorang bakhil, pengecut dan pendusta. Dan sungguh kalian adalah Raihanullah (rahmat dan rizki Allah).\" Hadits semakna juga diriwayatkan dari Ibnu Umar dan Al As'ats bin Qais. Abu Isa berkata; Haditsnya Ibnu Uyainah dari Ibrahim bin Maisarah, maka kami tidak mengetahuinya kecuali dari haditsnya. Dan kami juga tidak mengetahui bahwa Umar bin Abdul Aziz mendengar Khaulah."},"1834":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَأَبْصَرَ الْأَقْرَعُ بْنُ حَابِسٍ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُقَبِّلُ الْحَسَنَ قَالَ ابْنُ أَبِي عُمَرَ الْحُسَيْنَ أَوْ الْحَسَنَ فَقَالَ إِنَّ لِي مِنْ الْوَلَدِ عَشَرَةً مَا قَبَّلْتُ أَحَدًا مِنْهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ مَنْ لَا يَرْحَمُ لَا يُرْحَمُقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَعَائِشَةَ قَالَ أَبُو عِيسَى وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ اسْمُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Umar] dan [Sa'id bin Abdurrahman] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Al Aqara' bin Habis pernah melihat Nabi shallallahu 'alaihi wasallam mencium Al Hasan, Ibnu Abu Umar menyebutkan: Al Husain atau Al Hasan, maka ia pun berkata, \"Sesungguhnya aku mempunyai sepuluh anak, namun tidak satu pun dari mereka yang pernah kucium.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya siapa yang tidak mengasihi, maka ia tidak akan dikasihi.\" Hadits semakna juga diriwayatkan dari Anas dan Aisyah. Abu Isa berkata; Abu Salamah bin Abdurrahman namanya adalah Abdullah bin Abdurrahman bin Auf. Dan ini adalah hadits hasan shahih."},"1835":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَكُونُ لِأَحَدِكُمْ ثَلَاثُ بَنَاتٍ أَوْ ثَلَاثُ أَخَوَاتٍ فَيُحْسِنُ إِلَيْهِنَّ إِلَّا دَخَلَ الْجَنَّةَقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَعُقْبَةَ بْنِ عَامِرٍ وَأَنَسٍ وَجَابِرٍ وَابْنِ عَبَّاسٍ قَالَ أَبُو عِيسَى وَأَبُو سَعِيدٍ الْخُدْرِيُّ اسْمُهُ سَعْدُ بْنُ مَالِكِ بْنِ سِنَانٍ وَسَعْدُ بْنُ أَبِي وَقَّاصٍ هُوَ سَعْدُ بْنُ مَالِكِ بْنِ وُهَيْبٍ وَقَدْ زَادُوا فِي هَذَا الْإِسْنَادِ رَجُلًا","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [Sa'id bin Abdurrahman] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah salah seorang dari kalian memiliki tiga orang anak perempuan atau tiga orang saudara perempuan lalu berbuat baik kepada mereka semua kecuali dia akan masuk surga.\" Hadits semakna diriwayatkan dari 'Aisyah, Uqbah bin Amir, Anas, Jabir dan Ibnu Abbas. Berkata Abu 'Isa: Abu Sa'id Al Khudri bernama Sa'ad bin Malik bin Sinan dan Sa'ad bin Abi Waqqash bernama Sa'ad bin Malik bin Wuhaib. Dan mereka telah menambahkan seorang lelaki pada sanad ini."},"1836":{"ar":"حَدَّثَنَا الْعَلَاءُ بْنُ مَسْلَمَةَ الْبَغْدَادِيُّ حَدَّثَنَا عَبْدُ الْمَجِيدِ بْنُ عَبْدِ الْعَزِيزِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتُلِيَ بِشَيْءٍ مِنْ الْبَنَاتِ فَصَبَرَ عَلَيْهِنَّ كُنَّ لَهُ حِجَابًا مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Al Ala` bin Maslamah Al Baghdadi], telah menceritakan kepada kami [Abdul Hamid bin Abdul Aziz] dari [Ma'mar] dari [Az Zuhri] dari [Urwah] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang diuji dengan tiga orang anak wanita lalu ia bersabar atasnya, niscaya ketiganya akan menjadi hijab baginya dari api neraka.\" Abu Isa berkata; Ini adalah hadits hasan."},"1837":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ وَزِيرٍ الْوَاسِطِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ هُوَ الطَّنَافِسِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ الرَّاسِبِيُّ عَنْ أَبِي بَكْرِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَنَسِ بْنِ مَالِكٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَالَ جَارِيَتَيْنِ دَخَلْتُ أَنَا وَهُوَ الْجَنَّةَ كَهَاتَيْنِ وَأَشَارَ بِأُصْبُعَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَى مُحَمَّدُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الْعَزِيزِ غَيْرَ حَدِيثٍ بِهَذَا الْإِسْنَادِ و قَالَ عَنْ أَبِي بَكْرِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَنَسٍ وَالصَّحِيحُ هُوَ عُبَيْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ أَنَسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Wazir Al Wasithi], telah menceritakan kepada kami [Muhammad bin Ubaid Ath Thannafisi], telah menceritakan kepada kami [Muhammad bin Abdul Aziz Ar Rasibi] dari [Abu Bakr bin Ubaidullah bin Anas bin Malik] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memelihara dua orang anak wanita, maka aku dan ia akan masuk ke dalam surga seperti kedua (jari) ini.\" Beliau sambil memberi isyarat dengan kedua jari telunjuknya. Abu Isa berkata; Ini adalah hadits hasan gharib. Dan Muhammad bin Ubaid telah meriwayatkan dari Muhammad bin Abdul Aziz selain hadits ini dan dengan isnad ini dan ia menyebutkan; Dari Abu Bakr bin Ubaidullah bin Anas. Yang shahih, ia adalah Ubaidullah bin Abu Bakr bin Anas."},"1838":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ شِهَابٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ حَزْمٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَتْ امْرَأَةٌ مَعَهَا ابْنَتَانِ لَهَا فَسَأَلَتْ فَلَمْ تَجِدْ عِنْدِي شَيْئًا غَيْرَ تَمْرَةٍ فَأَعْطَيْتُهَا إِيَّاهَا فَقَسَمَتْهَا بَيْنَ ابْنَتَيْهَا وَلَمْ تَأْكُلْ مِنْهَا ثُمَّ قَامَتْ فَخَرَجَتْ فَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتُلِيَ بِشَيْءٍ مِنْ هَذِهِ الْبَنَاتِ كُنَّ لَهُ سِتْرًا مِنْ النَّارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak], telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Syihab], telah menceritakan kepada kami [Abdullah bin Abu Bakr bin Hazm] dari [Urwah] dari [Aisyah] ia berkata; Seorang wanita masuk menemuiku bersama dengan dua orang anak wanitanya, lalu wanita itu meminta, namun ia tidak mendapatkan sesuatu dariku kecuali kurma. Kemudian aku pun memberikan kurma itu padanya, lalu wanita itu membagikannya pada kedua anak wanitanya, sedang ia sendiri tidak memakannya. Kemudian wanita itu berdiri dan keluar. Sesudah itu, Nabi shallallahu 'alaihi wasallam masuk dan akupun langsung mengabarkan hal itu pada beliau, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang diuji lantaran memelihara anak-anak wanita ini, maka mereka akan menjadi tameng baginya dari api neraka.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1839":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَيُّوبَ بْنِ بَشِيرٍ عَنْ سَعِيدٍ الْأَعْشَى عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ لَهُ ثَلَاثُ بَنَاتٍ أَوْ ثَلَاثُ أَخَوَاتٍ أَوْ ابْنَتَانِ أَوْ أُخْتَانِ فَأَحْسَنَ صُحْبَتَهُنَّ وَاتَّقَى اللَّهَ فِيهِنَّ فَلَهُ الْجَنَّةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] Telah mengabarkan kepada kami [Ibnu Uyainah] dari [Suhail bin Abu Shalih] dari [Ayyub bin Basyir] dari [Sa'id Al A'masy] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memiliki tiga orang anak wanita, atau tiga orang saudara wanita atau dua orang anak wanita atau pun dua orang saudara wanita, lalu ia berlaku baik kepada kepada mereka dan juga bertakwa kepada Allah berkenaan dengan apa yang ada pada mereka, maka baginya adalah surga.\" Abu Isa berkata; Ini adalah hadits gharib."},"1840":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَعْقُوبَ الطَّالَقَانِيُّ حَدَّثَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ قَال سَمِعْتُ أَبِي يُحَدِّثُ عَنْ حَنَشٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَبَضَ يَتِيمًا مِنْ بَيْنِ الْمُسْلِمِينَ إِلَى طَعَامِهِ وَشَرَابِهِ أَدْخَلَهُ اللَّهُ الْجَنَّةَ إِلَّا أَنْ يَعْمَلَ ذَنْبًا لَا يُغْفَرُ لَهُقَالَ وَفِي الْبَاب عَنْ مُرَّةَ الْفِهْرِيِّ وَأَبِي هُرَيْرَةَ وَأَبِي أُمَامَةَ وَسَهْلِ بْنِ سَعْدٍ قَالَ أَبُو عِيسَى وَحَنَشٌ هُوَ حُسَيْنُ بْنُ قَيْسٍ وَهُوَ أَبُو عَلِيٍّ الرَّحَبِيُّ وَسُلَيْمَانُ التَّيْمِيُّ يَقُولُ حَنَشٌ وَهُوَ ضَعِيفٌ عِنْدَ أَهْلِ الْحَدِيثِ","id":"Telah menceritakan kepada kami [Sa'id bin Ya'qub Ath Thayalisi] telah menceritakan kepada kami [Al Mu'tamir bin Sulaiman] berkata; saya mendengar [Bapakku] menceritakan dari [Hanasy] dari [Ikrimah] dari [Ibnu Abbas] radliallahu 'anhuma berkata: Barangsiapa yang memelihara anak yatim dan memberinya makan dan minum niscaya Allah akan memasukkannya ke dalam surga kecuali jika dia melakukan dosa yang tidak dapat diampuni. Hadits semakna diriwayatkan dari Murrah Al fihri, Abu Hurairah, Abu Umamah dan Sahl bin Sa'ad. Berkata Abu Isa: Khanasy bernama Khanasy bin Qais dan dia adalah Abu Ali Ar Ruhaili, berkata Sulaiman At Taimi: Khanasy ialah seorang yang dha'if menurut ahli hadits."},"1841":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عِمْرَانَ أَبُو الْقَاسِمِ الْمَكِّيُّ الْقُرَشِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَكَافِلُ الْيَتِيمِ فِي الْجَنَّةِ كَهَاتَيْنِ وَأَشَارَ بِأُصْبُعَيْهِ يَعْنِي السَّبَّابَةَ وَالْوُسْطَىقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdullah bin Imran Abu Qasim Al Makki Al Qurasyi], telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [bapaknya] dari [Sahl bin Sa'd] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku dan para pengasuh anak yatim (kafilul yatim) akan berada di dalam surga seperti kedua ini.\" Beliau memberi isyarat dengan kedua jarinya, yaitu jari telunjuk dan jari tengah. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1842":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَرْزُوقٍ الْبَصْرِيُّ حَدَّثَنَا عُبَيْدُ بْنُ وَاقِدٍ عَنْ زَرْبِيٍّ قَال سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُجَاءَ شَيْخٌ يُرِيدُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَبْطَأَ الْقَوْمُ عَنْهُ أَنْ يُوَسِّعُوا لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ لَمْ يَرْحَمْ صَغِيرَنَا وَيُوَقِّرْ كَبِيرَنَاقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَأَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَزَرْبِيٌّ لَهُ أَحَادِيث�� مَنَاكِيرُ عَنْ أَنَسِ بْنِ مَالِكٍ وَغَيْرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Marzuq Al Bashari], telah menceritakan kepada kami [Ubaid bin Waqid] dari [Zabri] ia berkata, saya mendengar [Anas bin Malik] berkata; Seorang lelaki tua datang kepada Nabi shallallahu 'alaihi wasallam lantas orang-orang memperlambat untuk memperluas jalan untuknya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Bukan termasuk dari golongan kami orang yang tidak menyayangi anak kecil kami dan tidak menghormati orang tua (orang dewasa) kami.\" Hadits semakna diriwayatkan dari Abdullah bin Amr, Abu Hurairah, Ibnu Abbas dan Abu Umamah. Berkata Abu 'Isa: Ini merupakan hadits gharib dan Zarbi memiliki hadits-hadits munkar dari Anas bin Malik dan selainnya."},"1843":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ لَمْ يَرْحَمْ صَغِيرَنَا وَيَعْرِفْ شَرَفَ كَبِيرِنَاحَدَّثَنَا هَنَّادٌ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ نَحْوَهُ إِلَّا أَنَّهُ قَالَ وَيَعْرِفْ حَقَّ كَبِيرِنَا","id":"Telah menceritakan kepada kami [Abu Bakr Muhammad bin Aban], telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Muhammad bin Ishaq] dari [Amr bin Syu'aib] dari [bapaknya] dari [kakeknya], ia berkata; bersabda: \"Tidak termasuk golongan kami, orang yang tidak mengasihi anak-anak kecil dan tidak pula menghormati para orang tua kami.\" Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abdah] dari [Muhammad bin Ishaq] semisalnya. Hanya saja, ia menyebutkan; \"Dan (tidak pula) mengetahui hak para orang tua kami.\""},"1844":{"ar":"حَدَّثَنَا أَبُو بَكْرٍ مُحَمَّدُ بْنُ أَبَانَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ شَرِيكٍ عَنْ لَيْثٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا مَنْ لَمْ يَرْحَمْ صَغِيرَنَا وَيُوَقِّرْ كَبِيرَنَا وَيَأْمُرْ بِالْمَعْرُوفِ وَيَنْهَ عَنْ الْمُنْكَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَحَدِيثُ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ حَدِيثٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو مِنْ غَيْرِ هَذَا الْوَجْهِ أَيْضًا قَالَ بَعْضُ أَهْلِ الْعِلْمِ مَعْنَى قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ مِنَّا يَقُولُ لَيْسَ مِنْ سُنَّتِنَا لَيْسَ مِنْ أَدَبِنَا و قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ كَانَ سُفْيَانُ الثَّوْرِيُّ يُنْكِرُ هَذَا التَّفْسِيرَ لَيْسَ مِنَّا يَقُولُ لَيْسَ مِنْ مِلَّتِنَا","id":"Telah menceritakan kepada kami [Abu Muhammad bin Aban], telah menceritakan kepada kami [Yazid bin Harun] dari [Syarik] dari [Laits] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukanlah termasuk golongan kami, mereka yang tidak mengahisihi anak-anak kecil kami dan tidak pula menghormati orang tua kami, serta tidak menyuruh yang ma'ruf dan melarang yang munkar.\" Abu Isa berkata; Ini adalah hadits hasan gharib, dan haditsnya Muhammad bin Ishaq dari Amr bin Syu'aib adalah hadits shahih. Dan telah diriwayatkan pula dari Abdullah bin Amr selain jalur ini. Sebagian Ahlul Ilmi berkata; Makna sabda Nabi shallallahu 'alaihi wasallam, \"Bukan dari golongan kami.\" Maksudnya adalah bukan dari sunnah kami dan tidak pula dari adab kami. Dan Ali bin Al Madini berkata; Yahya bin Sa'id berkata, \"Bahwa Sufyan Ats Tsauri mengingkari tafsir ini. Bukan dari golongan kami maksudnya adalah bukanlah dari millah kami.\""},"1845":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ حَدَّثَنَا قَيْسٌ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَا يَرْحَمُ النَّاسَ لَا يَرْحَمُهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَأَبِي سَعِيدٍ وَابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il bin Abu Khalid], telah menceritakan kepada kami [Qais], Telah menceritakan kepada kami [Jarir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang tidak mengasihi manusia, maka Allah tidak akan mengasihinya.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Hadits semakna juga diriwayatkan dari Abdurrahman bin Auf, Abu Sa'id, Ibnu Umar, Abu Hurairah dan Abdullah bin Amr."},"1846":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ أَخْبَرَنَا شُعْبَةُ قَالَ كَتَبَ بِهِ إِلَيَّ مَنْصُورٌ وَقَرَأْتُهُ عَلَيْهِ سَمِعَ أَبَا عُثْمَانَ مَوْلَى الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُنْزَعُ الرَّحْمَةُ إِلَّا مِنْ شَقِيٍّقَالَ وَأَبُو عُثْمَانَ الَّذِي رَوَى عَنْ أَبِي هُرَيْرَةَ لَا يُعْرَفُ اسْمُهُ وَيُقَالُ هُوَ وَالِدُ مُوسَى بْنِ أَبِي عُثْمَانَ الَّذِي رَوَى عَنْهُ أَبُو الزِّنَادِ وَقَدْ رَوَى أَبُو الزِّنَادِ عَنْ مُوسَى بْنِ أَبِي عُثْمَانَ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ حَدِيثٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Dawud], telah mengabarkan kepada kami [Syu'bah] ia berkata; [Manshur] menuliskannya kepadaku dan aku membanyakannya kepadanya, dia mendengar [Abu Utsman] mantan budak Al Mughirah bin Syu'bah; dari [Abu Hurairah] radliallahu 'anhu berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, \"Rasa kasih sayang tidak akan dicabut kecuali dari orang yang celaka.\" Berkata Abu Utsman: Orang yang meriwayatkan dari Abu Hurairah namanya tidak diketahui dan dikatakan dia adalah orang tuanya Musa bin Abi Utsman yang meriwayatkan darinya Abu Zinad dan Abu Zinad telah meriwayatkan hadits dari Musa bin Abi Utsman dari bapaknya dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam lebih dari satu hadits. Berkata Abu Isa: ini merupakan hadits hasan."},"1847":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي قَابُوسَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّاحِمُونَ يَرْحَمُهُمْ الرَّحْمَنُ ارْحَمُوا مَنْ فِي الْأَرْضِ يَرْحَمْكُمْ مَنْ فِي السَّمَاءِ الرَّحِمُ شُجْنَةٌ مِنْ الرَّحْمَنِ فَمَنْ وَصَلَهَا وَصَلَهُ اللَّهُ وَمَنْ قَطَعَهَا قَطَعَهُ اللَّهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Amr bin Dinar] dari [Abu Qabus] dari [Abdullah bin Amr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang yang mengasihi akan dikasihi oleh Ar Rahman, berkasih sayanglah kepada siapapun yang ada dibumi, niscaya Yang ada di langit akan mengasihi kalian. Lafazh Ar Rahim (rahim atau kasih sayang) itu diambil dari lafazh Ar Rahman, maka barang siapa yang menyambung tali silaturrahmi niscaya Allah akan menyambungnya (dengan rahmat-Nya) dan barang siapa yang memutus tali silaturrahmi maka Allah akan memutusnya (dari rahmat-Nya).\" Berkata Abu 'Isa: Ini merupakan hadits hasan shahih."},"1848":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِكُلِّ مُسْلِمٍقَالَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Jarir bin Abdullah] ia berkata; \"Aku berbai'at kepada Rasulullah shallallahu 'alaihi wasallam untuk menunaikan shalat, mengeluarkan zakat dan selalu memberikan nasehat kepada sesama muslim.\" Dan ini adalah hadits hasan shahih."},"1849":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الدِّينُ النَّصِيحَةُ ثَلَاثَ مِرَارٍ قَالُوا يَا رَسُولَ اللَّهِ لِمَنْ قَالَ لِلَّهِ وَلِكِتَابِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَتَمِيمٍ الدَّارِيِّ وَجَرِيرٍ وَحَكِيمِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ وَثَوْبَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Shafwan bin Isa] dari [Muhammad bin Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Agama itu adalah nasehat.\" Beliau mengulanginya hingga tiga kali. Kemudian para shahabat bertanya, \"Bagi siapakah wahai Rasulullah?\" beliau menjawab: \"Bagi Allah, Kitab-Nya, bagi para pemimpin dan kaum muslimin seluruhnya.\" Berkata Abu Isa; Ini merupakan hadits hasan shahih. Hadits semakna diriwayatkan dari Ibnu Umar, Tamim Ad Dari, Jarir dan Hakim bin Abi Yazid dari bapaknya serta Tsauban."},"1850":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ حَدَّثَنِي أَبِي عَنْ هِشَامِ بْنِ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُ أَخُو الْمُسْلِمِ لَا يَخُونُهُ وَلَا يَكْذِبُهُ وَلَا يَخْذُلُهُ كُلُّ الْمُسْلِمِ عَلَى الْمُسْلِمِ حَرَامٌ عِرْضُهُ وَمَالُهُ وَدَمُهُ التَّقْوَى هَا هُنَا بِحَسْبِ امْرِئٍ مِنْ الشَّرِّ أَنْ يَحْتَقِرَ أَخَاهُ الْمُسْلِمَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَفِي الْبَاب عَنْ عَلِيٍّ وَأَبِي أَيُّوبَ","id":"Telah menceritakan kepada kami [Ubaid bin Asbath bin Muhammad Al Qurasyi], telah menceritakan kepadaku [bapakku] dari [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim itu saudara bagi seorang muslim, dia tidak mengkhianatinya, tidak berdusta kepadanya juga tidak menelantarkannya. Seorang muslim itu haram atas muslim lainnya untuk mengganggu kehormatannya, hartanya dan tidak pula menumpahkan darahnya. Takwa itu berada di sini, cukuplah dalam hati seseorang itu ada keburukan apabila dia menghina saudaranya yang muslim.\" Berkata Abu 'Isa: Ini merupakan hadits hasan gharib dan hadits semakna diriwayatkan dari Ali dan Abu Ayyub."},"1851":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ غَيْرَ وَاحِدٍ قَالُوا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي بُرْدَةَ عَنْ جَدِّهِ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ لِلْمُؤْمِنِ كَالْبُنْيَانِ يَشُدُّ بَعْضُهُ بَعْضًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] lebih dari satu, mereka berkata, Telah menceritakan kepada kami [Abu Usamah] dari [Buraid bin Abdullah bin Abu Burdah] dari [kakeknya] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Antara seorang mukmin dengan mukmin yang lainnya adalah bagaikan satu bangunan, yang saling menguatkan satu sama lainnya.\" Abu Isa berkata; Ini adalah adalah hasan shahih."},"1852":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا يَحْيَى بْنُ عُبَيْدِ اللَّهِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحَدَكُمْ مِرْآةُ أَخِيهِ فَإِنْ رَأَى بِهِ أَذًى فَلْيُمِطْهُ عَنْهُقَالَ أَبُو عِيسَى وَيَحْيَى بْنُ عُبَيْدِ اللَّهِ ضَعَّفَهُ شُعْبَةُ قَالَ وَفِي الْبَاب عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Al Mubarak], telah mengabarkan kepada kami [Yahya bin Ubaidullah] dari [bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang dari kalian cermin bagi saudaranya, jika dia melihat ada aib padanya maka hendaknya dia menghilangkannya darinya.\" Berkata Abu Isa: Yahya bin Ubaidillah didha'ifkan oleh Syu'bah. Hadits semakna diriwayatkan dari Anas."},"1853":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ أَسْبَاطِ بْنِ مُحَمَّدٍ الْقُرَشِيُّ حَدَّثَنِي أَبِي عَنْ الْأَعْمَشِ قَالَ حُدِّثْتُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ نَفَّسَ عَنْ مُسْلِمٍ كُرْبَةً مِنْ كُرَبِ الدُّنْيَا نَفَّسَ اللَّهُ عَنْهُ كُرْبَةً مِنْ كُرَبِ يَوْمِ الْقِيَامَةِ وَمَنْ يَسَّرَ عَلَى مُعْسِرٍ فِي الدُّنْيَا يَسَّرَ اللَّهُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَمَنْ سَتَرَ عَلَى مُسْلِمٍ فِي الدُّنْيَا سَتَرَ اللَّهُ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَاللَّهُ فِي عَوْنِ الْعَبْدِ مَا كَانَ الْعَبْدُ فِي عَوْنِ أَخِيهِقَالَ وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَعُقْبَةَ بْنِ عَامِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَقَدْ رَوَى أَبُو عَوَانَةَ وَغَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرُوا فِيهِ حُدِّثْتُ عَنْ أَبِي صَالِحٍ","id":"Telah menceritakan kepada kami [Ubaid bin Asbath bin Muhammad Al Qurasyi], telah menceritaka kepadaku [bapakku] dari [Al A'masy] berkata, Telah diceritakan kepada dari [Abu Shalih] dari [Abu Hurairah], dari Nabi shallallahu 'alaihi wasallam bersabda, \"Barangsiapa yang meringankan (menghilangkan) kesulitan seorang muslim kesulitan-kesulitan duniawi, maka Allah akan meringankan (menghilangkan) baginya kesulitan di akhirat kelak. Barangsiapa yang memberikan kemudahan bagi orang yang mengalami kesulitan di dunia, maka Allah akan memudahkan baginya kemudahan (urusan) di dunia dan akhirat. Dan barangsiapa yang menutupi (aib) seorang muslim sewaktu di dunia, maka Allah akan menutup (aibnya) di dunia dan akhirat. Sesungguhnya Allah akan senantiasa menolong seorang hamba selalu ia menolong saudaranya.\" Ia (At Tirmidzi) berkata, Dan di dalam bab ini diriwayatkan dari Ibnu Umar dan Uqbah bin Amir. Abu Isa berkata, hadits ini hasan. [Abu Awanah] dan juga para perawi yang lain meriwayatkan hadits ini dari [A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam hadits yang sama tetapi tanpa ada teks 'hudditstu 'an Abi Shalih' (Telah diceritakan kepada dari Abu Shalih) "},"1854":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ أَبِي بَكْرٍ النَّهْشَلِيِّ عَنْ مَرْزُوقٍ أَبِي بَكْرٍ التَّيْمِيِّ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَدَّ عَنْ عِرْضِ أَخِيهِ رَدَّ اللَّهُ عَنْ وَجْهِهِ النَّارَ يَوْمَ الْقِيَامَةِقَالَ وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Ibnul Mubarak;] dari [Abu Bakr An Nahsyali] dari [Mazruq Abu Bakr At Taimi] dari [Ummu Darda`] dari [Abu Darda'] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang menahan ghibah terhadap saudaranya, maka Allah akan menyelamatkan wajahnya dari api neraka kelak pada hari kiamat.\" Hadits semakna juga diriwayatkan dari Asma` binti Yazid. Abu Isa berkata; Ini adalah hadits hasan."},"1855":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ ح قَالَ وَحَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ اللَّيْثِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثٍ يَلْتَقِيَانِ فَيَصُدُّ هَذَا وَيَصُدُّ هَذَا وَخَيْرُهُمَا الَّذِي يَبْدَأُ بِالسَّلَامِقَالَ وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَأَنَسٍ وَأَبِي هُرَيْرَةَ وَهِشَامِ بْنِ عَامِرٍ وَأَبِي هِنْدٍ الدَّارِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] -dalam riwayat lalin- Dan telah menceritakan kepada kami [Sa'id bin Abdurrahman] Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Atha` bin Yazid Al Laitsi] dari [Abu Ayyub Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang muslim untuk mendiamkan saudaranya lebih dari tiga hari, dimana bila keduanya berjumpa, yang ini memalingkan pandangannya (dari yang lain) dan yang ini juga melakukan hal yang sama, maka yang terbaik dari keduanya adalah yang memulai mengucapkan salam.\" Ia (At Tirmidzi) berkata, dan dalam bab ini diriwayatkan dari Abdullah bin Mas'ud, Anas, Abu Hurairah, Hisyam bin Amir, dan Abu Hind Ad Dari. Abu Isa berkata, Hadits ini hasan shahih."},"1856":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَلَمَّا قَدِمَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ الْمَدِينَةَ آخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُ وَبَيْنَ سَعْدِ بْنِ الرَّبِيعِ فَقَالَ لَهُ هَلُمَّ أُقَاسِمُكَ مَالِي نِصْفَيْنِ وَلِيَ امْرَأَتَانِ فَأُطَلِّقُ إِحْدَاهُمَا فَإِذَا انْقَضَتْ عِدَّتُهَا فَتَزَوَّجْهَا فَقَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ دُلُّونِي عَلَى السُّوقِ فَدَلُّوهُ عَلَى السُّوقِ فَمَا رَجَعَ يَوْمَئِذٍ إِلَّا وَمَعَهُ شَيْءٌ مِنْ أَقِطٍ وَسَمْنٍ قَدْ اسْتَفْضَلَهُ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ وَعَلَيْهِ وَضَرٌ مِنْ صُفْرَةٍ فَقَالَ مَهْيَمْ قَالَ تَزَوَّجْتُ امْرَأَةً مِنْ الْأَنْصَارِ قَالَ فَمَا أَصْدَقْتَهَا قَالَ نَوَاةً قَالَ حُمَيْدٌ أَوْ قَالَ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ فَقَالَ أَوْلِمْ وَلَوْ بِشَاةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ أَحْمَدُ بْنُ حَنْبَلٍ وَزْنُ نَوَاةٍ مِنْ ذَهَبٍ وَزْنُ ثَلَاثَةِ دَرَاهِمَ وَثُلُثٍ و قَالَ إِسْحَقُ بْنُ إِبْرَاهِيمَ وَزْنُ نَوَاةٍ مِنْ ذَهَبٍ وَزْنُ خَمْسَةِ دَرَاهِمَ سَمِعْتُ إِسْحَقَ بْنَ مَنْصُورٍ يَذْكُرُ عَنْهُمَا هَذَا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Isma'il bin Ibrahim], telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata; Ketika Abdurrahman bin Auf sampai di Madinah, Nabi shallallahu 'alaihi wasallam mempersaudarakannya dengan Sa'd bin Ar Rabi', lalu Sa'd bin Ar Rabi' berkata kepadanya, Marilah (silahkan), akan aku bagi hartaku menjadi dua bagian, dan akau mempunyai dua istri, maka kana kau ceraikan salah satunya, jika masa iddahnya telah berlalu, maka nikahilah ia. Maka Abdurahman bin Auf menjawab, \"Semoga Allah memberkahimu, atas keluarga dan harta bendamu. Tunjukkanlah kepadaku letak pasar. Maka, mereka pun menunjukkan letak pasar kepadanya. Maka, tidaklah ia pulang pada hari itu (dari pasar) kecuali dengan membawa keju dan minyak samin yang telah ia ambil keuntungan darinya. Dan setelah itu, Rasulullah shallallahu 'alaihi wasallam melihatnya masih ada bekas padanya wadhar shufrah (warna kuning dari minyak za'faran). Maka beliau berkata, \"Ada apa denganmu?\" Ia menjawab, \"Aku telah menikah dengan seorang wanita Anshar.\" Nabi bertanya, \"Dengan apa kamu membayar mahar kepadanya? Ia menjawab, \"Dengan nawat.\" Humaid berkata, \"Ia berkata, \"Dengan seberat nawat dari emas.\" Lalu beliau berkata, \"Rayakanlah (pernikahanmu), walaupun hanya dengan memotong seekor kambing.\" Abu Isa berkata, \"Hadits ini hasan shahih.\" Imam bin Hambal berkata, \"Ukuran seberat nawat dari emas setara dengan 3 1/3 dirham. Ishaq bin Ibrahim berkata, Ukuran seberat nawat dari emas setara dengan 5 dirham. Aku mendengar Ishaq bin Manshur menyebutkan dari keduanya seperti ini."},"1857":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقِيلَ يَا رَسُولَ اللَّهِ مَا الْغِيبَةُ قَالَ ذِكْرُكَ أَخَاكَ بِمَا يَكْرَهُ قَالَ أَرَأَيْتَ إِنْ كَانَ فِيهِ مَا أَقُولُ قَالَ إِنْ كَانَ فِيهِ مَا تَقُولُ فَقَدْ اغْتَبْتَهُ وَإِنْ لَمْ يَكُنْ فِيهِ مَا تَقُولُ فَقَدْ بَهَتَّهُقَالَ وَفِي الْبَاب عَنْ أَبِي بَرْزَةَ وَابْنِ عُمَرَ وَعَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al Ala` bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] ia berkata; Ditatanyakan kepada Rasulullah, \"Wahai Rasulullah, apakah ghibah itu?\" beliau menjawab: \"Kamu menyebutkan tentang temanmu dengan sesuatu yang ia benci.\" Ia bertanya lagi, \"Bagaimana sekiranya apa yang kukatakan memang benar?\" Beliau menjawab: \"Jika memang apa yang kamu katakan itu benar, maka sungguh kamu telah menggibahnya, namun jika apa yang kamu katakan itu tidak benar, maka sungguh kamu telah berdusta.\" Hadits semakna juga diriwayatkan dari Abu Bazrah, Ibnu Umar dan Abdullah bin Amr. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1858":{"ar":"حَدَّثَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ الْعَطَّارُ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقَاطَعُوا وَلَا تَدَابَرُوا وَلَا تَبَاغَضُوا وَلَا تَحَاسَدُوا وَكُونُوا عِبَادَ اللَّهِ إِخْوَانًا وَلَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ وَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَالزُّبَيْرِ بْنِ الْعَوَّامِ وَابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Abdul Jabbar bin Al Ala` Al 'Aththar] dan [Sa'id bin Abdurrahman] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian saling memutuskan silaturrahim, bermusuh-musuhan, membenci dan janganlah pula saling dengki. Jadilah kalian sebagai hamba Allah yang saling bersaudara. Dan tidaklah halal bagi seorang mukmin untuk mendiamkan saudaranya lebih dari tiga hari.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Hasdits semakna juga diriwayatkan dari Abu Bakr Ash Shiddiq dan Az Zubair bin Awwam dan Ibnu Mas'ud dan Abu Hurairah."},"1859":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالًا فَهُوَ يُنْفِقُ مِنْهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَرَجُلٌ آتَاهُ اللَّهُ الْقُرْآنَ فَهُوَ يَقُومُ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ ابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Az Zuhri] dari [Salim] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan hasad kecuali pada dua hal; seorang laki-laki yang diberikan karunia oleh Allah berupa harta sehingga ia menginfakkannya di sepanjang malam dan siang, dan seseorang yang diberi karunia oleh berupa Al Qur`an hingga ia shalat dengannya di pertengahan malam dan siang.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Dan telah diriwayatkan pula dari Ibnu Mas'ud dan Abu Hurairah dari Nabi shallallahu 'alaihi wasallam semisal dengan hadits ini."},"1860":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّيْطَانَ قَدْ يَئِسَ أَنْ يَعْبُدَهُ الْمُصَلُّونَ وَلَكِنْ فِي التَّحْرِيشِ بَيْنَهُمْقَالَ وَفِي الْبَاب عَنْ أَنَسٍ وَسُلَيْمَانَ بْنِ عَمْرِو بْنِ الْأَحْوَصِ عَنْ أَبِيهِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَأَبُو سُفْيَانَ اسْمُهُ طَلْحَةُ بْنُ نَافِعٍ","id":"Telah menceritakan kepada kami [Hannad], elah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya setan telah putus asa untuk disembah oleh para penyembah. Namun ia terus menggalakkan permusuhan di antara mereka.\" Hadits semakna juga diriwayatkan dari Anas dan Sulaiman bin Amr bin Al Ahwash dari bapaknya. Abu Isa berkata; Ini adalah hadits Hasan. Dan Abu Sufyan namanya adalah Thalhah bin Nafi'. "},"1861":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّهِ أُمِّ كُلْثُومٍ بِنْتِ عُقْبَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيْسَ بِالْكَاذِبِ مَنْ أَصْلَحَ بَيْنَ النَّاسِ فَقَالَ خَيْرًا أَوْ نَمَى خَيْرًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ma'mar] dari [Az Zuhri] dari [Humaid bin Abdurrahman] dari [ibunya] Ummu Kultsum binti Uqbah, ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah termasuk pendusta, yaitu mereka yang mendamaikan perkara di antara manusia sehingga ia berkata yang baik atau menyampaikan sesuatu yang baik.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1862":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ قَالَ ح و حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ وَأَبُو أَحْمَدَ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ الْكَذِبُ إِلَّا فِي ثَلَاثٍ يُحَدِّثُ الرَّجُلُ امْرَأَتَهُ لِيُرْضِيَهَا وَالْكَذِبُ فِي الْحَرْبِ وَالْكَذِبُ لِيُصْلِحَ بَيْنَ النَّاسِو قَالَ مَحْمُودٌ فِي حَدِيثِهِ لَا يَصْلُحُ الْكَذِبُ إِلَّا فِي ثَلَاثٍ هَذَا حَدِيثٌ حَسَنٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أَسْمَاءَ إِلَّا مِنْ حَدِيثِ ابْنِ خُثَيْمٍ وَرَوَى دَاوُدُ بْنُ أَبِي هِنْدٍ هَذَا الْحَدِيثَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ فِيهِ عَنْ أَسْمَاءَ حَدَّثَنَا بِذَلِكَ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ دَاوُدَ وَفِي الْبَاب عَنْ أَبِي بَكْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abu Ahmad Az Zubairi], telah menceritakan kepada kami [Sufyan] ia berkata (dalam riwayat lain) Dan telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Bisyr As Sali] dan [Abu Ahmad] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Utsman bin Khutsaim] dari [Syahr bin Hausyab] dari [Asma` binti Yazid] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kedustaan itu tidak halal kecuali pada tiga hal; seorang suami yang berbicara terhadap isterinya agar ia ridla padanya; kedustaan pada peperangan; dan kedustaan yang dilakukan dalam rangka untuk mendamaikan (sesama) manusia.\" Mahmud berkata di dalam haditsnya; \"Tidak boleh berdusta kecuali pada tiga perkara.\" Ini adalah hadits hasan, kami tidak mengetahuinya dari hadits Asma` kecuali dari haditsnya Ibnu Khutsaim. Dan Dawud bin Abu Hind meriwayatkan hadits ini dari Syahr bin Hausyab dari Nabi shallallahu 'alaihi wasallam, dan di dalamnya ia tidak menyebutkan dari Asma`. Demikian pula, telah menceritakan kepada kami [Muhammad bin Al Ala`], telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Dawud]. Hadits semakna juga diriwayatkan dari Abu Bakar."},"1863":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ لُؤْلُؤَةَ عَنْ أَبِي صِرْمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ضَارَّ ضَارَّ اللَّهُ بِهِ وَمَنْ شَاقَّ شَاقَّ اللَّهُ عَلَيْهِوَفِي الْبَاب عَنْ أَبِي بَكْرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Lu`lu`ah] dari [Abu Shirmah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang akan mencelakai seseorang, maka Allah akan mencelakakannya, siapa yang akan menimpakan kesulitan terhadap seseorang, maka Allah akan menimpakan kesempitan atasnya.\" Hadits semakna juga diriwayatkan dari Abu Bakar. Abu Isa berkata; Ini adalah hadits hasan gharib."},"1864":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ الْعُكْلِيُّ حَدَّثَنِي أَبُو سَلَمَةَ الْكِنْدِيُّ حَدَّثَنَا فَرْقَدُ السَّبَخِيُّ عَنْ مُرَّةَ بْنِ شَرَاحِيلَ الْهَمْدَانِيِّ وَهُوَ الطَّيِّبُ عَنْ أَبِي بَكْرٍ الصِّدِّيقِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَلْعُونٌ مَنْ ضَارَّ مُؤْمِنًا أَوْ مَكَرَ بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abdu bin Humaid], telah menceritakan kepada kami [Zaid bin Al Hubab Al Ukli] telah menceritakan kepadaku [Abu Salamah Al Kindi], telah menceritakan kepada kami [Farqad As Sabakhi] dari [Murrah bin Syarahil Al Hamdani Ath Thyyib] dari [Abu Bakar Ash Shiddiq] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Terlaknatlah orang yang mencelakai seorang muslim atau berbuat makar kepadanya.\" Berkata Abu 'Isa: Ini merupakan hadits gharib."},"1865":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي بَكْرٍ هُوَ ابْنُ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا زَالَ جِبْرِيلُ يُوصِينِي بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Laits bin Sa'd] dari [Yahya bin Sa'id] dari [Abu Bakr bin Muhammad bin Amru bin Hazm] dari [Amrah] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jibril terus berwasiat kepadaku untuk berbuat baik kepada tetangga hingga aku mengira dia akan mewarisinya.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1866":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ دَاوُدَ بْنِ شَابُورَ وَبَشِيرٍ أَبِي إِسْمَعِيلَ عَنْ مُجَاهِدٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍوذُبِحَتْ لَهُ شَاةٌ فِي أَهْلِهِ فَلَمَّا جَاءَ قَالَ أَهْدَيْتُمْ لِجَارِنَا الْيَهُودِيِّ أَهْدَيْتُمْ لِجَارِنَا الْيَهُودِيِّ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا زَالَ جِبْرِيلُ يُوصِينِي بِالْجَارِ حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُقَالَ وَفِي الْبَاب عَنْ عَائِشَةَ وَابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَأَنَسٍ وَالْمِقْدَادِ بْنِ الْأَسْوَدِ وَعُقْبَةَ بْنِ عَامِرٍ وَأَبِي شُرَيْحٍ وَأَبِي أُمَامَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مُجَاهِدٍ عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْضًا","id":"Telah menceritakan kepada kami [Muhammad bin A'la], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Dawud bin Syabur] dan [Basyir Abu Isma'il] dari [Mujahid] bahwasanya; Pernah suatu ketika, seekor kambing disembelih dirumahnya [Abdullah bin Amr], maka ketika ia datang, ia pun bertanya, \"Apakah kalian sudah memberi tetangga Yahudi kita? Apakah kalian sudah memberi tetangga Yahudi kita? aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jibril terus berwasiat kepadaku untuk berbuat baik kepada tetangga hingga aku mengira dia akan mewarisinya.'\" Hadits semakna diriwayatkan dari 'Aisyah, Ibnu Abbas, Abu Hurairah, Anas, Miqdad bin Aswad, Uqbah bin Amir, Abu Syuraih dan Abu Umamah. Berkata Abu Isa: Ini merupakan hadits hasan gharib dari jalur ini. Hadits ini telah diriwayatkan juga dari [Mujahid] dari ['Aisyah] dan [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam."},"1867":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ حَيْوَةَ بْنِ شُرَيْحٍ عَنْ شُرَحْبِيلَ بْنِ شَرِيكٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الْأَصْحَابِ عِنْدَ اللَّهِ خَيْرُهُمْ لِصَاحِبِهِ وَخَيْرُ الْجِيرَانِ عِنْدَ اللَّهِ خَيْرُهُمْ لِجَارِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ اسْمُهُ عَبْدُ اللَّهِ بْنُ يَزِيدَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Haiwah bin Syuraih] dari [Syurahbil bin Syarik] dari [Abu Abdurrahman Al Hubuli] dari [Abdullah bin Amr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik sahabat di sisi Allah adalah seorang yang terbaik terhadap temannya. Dan tetangga yang paling terbaik di sisi Allah adalah seorang yang paling baik baik terhadap tetangganya.\" Abu Isa berkata; Ini adalah hadits hasan gharib. Abu Abdurrahman Al Hubuli, namanya adalah Abdullah bin Yazid."},"1868":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ وَاصِلٍ عَنْ الْمَعْرُورِ بْنِ سُوَيْدٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِخْوَانُكُمْ جَعَلَهُمْ اللَّهُ فِتْيَةً تَحْتَ أَيْدِيكُمْ فَمَنْ كَانَ أَخُوهُ تَحْتَ يَدِهِ فَلْيُطْعِمْهُ مِنْ طَعَامِهِ وَلْيُلْبِسْهُ مِنْ لِبَاسِهِ وَلَا يُكَلِّفْهُ مَا يَغْلِبُهُ فَإِنْ كَلَّفَهُ مَا يَغْلِبُهُ فَلْيُعِنْهُقَالَ وَفِي الْبَاب عَنْ عَلِيٍّ وَأُمِّ سَلَمَةَ وَابْنِ عُمَرَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Sufyan] dari [Washil] dari [Al Ma'rur bin Suwaid] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ada saudara-saudara kalian yang Allah memberikan ujian atas mereka dengan memberikan rezeki di bawah apa yang kalian miliki. Karena itu, barangsiapa yang saudaranya berada pada tanggungannya, hendaklah ia memberinya makan dari makanan yang ia miliki dan memberinya pakaian dari pakaian yang ia miliki. Serta janganlah ia membebaninya melebihi kemampuannya, jika ia membebaninya melebihi kemampuannya hendaklah ia membantunya.\" Hadits semakna juga diriwayatkan dari Ali, Ummu Salamah, Ibnu Umar dan Abu Hurairah. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1869":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ هَمَّامِ بْنِ يَحْيَى عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ مُرَّةَ عَنْ أَبِي بَكْرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ سَيِّئُ الْمَلَكَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ تَكَلَّمَ أَيُّوبُ السَّخْتِيَانِيُّ وَغَيْرُ وَاحِدٍ فِي فَرْقَدٍ السَّبَخِيِّ مِنْ قِبَلِ حِفْظِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Yazid bin Harun] dari [Hammam bin Yahya] dari [Farqad As Sabakhi] dari [Murrah] dari [Abu Bakar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan masuk surga majikan yang buruk.\" Abu Isa berkata; Ini adalah hadits gharib. Abu As Sakhtiyani dan lainnya mengenai Farqad As Sabakhi terkait dengan hafalannya (yang bermasalah)."},"1870":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ فُضَيْلِ بْنِ غَزْوَانَ عَنْ ابْنِ أَبِي نُعْمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيُّ التَّوْبَةِ مَنْ قَذَفَ مَمْلُوكَهُ بَرِيئًا مِمَّا قَالَ لَهُ أَقَامَ عَلَيْهِ الْحَدَّ يَوْمَ الْقِيَامَةِ إِلَّا أَنْ يَكُونَ كَمَا قَالَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَابْنُ أَبِي نُعْمٍ هُوَ عَبْدُ الرَّحْمَنِ بْنُ أَبِي نُعْمٍ الْبَجَلِيُّ يُكْنَى أَبَا الْحَكَمِ وَفِي الْبَاب عَنْ سُوَيْدِ بْنِ مُقَرِّنٍ وَعَبْدِ اللَّهِ بْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Fudlail bin Ghazwan] dari [Abu Nu'm] dari [Abu Hurairah] ia berkata; Abul Qasim shallallahu 'alaihi wasallam Nabiyut Taubah bersabda: \"Barangsiapa yang menuduh budaknya berzina, padahal budak itu bebas dari tuduhannya, maka hukuman had akan ditegakkan atasnya kelak pada hari kiamat. Kecuali jika mematang tuduhan itu adalah benar.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Ibnu Abu Nu'm adalah Abdurrahman bin Abu Nu'm Al Bajali, kuniahnya adalah Abul Hakam. Hadits semakna juga diriwayatkan dari Suwaid bin Muqarrin dan Abdullah bin Umar."},"1871":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَكُنْتُ أَضْرِبُ مَمْلُوكًا لِي فَسَمِعْتُ قَائِلًا مِنْ خَلْفِي يَقُولُ اعْلَمْ أَبَا مَسْعُودٍ اعْلَمْ أَبَا مَسْعُودٍ فَالْتَفَتُّ فَإِذَا أَنَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَلَّهُ أَقْدَرُ عَلَيْكَ مِنْكَ عَلَيْهِ قَالَ أَبُو مَسْعُودٍ فَمَا ضَرَبْتُ مَمْلُوكًا لِي بَعْدَ ذَلِكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَإِبْرَاهِيمُ التَّيْمِيُّ إِبْرَاهِيمُ بْنُ يَزِيدَ بْنِ شَرِيكٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Mu`amal], telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim At Tamimi] dari [bapaknya] dari [Abu Mas'ud Al Anshari] ia berkata; Aku pernah memukul budak milikku, lalu aku mendengar seseorang berkata di belakangku: \"Ketahuilah wahai Abu Mas'ud, ketahuilah wahai Abu Mas'ud.\" Maka aku pun berpaling, dan ternyata ia adalah Rasulullah shallallahu 'alaihi wasallam, kemudian beliau bersabda: \"Sesungguhnya Allah lebih mampu untuk berbuat sesuatu atasmu, daripada kamu berbuat sesuatu atasnya.\" Abu Mas'ud berkata, \"Maka aku tidak pernah lagi memukul budak milikku setelah kejadian itu.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Ibrahim At Tamimi adalah Ibrahim bin Yazid bin Syarik."},"1872":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ عَنْ أَبِي هَانِئٍ الْخَوْلَانِيِّ عَنْ عَبَّاسٍ الْحَجْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كَمْ أَعْفُو عَنْ الْخَادِمِ فَصَمَتَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ كَمْ أَعْفُو عَنْ الْخَادِمِ فَقَالَ كُلَّ يَوْمٍ سَبْعِينَ مَرَّةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَاهُ عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ أَبِي هَانِئٍ الْخَوْلَانِيِّ نَحْوًا مِنْ هَذَا وَالْعَبَّاسُ هُوَ ابْنُ جُلَيْدٍ الْحَجْرِيُّ الْمِصْرِيُّ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ أَبِي هَانِئٍ الْخَوْلَانِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ عَبْدِ اللَّهِ بْنِ وَهْبٍ بِهَذَا الْإِسْنَادِ وَقَالَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Risydin bin Sa'd] dari [Abu Hani` Al Khaulani] dari [Abbas Al Hajri] dari [Abdullah bin Umar] ia berkata; Seorang lelaki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rosulullah, berapa kalikah aku harus memaafkan pembantu?\" Lalu Nabi shallallahu 'alaihi wasallam terdiam, kemudian dia bertanya, \"Wahai Rasulullah, berapa kalikah aku harus memaafkan pembantu?\" Nabi menjawab: \"Kamu memaafkan sebanyak tujuh puluh kali dalam sehari.\" Berkata Abu 'Isa: Ini merupakan hadits hasan gharib. Dan diriwayatkan oleh [Abdullah bin Wahb] dari [Abi Hani Al Khaulani] seperti lafazh hadits ini. Al Abbas ialah Ibnu Julaid Al Hajri Al Mishri. Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdullah bin Wahb] dari [Abu Hani` Al Khaulani] dengan isnad ini semisalnya. Dan sebagian mereka meriwayatkan hadits ini dengan isnad ini dari [Abdullah bin Wahb], dan ia berkata; Dari [Abdullah bin Amr]."},"1873":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ أَبِي هَارُونَ الْعَبْدِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ضَرَبَ أَحَدُكُمْ خَادِمَهُ فَذَكَرَ اللَّهَ فَارْفَعُوا أَيْدِيَكُمْقَالَ أَبُو عِيسَى وَأَبُو هَارُونَ الْعَبْدِيُّ اسْمُهُ عُمَارَةُ بْنُ جُوَيْنٍ قَالَ قَالَ أَبُو بَكْرٍ الْعَطَّارُ قَالَ عَلِيُّ بْنُ الْمَدِينِيِّ قَالَ يَحْيَى بْنُ سَعِيدٍ ضَعَّفَ شُعْبَةُ أَبَا هَارُونَ الْعَبْدِيَّ قَالَ يَحْيَى وَمَا زَالَ ابْنُ عَوْنٍ يَرْوِي عَنْ أَبِي هُرَيْرَةَ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Sufyan] dari [Abu Harun Al Abdi] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian memukul pembantunya lalu dia menyebut nama Allah, maka angkatlah tangan kalian.\" Berkata Abu Isa: Abu Harun Al 'Abdi bernama: 'Umarah bin Juwain. Dia berkata: Abu Bakar Al 'Attar berkata, Ali bin Al Madini berkata, Yahya bin Sa'id berkata, \"Syu'bah men-dla'if-kan Abu Harun Al 'Abdi. Yahya berkata: Ibnu 'Aun masih terus meriwayatkan dari Abu Hurairah hingga dia meninggal."},"1874":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَحْيَى بْنُ يَعْلَى عَنْ نَاصِحٍ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يُؤَدِّبَ الرَّجُلُ وَلَدَهُ خَيْرٌ مِنْ أَنْ يَتَصَدَّقَ بِصَاعٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَنَاصِحٌ هُوَ أَبُو الْعَلَاءِ كُوفِيٌّ لَيْسَ عِنْدَ أَهْلِ الْحَدِيثِ بِالْقَوِيِّ وَلَا يُعْرَفُ هَذَا الْحَدِيثُ إِلَّا مِنْ هَذَا الْوَجْهِ وَنَاصِحٌ شَيْخٌ آخَرُ بَصْرِيٌّ يَرْوِي عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ وَغَيْرِهِ هُوَ أَثْبَتُ مِنْ هَذَا","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Yahya bin Ya'la] dari [Nashih] dari [Simak bin Harb] dari [Jabir bin Samurah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seseorang yang mengajari anaknya tentang kebaikan adalah lebih baik baginya daripada ia bersedekah sebanyak satu sha'.\" Abu Isa berkata; Ini adalah hadits gharib. Nashih adalah Abul Ala` Kufi, menurut Ahli hadits ia bukanlah termasuk rawi yang kuat. Dan hadits ini tidak diketahui kecuali dari jalur ini. Sedangkan Nashih adalah seorang syaikh yang lain, ia berasal dari Basrah dan meriwayatkan dari Ammar bin Abu Ammar dan juga selainnya, dan ia lebih kuat dari pada yang ini."},"1875":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا عَامِرُ بْنُ أَبِي عَامِرٍ الْخَزَّازُ حَدَّثَنَا أَيُّوبُ بْنُ مُوسَى عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا نَحَلَ وَالِدٌ وَلَدًا مِنْ نَحْلٍ أَفْضَلَ مِنْ أَدَبٍ حَسَنٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَامِرِ بْنِ أَبِي عَامِرٍ الْخَزَّازِ وَهُوَ عَامِرُ بْنُ صَالِحِ بْنِ رُسْتُمَ الْخَزَّازُ وَأَيُّوبُ بْنُ مُوسَى هُوَ ابْنُ عَمْرِو بْنِ سَعِيدِ بْنِ الْعَاصِي وَهَذَا عِنْدِي حَدِيثٌ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami], telah menceritakan kepada kami [Amir bin Abu Amir Al Khazzar], telah menceritakan kepada kami [Ayyub bin Musa] dari [bapaknya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada suatu pemberian seorang ayah kepada anaknya yang lebih utama daripada adab (akhlak) yang baik.\" Abu Isa berkata; Ini adalah hadits gharib, kami tidak mengetahuinya kecuali dari haditsnya Amir bin Abu Amir Al Khazzar, ia adalah Amir bin Shalih bin Rustum Al Khazzar. Sedangkan Ayyub bin Musa adalah Ibnu Amr bin Sa'id bin Al Ash. Dan menurutku, ini adalah hadits Mursal."},"1876":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَكْثَمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْبَلُ الْهَدِيَّةَ وَيُثِيبُ عَلَيْهَاوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَأَنَسٍ وَابْنِ عُمَرَ وَجَابِرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ مِنْ هَذَا الْوَجْهِ لَا نَعْرِفُهُ مَرْفُوعًا إِلَّا مِنْ حَدِيثِ عِيسَى بْنِ يُونُسَ عَنْ هِشَامٍ","id":"Telah menceritakan kepada kami [Yahya bin Aktsam] dan [Ali bin Khasyram] keduanya berkata, Telah menceritakan kepada kami [Isa bin Yunus] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwasanya Nabi shallallahu 'alaihi wasallam menerima hadiah dan membalasnya. Hadits semakna juga diriwayatkan dari Abu Hurairah, Anas, Ibnu Umar dan Jabir. Abu Isa berkata; Ini adalah hadits hasan gharib shahih ditinjau dari jalur ini. Kami tidak mengetahuinya sebagai hadits Marfu' kecuali dari haditsnya Isa bin Yunus dari Hisyam."},"1877":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا الرَّبِيعُ بْنُ مُسْلِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَا يَشْكُرُ النَّاسَ لَا يَشْكُرُ اللَّهَقَالَ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak], telah menceritakan kepada kami [Ar Rabi' bin Muslim], telah menceritakan kepada kami [Muhammad bin Ziyad] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang tidak pandai bersyukur (berterima kasih) kepada manusia, berarti ia belum bersyukur kepada Allah.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1878":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ ابْنِ أَبِي لَيْلَى ح و حَدَّثَنَا سُفْيَانُ بْنُ وَكِيعٍ حَدَّثَنَا حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ الرُّوَاسِيُّ عَنْ ابْنِ أَبِي لَيْلَى عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَشْكُرْ النَّاسَ لَمْ يَشْكُرْ اللَّهَوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَالْأَشْعَثِ بْنِ قَيْسٍ وَالنُّعْمَانِ بْنِ بَشِيرٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Ibnu Abu Laila] (dalam riwayat lain). Dan telah menceritakan kepada kami [Sufyan bin Waki'], telah menceritakan kepada kami [Humaid bin Abdurrahman Ar Ruwasi] dari [Ibnu Abu Laila] dari ['Athiyyah] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang tidak bersyukur kepada manusia, berarti ia belum bersyukur kepada Allah.\" Hadits semakna juga diriwyakan dari Abu Hurairah, Al Asy'ats bin Qais dan An Nu'man bin Basyir. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1879":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ حَدَّثَنَا النَّضْرُ بْنُ مُحَمَّدٍ الْجُرَشِيُّ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا أَبُو زُمَيْلٍ عَنْ مَالِكِ بْنِ مَرْثَدٍ عَنْ أَبِيهِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَسُّمُكَ فِي وَجْهِ أَخِيكَ لَكَ صَدَقَةٌ وَأَمْرُكَ بِالْمَعْرُوفِ وَنَهْيُكَ عَنْ الْمُنْكَرِ صَدَقَةٌ وَإِرْشَادُكَ الرَّجُلَ فِي أَرْضِ الضَّلَالِ لَكَ صَدَقَةٌ وَبَصَرُكَ لِلرَّجُلِ الرَّدِيءِ الْبَصَرِ لَكَ صَدَقَةٌ وَإِمَاطَتُكَ الْحَجَرَ وَالشَّوْكَةَ وَالْعَظْمَ عَنْ الطَّرِيقِ لَكَ صَدَقَةٌ وَإِفْرَاغُكَ مِنْ دَلْوِكَ فِي دَلْوِ أَخِيكَ لَكَ صَدَقَةٌقَالَ وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَجَابِرٍ وَحُذَيْفَةَ وَعَائِشَةَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو زُمَيْلٍ اسْمُهُ سِمَاكُ بْنُ الْوَلِيدِ الْحَنَفِيُّ","id":"Telah menceritakan kepada kami [Abbas bin Abdul Azhim Al Anbari], telah menceritakan kepada kami [An Nadlr bin Muhammad Al Jurasyi Al Yamami], telah menceritakan kepada kami [Ikrimah bin Ammar], telah menceritakan kepada kami [Abu Zuamail] dari [Malik bin Martsad] dari [bapaknya] dari [Abu Dzarr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Senyummu kepada saudaramu merupakan sedekah, engkau berbuat ma'ruf dan melarang dari kemungkaran juga sedekah, engkau menunjukkan jalan kepada orang yang tersesat juga sedekah, engkau menuntun orang yang berpenglihatan kabur juga sedekah, menyingkirkan batu, duri dan tulang dari jalan merupakan sedekah, dan engkau menuangkan air dari embermu ke ember saudaramu juga sedekah.\" Hadits semakna diriwayatkan dari Ibnu Mas'ud, Jabir, Hudzaifah, 'Aisyah dan Abu Hurairah. Berkata Abu 'Isa: Ini merupakan hadits hasan gharib dan Abu Zumail bernama Simak bin Walid Al Hanafi."},"1880":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يُوسُفَ بْنِ أَبِي إِسْحَقَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَقَ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ قَال سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَوْسَجَةَ يَقُولُ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ مَنَحَ مَنِيحَةَ لَبَنٍ أَوْ وَرِقٍ أَوْ هَدَى زُقَاقًا كَانَ لَهُ مِثْلَ عِتْقِ رَقَبَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ أَبِي إِسْحَقَ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رَوَى مَنْصُورُ بْنُ الْمُعْتَمِرِ وَشُعْبَةُ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ هَذَا الْحَدِيثَ وَفِي الْبَاب عَنْ النُّعْمَانِ بْنِ بَشِيرٍ وَمَعْنَى قَوْلِهِ مَنْ مَنَحَ مَنِيحَةَ وَرِقٍ إِنَّمَا يَعْنِي بِهِ قَرْضَ الدَّرَاهِمِ قَوْلُهُ أَوْ هَدَى زُقَاقًا يَعْنِي بِهِ هِدَايَةَ الطَّرِيقِ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Ibrahim bin Yusuf bin Abu Ishaq] dari [bapaknya] dari [Abu Ishaq] dari [Thalhah bin Musharrif] ia berkata, saya mendengar [Abdurrahman bin Ausajah] berkata, saya mendengar [Al Barra` bin Azib] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan pemberian susu (memberikan unta atau kambing untuk diambil susunya lalu dikembalikan lagi) dan wariq (perak, yakni meminjaminya), menunjuki jalan (kepada orang yang tersesat dan orang buta), maka baginya pahala seperti memerdekakan budak.\" Abu Isa berkata, hadits ini hasan shahih gharib, dari hadits Abu Ishaq dari Thalhah bin Musharrif, kami tidak mengetahuinya kecuali dari jalur periwayatan ini. Telah meriwayatkan hadits ini juga [Manshur bin Al Mu'tamir] dan [Syu'bah] dari [Thalhah bin Musharrif], dan dalam bab ini dari Nu'man bin Basyir. Makna sabda beliau 'memberikan pemberian wariq (perak) ' adalah memberikan pinjaman beberapa dirham. Dan makna sabda beliau 'hada zuqaqan' adalah menunjuki (arah) jalan."},"1881":{"ar":"حَدَّثَنَا قُتَيْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَيْنَمَا رَجُلٌ يَمْشِي فِي طَرِيقٍ إِذْ وَجَدَ غُصْنَ شَوْكٍ فَأَخَّرَهُ فَشَكَرَ اللَّهُ لَهُ فَغَفَرَ لَهُوَفِي الْبَاب عَنْ أَبِي بَرْزَةَ وَابْنِ عَبَّاسٍ وَأَبِي ذَرٍّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] dari [Malik bin Anas] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada seseorang berjalan, tiba-tiba ia menemukan sebuah ranting duri, lalu ia pun menyingkirkan (membuangnya dari jalan), maka Allah bersyukur kepadanya dan mengampuninya.' Dalam bab ini diriwayatkan dari Abu Barzah, Ibnu Abbas, dan Abu Dzar Abu Isa berkata, hadits ini hasan shahih."},"1882":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ ابْنِ أَبِي ذِئْبٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَطَاءٍ عَنْ عَبْدِ الْمَلِكِ بْنِ جَابِرِ بْنِ عَتِيكٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا حَدَّثَ الرَّجُلُ الْحَدِيثَ ثُمَّ الْتَفَتَ فَهِيَ أَمَانَةٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَإِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ ابْنِ أَبِي ذِئْبٍ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Ibnu Abu Dzi`b] ia berkata, Telah mengabarkan kepadaku [Abdurrahman bin Atha`] dari [Abdul Malik bin Jabir bin Atik] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika seseorang bercerita tentang sesuatu kata lalu ia berpaling (agar perkataannya tidak tersebar), maka ungkapkannya itu adalah amanah.\" Abu Isa berkata; Ini adalah hadits Hasan, namun kami hanya mengetahuinya dari haditsnya Ibnu Abu Dzi`b."},"1883":{"ar":"حَدَّثَنَا أَبُو الْخَطَّابِ زِيَادُ بْنُ يَحْيَى الْبَصْرِيُّ حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ حَدَّثَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ لَيْسَ لِي مِنْ بَيْتِي إِلَّا مَا أَدْخَلَ عَلَيَّ الزُّبَيْرُ أَفَأُعْطِي قَالَ نَعَمْ وَلَا تُوكِي فَيُوكَى عَلَيْكِ يَقُولُ لَا تُحْصِي فَيُحْصَى عَلَيْكِوَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَ�� هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ بِهَذَا الْإِسْنَادِ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا وَرَوَى غَيْرُ وَاحِدٍ هَذَا عَنْ أَيُّوبَ وَلَمْ يَذْكُرُوا فِيهِ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ","id":"Telah menceritakan kepada kami [Abu Al Khaththab Ziyad bin Yahya Al Bashari], telah menceritakan kepada kami [Hatim bin Wardan], telah menceritakan kepada kami [Ayyub] dari [Abu Mulaikah] dari [Asma' binti Abu Bakar] ia berkata, \"Wahai Rasulullah, sesungguhnya aku tidak memiliki sesuatu kecuali apa yang diberikan oleh Zubair kepadaku, apakah aku harus bersedekah dengannya?\" Nabi menjawab: \"Ya, dan janganlah engkau bakhil, maka Allah akan bakhil kepadamu. Hadits semakna diriwayatkan dari 'Aisyah dan Abu Hurairah. Berkata Abu Isa; Ini merupakan hadits hasan shahih. Dan sebagian mereka meriwayatkan hadits ini dengan sanad ini dari [Ibnu Abi Mulaikah] dari ['Abbad bin Abdullah bin Zubair] dari [Asma' binti Abi Bakar] radliallahu 'anhuma. Dan banyak yang meriwayatkan hadits ini dari [Ayyub], namun mereka tidak menyebutkan di dalamnya dari Abbad bin Abdullah bin Zubair."},"1884":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَرَفَةَ حَدَّثَنَا سَعِيدُ بْنُ مُحَمَّدٍ الْوَرَّاقُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّخِيُّ قَرِيبٌ مِنْ اللَّهِ قَرِيبٌ مِنْ الْجَنَّةِ قَرِيبٌ مِنْ النَّاسِ بَعِيدٌ مِنْ النَّارِ وَالْبَخِيلُ بَعِيدٌ مِنْ اللَّهِ بَعِيدٌ مِنْ الْجَنَّةِ بَعِيدٌ مِنْ النَّاسِ قَرِيبٌ مِنْ النَّارِ وَلَجَاهِلٌ سَخِيٌّ أَحَبُّ إِلَى اللَّهِ عَزَّ وَجَلَّ مِنْ عَالِمٍ بَخِيلٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ يَحْيَى بْنِ سَعِيدٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ إِلَّا مِنْ حَدِيثِ سَعِيدِ بْنِ مُحَمَّدٍ وَقَدْ خُولِفَ سَعِيدُ بْنُ مُحَمَّدٍ فِي رِوَايَةِ هَذَا الْحَدِيثِ عَنْ يَحْيَى بْنِ سَعِيدٍ إِنَّمَا يُرْوَى عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَائِشَةَ شَيْءٌ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Hasan bin Arafah], telah menceritakan kepada kami [Sa'id bin Muhammad Al Warraq] dari [Yahya bin Sa'id] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang dermawan itu dekat dengan Allah, dekat dengan surga, dekat dengan manusia, dan jauh dari neraka. Sedangkan orang yang bakhil itu jauh dari Allah, jauh dari surga, jauh dari menusia, dan dekat dengan neraka. Sesungguhnya orang bodoh yang dermawan lebih Allah cintai dari pada seorang 'alim yang bakhil.\" Abu 'Isa berkata; Ini merupakan hadits gharib tidak kami ketahui dari haditsnya Yahya bin 'Araj dari Abu Hurairah kecuali dari haditsnya Sa'id bin Muhammad dan Sa'id bin Muhammad telah ditentang dalam periwayatan hadits ini dari Yahya bin Sa'id Al Anshari, Sebenarnya yang diriwayatkan dari Yahya bin Sa'id dari 'Aisyah merupakan hadits mursal."},"1885":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ أَخْبَرَنَا أَبُو دَاوُدَ حَدَّثَنَا صَدَقَةُ بْنُ مُوسَى حَدَّثَنَا مَالِكُ بْنُ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ غَالِبٍ الْحُدَّانِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَصْلَتَانِ لَا تَجْتَمِعَانِ فِي مُؤْمِنٍ الْبُخْلُ وَسُوءُ الْخُلُقِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ صَدَقَةَ بْنِ مُوسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Abu Hafsh Amr bin Ali], telah mengabarkan kepada kami [Abu Dawud], telah menceritakan kepada kami [Shadaqah bin Musa], telah menceritakan kepada kami [Malik bin Dinar] dari [Abdullah bin Ghalib Al Huddani] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada dua sifat yang tidak akan berkumpul dalam diri seorang mukmin, yaitu: Sifat bakhil dan akhlak yang buruk.\" Abu Isa berkata; Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari haditsnya Shadaqah bin Musa. Dan hadits semakna diriwayatkan dari Abu Hurairah."},"1886":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا صَدَقَةُ بْنُ مُوسَى عَنْ فَرْقَدٍ السَّبَخِيِّ عَنْ مُرَّةَ الطَّيِّبِ عَنْ أَبِي بَكْرٍ الصِّدِّيقِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ خِبٌّ وَلَا مَنَّانٌ وَلَا بَخِيلٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Yazid bin Harun], telah menceritakan kepada kami [Shadaqah bin Musa] dari [Farqad As Sabakhi] dari [Murrah Ath Thayyib] dari [Abu Bakr Ash Shiddiq] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan masuk surga yaitu Khibbun (penipu dan selalu membuat kerusakan di tengah manusia) dan Al Mannan (seorang yang membangga-banggakan kebaikannya).\" Abu Isa berkata; Ini adalah hadits hasan gharib."},"1887":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ بِشْرِ بْنِ رَافِعٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُؤْمِنُ غِرٌّ كَرِيمٌ وَالْفَاجِرُ خِبٌّ لَئِيمٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'], telah menceritakan kepada kami [Abdurrazzaq] dari [Bisyr bin Rafi'] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang mukmin itu senantiasa berlapang dada dan dermawan, sedangkan seorang fajir itu bakhil dan berakhlak buruk.\" Abu 'Isa berkata; Ini adalah hadits gharib, tidak kami ketahui kecuali dari jalur ini."},"1888":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ شُعْبَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَفَقَةُ الرَّجُلِ عَلَى أَهْلِهِ صَدَقَةٌوَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَمْرِو بْنِ أُمَيَّةَ الضَّمْرِيِّ وَأَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Syu'bah] dari [Adi bin Tsabit] dari [Abdullah bin Yazid] dari [Abu Mas'ud Al Anshari] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Nafkah yang diberikan seseorang kepada keluarganya adalah bernilai sedekah.\" Hadits semakna juga diriwayatkan dari Abdullah bin Amr, Amr bin Umayyah Adl Dlamri dan Abu Hurairah. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1889":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَفْضَلُ الدِّينَارِ دِينَارٌ يُنْفِقُهُ الرَّجُلُ عَلَى عِيَالِهِ وَدِينَارٌ يُنْفِقُهُ الرَّجُلُ عَلَى دَابَّتِهِ فِي سَبِيلِ اللَّهِ وَدِينَارٌ يُنْفِقُهُ الرَّجُلُ عَلَى أَصْحَابِهِ فِي سَبِيلِ اللَّهِ قَالَ أَبُو قِلَابَةَ بَدَأَ بِالْعِيَالِ ثُمَّ قَالَ فَأَيُّ رَجُلٍ أَعْظَمُ أَجْرًا مِنْ رَجُلٍ يُنْفِقُ عَلَى عِيَالٍ لَهُ صِغَارٍ يُعِفُّهُمْ اللَّهُ بِهِ وَيُغْنِيهِمْ اللَّهُ بِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma`] dari [Tsauban] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Dinar yang paling utama adalah Dinar yang diinfakkan seseorang untuk keluarganya, Dinar yang dibelanjakan seseorang untuk kendaraannya di jalan Allah, dan Dinar yang dibelanjakan oleh seseorang untuk para sahabatnya di jalan Allah.\" Abu Qilabah berkata; Beliau memulai dengan keluarga. Kemudian beliau berkata: \"Lalu siapakah yang lebih besar (pahalanya) daripada seorang yang membelanjakan hartanya untuk keluarganya, dimana dengannya Allah memuliakan mereka dan memberi mereka kecukupan?\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1890":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّ أَنَّهُ قَالَأَبْصَرَتْ عَيْنَايَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعَتْهُ أُذُنَايَ حِينَ تَكَلَّمَ بِهِ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتَهُ قَالُوا وَمَا جَائِزَتُهُ قَالَ يَوْمٌ وَلَيْلَةٌ وَالضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَمَا كَانَ بَعْدَ ذَلِكَ فَهُوَ صَدَقَةٌ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Laitsi bin Sa'd] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Syuraih Al Adawi] ia berkata; Kedua mataku pernah melihat Rasulullah shallallahu 'alaihi wasallam dan kedua telingapun mendengar saat beliau bersabda: \"Barangsiapa yang beriman kepada Allah, maka hendaklah ia memuliakan tamunya dengan memenuhi bagian (hak, batasan) nya.\" Mereka para sahabat berkata, \"Apakah bagiannya?\" Beliau menjawab: \"Bagiannya adalah sehari semalam. Batasan bertamu itu adalah tiga hari, dan setelah hari itu adalah sedekah. Dan barangsiapa yang beriman kepada Allah dan hari akhirat, maka hendaklah ia berkata-kata baik atau diam.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1891":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْكَعْبِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَجَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ وَمَا أُنْفِقَ عَلَيْهِ بَعْدَ ذَلِكَ فَهُوَ صَدَقَةٌ وَلَا يَحِلُّ لَهُ أَنْ يَثْوِيَ عِنْدَهُ حَتَّى يُحْرِجَهُوَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو شُرَيْحٍ الْخُزَاعِيُّ هُوَ الْكَعْبِيُّ وَهُوَ الْعَدَوِيُّ اسْمُهُ خُوَيْلِدُ بْنُ عَمْرٍو وَمَعْنَى قَوْلِهِ لَا يَثْوِي عِنْدَهُ يَعْنِي الضَّيْفَ لَا يُقِيمُ عِنْدَهُ حَتَّى يَشْتَدَّ عَلَى صَاحِبِ الْمَنْزِلِ وَالْحَرَجُ هُوَ الضِّيقُ إِنَّمَا قَوْلُهُ حَتَّى يُحْرِجَهُ يَقُولُ حَتَّى يُضَيِّقَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Ibnu Ajlan] dari [Sa'id Al Maqburi] dari [Abu Syuraih Al Ka'bi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bertamu itu (batasannya) adalah tiga hari, sedangkan lamanya bertamu secara syar'i adalah sehari semalam. Dan apa yang diinfakkan kepadanya setelah itu adalah bernilai sedekah. Dan tidak halal baginya untuk bermalam di suatu rumah hingga ia menyusahkan shahibul bait (pemilik rumah).\" Hadits semakna juga diriwayatkan dari Aisyah dan Abu Hurairah. [Malik bin Anas] dan [Al Laits bin Sa'd] telah meriwayatkannya dari [Sa'id Al Maqburi]. Abu Isa berkata; Ini adalah hadits hasan shahih. Abu Syuraih adalah Al Ka'bi Al 'Adawi namanya Khuwailid bin Amr. Menurutnya, makna sabda beliau: \"Laa Yatswi\" bahwa hendaklah tamu tidak bermalam hingga menyusahkan shahibul bait. Al Haraj artinya kesempitan atau kesusahan. Sabda beliau: \"Hatta Yuhrijahu\" maksudnya: Hingga ia menyusahkannya."},"1892":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ صَفْوَانَ بْنِ سُلَيْمٍيَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّاعِي عَلَى الْأَرْمَلَةِ وَالْمِسْكِينِ كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ أَوْ كَالَّذِي يَصُومُ النَّهَارَ وَيَقُومُ اللَّيْلَحَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكٌ عَنْ ثَوْرِ بْنِ زَيْدٍ الدِّيلِيِّ عَنْ أَبِي الْغَيْثِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ وَهَذَا الْحَدِيثُ حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ وَأَبُو الْغَيْثِ اسْمُهُ سَالِمٌ مَوْلَى عَبْدِ اللَّهِ بْنِ مُطِيعٍ وَثَوْرُ بْنُ زَيْدٍ مَدَنِيٌّ وَثَوْرُ بْنُ يَزِيدَ شَامِيٌّ","id":"Telah menceritakan kepada kami [Al Anshari], telah menceritakan kepada kami [Ma'n], telah menceritakan kepada kami [Malik] dari [Shafwan bin Sulaim] ia saya memarfu-kan kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Orang yang memenuhi kebutuhan orang yang kehabisan bekal dan fakir miskin, maka pahalanya seperti Mujahid yang berjuang di jalan Allah, atau seperti seorang yang berpuasa sepanjang siang dan qiyamullail semalam suntuk.\" Telah menceritakan kepada kami [Al Anshari], telah menceritakan kepada kami [Ma'n], telah menceritakan kepada kami [Malik] dari [Ats Tsaur bin Zaid Ad Dili] dari [Abul Ghaits] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti itu. Dan hadits ini adalah hadits hasan gharib shahih. Abul Ghaits namanya adalah Salim mantan budak Abdullah bin Muthi'. Tsaur bin Zaid adalah Madani (orang Madinah), sedangkan Tsaur bin Yazid adalah Syami (orang Syam)."},"1893":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا الْمُنْكَدِرُ بْنُ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَعْرُوفٍ صَدَقَةٌ وَإِنَّ مِنْ الْمَعْرُوفِ أَنْ تَلْقَى أَخَاكَ بِوَجْهٍ طَلْقٍ وَأَنْ تُفْرِغَ مِنْ دَلْوِكَ فِي إِنَاءِ أَخِيكَوَفِي الْبَاب عَنْ أَبِي ذَرٍّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Munkadir bin Muhammad bin Al Munkadir] dari [bapaknya] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kebaikan adalah sedekah. Dan di antara bentuk kebaikan adalah kamu menjumpai saudaramu dengan wajah yang menyenangkan. Dan kamu menuangkan air dari embermu ke dalam bejana milik saudaramu.\" Hadits semakna juga diriwayatkan dari Abu Dzarr. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1894":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِالصِّدْقِ فَإِنَّ الصِّدْقَ يَهْدِي إِلَى الْبِرِّ وَإِنَّ الْبِرَّ يَهْدِي إِلَى الْجَنَّةِ وَمَا يَزَالُ الرَّجُلُ يَصْدُقُ وَيَتَحَرَّى الصِّدْقَ حَتَّى يُكْتَبَ عِنْدَ اللَّهِ صِدِّيقًا وَإِيَّاكُمْ وَالْكَذِبَ فَإِنَّ الْكَذِبَ يَهْدِي إِلَى الْفُجُورِ وَإِنَّ الْفُجُورَ يَهْدِي إِلَى النَّارِ وَمَا يَزَالُ الْعَبْدُ يَكْذِبُ وَيَتَحَرَّى الْكَذِبَ حَتَّى يُكْتَبَ عِنْدَ اللَّهِ كَذَّابًاوَفِي الْبَاب عَنْ أَبِي بَكْرٍ الصِّدِّيقِ وَعُمَرَ وَعَبْدِ اللَّهِ بْنِ الشِّخِّيرِ وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [A'masy] dari [Syaqiq bin Salamah] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaklah kalian bersikap jujur, karena kejujuran itu akan membawa pada kebaikan, sedangkan kebaikan akan membawa kepada surga. Tidaklah seorang bersikap jujur dan selalu berbuat jujur hingga ia ditulis di sisi Allah sebagai orang yang jujur. Dan hendaklah kalian menjauhi sikap dusta, karena kedustaan itu akan membawa pada kekejian, sedangkan kekejian akan membawa kepada neraka. Dan tidaklah seorang berbuat dusta dan selalu berdusta hingga ia ditulis di sisi Allah sebagai seorang pendusta.\" Hadits semakna juga diriwayatkan dari Abu Bakar Ash Shiddiq, Umar, Abdullah bin Asy Syikhkhir dan Ibnu Umar. Abu Isa berkata; Ini adalah hadits Hasan Shahih."},"1895":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى قَالَ قُلْتُ لِعَبْدِ الرَّحِيمِ بْنِ هَارُونَ الْغَسَّانِيِّ حَدَّثَكُمْ عَبْدُ الْعَزِيزِ بْنُ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَذَبَ الْعَبْدُ تَبَاعَدَ عَنْهُ الْمَلَكُ مِيلًا مِنْ نَتْنِ مَا جَاءَ بِهِ قَالَ يَحْيَى فَأَقَرَّ بِهِ عَبْدُ الرَّحِيمِ بْنُ هَارُونَ فَقَالَ نَعَمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ جَيِّدٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ تَفَرَّدَ بِهِ عَبْدُ الرَّحِيمِ بْنُ هَارُونَ","id":"Telah menceritakan kepada kami [Yahya bin Musa] ia berkata; Abu pernah berkata kepada [Abdurrahim bin Harun Al Ghassani], telah menceritakan kepada kalian [Abdul Aziz bin Abu Rawwad] dari [Nafi'] dari [Ibnu Umar] ia berkata; Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang hamba berdusta, maka malaikat akan menjauh darinya sejauh satu mil karena bau busuk yang keluar darinya.\" Berkata Yahya: Abdurrahim bin Harun menetapkannya seraya berkata, \"Ya.\" Abu Isa berkata; Ini merupakan hadits hasan jayyid gharib tidak kami ketahui kecuali dari jalur ini dan Abdurrahim bin Harun sendirian dalam meriwayatkan hadits ini."},"1896":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَائِشَةَ قَالَتْمَا كَانَ خُلُقٌ أَبْغَضَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْكَذِبِ وَلَقَدْ كَانَ الرَّجُلُ يُحَدِّثُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْكِذْبَةِ فَمَا يَزَالُ فِي نَفْسِهِ حَتَّى يَعْلَمَ أَنَّهُ قَدْ أَحْدَثَ مِنْهَا تَوْبَةًقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Yahya bin Musa], telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Ayyub] dari [Ibnu Abu Mulaikah] dari [Aisyah] ia berkata; Tidak ada akhlak yang paling dibenci Allah melebihi sifat dusta."},"1897":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا كَانَ الْفُحْشُ فِي شَيْءٍ إِلَّا شَانَهُ وَمَا كَانَ الْحَيَاءُ فِي شَيْءٍ إِلَّا زَانَهُوَفِي الْبَاب عَنْ عَائِشَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّزَّاقِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul A'la Ash Shan'ani] dan lebih dari satu orang, mereka berkata, Telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Tsabit] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah sifat buruk berada dalam sesuatu kecuali akan memperburuknya, dan tidaklah sifat malu ada dalam sesuatu kecuali akan menghiasinya.\" Berkata Abu Isa: Ini merupakan hadits Hasan Gharib yang tidak kami ketahui kecuali dari haditsnya Abdurrazzaq."},"1898":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْأَعْمَشِ قَال سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خِيَارُكُمْ أَحَاسِنُكُمْ أَخْلَاقًا وَلَمْ يَكُنْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاحِشًا وَلَا مُتَفَحِّشًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah meriwayatkan kepada kami [Abu Dawud] ia berkata, Telah memberitakan kepada kami [Syu'bah] dari [A'masy] ia berkata; Aku mendengar [Abu Wa`il] menceritakan dari [Masruq] dari [Abdullah bin Amr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik orang di antara kalian adalah orang yang paling baik akhlaknya di antara kalian.\" Nabi shallallahu 'alaihi wasallam bukanlah seorang yang buruk perangainya. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1899":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدَبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلَاعَنُوا بِلَعْنَةِ اللَّهِ وَلَا بِغَضَبِهِ وَلَا بِالنَّارِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَأَبِي هُرَيْرَةَ وَابْنِ عُمَرَ وَعِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian saling melaknat dengan mengucapkan, Allah melaknat kamu atau Kamu mendapatkan murka Allah atau semoga Allah memasukkanmu ke dalam neraka.\" Dia berkata: Hadits semakna diriwayatkan dari Ibnu Abbas, Abu Hurairah, Ibnu Umar dan Imran bin Husain. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1900":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْأَزْدِيُّ الْبَصْرِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ عَنْ إِسْرَائِيلَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ الْمُؤْمِنُ بِالطَّعَّانِ وَلَا اللَّعَّانِ وَلَا الْفَاحِشِ وَلَا الْبَذِيءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ عَنْ عَبْدِ اللَّهِ مِنْ غَيْرِ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Azdi Al Bashari], telah menceritakan kepada kami [Muhammad bin Sabiq] dari [Isra`il] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah termasuk hamba yang mukmin, yaitu mereka yang selalu mengungkap aib, melaknat, berperangai buruk dan suka menyakiti.\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib. Dan telah diriwayatkan pula dari Abdullah selain jalur ini."},"1901":{"ar":"حَدَّثَنَا زَيْدُ بْنُ أَخْزَمَ الطَّائِيُّ الْبَصْرِيُّ حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ قَتَادَةَ عَنْ أَبِي الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا لَعَنَ الرِّيحَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَلْعَنْ الرِّيحَ فَإِنَّهَا مَأْمُورَةٌ وَإِنَّهُ مَنْ لَعَنَ شَيْئًا لَيْسَ لَهُ بِأَهْلٍ رَجَعَتْ اللَّعْنَةُ عَلَيْهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْلَمُ أَحَدًا أَسْنَدَهُ غَيْرَ بِشْرِ بْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Zaid bin Akhzam Ath Tha`i Al Bashari], telah menceritakan kepada kami [Bisyr bin Umar], telah menceritakan kepada kami [Aban bin Yazid] dari [Qatadah] dari [Abu Al 'Aliyah] dari [Ibnu Abbas] bahwasanya; Ada seorang lelaki melaknat angin dihadapan Nabi shallallahu 'alaihi wasallam. Lantas beliau pun bersabda: \"Janganlah kamu melaknat angin karena dia itu diperintah, barangsiapa yang melaknat sesuatu sedangkan yang dilaknat itu tidak berhak atasnya (laknatan itu), maka laknat itu akan kembali kepadanya.\" Abu Isa berkata: Ini merupakan hadits gharib yang tidak kami ketahui seorangpun mensanadkannya kecuali Bisyr bin Umar."},"1902":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ عَبْدِ الْمَلِكِ بْنِ عِيسَى الثَّقَفِيِّ عَنْ يَزِيدَ مَوْلَى الْمُنْبَعِثِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَلَّمُوا مِنْ أَنْسَابِكُمْ مَا تَصِلُونَ بِهِ أَرْحَامَكُمْ فَإِنَّ صِلَةَ الرَّحِمِ مَحَبَّةٌ فِي الْأَهْلِ مَثْرَاةٌ فِي الْمَالِ مَنْسَأَةٌ فِي الْأَثَرِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَمَعْنَى قَوْلِهِ مَنْسَأَةٌ فِي الْأَثَرِ يَعْنِي بِهِ الزِّيَادَةَ فِي الْعُمُرِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Abdul Malik bin Isa Ats Tsaqafi] dari [Yazid Maula Al Munba'itsi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Belajarlah dari nasab kalian yang dapat membantu untuk silaturrahmi karena silaturrahmi itu dapat membawa kecintaan dalam keluarga dan memperbanyak harta, serta dapat memperpanjang umur.\" Abu Isa berkata: Ini merupakan hadits gharib melalui jalur ini."},"1903":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا قَبِيصَةُ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ زِيَادِ بْنِ أَنْعُمٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا دَعْوَةٌ أَسْرَعَ إِجَابَةً مِنْ دَعْوَةِ غَائِبٍ لِغَائِبٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَالْأَفْرِيقِيُّ يُضَعَّفُ فِي الْحَدِيثِ وَهُوَ عَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمٍ وَعَبْدُ اللَّهِ بْنُ يَزِيدَ هُوَ أَبُو عَبْدِ الرَّحْمَنِ الْحُبُلِيُّ","id":"Telah menceritakan kepada kami [Abdu bin Humaid], telah menceritakan kepada kami [Qabishah] dari [Sufyan] dari [Abdurrahman bin Ziyad bin An'um] dari [Abdullah bin Yazid] dari [Abdullah bin Amr] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada do'a yang lebih cepat dikabulkan dari pada do'a orang yang ghaib untuk yang ghaib (yakni tidak diketahui oleh yang didoakan karena ketulusannya dan jauh dari riya').\" Abu Isa berkata: Ini merupakan hadits gharib tidak kami ketahui kecuali dari jalur ini dan Al Ifriqy adalah seorang yang didla'ifkan dalam hadits, dia bernama Abdurrahman bin Ziyad bin An'um."},"1904":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْتَبَّانِ مَا قَالَا فَعَلَى الْبَادِي مِنْهُمَا مَا لَمْ يَعْتَدْ الْمَظْلُومُوَفِي الْبَاب عَنْ سَعْدٍ وَابْنِ مَسْعُودٍ وَعَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al 'Ala` bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] ia berkata; Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Kedua orang yang saling menghina, maka dosa dari perkataan keduanya ditanggung oleh orang yang memulai selama orang yang dizhalimi (dihina) tidak berlebih-lebihan dalam membalas hinaan.\" Hadits semakna diriwayatkan dari Sa'ad, Ibnu Mas'ud dan Abdullah bin Mughaffal. Berkata Abu Isa: Ini merupakan hadits hasan shahih."},"1905":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَال سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَسُبُّوا الْأَمْوَاتَ فَتُؤْذُوا الْأَحْيَاءَقَالَ أَبُو عِيسَى وَقَدْ اخْتَلَفَ أَصْحَابُ سُفْيَانَ فِي هَذَا الْحَدِيثِ فَرَوَى بَعْضُهُمْ مِثْلَ رِوَايَةِ الْحَفَرِيِّ وَرَوَى بَعْضُهُمْ عَنْ سُفْيَانَ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَال سَمِعْتُ رَجُلًا يُحَدِّثُ عِنْدَ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Dawud Al Hafari] dari [Sufyan] dari [Ziyad bin Ilaqah] ia berkata, saya mendengar [Al Mughirah bin Syu'bah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengina mereka yang sudah mati, sehingga kalian menyakiti mereka yang masih hidup.\" Abu Isa berkata; para teman (pengikut) Sufyan berselisih terkait dengan hadits ini. Sebagian mereka meriwayatkan sebagaimana riwayatnya Al Hafari, dan sebagian yang lain meriwayatkan dari Sufyan dari Ziyad bin Ilaqah, ia berkata, mendengar seorang laki-laki menceritakan di sisi Al Mughirah bin Syu'bah dari Nabi shallallahu 'alaihi wasallam, semisalnya."},"1906":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ زُبَيْدِ بْنِ الْحَارِثِ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِبَابُ الْمُسْلِمِ فُسُوقٌ وَقِتَالُهُ كُفْرٌ قَالَ زُبَيْدٌ قُلْتُ لِأَبِي وَائِلٍ أَأَنْتَ سَمِعْتَهُ مِنْ عَبْدِ اللَّهِ قَالَ نَعَمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Waki'], telah menceritakan kepada kami [Sufyan] dari [Zubaid bin Al Harits] dari [Abu Wa`il] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menghina seorang mukmin adalah perbuatan fasik, sedangkan membunuhkan adalah kekafiran.\" Zaid berkata; Aku bertanya kepada Abu Wa`il, \"Apakah Anda mendengarnya dari Abdullah?\" Ia menjawab, \"Ya.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1907":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ النُّعْمَانِ بْنِ سَعْدٍ عَنْ عَلِيٍّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجَنَّةِ غُرَفًا تُرَى ظُهُورُهَا مِنْ بُطُونِهَا وَبُطُونُهَا مِنْ ظُهُورِهَا فَقَامَ أَعْرَابِيٌّ فَقَالَ لِمَنْ هِيَ يَا رَسُولَ اللَّهِ قَالَ لِمَنْ أَطَابَ الْكَلَامَ وَأَطْعَمَ الطَّعَامَ وَأَدَامَ الصِّيَامَ وَصَلَّى لِلَّهِ بِاللَّيْلِ وَالنَّاسُ نِيَامٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْحَدِيثِ فِي عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ هَذَا مِنْ قِبَلِ حِفْظِهِ وَهُوَ كُوفِيٌّ وَعَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ الْقُرَشِيُّ مَدَنِيُّ وَهُوَ أَثْبَتُ مِنْ هَذَا وَكِلَاهُمَا كَانَا ف��ي عَصْرٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Ali bin Hujr], telah menceritakan kepada kami [Ali bin Mushir] dari [Abdurrahman bin Ishaq] dari [An Nu'man bin Sa'd] dari [Ali] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di surga terdapat kamar-kamar yang mana bagian luarnya terlihat dari bagian dalam dan bagian dalamnya terlihat dari bagian luarnya.\" Lantas seorang arab baduwi berdiri sambil berkata, \"Bagi siapakah kamar-kamar itu diperuntukkan wahai Rasululullah?\" Nabi menjawab: \"Untuk orang yang berkata benar, yang memberi makan, dan yang senantiasa berpuasa dan shalat pada malam hari diwaktu manusia pada tidur.\" Berkata Abu Isa: Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari haditsnya Abdurrahman bin Ishaq dan sebagian ahli hadits telah mengomentari Abdurrahman bin Ishaq dari segi hapalannya, dia berasal dari Kufah. Adapun Abdurrahman bin Ishaq Al Qurasyi dia berasal dari Madinah dan hapalannya lebih kuat dari yang tadi, dan keduanya hidup sezaman."},"1908":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعِمَّا لِأَحَدِهِمْ أَنْ يُطِيعَ رَبَّهُ وَيُؤَدِّيَ حَقَّ سَيِّدِهِ يَعْنِي الْمَمْلُوكَو قَالَ كَعْبٌ صَدَقَ اللَّهُ وَرَسُولُهُ وَفِي الْبَاب عَنْ أَبِي مُوسَى وَابْنِ عُمَرَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [A'masy] dari [Abu Shalih] dari [Abu Hurairah] berkata: bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh bahagia salah seorang mereka yang menta'ati Rabb-nya dan menunaikan hak-hak tuannya (yaitu seorang budak belian).\" Ka'ab berkata: Telah jujur Allah dan Rasul-Nya. Hadits semakna diriwayatkan dari Abu Musa dan Ibnu Umar. Berkata Abu Isa: Ini merupakan hadits hasan shahih."},"1909":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي الْيَقْظَانِ عَنْ زَاذَانَ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ عَلَى كُثْبَانِ الْمِسْكِ أُرَاهُ قَالَ يَوْمَ الْقِيَامَةِ عَبْدٌ أَدَّى حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِ وَرَجُلٌ أَمَّ قَوْمًا وَهُمْ بِهِ رَاضُونَ وَرَجُلٌ يُنَادِي بِالصَّلَوَاتِ الْخَمْسِ فِي كُلِّ يَوْمٍ وَلَيْلَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سُفْيَانَ الثَّوْرِيِّ عَنْ أَبِي الْيَقْظَانِ وَأَبُو الْيَقْظَانِ اسْمُهُ عُثْمَانُ بْنُ قَيْسٍ وَيُقَالُ ابْنُ عُمَيْرٍ وَهُوَ أَشْهَرُ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Yaqzhan] dari [Zadzan] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada tiga golongan yang akan berada di atas bukit Misk kelak pada hari kiamat. Seorang hamba sahaya yang menunaikan hak Allah dan juga hak majikannya; Seorang laki-laki yang memimpin suatu kaum sedangkan mereka (yang dimimpin) merasa ridha kepadanya; Dan seorang laki-laki yang selalu mengumandangkan adzan shalat limat waktu siang dan malam.\" Abu Isa berkata: Ini adalah hadits hasan gharib, kami tidak mengetahuinya kecuali dari haditsnya Sufyan Ats Tsauri dari Abu Al Yaqzhan. Sedangkan Abu Yaqzhan namanya adalah Utsman bin Qais, dan juga dipanggil Ibnu Umair, inilah yang paling masyhur."},"1910":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّقِ اللَّهِ حَيْثُمَا كُنْتَ وَأَتْبِعْ السَّيِّئَةَ الْحَسَنَةَ تَمْحُهَا وَخَالِقِ النَّاسَ بِخُلُقٍ حَسَنٍقَالَ وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أَحْمَدَ وَأَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ حَبِيبٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ قَالَ مَحْمُودٌ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مَيْمُونِ بْنِ أَبِي شَبِيبٍ عَنْ مُعَاذِ بْنِ جَبَلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ مَحْمُودٌ وَالصَّحِيحُ حَدِيثُ أَبِي ذَرٍّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman bin Mahdi], telah menceritakakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Maimun bin Abu Syabib] dari [Abu Dzar] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah bersabda kepadaku: \"Bertakwalah kamu kepada Allah dimana saja kamu berada dan ikutilah setiap keburukan dengan kebaikan yang dapat menghapuskannya, serta pergauilah manusia dengan akhlak yang baik.\" Hadits semakna juga diriwayatkan oleh Abu Hurairah. Abu Isa berkata; Ini adalah hadits hasan shahih. Telah menceritakan kepada kami [Mahmud bin Ghailan] Telah menceritakan kepada kami [Abu Ahmad] dan [Abu Nu'aim] dari [Sufyan] dari [Habib] dengan isnad ini semisalnya. Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Tsabit] dari [Maimun bin Abu Syabib] dari [Mu'adz bin Jabal] dari Nabi shallallahu 'alaihi wasallam semisalnya. Mahmud berkata; Yang shahih adalah haditsnya Abu Dzar."},"1911":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالظَّنَّ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ قَالَ و سَمِعْت عَبْدَ بْنَ حُمَيْدٍ يَذْكُرُ عَنْ بَعْضِ أَصْحَابِ سُفْيَانَ قَالَ قَالَ سُفْيَانُ الظَّنُّ ظَنَّانِ فَظَنٌّ إِثْمٌ وَظَنٌّ لَيْسَ بِإِثْمٍ فَأَمَّا الظَّنُّ الَّذِي هُوَ إِثْمٌ فَالَّذِي يَظُنُّ ظَنًّا وَيَتَكَلَّمُ بِهِ وَأَمَّا الظَّنُّ الَّذِي لَيْسَ بِإِثْمٍ فَالَّذِي يَظُنُّ وَلَا يَتَكَلَّمُ بِهِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah oleh kalian prasangka, karena prasangka itu adalah ungkapan yang paling dusta.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Ia juga berkata; Dan aku mendengar Abda bin Humaid menyebutkan dari sebahagian sahabat Sufyan berkata, bahwa Sufyan berkata, \"Prasangka itu ada dua, yaitu prasangka yang mengandung dosa dan prasangka yang tidak mengandung dosa. Yang mengandung dosa adalah seorang yang berprasangka buruk lalu ia membicarakannya. Sedangkan yang tidak mengandung dosa adalah seorang yang berprasangka, namun ia tidak membicarakannya.\""},"1912":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْوَضَّاحِ الْكُوفِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُخَالِطُنَا حَتَّى إِنْ كَانَ لَيَقُولُ لِأَخٍ لِي صَغِيرٍ يَا أَبَا عُمَيْرٍ مَا فَعَلَ النُّغَيْرُحَدَّثَنَا هَنَّادٌ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ نَحْوَهُ وَأَبُو التَّيَّاحِ اسْمُهُ يَزِيدُ بْنُ حُمَيْدٍ الضُّبَعِيُّ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdullah bin Al Wadldlah Al Kufi], telah menceritakan kepada kami [Abdullah bin Idris] dari [Syu'bah] dari [Abu At Tayyah] dari [Anas] ia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam ikut bergabung bersama kami hingga beliau bertanya kepada adikku: \"Wahai Abu Umair, apa yang dilakukan An Nughair?\" Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Abu At Tayyah] dari [Anas] semisalnya. Abu At Tayyah namanya adalah Yazid bin Humaid Adl Dluba'i. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1913":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ الْبَغْدَادِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالُوا يَا رَسُولَ اللَّهِ إِنَّكَ تُدَاعِبُنَا قَالَ إِنِّي لَا أَقُولُ إِلَّا حَقًّاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abbas bin Muhammad Ad Duri Al Baghdadi], telah menceritakan kepada kami [Ali bin Al Hasan], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Usamah bin Zaid] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata; Mereka (para sahabat) berkata, \"Sesungguhnya Anda ….\" Beliau bersabda: \"Sesungguhnya aku tidaklah mengatakan sesuatu kecuali yang benar.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1914":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ الْوَاسِطِيُّ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا اسْتَحْمَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي حَامِلُكَ عَلَى وَلَدِ النَّاقَةِ فَقَالَ يَا رَسُولَ اللَّهِ مَا أَصْنَعُ بِوَلَدِ النَّاقَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَلْ تَلِدُ الْإِبِلَ إِلَّا النُّوقُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Khalid bin Abdullah Al Wasithi] dari [Humaid] dari [Anas bin Malik] bahwasanya seorang laki-laki meminta kepada Rasulullah shallallahu 'alaihi wasallam agar ia diikutsertakan, maka beliau pun bersabda: \"Aku akan mengikutsertakanmu dengan mengendarai anak unta.\" Kemudian laki-laki itu berkata, \"Wahai Rasululah, apa yang dapat saya lakukan dengan anak unta?\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah ibil itu melahirkan An-Nuuq?\" Abu Isa berkata; Ini adalah hadits hasan shahih gharib. "},"1915":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ شَرِيكٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَا ذَا الْأُذُنَيْنِ قَالَ مَحْمُودٌ قَالَ أَبُو أُسَامَةَ يَعْنِي مَازَحَهُوَهَذَا الْحَدِيثُ حَدِيثٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Usamah] dari [Syarik] dari [Ashim Al Ahwal] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Wahai orang yang memiliki dua telinga.\" Mahmud berkata; Abu Usamah berkata, \"Yakni, beliau sedang bergurau dengannya.\" Hadits ini adalah hadits shahih gharib."},"1916":{"ar":"حَدَّثَنَا عُقْبَةُ بْنُ مُكَرِّمٍ الْعَمِّيُّ الْبَصْرِيُّ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ قَالَ حَدَّثَنِي سَلَمَةُ بْنُ وَرْدَانَ اللَّيْثِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْكَذِبَ وَهُوَ بَاطِلٌ بُنِيَ لَهُ فِي رَبَضِ الْجَنَّةِ وَمَنْ تَرَكَ الْمِرَاءَ وَهُوَ مُحِقٌّ بُنِيَ لَهُ فِي وَسَطِهَا وَمَنْ حَسَّنَ خُلُقَهُ بُنِيَ لَهُ فِي أَعْلَاهَاوَهَذَا الْحَدِيثُ حَدِيثٌ حَسَنٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سَلَمَةَ بْنِ وَرْدَانَ عَنْ أَنَسِ بْنِ مَالِكٍ","id":"Telah menceritakan kepada kami [Uqbah bin Mukarram Al 'Ammiyyu Al Bashari], telah menceritakan kepada kami [Ibnu Abu Fudaik] ia berkata, Telah menceritakan kepadaku [Salamah bin Wardan Al Laitsi] dari [Anas bin Malik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meninggalkan berbohong (dan berbohong pada waktu itu sesuatu yang tidak dibenarkan) maka akan dibangunkan untuknya rumah di sekitar surga, barangsiapa yang meninggalkan perdebatan (sedang dia orang yang berhak untuk berdebat) maka akan dibangunkan untuknya rumah di tengah surga, dan barangsiapa yang memperbagus akhlaknya maka akan dibangunkan rumah untuknya di bagian yang paling atas.\" Ini merupakan hadits hasan yang tidak kami ketahui, kecuali dari hadits Salamah bin Wardan dari Anas bin Malik."},"1917":{"ar":"حَدَّثَنَا فَضَالَةُ بْنُ الْفَضْلِ الْكُوفِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ ابْنِ وَهْبِ بْنِ مُنَبِّهٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَفَى بِكَ إِثْمًا أَنْ لَا تَزَالَ مُخَاصِمًاوَهَذَا الْحَدِيثُ حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Fadlalah bin Al Fadl Al Kufi], telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Ibnu Wahb bin Munabbih] dari [bapaknya] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau akan mendapatkan dosa selama engkau suka berdebat.\" Ini merupakan hadits gharib tidak kami ketahui kecuali melalui jalur ini."},"1918":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ الْبَغْدَادِيُّ حَدَّثَنَا الْمُحَارِبِيُّ عَنْ اللَّيْثِ وَهُوَ ابْنُ أَبِي سُلَيْمٍ عَنْ عَبْدِ الْمَلِكِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُمَارِ أَخَاكَ وَلَا تُمَازِحْهُ وَلَا تَعِدْهُ مَوْعِدَةً فَتُخْلِفَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ وَعَبْدُ الْمَلِكِ عِنْدِي هُوَ ابْنُ بَشِيرٍ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub Al Baghdadi], telah menceritakan kepada kami [Al Muharibi] dari [Al Laits] ia adalah Ibnu Abu Sulaim, dari [Abdul Malik] dari [Ikrimah] dari [Ibnu Abbas], dari Nabi Shallallaahu 'alaihi wa sallam, beliau bersabda: \"Janganlah engkau debat saudaramu, janganlah engkau permainkan dia, dan janganlah engkau membuat janji dengannya lalu engkau mengingkarinya.\" Berkata Abu Isa: Ini merupakan hadits hasan gharib, tidak kami ketahui kecuali melalui jalur ini, dan menurutku Abdul Malik bin Marwan ialah Ibnu Bisyr."},"1919":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْاسْتَأْذَنَ رَجُلٌ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عِنْدَهُ فَقَالَ بِئْسَ ابْنُ الْعَشِيرَةِ أَوْ أَخُو الْعَشِيرَةِ ثُمَّ أَذِنَ لَهُ فَأَلَانَ لَهُ الْقَوْلَ فَلَمَّا خَرَجَ قُلْتُ لَهُ يَا رَسُولَ اللَّهِ قُلْتَ لَهُ مَا قُلْتَ ثُمَّ أَلَنْتَ لَهُ الْقَوْلَ فَقَالَ يَا عَائِشَةُ إِنَّ مِنْ شَرِّ النَّاسِ مَنْ تَرَكَهُ النَّاسُ أَوْ وَدَعَهُ النَّاسُ اتِّقَاءَ فُحْشِهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Muhammad bin Al Munkadir] dari [Urwah bin Az Zubair] dari ['Aisyah], ia berkata; Seorang laki-laki pernah meminta izin kepada Rasulullah shallallahu 'alaihi wasallam, dan pada saat itu aku sedang berada di sisi beliau. Maka beliau pun bersabda: \"Seburuk-buruk orang adalah Ibnul 'Asyirah atau Akhul 'Asyirah.\" Setelah itu, beliau berkata-kata lembut dan mengizinkannya. Dan setelah laki-laki itu keluar, aku berkata, \"Wahai Rasulullah, Anda telah berkata keras padanya, lalu kemudian Anda berkata lembut.\" Beliau pun bersabda: \"Wahai Aisyah, sesungguhnya manusia yang paling buruk adalah orang yang ditinggalkan oleh manusia, atau orang-orang meninggalkannya untuk menghindar dari keburukannya.\" Abu Isa berkata; Ini adalah hadits hasan shahih. "},"1920":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا سُوَيْدُ بْنُ عَمْرٍو الْكَلْبِيُّ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ أُرَاهُ رَفَعَهُ قَالَأَحْبِبْ حَبِيبَكَ هَوْنًا مَا عَسَى أَنْ يَكُونَ بَغِيضَكَ يَوْمًا مَا وَأَبْغِضْ بَغِيضَكَ هَوْنًا مَا عَسَى أَنْ يَكُونَ حَبِيبَكَ يَوْمًا مَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ بِهَذَا الْإِسْنَادِ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ هَذَا الْحَدِيث عَنْ أَيُّوبَ بِإِسْنَادٍ غَيْرِ هَذَا رَوَاهُ الْحَسَنُ بْنُ أَبِي جَعْفَرٍ وَهُوَ حَدِيثٌ ضَعِيفٌ أَيْضًا بِإِسْنَادٍ لَهُ عَنْ عَلِيٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالصَّحِيحُ عَنْ عَلِيٍّ مَوْقُوفٌ قَوْلُهُ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Suwaid bin Amru Al Kalbi] dari [Hammad bin Salamah] dari [Ayyub] dari [Muhammad bin Sirrin] dari [Abu Hurairah] (aku menduga, bahwa dia memarfu'kannya) berkata: \"Cintailah orang yang engkau cintai seperlunya, karena bisa saja suatu hari dia akan menjadi musuhmu, dan bencilah orang yang kamu benci seperlunya, karena bisa jadi suatu hari kelak dia akan menjadi orang yang engkau cintai.\" Berkata Abu Isa: Ini merupakan hadits gharib, yang tidak kami ketahui kecuali dengan sanad ini melalui jalur ini. Hadits ini juga telah diriwayatkan dari [Ayyub] dengan selain sanad ini yang diriwayatkan oleh [Hasan bin Abi Ja'far] dan dia merupakan hadits yang dha'if dengan sanad dari [Ali] dari Nabi shallallahu 'alaihi wasallam, namun yang benar hadits ini mauquf kepada Ali."},"1921":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ كِبْرٍ وَلَا يَدْخُلُ النَّارَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ إِيمَانٍوَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَابْنِ عَبَّاسٍ وَسَلَمَةَ بْنِ الْأَكْوَعِ وَأَبِي سَعِيدٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'i], telah menceritakan kepada kami [Abu Bakr bin Ayyasy] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga seseorang yang di dalam hatinya terdapat sifat sombong meskipun hanya sebesar biji khardal (sejenis biji-bijian yang sangat kecil). Dan tidak akan pula masuk neraka bagi seorang yang di dalam hatinya terdapat iman meskipun sekecil biji (yang sangat kecil).\" Hadits semakna juga diriwayatkan dari Abu Hurairah, Ibnu Abbas, Salamah bin Al Akwa' dan Abu Sa'id. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1922":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَعَب��دُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبَانَ بْنِ تَغْلِبٍ عَنْ فُضَيْلِ بْنِ عَمْرٍو عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ كِبْرٍ وَلَا يَدْخُلُ النَّارَ يَعْنِي مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ إِيمَانٍ قَالَ فَقَالَ لَهُ رَجُلٌ إِنَّهُ يُعْجِبُنِي أَنْ يَكُونَ ثَوْبِي حَسَنًا وَنَعْلِي حَسَنَةً قَالَ إِنَّ اللَّهَ يُحِبُّ الْجَمَالَ وَلَكِنَّ الْكِبْرَ مَنْ بَطَرَ الْحَقَّ وَغَمَصَ النَّاسَو قَالَ بَعْضُ أَهْلِ الْعِلْمِ فِي تَفْسِيرِ هَذَا الْحَدِيثِ لَا يَدْخُلُ النَّارَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ إِيمَانٍ إِنَّمَا مَعْنَاهُ لَا يُخَلَّدُ فِي النَّارِ وَهَكَذَا رُوِيَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْرُجُ مِنْ النَّارِ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ ذَرَّةٍ مِنْ إِيمَانٍ وَقَدْ فَسَّرَ غَيْرُ وَاحِدٍ مِنْ التَّابِعِينَ هَذِهِ الْآيَةَ{ رَبَّنَا إِنَّكَ مَنْ تُدْخِلْ النَّارَ فَقَدْ أَخْزَيْتَهُ }فَقَالَ مَنْ تُخَلِّدُ فِي النَّارِ فَقَدْ أَخْزَيْتَهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Abdullah bin Abdurrahman] keduanya berkata, Telah menceritakan kepada kami [Yahya bin Hammad], telah menceritakan kepada kami [Syu'bah] dari [Aban bin Taghlib] dari [Fudlail bin Amr] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak akan masuk surga bagi seseorang yang di dalam hatinya terdapat sifat sombong meskipun hanya sebesar biji dzarrah. Dan tidak akan pula masuk neraka, yaitu seorang yang di dalam hatinya terdapat keimanan meskipun hanya sebesar biji dzarrah.\" Abdullah berkata; Kemudian seseorang berkata kepada beliau, \"Sesungguhnya aku merasa bangga, jika pakaianku bagus dan sandalku juga bagus.\" Beliau bersabda: \"Sesungguhnya Allah menyukai keindahan. Akan tetapi yang dimaksud kesombongan adalah menolak kebenaran dan merendahkan manusia.\" Sebagian Ahli Ilmi berkata terkait tafsir hadits ini, \"Tidak akan pula masuk neraka, yaitu seorang yang di dalam hatinya terdapat keimanan meskipun hanya sebesar biji dzarrah.\" Maknanya, tidak akan kekal di dalam neraka. Dan seperti inilah sebagaimana yang diriwayatkan dari Abu Sa'id Al Khudri dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akan dikeluarkan dari neraka, yaitu seorang yang di dalam hatinya terdapat keimanan meskipun hanya sebesar biji dzarrah.\" Kalangan Tabi'in memberikan tafsiran terkait ayat ini, \"Siapa yang Engkau masukkan ke dalam neraka, maka sungguh Engkau telah menghinakannya.\" Maksudnya, Siapa yang Engkau kekalkan di dalam neraka, maka sungguh Engkau telah menghinakannya. Abu Isa berkata; Ini adalah hadits hasan shahih gharib."},"1923":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عُمَرَ بْنِ رَاشِدٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ الرَّجُلُ يَذْهَبُ بِنَفْسِهِ حَتَّى يُكْتَبَ فِي الْجَبَّارِينَ فَيُصِيبُهُ مَا أَصَابَهُمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritkan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Umar bin Rasyid] dari [Iyas bin Salamah bin Al Akwa'] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang lelaki senantiasa menyombongkan dirinya kepada orang lain hingga dia dituliskan termasuk dalam golongan para diktator, lalu sesuatu akan menimpanya sebagaimana yang telah menimpa mereka.\" Berkata Abu Isa: Ini merupakan hadits hasan gharib."},"1924":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عِيسَى الْبَغْدَادِيُّ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْقَاسِمِ بْنِ عَبَّاسٍ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ قَالَتَقُولُونَ فِيَّ التِّيهُ وَقَدْ رَكِبْتُ الْحِمَارَ وَلَبِسْتُ الشَّمْلَةَ وَقَدْ حَلَبْتُ الشَّاةَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فَعَلَ هَذَا فَلَيْسَ فِيهِ مِنْ الْكِبْرِ شَيْءٌقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Ali bin Isa Al Baghdadi], telah menceritakan kepada kami [Syababah bin Sawwar], telah menceritakan kepada kami [Ibnu Abu Dzi`bi] dari [Al Qasim bin Abbas] dari [Nafi' bin Jubair bin Muth'im] dari [bapaknya] ia berkata; Kalian mengatakan aku orang yang sombong, sedang aku mengendarai keledai dan memakai jubah serta memerah susu kambing, dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang melakukan semua itu, maka dia tidak termasuk orang yang sombong.\" Berkata Abu Isa: Ini merupakan hadits hasan shahih gharib."},"1925":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا شَيْءٌ أَثْقَلُ فِي مِيزَانِ الْمُؤْمِنِ يَوْمَ الْقِيَامَةِ مِنْ خُلُقٍ حَسَنٍ وَإِنَّ اللَّهَ لَيُبْغِضُ الْفَاحِشَ الْبَذِيءَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَأَبِي هُرَيْرَةَ وَأَنَسٍ وَأُسَامَةَ بْنِ شَرِيكٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Amru bin Dinar] dari [Ibnu Abu Mulaikah] dari [Ya'la bin Mamlak] dari [Ummu Darda`] dari [Abu Darda`] bahwasanya Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak sesuatu yang lebih berat dalam timbangan seorang mukmin kelak pada hari kiamat daripada akhlak yang baik. Sesungguhnya Allah amatlah murka terhadap seorang yang keji lagi jahat.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Aisyah, Abu Hurairah, Anas dan Usamah bin Syarik. Dan hadits ini adalah hadits hasan shahih."},"1926":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا قَبِيصَةُ بْنُ اللَّيْثِ الْكُوفِيُّ عَنْ مُطَرِّفٍ عَنْ عَطَاءٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ شَيْءٍ يُوضَعُ فِي الْمِيزَانِ أَثْقَلُ مِنْ حُسْنِ الْخُلُقِ وَإِنَّ صَاحِبَ حُسْنِ الْخُلُقِ لَيَبْلُغُ بِهِ دَرَجَةَ صَاحِبِ الصَّوْمِ وَالصَّلَاةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Qabishah bin Al Laits Al Kufi] dari [Al Mutharrif] dari ['Atha`] dari [Ummu Darda`] dari [Abu Darda`] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang lebih berat dalam timbangan daripada akhlak yang baik, dan sesungguhnya orang yang berakhlak baik akan mencapai derajat orang yang berpuasa dan shalat.\" Berkata Abu Isa: Ini merupakan hadits gharib melalui jalur ini."},"1927":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ حَدَّثَنِي أَبِي عَنْ جَدِّي عَنْ أَبِي هُرَيْرَةَ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْثَرِ مَا يُدْخِلُ النَّاسَ الْجَنَّةَ فَقَالَ تَقْوَى اللَّهِ وَحُسْنُ الْخُلُقِ وَسُئِلَ عَنْ أَكْثَرِ مَا يُدْخِلُ النَّاسَ النَّارَ فَقَالَ الْفَمُ وَالْفَرْجُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ غَرِيبٌ وَعَبْدُ اللَّهِ بْنُ إِدْرِيسَ هُوَ ابْنُ يَزِيدَ بْنِ عَبْدِ الرَّحْمَنِ الْأَوْدِيُّ","id":"Telah menceritakan kepada kami [Abu Kuraib Muhammad bin Al Ala`], telah menceritakan kepada kami [Abdullah bin Idris], telah menceritakan kepadaku [bapakku] dari [kakekku] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya tentang sesuatu yang paling banyak memasukkan seseorang ke dalam surga, maka beliau pun menjawab: \"Takwa kepada Allah dan akhlak yang mulia.\" Dan beliau juga ditanya tentang sesuatu yang paling banyak memasukkan orang ke dalam neraka, maka beliau menjawab: \"Mulut dan kemaluan.\" Abu Isa berkata; Ini adalah hadits shahih gharib. Abdullah bin Idris adalah Ibnu Yazid bin Abdurrahman Al Audi."},"1928":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ حَدَّثَنَا أَبُو وَهْبٍ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِأَنَّهُ وَصَفَ حُسْنَ الْخُلُقِ فَقَالَ هُوَ بَسْطُ الْوَجْهِ وَبَذْلُ الْمَعْرُوفِ وَكَفُّ الْأَذَى","id":"Telah menceritakan kepada kami [Ahmad bin Abdah Adl Dlabbi], telah menceritakan kepada kami [Abu Wahb] dari [Abdullah bin Mubarak] bahwasanya ia menjelaskan tentang husnul khuluq (akhlak yang baik) seraya berkata, \"Berwajah ceria, menebarkan kebaikan dan mencegah keburukan.\""},"1929":{"ar":"حَدَّثَنَا بُنْدَارٌ وَأَحْمَدُ بْنُ مَنِيعٍ وَمَحْمُودُ بْنُ غَيْلَانَ قَالُوا حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ الرَّجُلُ أَمُرُّ بِهِ فَلَا يَقْرِينِي وَلَا يُضَيِّفُنِي فَيَمُرُّ بِي أَفَأُجْزِيهِ قَالَ لَا اقْرِهِ قَالَ وَرَآَّنِي رَثَّ الثِّيَابِ فَقَالَ هَلْ لَكَ مِنْ مَالٍ قُلْتُ مِنْ كُلِّ الْمَالِ قَدْ أَعْطَانِيَ اللَّهُ مِنْ الْإِبِلِ وَالْغَنَمِ قَالَ فَلْيُرَ عَلَيْكَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَجَابِرٍ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو الْأَحْوَصِ اسْمُهُ عَوْفُ بْنُ مَالِكِ بْنِ نَضْلَةَ الْجُشَمِيُّ وَمَعْنَى قَوْلِهِ اقْرِهِ أَضِفْهُ وَالْقِرَى هُوَ الضِّيَافَةُ","id":"Telah menceritakan kepada kami [Bundar] dan [Ahmad bin Mani'] dan [Mahmud bin Ghailan] mereka berkata, Telah menceritakan kepada kami [Abu Ahmad Az Zubairi] dari [Sufyan] dari [Abu Ishaq] dari [Abu Ahwash] dari [bapaknya] ia berkata; Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, aku lewat di hadapannya, namun ia tidaklah menyapa dan tidak pula menjamuku. Maka bolehkah aku membalasnya?\" Beliau menjawab: \"tidak, tapi sapalah ia.\" Dia menerangkan; dan beliau melihatku yang pada saat itu mengenakan pakaian yang lusuh, beliau bertanya: \"apakah kamu memiliki harta?\" aku menjawab; semua harta yang tela Allah anugerahkan kepadaku berupa unta dan kambing. Beliau bersabda: \"perlihatkanlah (harta yang telah di anugerahkan) kepadamu.\" Abu 'Isa berkata; di dalam bab terdapat hadits dari jalur 'Aisyah, Jabir dan Abu Hurairah. Dan hadits ini adalah hadits hasan shahih. Sedang Abu Al Ahwash namanya 'Auf bin Malik bin Nadhlah al Jusyami. Dan makna sabda beliau sapalah dia adalah jamulah dia. Dan al qiraa bermakna dhiyafah (menjamu)."},"1930":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ مُحَمَّدُ بْنُ يَزِيدَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ بْنِ جُمَيْعٍ عَنْ أَبِي الطُّفَيْلِ عَنْ حُذَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكُونُوا إِمَّعَةً تَقُولُونَ إِنْ أَحْسَنَ النَّاسُ أَحْسَنَّا وَإِنْ ظَلَمُوا ظَلَمْنَا وَلَكِنْ وَطِّنُوا أَنْفُسَكُمْ إِنْ أَحْسَنَ النَّاسُ أَنْ تُحْسِنُوا وَإِنْ أَسَاءُوا فَلَا تَظْلِمُواقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada [Abu Hisyam Ar Rifa'i Muhammad bin Yazid], telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Al Walid bin Abdullah bin Jumai'] dari [Abu Thufail] dari [Hudzaifah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menjadi orang yang suka mengekor orang lain. Jika manusia menjadi baik, maka kami juga akan berbuat baik. Dan jika mereka berbuat zhalim, maka kami juga akan berbuat zhalim.' Akan tetapi mantapkanlah hati kalian, jika manusia berbuat baik kalian juga berbuat baik, namun jika mereka berlaku buruk, janganlah kalian berbuat zhalim.\" Berkata Abu Isa: Ini merupakan hadits hasan gharib tidak kami ketahui kecuali melalui jalur ini."},"1931":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ وَالْحُسَيْنُ بْنُ أَبِي كَبْشَةَ الْبَصْرِيُّ قَالَا حَدَّثَنَا ��ُوسُفُ بْنُ يَعْقُوبَ السَّدُوسِيُّ حَدَّثَنَا أَبُو سِنَانٍ الْقَسْمَلِيُّ هُوَ الشَّامِيُّ عَنْ عُثْمَانَ بْنِ أَبِي سَوْدَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ عَادَ مَرِيضًا أَوْ زَارَ أَخًا لَهُ فِي اللَّهِ نَادَاهُ مُنَادٍ أَنْ طِبْتَ وَطَابَ مَمْشَاكَ وَتَبَوَّأْتَ مِنْ الْجَنَّةِ مَنْزِلًاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَأَبُو سِنَانٍ اسْمُهُ عِيسَى بْنُ سِنَانٍ وَقَدْ رَوَى حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا مِنْ هَذَا","id":"Telah menceritakan kepada kami [Muhammd bin Basysyar] dan [Al Husain bin Abu Kasybah Al Bashari] keduanya berkata, Telah menceritakan kepada kami [Yusuf bin Ya'qub As Sadusi] Telah menceritakan kepada kami [Abu Sinan Al Qasmali Asy Syami] dari [Utsman bin Abu Saudah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menjenguk orang sakit atau mengunjungi saudaranya semata-mata karena Allah, maka seorang penyeru akan menyeru: Engkau telah berbuat baik dan berjalanmu pun baik serta engkau telah memesan sebuah tempat di surga.\" Berkata Abu Isa: Ini merupakan hadits hasan gharib dan Abu Sinan bernama Isa bin Sinan. [Hammad bin Salamah] telah meriwayatkan dari [Tsabit] dari [Abi Rafi'] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam sebagian dari hadits ini."},"1932":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَعَبْدُ الرَّحِيمِ وَمُحَمَّدُ بْنُ بِشْرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَيَاءُ مِنْ الْإِيمَانِ وَالْإِيمَانُ فِي الْجَنَّةِ وَالْبَذَاءُ مِنْ الْجَفَاءِ وَالْجَفَاءُ فِي النَّارِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عُمَرَ وَأَبِي بَكْرَةَ وَأَبِي أُمَامَةَ وَعِمْرَانَ بْنِ حُصَيْنٍ هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abdah bin Sulaiman] dan [Abdurrahim] dan [Muhammad bin Bisyr] dari [Muhammad bin Amr], telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sifat malu adalah bagian dari iman, sedangkan iman itu tempatnya di dalam surga. Perkataan yang keji itu berasal dari watak dan perangai yang keras, sedangkan kekerasan itu tempatnya di dalam neraka.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Umar, Abu Bakrah, Abu Umamah, Imran bin Husain. Hadits ini adalah hasan shahih."},"1933":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عِمْرَانَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ الْمُزَنِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّمْتُ الْحَسَنُ وَالتُّؤَدَةُ وَالِاقْتِصَادُ جُزْءٌ مِنْ أَرْبَعَةٍ وَعِشْرِينَ جُزْءًا مِنْ النُّبُوَّةِقَالَ وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عِمْرَانَ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَاصِمٍ وَالصَّحِيحُ حَدِيثُ نَصْرِ بْنِ عَلِيٍّ","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami], telah menceritakan kepada kami [Nuh bin Qais] dari [Abdullah bin Imran] dari ['Ashim Al Ahwal] dari [Abdullah bin Sarjisa Al Muzani] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Perangai yang baik, sifat kehati-hatian dan tidak berlebihan merupakan bagian dari dua puluh empat bagian dari (sifat) kenabian.\" Hadits juga semakna diriwayatkan dari Ibnu Abbas dan ini merupakan hadits Hasan Gharib. Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Nuh bin Qais] dari [Abdullah bin Imran] dari [Abdullah bin Sarjisa] dari Nabi shallallahu 'alaihi wasallam semisalnya. Namun di dalamnya ia tidak menyebutkan nama 'Ashim, dan yang shahih adalah haditsnya Nashr bin 'Ali."},"1934":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ قُرَّةَ بْنِ خَالِدٍ عَنْ أَبِي جَمْرَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَشَجِّ عَبْدِ الْقَيْسِ إِنَّ فِيكَ خَصْلَتَيْنِ يُحِبُّهُمَا اللَّهُ الْحِلْمُ وَالْأَنَاةُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَفِي الْبَاب عَنْ الْأَشَجِّ الْعَصَرِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Bazi'], telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dari [Qurrah bin Khalid] dari [Abu Jamrah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Asyaj bin Abdil Qais: \"Sesungguhnya pada dirimu terdapat dua sifat yang dicintai oleh Allah, yaitu, lemah lembut dan sifat kehati-hatian.\" Berkata Abu Isa: Ini merupakan hadits hasan shahih gharib dan hadits semakna diriwayatkan dari Asyaj Al 'Ashri."},"1935":{"ar":"حَدَّثَنَا أَبُو مُصْعَبٍ الْمَدَنِيُّ حَدَّثَنَا عَبْدُ الْمُهَيْمِنِ بْنُ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيُّ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَنَاةُ مِنْ اللَّهِ وَالْعَجَلَةُ مِنْ الشَّيْطَانِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَقَدْ تَكَلَّمَ بَعْضُ أَهْلِ الْحَدِيثِ فِي عَبْدِ الْمُهَيْمِنِ بْنِ عَبَّاسِ بْنِ سَهْلٍ وَضَعَّفَهُ مِنْ قِبَلِ حِفْظِهِ وَالْأَشَجُّ بْنُ عَبْدِ الْقَيْسِ اسْمُهُ الْمُنْذِرُ بْنُ عَائِذٍ","id":"Telah menceritakan kepada kami [Abu Mush'ab Al Madani], telah menceritakan kepada kami [Abdul Al Muhaimin bin Abbas bin Sahl bin Sa'd As Sa'idi] dari [bapaknya] dari [kakeknya] ia berkata; Rasulullah Shallallaahu 'alaihi wasallam bersabda: \"Sifat hati-hati (waspada) itu dari Allah dan tergesa-gesa itu godaan dari setan.\" Berkata Abu Isa: Ini merupakan hadits Hasan Gharib. Sebagian ahli hadits telah mencela Abdul Muhaimin bin Abbas bin Sahl dan mendha'ifkannya dari segi hapalannya. Asyaj bin Abdil Qais bernama Al Mundzir bin 'Aidz."},"1936":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُعْطِيَ حَظَّهُ مِنْ الرِّفْقِ فَقَدْ أُعْطِيَ حَظَّهُ مِنْ الْخَيْرِ وَمَنْ حُرِمَ حَظَّهُ مِنْ الرِّفْقِ فَقَدْ حُرِمَ حَظَّهُ مِنْ الْخَيْرِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَجَرِيرِ بْنِ عَبْدِ اللَّهِ وَأَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Amru bin Dinar] dari [Ibnu Abu Mulaikah] dari [Ya'la bin Mamlak] dari [Ummu Darda`] dari [Abu Darda`] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang diberi bagian dari bagian kelemahlembutan, maka sungguh ia telah diberi bagian dari kebaikan. Dan barangsiapa yang diharamkan untuk mendapatkan bagian dari kelemahlembutan, maka sungguh ia telah diharamkan untuk mendapatkan kebaikan.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Aisyah, Jarir bin Abdullah dan Abu Hurairah. Dan hadits adalah hasan shahih."},"1937":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ عَنْ زَكَرِيَّا بْنِ إِسْحَقَ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ مُعَاذَ بْنَ جَبَلٍ إِلَى الْيَمَنِ فَقَالَ اتَّقِ دَعْوَةَ الْمَظْلُومِ فَإِنَّهَا لَيْسَ بَيْنَهَا وَبَيْنَ اللَّهِ حِجَابٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَأَبِي هُرَيْرَةَ وَعَبْدِ اللَّهِ بْنِ عُمَرَ وَأَبِي سَعِيدٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو مَعْبَدٍ اسْمُهُ نَافِذٌ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Waki'] dari [Zakaria bin Ishaq] dari [Yahya bin Abdullah bin Shaifi] dari [Abu Ma'bad] dari [Ibnu Abbas] bahwasanya Rasulullah shallallahu 'alaihi wasallam pernah mengutus Mu'adz bin Jabal ke negeri Yaman, maka beliau pun bersabda: \"Takutlah kamu do'a orang yang terzhalimi. Sebab, antara do'anya dengan Allah tidak ada hijab (yang akan menghalanginya).\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Anas, Abu Hurairah, Abdullah bin Umar dan Abu Sa'id. Dan hadits ini adalah hasan shahih. Abu Ma'bad namanya adalah Nafidz."},"1938":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ الضُّبَعِيُّ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَخَدَمْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَ سِنِينَ فَمَا قَالَ لِي أُفٍّ قَطُّ وَمَا قَالَ لِشَيْءٍ صَنَعْتُهُ لِمَ صَنَعْتَهُ وَلَا لِشَيْءٍ تَرَكْتُهُ لِمَ تَرَكْتَهُ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَحْسَنِ النَّاسِ خُلُقًا وَلَا مَسَسْتُ خَزًّا قَطُّ وَلَا حَرِيرًا وَلَا شَيْئًا كَانَ أَلْيَنَ مِنْ كَفِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا شَمَمْتُ مِسْكًا قَطُّ وَلَا عِطْرًا كَانَ أَطْيَبَ مِنْ عَرَقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَائِشَةَ وَالْبَرَاءِ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Ja'far bin Sulaiman Adl Dluba'i] dari [Tsabit] dari [Anas] ia berkata; Aku telah menjadi khadim (pembantu) Nabi shallallahu 'alaihi wasallam selama sepuluh tahun, namun selama itu beliau belum pernah berkata `Uff (ah..) kepadaku sekalipun. Juga tidak pernah menanyakan mengenai sesuatu yang aku lakukan kenapa aku melakukannya, dan tidak pula terhadap sesuatu yang aku tinggalkan, kenapa aku meninggalkannya. Rasulullah shallallahu 'alaihi wasallam adalah manusia yang paling baik akhlaknya."},"1939":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَال سَمِعْتُ أَبَا عَبْدِ اللَّهِ الْجَدَلِيَّ يَقُولُسَأَلْتُ عَائِشَةَ عَنْ خُلُقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ لَمْ يَكُنْ فَاحِشًا وَلَا مُتَفَحِّشًا وَلَا صَخَّابًا فِي الْأَسْوَاقِ وَلَا يَجْزِي بِالسَّيِّئَةِ السَّيِّئَةَ وَلَكِنْ يَعْفُو وَيَصْفَحُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو عَبْدِ اللَّهِ الْجَدَلِيُّ اسْمُهُ عَبْدُ بْنُ عَبْدٍ وَيُقَالُ عَبْدُ الرَّحْمَنِ بْنُ عَبْدٍ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Dawud] ia berkata, Telah memberitakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, aku mendengar [Abu Abdullah Al Jadali] berkata; Aku pernah bertanya kepada [Aisyah] mengenai akhlak Rasulullah shallallahu 'alaihi wasallam, maka ia pun menjawab, \"Beliau bukanlah seorang yang buruk prilakunya, tidak pula menjelek-jelekkan orang lain. Beliau tidak suka berteriak di pasar-pasar. Beliau bukanlah tipe orang yang membalas keburukan dengan keburukan, namun beliau selalu memaafkan dengan lapang dada.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Sedangkan Abdullah Al Jadali, nama aslinya adalah Abdu bin Abdi, dan dipanggil juga Abdurrahman bin Abdin."},"1940":{"ar":"حَدَّثَنَا أَبُو هِشَامٍ الرِّفَاعِيُّ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا غِرْتُ عَلَى أَحَدٍ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا غِرْتُ عَلَى خَدِيجَةَ وَمَا بِي أَنْ أَكُونَ أَدْرَكْتُهَا وَمَا ذَاكَ إِلَّا لِكَثْرَةِ ذِكْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهَا وَإِنْ كَانَ لَيَذْبَحُ الشَّاةَ فَيَتَتَبَّعُ بِهَا صَدَائِقَ خَدِيجَةَ فَيُهْدِيهَا لَهُنَّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Hisyam Ar Rifa'i], telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkata, \"Aku tidak pernah merasa cemburu terhadap isteri-isteri Rasulullah shallallahu 'alaihi wasallam seperti cemburuku terhadap Khadijah. Bukan karena aku mendapatinya, namun lantaran Rasulullah shallallahu 'alaihi wasallam begitu banyak menyebut namanya. Jika beliau menyembelih seekor kambing, maka beliau akan mengikutinya dengan sedekah Khadijah lalu menghadiahkannya untuk mereka.\" Abu Isa berkata; Hadits ini adalah hadits hasan gharib shahih."},"1941":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَسَنِ بْنِ خِرَاشٍ الْبَغْدَادِيُّ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا مُبَارَكُ بْنُ فَضَالَةَ حَدَّثَنِي عَبْدُ رَبِّهِ بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أَحَبِّكُمْ إِلَيَّ وَأَقْرَبِكُمْ مِنِّي مَجْلِسًا يَوْمَ الْقِيَامَةِ أَحَاسِنَكُمْ أَخْلَاقًا وَإِنَّ أَبْغَضَكُمْ إِلَيَّ وَأَبْعَدَكُمْ مِنِّي مَجْلِسًا يَوْمَ الْقِيَامَةِ الثَّرْثَارُونَ وَالْمُتَشَدِّقُونَ وَالْمُتَفَيْهِقُونَ قَالُوا يَا رَسُولَ اللَّهِ قَدْ عَلِمْنَا الثَّرْثَارُونَ وَالْمُتَشَدِّقُونَ فَمَا الْمُتَفَيْهِقُونَ قَالَ الْمُتَكَبِّرُونَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي هُرَيْرَةَ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ الْمُبَارَكِ بْنِ فَضَالَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَذْكُرْ فِيهِ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ وَهَذَا أَصَحُّ وَالثَّرْثَارُ هُوَ الْكَثِيرُ الْكَلَامِ وَالْمُتَشَدِّقُ الَّذِي يَتَطَاوَلُ عَلَى النَّاسِ فِي الْكَلَامِ وَيَبْذُو عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hasan bin Hirasy Al Baghdadi], telah menceritakan kepada kami [Habban bin Hilal], telah menceritakan kepada kami [Mubarak bin Fadlalah], telah menceritakan kepadaku [Abdu Rabbih bin Sa'id] dari [Muhammad bin Al Munkadir] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara orang yang paling aku cintai dan yang tempat duduknya lebih dekat kepadaku pada hari kiamat ialah orang yang akhlaknya paling bagus. Dan sesungguhnya orang yang paling aku benci dan paling jauh tempat duduknya dariku pada hari kiamat ialah orang yang paling banyak bicara (kata-kata tidak bermanfaat dan memperolok manusia).\" Para shahabat bertanya, \"Wahai Rasulullah, siapakah orang yang paling banyak bicara itu?\" Nabi menjawab: \"Yaitu orang-orang yang sombong.\" Berkata Abu Isa: Hadits semakna juga diriwayatkan dari Abu Hurairah dan ini merupakan hadits Hasan Gharib melalui jalur ini. Sebagian mereka meriwayatkan hadits ini dari [Mubarak bin Fadlalah] dari [Muhammad bin Al Munkadir] dari [Jabir] dari Nabi shallallaahu 'alaihi wasallam namun tidak disebutkan didalamnya dari Abdu Rabbih bin Sa'id dan riwayat ini lebih shahih."},"1942":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَكُونُ الْمُؤْمِنُ لَعَّانًاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَرَوَى بَعْضُهُمْ بِهَذَا الْإِسْنَادِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْبَغِي لِلْمُؤْمِنِ أَنْ يَكُونَ لَعَّانًا وَهَذَا الْحَدِيثُ مُفَسِّرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Abu Amir] dari [Katsir bin Zaid] dari [Salim] dari [Ibnu Umar] ia berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seorang mukmin menjadi orang yang suka melaknat.\" Berkata Abu Isa: Hadits semakna juga diriwayatkan dari Abdullah bin Mas'ud dan ini merupakan hadits hasan gharib. Sebagian mereka meriwayatkan dengan sanad ini dari Nabi shallallahu 'alaihi wasallam dengan lafazh: \"Tidak sepantasnya seorang mukmin itu menjadi orang yang suka melaknat.\" Dan hadits ini sebagai tafsir bagi hadits yang lain."},"1943":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ وَحَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلِّمْنِي شَيْئًا وَلَا تُكْثِرْ عَلَيَّ لَعَلِّي أَعِيهِ قَالَ لَا تَغْضَبْ فَرَدَّدَ ذَلِكَ مِرَارًا كُلُّ ذَلِكَ يَقُولُ لَا تَغْضَبْقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَبِي سَعِيدٍ وَسُلَيْمَانَ بْنِ صُرَدٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ هَذَا الْوَجْهِ وَأَبُو حَصِينٍ اسْمُهُ عُثْمَانُ بْنُ عَاصِمٍ الْأَسَدِيُّ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Abu Bakar bin Ayyasy] dari [Abu Hushain] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Seorang laki-laki menghadap Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Ajarkanlah sesuatu kepadaku, namun jangan engkau memperbanyaknya, sehingga aku mudah untuk mengingatnya.\" Maka beliau pun bersabda: \"Janganlah kamu marah.\" Lalu beliau mengulang-ngulang ungkapan itu. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abu Sa'id dan Sulaiman bin Shurd. Dan hadits ini adalah hadits hasan shahih gharib bila ditinjau dari jalur ini."},"1944":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي أَبُو مَرْحُومٍ عَبْدُ الرَّحِيمِ بْنُ مَيْمُونٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ الْجُهَنِيِّ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَظَمَ غَيْظًا وَهُوَ يَسْتَطِيعُ أَنْ يُنَفِّذَهُ دَعَاهُ اللَّهُ يَوْمَ الْقِيَامَةِ عَلَى رُءُوسِ الْخَلَائِقِ حَتَّى يُخَيِّرَهُ فِي أَيِّ الْحُورِ شَاءَقَالَ هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan [Abbas bin Muhammad Ad Duri] dan lebih dari satu orang perawi berkata, Telah menceritakan kepada kami [Abdullah bin Yazid Al Muqri] Telah menceritakan kepada kami [Sa'id bin Abu Ayyub] Telah menceritakan kepadaku [Abu Marhum Abdurrahim bin Maimun] dari [Sahl bin Mu'adz bin Anas Al Juhani] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang menahan amarahnya, sedangkan ia mampu untuk menumpahkannya, maka Allah akan memanggilnya kelak pada hari kiamat di atas kepada seluruh makhluk, sehingga Allah memberikannya pilihan yang ia inginkan.\" Ini adalah hadits hasan gharib."},"1945":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَزِيدُ بْنُ بَيَانٍ الْعُقَيْلِيُّ حَدَّثَنَا أَبُو الرَّحَّالِ الْأَنْصَارِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَكْرَمَ شَابٌّ شَيْخًا لِسِنِّهِ إِلَّا قَيَّضَ اللَّهُ لَهُ مَنْ يُكْرِمُهُ عِنْدَ سِنِّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ هَذَا الشَّيْخِ يَزِيدَ بْنِ بَيَانٍ وَأَبُو الرِّجَالِ الْأَنْصَارِيُّ آخَرُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Yazid bin Bayan Al 'Uqaili], telah menceritakan kepada kami [Abu Rahhal Al Anshari] dari [Anas bin Malik] ia berkata: Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang pemuda menghormati orang yang tua karena umurnya melainkan Allah akan menjadikan untuknya orang yang menghormatinya karena umurnya (di masa tuanya).\" Berkata Abu Isa: Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari haditsnya syaikh ini yaitu Yazid bin Bayan."},"1946":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُفَتَّحُ أَبْوَابُ الْجَنَّةِ يَوْمَ الِاثْنَيْنِ وَالْخَمِيسِ فَيُغْفَرُ فِيهِمَا لِمَنْ لَا يُشْرِكُ بِاللَّهِ شَيْئًا إِلَّا الْمُهْتَجِرَيْنِ يُقَالُ رُدُّوا هَذَيْنِ حَتَّى يَصْطَلِحَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَيُرْوَى فِي بَعْضِ الْحَدِيثِ ذَرُوا هَذَيْنِ حَتَّى يَصْطَلِحَا قَالَ وَمَعْنَى قَوْلِهِ الْمُهْتَجِرَيْنِ يَعْنِي الْمُتَصَارِمَيْنِ وَهَذَا مِثْلُ مَا رُوِيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثَةِ أَيَّامٍ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah Shalallallahu 'alaihi wa sallam bersabda: \"Pada hari senin dan kamis pintu-pintu surga akan dibuka. Lalu, pada hari itu Allah akan mengampuni bagi mereka yang tidak menyekutukan-Nya dengan sesuatu apa pun, kecuali dua orang yang saling berseteru, sehingga dikatakanlah kepada Malaikat, 'Kembalikanlah dua orang ini, sehingga keduanya saling berbaikan.'\" Abu Isa berkata; Ini adalah hadits hasan shahih. Dan dalam sebagian hadits juga diriwayatkan dengan redaksi: \"DZARUU HAADZAINI HATTAA YASHLIHAA (Tinggalkanlah dua orang ini, hingga keduanya baikan).\" Maksab sabda beliau: \"AL MUHTAJIRAINI\" adalah dua orang yang saling bermusuhan. Ini sebagaimana pula yang diriwayatkan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Tidak halal bagi seorang mukmin untuk mendiamkan saudaranya lebih dari tiga hari.\""},"1947":{"ar":"حَدَّثَنَا الْأَنْصَارِيُّ حَدَّثَنَا مَعْنٌ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ أَبِي سَعِيدٍأَنَّ نَاسًا مِنْ الْأَنْصَارِ سَأَلُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْطَاهُمْ ثُمَّ سَأَلُوهُ فَأَعْطَاهُمْ ثُمَّ قَالَ مَا يَكُونُ عِنْدِي مِنْ خَيْرٍ فَلَنْ أَدَّخِرَهُ عَنْكُمْ وَمَنْ يَسْتَغْنِ يُغْنِهِ اللَّهُ وَمَنْ يَسْتَعْفِفْ يُعِفَّهُ اللَّهُ وَمَنْ يَتَصَبَّرْ يُصَبِّرْهُ اللَّهُ وَمَا أُعْطِيَ أَحَدٌ شَيْئًا هُوَ خَيْرٌ وَأَوْسَعُ مِنْ الصَّبْرِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ عَنْ مَالِكٍ هَذَا الْحَدِيثُ فَلَنْ أَذْخَرَهُ عَنْكُمْ وَالْمَعْنَى فِيهِ وَاحِدٌ يَقُولُ لَنْ أَحْبِسَهُ عَنْكُمْ","id":"Telah menceritakan kepada kami [Al Anshari], telah menceritakan kepada kami [Ma'n], telah menceritakan kepada kami [Malik bin Anas] dari [Az Zuhri] dari [Atha` bin Yazid] dari [Abu Sa'id] bahwasanya; Sekelompok orang dari kalangan Anshar meminta sesuatu kepada Rasulullah Shallallhu 'Alaihi wa Sallam, maka beliau pun memberikannya kepada mereka. Kemudian mereka meminta lagi, dan beliau memperkenankan permintaan mereka lalu bersabda: \"Jika aku memiliki sesuatu yang baik, maka aku tidak akan menyembunyikannya dan menahannya dari kalian. Barangsiapa yang merasa cukup, maka Allah akan memberinya kecukupan. Dan siapa yang bersikap iffah (menjaga kehormatan harga diri), maka Allah akan memuliakannya. Dan barangsiapa yang berusaha untuk selalu sabar, maka Allah akan memberinya kesabaran. Dan tidaklah seseorang diberi sesuatu yang lebih baik dan lapang daripada kesabaran.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Anas. Dan Hadits ini adalah Hasan Shahih. Dan telah dirirwayatkan pula dari Malik dengan redaksi: \"FALAN ADKHARAHU 'ANKUM\" namun maknanya adalah sama, ia menjelaskan, \"Aku tidak akan menahannya dari kalian.\""},"1948":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ شَرِّ النَّاسِ عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ ذَا الْوَجْهَيْنِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَعَمَّارٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya manusia yang paling buruk di sisi Allah kelak pada hari kiamat adalah seorang yang bermuka dua.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Anas dan Ammar. Dan hadits ini adalah hasan shahih."},"1949":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ هَمَّامِ بْنِ الْحَارِثِ قَالَمَرَّ رَجُلٌ عَلَى حُذَيْفَةَ بْنِ الْيَمَانِ فَقِيلَ لَهُ إِنَّ هَذَا يُبَلِّغُ الْأُمَرَاءَ الْحَدِيثَ عَنْ النَّاسِ فَقَالَ حُذَيْفَةُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَدْخُلُ الْجَنَّةَ قَتَّاتٌقَالَ سُفْيَانُ وَالْقَتَّاتُ النَّمَّامُ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Manshur] dari [Ibrahim] dari [Hammam bin Al Harits] ia berkata; Pernah seorang laki-laki lewat di hadapan [Hudzaifah bin Al Yaman], lalu dikatakanlah kepadanya, \"Sesungguhnya orang ini sering menyiarkan hal-hal yang buruk dari manusia.\" Maka Hudzaifah berkata; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga, yaitu Al Fattat.\" Sufyan berkata, \"Al Fattaat artinya An Nammam (penyebar keburukan, pelaku namimah).\" Dan ini adalah hadits hasan shahih."},"1950":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ أَبِي غَسَّانَ مُحَمَّدِ بْنِ مُطَرِّفٍ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي أُمَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحَيَاءُ وَالْعِيُّ شُعْبَتَانِ مِنْ الْإِيمَانِ وَالْبَذَاءُ وَالْبَيَانُ شُعْبَتَانِ مِنْ النِّفَاقِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ أَبِي غَسَّانَ مُحَمَّدِ بْنِ مُطَرِّفٍ قَالَ وَالْعِيُّ قِلَّةُ الْكَلَامِ وَالْبَذَاءُ هُوَ الْفُحْشُ فِي الْكَلَامِ وَالْبَيَانُ هُوَ كَثْرَةُ الْكَلَامِ مِثْلُ هَؤُلَاءِ الْخُطَبَاءِ الَّذِينَ يَخْطُبُونَ فَيُوَسِّعُونَ فِي الْكَلَامِ وَيَتَفَصَّحُونَ فِيهِ مِنْ مَدْحِ النَّاسِ فِيمَا لَا يُرْضِي اللَّهَ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Yazid bin Harun] dari [Abu Ghassan Muhammad bin Mutharrif] dari [Hasan bin 'Athiyyah] dari [Abu Umamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sifat malu dan al 'iyyu adalah dua cabang dari cabang-cabang keimanan. Sedangkan Al Badza` dan Al Bayan adalah dua cabang dari cabang-cabang kemunafikan.\" Abu Isa berkata; Ini adalah hadits Hasan Gharib, kami mengetahuinya hanya dari haditsnya Abu Ghassan Muhammad bin Mutharrif. Ia berkata, Al 'Iyy adalah sedikit bicara dan Al Badza` adalah kata-kata yang keji, sedangkan Al Bayan adalah banyak bicara seperi para khatib-khatib yang memperpanjang dan menambah-nambahkan isi pembicaraan guna memperoleh pujian publik dalam hal-hal yang tidak diridlai Allah."},"1951":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ ابْنِ عُمَرَأَنَّ رَجُلَيْنِ قَدِمَا فِي زَمَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَا فَعَجِبَ النَّاسُ مِنْ كَلَامِهِمَا فَالْتَفَتَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ مِنْ الْبَيَانِ سِحْرًا أَوْ إِنَّ بَعْضَ الْبَيَانِ سِحْرٌقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَمَّارٍ وَابْنِ مَسْعُودٍ وَعَبْدِ اللَّهِ بْنِ الشِّخِّيرِ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Zaid bin Aslam] dari [Ibnu Umar] bahwasanya; Suatu ketika pada zaman Rasulullah shallallahu 'alaihi wasallam, datanglah dua orang laki-laki lalu keduanya menyampaikan khutbah kepada khalayak, dan orang-orang pun merasa kagum terhadap pembicaraannya. Kemudian Rasulullah shallallahu 'alaihi wasallam berpaling ke arah kami dan bersabda: \"Sesungguhnya diantara bayan (penjelasan dengan kata-kata) itu adalah sihir.\" Atau, \"Sesungguhnya sebagian dari Bayan itu adalah sihir.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ammar, Ibnu Mas'ud, dan Abdullah bin Asy Syikhkhir. Dan hadits ini adalah Hasan Shahih."},"1952":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ وَمَا زَادَ رَجُلًا بِعَفْوٍ إِلَّا عِزًّا وَمَا تَوَاضَعَ أَحَدٌ لِلَّهِ إِلَّا رَفَعَهُ اللَّهُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَابْنِ عَبَّاسٍ وَأَبِي كَبْشَةَ الْأَنَّمَارِيِّ وَاسْمُهُ عُمَرُ بْنُ سَعْدٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Al Ala` bin Abdurrahman] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sedekah itu, pada hakekatnya tidak akan mengurangi harta. Tidaklah seorang memberikan maaf, kecuali ia akan semakin bertambah mulia. Dan tidaklah seorang yang tawadhu' karena Allah, kecuali Allah akan meninggikan derajatnya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abdurrahman bin Auf, Ibnu Abbas, dan Ibnu Kasyabah Al Anmari, namanya adalah Umar bin Sa'd. Hadits ini adalah hadits hasan shahih."},"1953":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الظُّلْمُ ظُلُمَاتٌ يَوْمَ الْقِيَامَةِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَعَائِشَةَ وَأَبِي مُوسَى وَأَبِي هُرَيْرَةَ وَجَابِرٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Abbas Al 'Anbari], telah menceritakan kepada kami [Abu Dawud Ath Thiyalisi] dari [Abdul Aziz bin Abdullah bin Abu Salamah] dari [Abdullah bin Dinar] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kezhaliman adalah kegelapan kelak pada hari kiamat.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Abdullah bin Amr, Aisyah, Abu Musa, Abu Hurairah dan Jabir. Hadits ini adalah hasan shahih gharib dari Ibnu Umar."},"1954":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا عَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا قَطُّ كَانَ إِذَا اشْتَهَاهُ أَكَلَهُ وَإِلَّا تَرَكَهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَأَبُو حَازِمٍ هُوَ الْأَشْجَعِيُّ الْكُوفِيُّ وَاسْمُهُ سَلْمَانُ مَوْلَى عَزَّةَ الْأَشْجَعِيَّةِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Sufyan] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam sama sekali tidak pernah mencela makanan. Bila beliau menyukainya, maka beliau akan memakannya, dan bila tidak selera, beliau tinggalkan.\" Abu Isa berkata; Hadits ini adalah hasan shahih. Abu Hazim adalah Al Asyja'i Al Kufi, namanya adalah Salman Maula 'Azzah Al Asyja'iyyah."},"1955":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَكْثَمَ وَالْجَارُودُ بْنُ مُعَاذٍ قَالَا حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى حَدَّثَنَا الْحُسَيْنُ بْنُ وَاقِدٍ عَنْ أَوْفَى بْنِ دَلْهَمٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِنْبَرَ فَنَادَى بِصَوْتٍ رَفِيعٍ فَقَالَ يَا مَعْشَرَ مَنْ أَسْلَمَ بِلِسَانِهِ وَلَمْ يُفْضِ الْإِيمَانُ إِلَى قَلْبِهِ لَا تُؤْذُوا الْمُسْلِمِينَ وَلَا تُعَيِّرُوهُمْ وَلَا تَتَّبِعُوا عَوْرَاتِهِمْ فَإِنَّهُ مَنْ تَتَبَّعَ عَوْرَةَ أَخِيهِ الْمُسْلِمِ تَتَبَّعَ اللَّهُ عَوْرَتَهُ وَمَنْ تَتَبَّعَ اللَّهُ عَوْرَتَهُ يَفْضَحْهُ وَلَوْ فِي جَوْفِ رَحْلِهِقَالَ وَنَظَرَ ابْنُ عُمَرَ يَوْمًا إِلَى الْبَيْتِ أَوْ إِلَى الْكَعْبَةِ فَقَالَ مَا أَعْظَمَكِ وَأَعْظَمَ حُرْمَتَكِ وَالْمُؤْمِنُ أَعْظَمُ حُرْمَةً عِنْدَ اللَّهِ مِنْكِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ الْحُسَيْنِ بْنِ وَاقِدٍ وَرَوَى إِسْحَقُ بْنُ إِبْرَاهِيمَ السَّمَرْقَنْدِيُّ عَنْ حُسَيْنِ بْنِ وَاقِدٍ نَحْوَهُ وَرُوِي عَنْ أَبِي بَرْزَةَ الْأَسْلَمِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوُ هَذَا","id":"Telah menceritakan kepada kami [Yahya bin Aktsam] dan [Al Jarud bin Mu'adz] keduanya berkata, Telah menceritakan kepada kami [Al Fadlu bin Musa], telah menceritakan kepada kami [Al Husain bin Waqid] dari [Aufa bin Dalham] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah Shallallaahu 'alaihi wa sallam menaiki mimbar lalu menyeru dengan suara yang lantang: \"Wahai sekalian orang yang telah berIslam dengan lisannya namun keimanan belum tertancap di hatinya, janganlah kalian menyakiti kaum muslimin dan jangan pula kalian memperolok mereka, jangan pula kalian menelusuri dan membongkar aib mereka, maka barang siapa yang menyelidiki aib saudaranya seIslam niscaya Allah akan menyelidiki aibnya dan barang siapa yang aibnya diselidiki aibnya oleh Allah niscaya Allah akan membongkar aibnya meskipun di dalam rumahnya sendiri.\" Nafi' berkata: Suatu hari Ibnu Umar melihat Ka'bah, lantas beliau berkata, \"Betapa agungnya kamu, dan betapa luhurnya kehormatanmu namun seorang mukmin lebih agung kehormatannya di sisi Allah dari padamu. Berkata Abu Isa; Ini merupakan hadits gharib yang tidak kami ketahui kecuali dari haditsnya Al Husain bin Wakid. Dan [Ishaq bin Ibrahim As Samarqandi] meriwayatkan dari [Husain bin Wakid] seperti hadits di atas. Diriwayatkan juga dari Abi Barzah Al Aslamy dari Nabi Shallallaahu 'alaihi wa sallam seperti hadits di atas."},"1956":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَلِيمَ إِلَّا ذُو عَثْرَةٍ وَلَا حَكِيمَ إِلَّا ذُو تَجْرِبَةٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Abdullah bin Wahb] dari [Amr bin Harits] dari [Darraj] dari [Abu Al Haitsam] dari [Abu Sa'id] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiada yang memiliki ketabahan kecuali seorang yang telah mengalami ujian. Tidak ada kebijaksanaan, kecuali yang telah kenyang pengalaman.\" Abu Isa berkata; Ini adalah hadits hasan gharib, kami tidak mengetahuinya kecuali dari jalur ini."},"1957":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُعْطِيَ عَطَاءً فَوَجَدَ فَلْيَجْزِ بِهِ وَمَنْ لَمْ يَجِدْ فَلْيُثْنِ فَإِنَّ مَنْ أَثْنَى فَقَدْ شَكَرَ وَمَنْ كَتَمَ فَقَدْ كَفَرَ وَمَنْ تَحَلَّى بِمَا لَمْ يُعْطَهُ كَانَ كَلَابِسِ ثَوْبَيْ زُورٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَعَائِشَةَ وَمَعْنَى قَوْلِهِ وَمَنْ كَتَمَ فَقَدْ كَفَرَ يَقُولُ قَدْ كَفَرَ تِلْكَ النِّعْمَةَ","id":"Telah menceritakan kepada kami [Ali bin Hujr], telah mengabarkan kepada kami [Isma'il bin 'Ayysy] dari [Umarah bin Ghaziyyah] dari [Abu Zubair] dari [Jabir] dari Nabi Shallallaahu 'Alaihi wa Sallam, beliau bersabda: \"Barang siapa yang diberi suatu pemberian lalu dia memperoleh kelebihan harta, maka hendaknya dia memberi. Dan barang siapa yang tidak mendapatkan kelebihan harta hendaknya dia memuji, karena barang siapa yang memuji dia telah bersyukur dan barang siapa yang menyembunyikan nikmat berarti dia telah kufur nikmat. Dan barang siapa yang bersikap (mengaku) dengan sesuatu yang tidak diberikan kepadanya, maka dia ibarat orang yang memakai dua buah baju kebohongan.\" Berkata Abu Isa: Ini merupakan hadits hasan gharib. Hadits semakna juga diriwayatkan dari Asma' binti Abu Bakar dan 'Aisyah."},"1958":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ الْحَسَنِ الْمَرْوَزِيُّ بِمَكَّةَ وَإِبْرَاهِيمُ بْنُ سَعِيدٍ الْجَوْهَرِيُّ قَالَا حَدَّثَنَا الْأَحْوَصُ بْنُ جَوَّابٍ عَنْ سُعَيْرِ بْنِ الْخِمْسِ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صُنِعَ إِلَيْهِ مَعْرُوفٌ فَقَالَ لِفَاعِلِهِ جَزَاكَ اللَّهُ خَيْرًا فَقَدْ أَبْلَغَ فِي الثَّنَاءِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ جَيِّدٌ غَرِيبٌ لَا نَعْرِفُهُ مِنْ حَدِيثِ أُسَامَةَ بْنِ زَيْدٍ إِلَّا مِنْ هَذَا الْوَجْهِ وَقَدْ رُوِيَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَسَأَلْتُ مُحَمَّدًا فَلَمْ يَعْرِفْهُ حَدَّثَنِي عَبْدُ الرَّحِيمِ بْنُ حَازِمٍ الْبَلْخِيُّ قَال سَمِعْتُ الْمَكِّيَّ بْنَ إِبْرَاهِيمَ يَقُولُ كُنَّا عِنْدَ ابْنِ جُرَيْجٍ الْمَكِّيِّ فَجَاءَ سَائِلٌ فَسَأَلَهُ فَقَالَ ابْنُ جُرَيْجٍ لِخَازِنِهِ أَعْطِهِ دِينَارًا فَقَالَ مَا عِنْدِي إِلَّا دِينَارٌ إِنْ أَعْطَيْتُهُ لَجُعْتَ وَعِيَالُكَ قَالَ فَغَضِبَ وَقَالَ أَعْطِهِ قَالَ الْمَكِّيُّ فَنَحْنُ عِنْدَ ابْنِ جُرَيْجٍ إِذْ جَاءَهُ رَجُلٌ بِكِتَابٍ وَصُرَّةٍ وَقَدْ بَعَثَ إِلَيْهِ بَعْضُ إِخْوَانِهِ وَفِي الْكِتَابِ إِنِّي قَدْ بَعَثْتُ خَمْسِينَ دِينَارًا قَالَ فَحَلَّ ابْنُ جُرَيْجٍ الصُّرَّةَ فَعَدَّهَا فَإِذَا هِيَ أَحَدٌ وَخَمْسُونَ دِينَارًا قَالَ فَقَالَ ابْنُ جُرَيْجٍ لِخَازِنِهِ قَدْ أَعْطَيْتَ وَاحِدًا فَرَدَّهُ اللَّهُ عَلَيْكَ وَزَادَكَ خَمْسِينَ دِينَارًا","id":"Telah menceritakan kepada kami [Al Husain bin Al Hasan Al Marwazi] di Makkah, dan [Ibrahim bin Sa'id Al Jauhari] keduanya berkata, Telah menceritakan kepada kami [Al Ahwash bin Jawwab] dari [Su'air bin Al Khims] dari [Sulaiman At Taimi] dari [Abu Utsman An Nahdi] dari [Usamah bin Zaid] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang diperlakukan dengan baik kemudian dia mengucapkan, 'JAZAAKALLAAHU KHAIRAN' maka sungguh dia telah memberikan pujian yang terbaik.\" Berkata Abu Isa: Ini merupakan hadits hasan jayyid gharib yang tidak kami ketahui dari haditsnya Usamah bin Zaid kecuali dari jalur ini dan telah diriwayatkan dari Abu Hurairah dari Nabi shallallaahu 'alaihi wa sallam hadits yang serupa. Aku bertanya kepada Muhammad, namun dia tidak mengetahuinya. Telah menceritakan kepadaku Abdurrahim bin Hazim Al Balkhi ia berkata, Aku mendengar Al Makki bin Ibrahim berkata; Suatu ketika kami bersama Ibnu Juraij Al Makki, tiba-tiba datang seseorang meminta sesuatu kepadanya lalu Ibnu Juraij berkata kepada bendaharanya, \"Berilah dia satu Dinar.\" Sang bendahara pun berkata, \"Aku tidak memiliki kecuali satu Dinar, jika aku berikan kepadanya niscaya Anda sekeluarga akan kelaparan.\" Lantas Ibnu Juraij marah dan berkata, \"Berikan kepadanya.\" Al Makki berkata; Tatkala kami bersama Ibnu juraij, tiba-tiba seseorang datang dengan membawa sebuah buku dan sekantung uang dan sebagian sahabatnya telah mengirim pesan kepadanya, \"Aku telah mengirim untukmu lima puluh dinar.\" Lantas Ibnu Juraij membuka kantung tersebut lalu menghitungnya dan ternyata jumlahnya lima puluh satu Dinar. Maka Ibnu Juarij berkata kepada bendaharanya, \"Kamu telah memberi satu Dinar, lalu Allah mengembalikannya kepadamu dan menambahnya dengan lima puluh dinar.\""},"1959":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا إِسْحَقُ بْنُ مُحَمَّدٍ الْفَرْوِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ قَتَادَةَ بْنِ النُّعْمَانِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَحَبَّ اللَّهُ عَبْدًا حَمَاهُ الدُّنْيَا كَمَا يَظَلُّ أَحَدُكُمْ يَحْمِي سَقِيمَهُ الْمَاءَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ صُهَيْبٍ وَأُمِّ الْمُنْذِرِ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَقَدْ رُوِيَ هَذَا الْحَدِيثُ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْسَلًا حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ عَاصِمِ بْنِ عُمَرَ بْنِ قَتَادَةَ عَنْ مَحْمُودِ بْنِ لَبِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَلَمْ يَذْكُرْ فِيهِ عَنْ قَتَادَةَ بْنِ النُّعْمَانِ قَالَ أَبُو عِيسَى وَقَتَادَةُ بْنُ النُّعْمَانِ الظَّفَرِيُّ هُوَ أَخُو أَبِي سَعِيدٍ الْخُدْرِيِّ لِأُمِّهِ وَمَحْمُودُ بْنُ لَبِيدٍ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَآهُ وَهُوَ غُلَامٌ صَغِيرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Ishaq bin Muhammad Al Farwi], telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Umarah bin Ghaziyyah] dari [Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari [Qatadah bin An Nu'man] bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila Allah mencintai seorang hamba, maka Dia akan melindunginya dari fitnah dunia. Sebagaimana salah seorang dari kalian berteduh untuk melindungi sakitnya dari percikan air.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Shuhaib dan Ummu Al Mundzir. Ini adalah hadits Hasan Gharib. Hadits ini telah diriwayatkan pula dari [Mahmud bin Labid], dari Nabi shallallahu 'alaihi wasallam secara Mursal. Telah menceritakan kepada kami [Ali bin Hujr], telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Amru bin Abu Amru] dan dari [Ashim bin Umar bin Qatadah] dari [Mahmud bin Labid] dari Nabi shallallahu 'alaihi wasallam semisalnya. Namun di dalamnya ia tidak menyebutkan; Dari Qatadah bin An Nu'man. Abu Isa berkata; Qatadah bin An Nu'man Azh Zhafari adalah saudaranya Sa'id Al Khudri dari jalur ibunya. Sedangkan Mahmud bin Labid mendapati Nabi shallallahu 'alaihi wasallam dan sempat melihatnya, yang pada saat itu ia masih anak-anak."},"1960":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ عُثْمَانَ بْنِ عَبْدِ الرَّحْمَنِ التَّيْمِيِّ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيٌّ وَلَنَا دَوَالٍ مُعَلَّقَةٌ قَالَتْ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ وَعَلِيٌّ مَعَهُ يَأْكُلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَلِيٍّ مَهْ مَهْ يَا عَلِيُّ فَإِنَّكَ نَاقِهٌ قَالَ فَجَلَسَ عَلِيٌّ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ قَالَتْ فَجَعَلْتُ لَهُمْ سِلْقًا وَشَعِيرًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ مِنْ هَذَا فَأَصِبْ فَإِنَّهُ أَوْفَقُ لَكَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ فُلَيْحٍ وَيُرْوَى عَنْ فُلَيْحٍ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو عَامِرٍ وَأَبُو دَاوُدَ قَالَا حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ الْأَنْصَارِيَّةِ قَالَتْ دَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَ حَدِيثِ يُونُسَ بْنِ مُحَمَّدٍ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ إِلَّا أَنَّهُ قَالَ أَنْفَعُ لَكَ وَقَالَ مُحَمَّدُ بْنُ بَشَّارٍ فِي حَدِيثِهِ وَحَدَّثَنِيهِ أَيُّوبُ بْنُ عَبْدِ الرَّحْمَنِ هَذَا حَدِيثٌ جَيِّدٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abbas bin Muhammad Ad Duri], telah menceritakan kepada kami [Yunus bin Muhammad], telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Utsman bin Abdurrahman At Taimi] dari [Ya'qub bin Abu Ya'qub] dari [Ummu Al Mundzir] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah menemuiki dan pada saat itu beliau bersama Ali. Ketika itu, kami memiliki ember-ember yang tergantung. Kemudian Rasulullah shallallahu 'alaihi wasallam makan dan Ali pun ikut makan. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ali: \"Wahai Ali, mah..mah.., sesungguhnya kamu adalah seorang yang paham.\" Maka Ali pun duduk sedangkan Nabi shallallahu 'alaihi wasallam makan. Lalau aku membikinkan As Silq (sejenis ubi) dan gandum bagi mereka. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Ali, mulailah dari sini, karena ia lebih pas untukmu.\" Abu Isa berkata; Ini adalah hadits hasan gharib, kami tidak mengetahuinya kecuali dari haditsnya Fulaih. Dan diriwayatkan pula dari [Fulaih] dari [Ayyub bin Abdurrahman] Telah menceritakan kepada kami [Muhammad bin Basysyar] Telah menceritakan kepada kami [Abu Amir] dari [Abu Dawud] keduanya berkata, Telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Ayyub bin Abdurrahman] dari [Ya'qub bin Abu Ya'qub] dari [Ummu Al Mundzir Al Anshariyah] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam menemui kami. Maka ia pun menyebutkan hadits seperti haditsnya Yunus bin Muhammad bin Fulaih bin Sulaiman, hanya saja ia menyebutkan, \"Ia lebih bermanfaat untukmu.\" Muhammad bin Basysyar berkata di dalam haditsnya; Dan telah menceritakan kepadaku Ayyub bin Abdurrahman. Hadits ini adalah hadits jayyid gharib."},"1961":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُعَاذٍ الْعَقَدِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَقَالَتْ الْأَعْرَابُ يَا رَسُولَ اللَّهِ أَلَا نَتَدَاوَى قَالَ نَعَمْ يَا عِبَادَ اللَّهِ تَدَاوَوْا فَإِنَّ اللَّهَ لَمْ يَضَعْ دَاءً إِلَّا وَضَعَ لَهُ شِفَاءً أَوْ قَالَ دَوَاءً إِلَّا دَاءً وَاحِدًا قَالُوا يَا رَسُولَ اللَّهِ وَمَا هُوَ قَالَ الْهَرَمُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَأَبِي هُرَيْرَةَ وَأَبِي خُزَامَةَ عَنْ أَبِيهِ وَابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Bisyr bin Mu'adz Al 'Aqadi], telah menceritakan kepada kami [Abu 'Awanah] dari [Ziyad bin Ilaqah] dari [Usamah bin Syarik] ia berkata; Para orang Arab baduwi berkata, \"Wahai Rasulullah, Tidakkah kami ini harus berobat (jika sakit)?\" Beliau menjawab: \"Iya wahai sekalian hamba Allah, Berobatlah sesungguhnya Allah tidak menciptakan suatu penyakit melainkan menciptakan juga obat untuknya kecuali satu penyakit.\" Mereka bertanya, \"Penyakit apakah itu wahai Rasulullah?\" Beliau menjawab: \"Yaitu penyakit tua (pikun).\" Abu Isa berkata; Hadits semakna diriwayatkan dari Ibnu Mas'ud, Abu Hurairah, Abu Khuzaimah dari bapaknya dan Ibnu Abbas. Dan ini merupakan hadits hasan shahih."},"1962":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ أَخْبَرَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ السَّائِبِ بْنِ بَرَكَةَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَخَذَ أَهْلَهُ الْوَعَكُ أَمَرَ بِالْحِسَاءِ فَصُنِعَ ثُمَّ أَمَرَهُمْ فَحَسَوْا مِنْهُ وَكَانَ يَقُولُ إِنَّهُ لَيَرْتُقُ فُؤَادَ الْحَزِينِ وَيَسْرُو عَنْ فُؤَادِ السَّقِيمِ كَمَا تَسْرُو إِحْدَاكُنَّ الْوَسَخَ بِالْمَاءِ عَنْ وَجْهِهَاقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ الْحُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا بِهِ أَبُو إِسْحَقَ الطَّالْقَانِيُّ عَنْ ابْنِ الْمُبَارَكِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah mengabarkan kepada kami [Isma'il bin Ibrahim] Telah menceritakan kepada kami [Muhammad bin As Sa`ib bin Barakah] dari [ibunya] dari [Aisyah] ia berkata; Apabila keluarga Rasulullah shallallahu 'alaihi wasallam tertimpa sakit, maka beliau memerintahkan untuk membuat Al Hisa`(sesuatu yang dihirup). Maka setelah dibuat, beliau memerintahkan mereka agar menghirupnya. Dan beliau bersabda: \"Sesungguhnya hal itu akan memulihkan keadaan hati orang-orang yang ditimpa kesedihan, dan akan menghilangkannya dari hati orang-orang yang sakit, sebagaimana kalian menghilangkan kotoran yang ada di wajah dengan air.\" Abu Isa berkata; Ini adalah hadits Hasan Shahih. Dan [Ibnul Mubarak] telah meriwayatkannya dari [Yunus] dari [Zuhri] dari [Urwah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami seperti itu [Al Husain bin Muhammad] Telah menceritakannya kepada kami [Abu Ishaq Ath Thalqani] dari [Ibnul Mubarak]."},"1963":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا بَكْرُ بْنُ يُونُسَ بْنِ بُكَيْرٍ عَنْ مُوسَى بْنِ عَلِيٍّ عَنْ أَبِيهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُكْرِهُوا مَرْضَاكُمْ عَلَى الطَّعَامِ فَإِنَّ اللَّهَ يُطْعِمُهُمْ وَيَسْقِيهِمْقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ هَذَا الْوَجْهِ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Bakr bin Yunus] dari [Musa bin 'Ali] dari [bapaknya] dari [Uqbah bin Amir Al Juhani] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memaksa orang yang sakit di antara kalian untuk memakan makanan, karena Allah yang akan memberi makan dan minum kepada mereka.\" Berkata Abu Isa; Ini merupakan hadits hasan gharib yang tidak kami ketahui kecuali melalui jalur ini."},"1964":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَيْكُمْ بِهَذِهِ الْحَبَّةِ السَّوْدَاءِ فَإِنَّ فِيهَا شِفَاءً مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ وَالسَّامُ الْمَوْتُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ بُرَيْدَةَ وَابْنِ عُمَرَ وَعَائِشَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَالْحَبَّةُ السَّوْدَاءُ هِيَ الشُّونِيزُ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] dan [Sa'id bin Abdurrahman Al Makhzumi] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwasanya Nabi Shallallahu 'Alaihi wa Salam bersabda: \"Hendaklah kalian selalau mengkomsumsi Habbatus Sauda`, karena di dalamnya terdapat kesembuhan bagi segala penyakit, kecuali As Sam. Sedangkan As Sam adalah kematian.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Buraidah, Ibnu Umar dan Aisyah. Hadits ini adalah hasan shahih. Al Habbatus Sauda` adalah Asy Syuuniz (jinten hitam)."},"1965":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا حُمَيْدٌ وَثَابِتٌ وَقَتَادَةُ عَنْ أَنَسٍأَنَّ نَاسًا مِنْ عُرَيْنَةَ قَدِمُوا الْمَدِينَةَ فَاجْتَوَوْهَا فَبَعَثَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلِ الصَّدَقَةِ وَقَالَ اشْرَبُوا مِنْ أَلْبَانِهَا وَأَبْوَالِهَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ��بْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad Az Za'farani], telah menceritakan kepada kami ['Affan], telah menceritakan kepada kami [Hammad bin Salamah], telah mengabarkan kepada kami [Humaid] dan [Tsabit] dan [Qatadah] dari [Anas] bahwa sekelompok orang dari 'Urainah mendatangi kota Madinah lalu mereka merasa suka tinggal di dalamnya. Kemudian Rasulullah shallallahu 'alaihi wasallam mengutus mereka dengan membawa unta sedekah, dan beliau bersabda: \"Minumlah kalian dengan air susunya dan air kencingnya.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Abbas. Dan ini adalah hadits hasan shahih."},"1966":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ أَرَاهُ رَفَعَهُ قَالَمَنْ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ جَاءَ يَوْمَ الْقِيَامَةِ وَحَدِيدَتُهُ فِي يَدِهِ يَتَوَجَّأُ بِهَا فِي بَطْنِهِ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا أَبَدًا وَمَنْ قَتَلَ نَفْسَهُ بِسُمٍّ فَسُمُّهُ فِي يَدِهِ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا أَبَدًا","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] Telah menceritakan kepada kami [Abidah bin Humaid] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah], menurutku ia memarfu-kannya, ia berkata, \"Barangsiapa yang membunuh dirinya sendiri dengan besi, maka ia akan datang kelak pada hari kiamat, sedangkan besi itu berada di tangannya seraya menusuk-nusuk perutnya di dalam neraka jahannam kekal selama-lamanya. Dan barangsiapa yang membunuh dirinya sendiri dengan racun, maka racun itu akan senantiasa berada di tangannya dan mengkomsumsinya di dalam neraka jahannam selama-lamanya.\""},"1967":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ قَال سَمِعْتُ أَبَا صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ فَحَدِيدَتُهُ فِي يَدِهِ يَتَوَجَّأُ بِهَا فِي بَطْنِهِ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ قَتَلَ نَفْسَهُ بِسُمٍّ فَسُمُّهُ فِي يَدِهِ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ تَرَدَّى مِنْ جَبَلٍ فَقَتَلَ نَفْسَهُ فَهُوَ يَتَرَدَّى فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًاحَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ حَدِيثِ شُعْبَةَ عَنْ الْأَعْمَشِ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَهُوَ أَصَحُّ مِنْ الْحَدِيثِ الْأَوَّلِ هَكَذَا رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَوَى مُحَمَّدُ بْنُ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ نَفْسَهُ بِسُمٍّ عُذِّبَ فِي نَارِ جَهَنَّمَ وَلَمْ يَذْكُرْ فِيهِ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَهَكَذَا رَوَاهُ أَبُو الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا أَصَحُّ لِأَنَّ الرِّوَايَاتِ إِنَّمَا تَجِيءُ بِأَنَّ أَهْلَ التَّوْحِيدِ يُعَذَّبُونَ فِي النَّارِ ثُمَّ يُخْرَجُونَ مِنْهَا وَلَمْ يُذْكَرْ أَنَّهُمْ يُخَلَّدُونَ فِيهَا","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan] Telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] dari [Al A'masy] ia berkata, Aku mendengar [Abu Shalih] dari [Abu Hurairah] bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membunuh dirinya sendirinya dengan besi, maka besi itu akan senantiasa berada di tangannya, membacok perutnya di dalam neraka jahannam selama-lamanya. Dan siapa yang membunuh dirinya dengan racun, maka racun itu pula akan selalu berada di tangannya dan menelannya dengan berada di dalam neraka jahannam selama-lamanya. Dan siapa yang menjatuhkan dirinya dari gunung, lalu ia membunuh dirinya, maka ia akan senantiasa terjatuh di dalam neraka jahannam selama-lamanya.\" Telah menceritakan kepada kami [Muhammad bin Al 'Ala`], telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti haditsnya Syu'bah dari A'masy. Abu Isa berkata; Ini adalah hadits shahih dan lebih shahih dari hadits pertama. Dan hadits ini telah diriwayatkan pula oleh lebih dari satu orang perawi dari Al A'masy dari Abu Shalih dari Abu Hurairah dari Nabi shallallahu 'alaihi wasallam. Dan [Muhammad bin Ajlan] telah meriwayatkan pula dari [Sa'id Al Maqburi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang membunuh dirinya sendiri dengan racun, maka ia akan diadzab dengannya kelak di dalam neraka jahannam.\" Namun di dalamnya ia tidak menyebutkan, \"Abadi selama-lamanya.\" Dan seperti ini pula yang diriwayatkan oleh [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dan riwayat ini lebih Shahih, karena riwayat-riwayat lain menunjukkan bahwa Ahlu Tuhid, mereka akan disiksa di dalam neraka lalu dikeluarkan darinya, dan tidak disebutkan bahwa mereka akan kekal di dalamnya."},"1968":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ نَصْرٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّوَاءِ الْخَبِيثِقَالَ أَبُو عِيسَى يَعْنِي السُّمَّ","id":"Telah menceritakan kepada kami [Suwaid bin Nashr], telah mengabarkan kepada kami [Abdullah bin Mubarak] dari [Yunus bin Abu Ishaq] dari [Mujahid] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang untuk berobat dengan sesuatu yang kotor (najis).\" Abu Isa berkata; Maksudnya adalah As Summ (racun)."},"1969":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا أَبُو دَاوُدَ عَنْ شُعْبَةَ عَنْ سِمَاكٍ أَنَّهُ سَمِعَ عَلْقَمَةَ بْنَ وَائِلٍ عَنْ أَبِيهِأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ سُوَيْدُ بْنُ طَارِقٍ أَوْ طَارِقُ بْنُ سُوَيْدٍ عَنْ الْخَمْرِ فَنَهَاهُ عَنْهُ فَقَالَ إِنَّا نَتَدَاوَى بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَيْسَتْ بِدَوَاءٍ وَلَكِنَّهَا دَاءٌحَدَّثَنَا مَحْمُودٌ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ وَشَبَابَةُ عَنْ شُعْبَةَ بِمِثْلِهِ قَالَ مَحْمُودٌ قَالَ النَّضْرُ طَارِقُ بْنُ سُوَيْدٍ وَقَالَ شَبَابَةُ سُوَيْدُ بْنُ طَارِقٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abu Dawud] dari [Syu'bah] dari [Syimak] bahwa ia mendengar [Alqamah bin Wa`il] dari [bapaknya] bahwa ia pernah menyaksikan Nabi shallallahu 'alaihi wasallam. Dan Suwaid bin Thariq atau Thariq bin Suwaid bertanya pada beliau tentang khamer, Suwaid berkata, \"Sesungguhnya kami menggunakannya sebagai obat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya khamer itu bukanlah obat, akan tetapi ia adalah penyakit.\" Telah menceritakan kepada kami [An Nashr bin Syumail] dan [Syababah] dari [Syu'bah] semisalnya. Mahmud berkata; An Nashr berkata; Tharib bin Suwaid. Dan Syababah berkata; Suwaid bin Thariq. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1970":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَدُّوَيْهِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَمَّادٍ الشُّعَيْثِيُّ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خَيْرَ مَا تَدَاوَيْتُمْ بِهِ السَّعُوطُ وَاللَّدُودُ وَالْحِجَامَةُ وَالْمَشِيُّ فَلَمَّا اشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَدَّهُ أَصْحَابُهُ فَلَمَّا فَرَغُوا قَالَ لُدُّوهُمْ قَالَ فَلُدُّوا كُلُّهُمْ غَيْرَ الْعَبَّاسِ","id":"Telah menceritakan kepada kami [Muhammad bin Madduwaih], telah menceritakan kepada kami [Abdurrahman bin Hammad Asy Syu'aitsi] Telah menceritakan kepada kami [Abbad bin Manshur] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik obat yang kalian gunakan ialah gurah, Laduud (obat yang diteteskan disisi mulut orang yang sakit), berbekam dan Al Masyiy (obat untuk mengosongkan isi perut).\" Maka, tatkala Nabi shallallaahu 'Alaihi wa Sallam sakit para shahabat memberinya laduud. Setelah mereka selesai beliau bersabda: \"Berilah mereka laduud.\" Lantas mereka pun memakai laduud selain Abbas."},"1971":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ خَيْرَ مَا تَدَاوَيْتُمْ بِهِ اللَّدُودُ وَالسَّعُوطُ وَالْحِجَامَةُ وَالْمَشِيُّ وَخَيْرُ مَا اكْتَحَلْتُمْ بِهِ الْإِثْمِدُ فَإِنَّهُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعْرَ وَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُكْحُلَةٌ يَكْتَحِلُ بِهَا عِنْدَ النَّوْمِ ثَلَاثًا فِي كُلِّ عَيْنٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَهُوَ حَدِيثُ عَبَّادِ بْنِ مَنْصُورٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya], telah menceritakan kepada kami [Yazid bin Harun] Telah menceritakan kepada kami [Abbad bin Manshur] dari [Ikrimah] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya obat yang paling baik untuk kalian gunakan adalah Al Ladud dan As Sa'uth, bekam dan Al Masyiy. Dan sebaik-baik sesuatu yang dapat kalian gunakan untuk bercelak adalah Al Itsmid, sebab ia akan menajamkan pandangan dan menumbuhkan rambut.\" Dan Rasulullah shallallahu 'alaihi wasallam mempunyai celak yang beliau gunakan sebanyak tiga kali dalam sehari pada kedua matanya. Abu Isa berkata; Hadits ini adalah hasan gharib. Ia haditsnya Abbad bin Manshur."},"1972":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْكَيِّقَالَ فَابْتُلِينَا فَاكْتَوَيْنَا فَمَا أَفْلَحْنَا وَلَا أَنْجَحْنَا قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Imran bin Husain] bahwa Rasulullah shallallahu 'alaihi wasallam melarang Kayy. Ia berkata, \"Kami pernah ditimpa bala`, lalu kami berobat dengan Kay, maka kami pun tidak beruntung.\" Abu Isa berkata; Ini adalah hadits hasan shahih. "},"1973":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَنُهِينَا عَنْ الْكَيِّقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَعُقْبَةَ بْنِ عَامِرٍ وَابْنِ عَبَّاسٍ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abdul Qudus bin Muhammad], telah menceritakan kepada kami [Amru bin 'Ashim], telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain] ia berkata, \"Kami dilarang untuk berobat dengan Kayy.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Mas'ud, Uqbah bin Amir, dan Ibnu Abbas. Dan ini adalah hadits hasan shahih."},"1974":{"ar":"حَدَّثَنَا حُمَيْدُ بْنُ مَسْعَدَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَوَى أَسْعَدَ بْنَ زُرَارَةَ مِنْ الشَّوْكَةِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أُبَيٍّ وَجَابِرٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Humaid bin Mas'adah], telah menceritakan kepada kami [Yazid bin Zura'] Telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Anas] bahwasanya Nabi shallallahu 'alaihi wasallam mengobati As'ad bin Zurarah dengan Kay dari duri. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ubay dan Jabir. Hadits ini adalah hadits hasan gharib."},"1975":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَسَنِ بْنِ خِرَاشٍ الْبَغْدَادِيُّ حَدَّثَنَا شَبَابَةُ عَنْ شُعْبَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَوَاهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ غَرِيبٌ وَرَوَى هَذَا الْحَدِيثَ غَيْرَ وَاحِدٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَوَى أُبَيَّ بْنَ كَعْبٍ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hasan bin Hirasy Al Baghdadi], telah menceritakan kepada kami [Syababah] dari [Syu'bah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah] dari [Ubay bin Ka'ab] bahwasanya Nabi shallallahu 'alaihi wasallam pernah mengobatinya dengan menggunakan Kay. Abu Isa berkata; Ini adalah hadits hasan gharib. Hadits ini juga diriwayatkan oleh lebih dari satu perawi dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] bahwasanya Nabi shallallahu 'alaihi wasallam mengobati Ubay bin Ka'ab dengan Kay."},"1976":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ بْنُ مُحَمَّدٍ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا هَمَّامٌ وَجَرِيرُ بْنُ حَازِمٍ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَجِمُ فِي الْأَخْدَعَيْنِ وَالْكَاهِلِ وَكَانَ يَحْتَجِمُ لِسَبْعَ عَشْرَةَ وَتِسْعَ عَشْرَةَ وَإِحْدَى وَعِشْرِينَقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ عَبَّاسٍ وَمَعْقِلِ بْنِ يَسَارٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Abdul Qudus bin Muhammad], telah menceritakan kepada kami [Amru bin Ashim], telah menceritakan kepada kami [Hammam] dan [Jarir bin Hazim] keduanya berkata, Telah menceritakan kepada kami [Qatadah] dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berbekam pada bagian punggungnya. Dan biasanya beliau berbekam pada tanggal sepuluh, Sembilan belas atau dua puluh satu.\" Abu Isa berkata; Hadits semaknya juga diriwayatkan dari Ibnu Abbas dan Ma'qil bin Yasir. Dan hadits ini adalah hadits hasan gharib."},"1977":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ بُدَيْلِ بْنِ قُرَيْشٍ الْيَامِّيُّ الْكُوفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ عَنْ أَبِيهِ عَنْ ابْنِ مَسْعُودٍ قَالَحَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لَيْلَةِ أُسْرِيَ بِهِ أَنَّهُ لَمْ يَمُرَّ عَلَى مَلَإٍ مِنْ الْمَلَائِكَةِ إِلَّا أَمَرُوهُ أَنْ مُرْ أُمَّتَكَ بِالْحِجَامَةِقَالَ أَبُو عِيسَى وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ مِنْ حَدِيثِ ابْنِ مَسْعُودٍ","id":"Telah menceritakan kepada kami [Ahmad bin Budail bin Quraisy Al Yami Al Kufi], telah menceritakan kepada kami [Muhammad bin Fudlail], telah menceritakan kepada kami [Abdurrahman bin Ishaq] dari [Al Qasim bin Abdurrahman] ia adalah Ibnu Abdullah bin Mas'ud, dari [bapaknya] dari [Ibnu Mas'ud] ia berkata; Rasulullah Shallallaahu 'alaihi wa sallam berkisah tentang malam beliau Isra' Mi'raj, dan sesungguhnya tidaklah beliau melewati sekelompok malaikat kecuali mereka semua menyuruh beliai untuk memerintahkan ummatnya berbekam. Berkata Abu Isa: Ini merupakan hadits hasan gharib dari haditsnya Ibnu Mas'ud."},"1978":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا عَبَّادُ بْنُ مَنْصُورٍ قَال سَمِعْتُ عِكْرِمَةَ يَقُولُكَانَ لِابْنِ عَبَّاسٍ غِلْمَةٌ ثَلَاثَةٌ حَجَّامُونَ فَكَانَ اثْنَانِ مِنْهُمْ يُغِلَّانِ عَلَيْهِ وَعَلَى أَهْلِهِ وَوَاحِدٌ يَحْجُمُهُ وَيَحْجُمُ أَهْلَهُ قَالَ وَقَالَ ابْنُ عَبَّاسٍ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الْعَبْدُ الْحَجَّامُ يُذْهِبُ الدَّمَ وَيُخِفُّ الصُّلْبَ وَيَجْلُو عَنْ الْبَصَرِ وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ عُرِجَ بِهِ مَا مَرَّ عَلَى مَلَإٍ مِنْ الْمَلَائِكَةِ إِلَّا قَالُوا عَلَيْكَ بِالْحِجَامَةِ وَقَالَ إِنَّ خَيْرَ مَا تَحْتَجِمُونَ فِيهِ يَوْمَ سَبْعَ عَشْرَةَ وَيَوْمَ تِسْعَ عَشْرَةَ وَيَوْمَ إِحْدَى وَعِشْرِينَ وَقَالَ إِنَّ خَيْرَ مَا تَدَاوَيْتُمْ بِهِ السَّعُوطُ وَاللَّدُودُ وَالْحِجَامَةُ وَالْمَشِيُّ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَدَّهُ الْعَبَّاسُ وَأَصْحَابُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَدَّنِي فَكُلُّهُمْ أَمْسَكُوا فَقَالَ لَا يَبْقَى أَحَدٌ مِمَّنْ فِي الْبَيْتِ إِلَّا لُدَّ غَيْرَ عَمِّهِ الْعَبَّاسِ قَالَ عَبْدٌ قَالَ النَّضْرُ اللَّدُودُ الْوَجُورُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ لَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ عَبَّادِ بْنِ مَنْصُورٍ وَفِي الْبَاب عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Abdu bin Humaid], telah mengabarkan kepada kami [An Nadlr bin Syumail], telah menceritakan kepada kami [Abbad bin Manshur] ia berkata, Saya mendengar [Ikrimah] berkata, [Ibnu Abbas] mempunyai tiga anak, ketiganya aalah menjadi tukang bekam. Dua orang dari anaknya itu mendapatkan uapah dari bekamnya dan memberikan kepadanya (Ibnu Abbas dan keluarganya), dan yang satunya membekamnya dan keluarganya. Ibnu Abbas berkata, Nabi shallallahu 'alaihi wasallam bersabda, \"Sebagus-bagus hamba adalah sebagai tukang bekam, membuang darah, meringankan tulang punggung, dan mempertajam pandangan.\" Ia berkata, Sesungguhnya ketika Nabi shallallahu 'alaihi wasallam mi'raj (diangkat oleh Allah ke langit) tidaklah beliau melewati pada malaikat kecuali mereka berkata, hendaklah kamu berbekam, beliau berkata, Sesungguhnya hari yang baik untuk berbekam adalah pada tanggal 17, 19, dan 21. Beliau berkata, Sesungguhnya sebaik-baik sarana untuk kalian berobat adalah dengan sa'uth (sejenis rerumputan), ladud (obat yang dimasukkan pada sisi mulut ketika sakit), bekam dan masy (obat perut), sesungguhnya Rasulullah diobati oleh Ibnu Abbas dari shahabat lainnya. Barangsiapa yang mengobatiku, hendaklah mereka semua diam. Maka tidak ada seorang pun yang tidak diobati kecuali paman beliau Ibnu Abbas, Abd berkata, ia berkata, nadhr, ladud, dan wajur sama. Abu Isa berkata, hadits ini hasan gharib, kami tidak mengetahuinya kecuali dari hadits Abbad bin Manshur, dan dalam bab ini dari Aisyah."},"1979":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا حَمَّادُ بْنُ خَالِدٍ الْخَيَّاطُ حَدَّثَنَا فَائِدٌ مَوْلًى لِآلِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ عُبَيْدِ اللَّهِ عَنْ جَدَّتِهِ سَلْمَى وَكَانَتْ تَخْدُمُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَا كَانَ يَكُونُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرْحَةٌ وَلَا نَكْبَةٌ إِلَّا أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَضَعَ عَلَيْهَا الْحِنَّاءَقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ فَائِدٍ وَرَوَى بَعْضُهُمْ هَذَا الْحَدِيثَ عَنْ فَائِدٍ وَقَالَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَلِيٍّ عَنْ جَدَّتِهِ سَلْمَى وَعُبَيْدُ اللَّهِ بْنُ عَلِيٍّ أَصَحُّ حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا زَيْدُ بْنُ حُبَابٍ عَنْ فَائِدٍ مَوْلَى عُبَيْدِ اللَّهِ بْنِ عَلِيٍّ عَنْ مَوْلَاهُ عُبَيْدِ اللَّهِ بْنِ عَلِيٍّ عَنْ جَدَّتِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'], telah menceritakan kepada kami [Hammad bin Khalid Al Khayyath] Telah menceritakan kepada kami [Fa`id] bekas budaknya keluarga Rafi', dari [Ali bin Ubaidullah] dari [neneknya Salma] -ia dahulu sering membantu Rasulullah Shallallaahu 'Alaihi wasallam- ia berkata, \"Tidaklah Rasulullah shallallahu 'alaihi wasallam menderita luka kecuali beliau menyuruhku untuk menaruh diatas lukanya Dedaunan obat (dapat mendinginkan panasnya luka).\" Berkata Abu Isa; Ini merupakan hadits Hasan Gharib, hanya kami ketahui kecuali dari haditsnya Qa`id. Sebagian mereka meriwayatkan hadits ini dari Qa`id dan dia berkata; Dari Ubaidullah bin Ali dari neneknya Salma dan Ubaidillah bin Ali lebih shahih. Telah menceritakan kepada kami [Muhammad bin Allaa'] telah menceritakan kepada kami [Zaid bin Hubab] dari [Fa`id] Maula Ubaidullah bn Ali, dari bekas budaknya [Ubaidullah bin Ali] dari [kakeknya] dari Nabi shallallahu 'alaihi wasallam seperti hadits diatas dengan maknanya."},"1980":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ عَقَّارِ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اكْتَوَى أَوْ اسْتَرْقَى فَقَدْ بَرِئَ مِنْ التَّوَكُّلِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ ابْنِ مَسْعُودٍ وَابْنِ عَبَّاسٍ وَعِمْرَانَ بْنِ حُصَيْنٍ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Sufyan] dari [Manshur] Dari [Mujahid] dari ['Aqqar bin Al Mughirah bin Syu'bah] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berobat dengan Kay atau meminta untuk diruqyah, maka sungguhnya ia telah berlepas diri dari sifat tawakkal.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Ibnu Mas'ud, Ibnu Abbas, dan Imran bin Husain. Abu Isa berakta; Ini adalah hadits hasan shahih."},"1981":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ عَنْ سُفْيَانَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الرُّقْيَةِ مِنْ الْحُمَةِ وَالْعَيْنِ وَالنَّمْلَةِ","id":"Telah menceritakan kepada kami [Abdah bin Abdullah Al Khuza'i], telah menceritakan kepada kami [Mu'awiyah bin Hisyam] dari [Sufyan] dari ['Ashim Al Ahwal] dari [Abdullah bin Harits] dari [Anas] ia berkata: \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam membolehkan ruqyah karena terkena racun, 'Ain (sejenis gangguan hasad dari jin dan manusia) dan luka.\""},"1982":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ وَأَبُو نُعَيْمٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ فِي الرُّقْيَةِ مِنْ الْحُمَةِ وَالنَّمْلَةِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ قَالَ أَبُو عِيسَى وَهَذَا عِنْدِي أَصَحُّ مِنْ حَدِيثِ مُعَاوِيَةَ بْنِ هِشَامٍ عَنْ سُفْيَانَ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ بُرَيْدَةَ وَعِمْرَانَ بْنِ حُصَيْنٍ وَجَابِرٍ وَعَائِشَةَ وَطَلْقِ بْنِ عَلِيٍّ وَعَمْرِو بْنِ حَزْمٍ وَأَبِي خُزَامَةَ عَنْ أَبِيهِ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Yahya bin Adam] dan [Abu Nu'aim] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Ashim Al Ahwal] dari [Yusuf bin Abdullah bin Harits] dari [Anas bin Malik] bahwasanya Rasulullah shallallahu 'alaihi wasallam membolehkan pengobatan dengan ruqyah akibat terkena racun atau terluka. Abu Isa berkata; Ini adalah hadits hasan shahih gharib. Abu Isa berkata lagi; Menurutku hadits ini lebih Shahih daripada haditsnya Mu'awiyah bin Hisyam dari Sufyan. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Buraidah, Imran bin Hushain, Jabir, Aisyah, Thalqi bin 'Ali, Amr bin Hazm dan Abu Khuzamah dari bapaknya."},"1983":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا رُقْيَةَ إِلَّا مِنْ عَيْنٍ أَوْ حُمَةٍقَالَ أَبُو عِيسَى وَرَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ بُرَيْدَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Hushain] dari [Asy Sya'bi] dari [Imran bin Hushain] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak diperbolehkan ruqyah, kecuali dari penyakit 'Ain atau terkena racun.\" Abu Isa berkata; [Syu'bah] juga meriwayatkan hadits ini dari [Hushain] dari [Asy Sya'bi] dari [Buraidah] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1984":{"ar":"حَدَّثَنَا هِشَامُ بْنُ يُونُسَ الْكُوفِيُّ حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ الْمُزَنِيُّ عَنْ الْجَرِيرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَعَوَّذُ مِنْ الْجَانِّ وَعَيْنِ الْإِنْسَانِ حَتَّى نَزَلَتْ الْمُعَوِّذَتَانِ فَلَمَّا نَزَلَتَا أَخَذَ بِهِمَا وَتَرَكَ مَا سِوَاهُمَاقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَنَسٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ","id":"Telah menceritakan kepada kami [Hisyam bin Yunus Al Kufi], telah menceritakan kepada kami [Al Qasim bin Malik Al Mazani] dari [Al Jariri] dari [Abu Nadlrah] dari [Abu Sa'id] ia berkata; Dahulu Rasulullah Shallallaahu 'alaihi wa sallam sering berlindung dari kejahatan jin dan 'Ain manusia hingga turun Al Mu'awwidzatain, maka setelah keduanya turun beliau membacanya dan meninggalkan selainnya. Berkata Abu Isa; Hadits semakna juga diriwayatkan dari Anas dan ini merupakan hadits hasan gharib."},"1985":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عُرْوَةَ وَهُوَ ابْنُ عَامِرٍ عَنْ عُبَيْدِ بْنِ رِفَاعَةَ الزُّرَقِيِّ أَنَّ أَسْمَاءَ بِنْتَ عُمَيْسٍ قَالَتْيَا رَسُولَ اللَّهِ إِنَّ وَلَدَ جَعْفَرٍ تُسْرِعُ إِلَيْهِمْ الْعَيْنُ أَفَأَسْتَرْقِي لَهُمْ فَقَالَ نَعَمْ فَإِنَّهُ لَوْ كَانَ شَيْءٌ سَابَقَ الْقَدَرَ لَسَبَقَتْهُ الْعَيْنُقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عِمْرَانَ بْنِ حُصَيْنٍ وَبُرَيْدَةَ وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رُوِيَ هَذَا عَنْ أَيُّوبَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عُرْوَةَ بْنِ عَامِرٍ عَنْ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ أَسْمَاءَ بِنْتِ عُمَيْسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا بِذَلِكَ الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ أَيُّوبَ بِهَذَا","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Amru bin Dinar] dari [Urwah] ia dalah Ibnu Amir, dari [Ubaid bin Rifa'ah Az Zuraqi] bahwasanya; [Asma' binti Umais] berkata, \"Wahai Rasuulullah, sesungguhnya pengaruh 'Ain ini cepat sekali menjalar pada anaknya Ja'far, apakah aku boleh meminta orang yang meruqyahnya?\" Maka beliau menjawab: \"Iya, seandainya ada yang mendahului takdir tentu dia adalah 'Ain (namun dia tidak dapat mendahuluinya).\" Berkata Abu Isa: Hadits semakna juga diriwayatkan dari Imran bin Husain dan Buraidah. Dan ini merupakan hadits hasan shahih. Dan hadits ini juga telah diriwayatkan dari [Ayyub] dari [Amr bin Dinar] dari [Urwah bin Amir] dari [Ubaid bin Rifa'ah] dari [Asma' binti Umais] dari Nabi Shallallaahu 'alaihi wa sallam. Demikian pula, [Hasan bin Ali Al Khallal] telah menceritakannya kepada kami, ia berkata, Telah menceritakan kepada kami [Abdurrazzaq] dari [Ma'mar], dari [Ayyub] dengan hadits ini."},"1986":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ وَيَعْلَى عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ الْمِنْهَالِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَوِّذُ الْحَسَنَ وَالْحُسَيْنَ يَقُولُ أُعِيذُكُمَا بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ كُلِّ شَيْطَانٍ وَهَامَّةٍ وَمِنْ كُلِّ عَيْنٍ لَامَّةٍ وَيَقُولُ هَكَذَا كَانَ إِبْرَاهِيمُ يُعَوِّذُ إِسْحَقَ وَإِسْمَعِيلَ عَلَيْهِمْ السَّلَامحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ وَعَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Mahmud bin Ghailan], telah menceritakan kepada kami [Abdurrazzaq] dan [Ya'la] dari [Sufyan] dari [Manshur] dari [Al Minhal bin Amru] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; Dahulu Rasulullah shallallahu 'alaihi wasallam sering mendo'akan Hasan dan husain dengan mengucapkan: \"U'IIDZUKUMAA BIKALIMAATILLAAHITAAMMAH MIN KULLI SYAITHAANIN WA HAMMAH, WA MIN KULLI 'AININ LAAMMAH (Aku melindungi kalian dengan kalimat Allah -Al quran atau asma' dan sifat-Nya- yang sempurna dari setiap syetan dan binatang berbisa serta 'Ain yang dengki).\" Beliau juga bersabda: \"Demikianlah dahulu Ibrahim melindungi Ishaq dan Isma'il 'Alaihimus salaam.\" Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal], telah menceritakan kepada kami [Yazid bin Harun] dan [Abdurrazzaq] dari [Sufyan] dari [Manshur] semisal dan semakna dengannya. Abu Isa berkata; Ini adalah hadits hasan shahih."},"1987":{"ar":"حَدَّثَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ كَثِيرٍ أَبُو غَسَّانَ الْعَنْبَرِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ حَدَّثَنِي حَيَّةُ بْنُ حَابِسٍ التَّمِيمِيُّ حَدَّثَنِي أَبِي أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا شَيْءَ فِي الْهَامِ وَالْعَيْنُ حَقٌّ","id":"Telah menceritakan kepada kami [Abu Hafsh Amr bin Ali], telah menceritakan kepada kami [Yahya bin Katsir Abu Ghassan Al 'Anburi], telah menceritakan kepada kami [Ali bin Mubarak] dari [Yahya bin Abu Katsir], telah menceritakan kepadaku [Hayyah bin Habis At Tamimi], telah menceritakan kepadaku [bapakku] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak masalah dalam Al Haam, sedangkan penyakit 'Ain itu adalah benar adanya.\""},"1988":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الْحَسَنِ بْنِ خِرَاشٍ الْبَغْدَادِيُّ حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ الْحَضْرَمِيُّ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُوسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ شَيْءٌ سَابَقَ الْقَدَرَ لَسَبَقَتْهُ الْعَيْنُ وَإِذَا اسْتُغْسِلْتُمْ فَاغْسِلُواقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَهَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ غَرِيبٌ وَحَدِيثُ حَيَّةَ بْنِ حَابِسٍ حَدِيثٌ غَرِيبٌ وَرَوَى شَيْبَانُ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ حَيَّةَ بْنِ حَابِسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلِيُّ بْنُ الْمُبَارَكِ وَحَرْبُ بْنُ شَدَّادٍ لَا يَذْكُرَانِ فِيهِ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hasan bin Khirasy Al Baghdadi], telah menceritakan kepada kami [Ahmad bin Ishaq Al Hadlrami], telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari [bapaknya] dari [Ibnu Abbas] ia berkata; Rasulullah Shallallaahu 'Alaihi wasallam bersabda: \"Jikalau ada sesuatu yang dapat mendahului taqdir maka itu adalah penyakit 'Ain (namun tidak ada yang dapat mendahuluinya) dan jika kalian diminta (oleh orang yang terkena 'ain) untuk mandi, maka mandilah.\" Berkata Abu Isa: Hadits semakna juga diriwayatkan dari Abdullah bin Amr dan ini merupakan hadits hasan shahih gharib. Dan hadits Hayyah bin Habis merupakan hadits gharib. [Syaiban] telah meriwayatkan dari [Yahya bin Abi Katsir] dari [Hayyah bin Habis] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, namun [Ali bin Mubarak] dan [Harb bin Syaddad] tidak menyebutkan di dalamnya dari Abu Hurairah."},"1989":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ جَعْفَرِ بْنِ إِيَاسٍ عَنْ أَ��ِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَنَزَلْنَا بِقَوْمٍ فَسَأَلْنَاهُمْ الْقِرَى فَلَمْ يَقْرُونَا فَلُدِغَ سَيِّدُهُمْ فَأَتَوْنَا فَقَالُوا هَلْ فِيكُمْ مَنْ يَرْقِي مِنْ الْعَقْرَبِ قُلْتُ نَعَمْ أَنَا وَلَكِنْ لَا أَرْقِيهِ حَتَّى تُعْطُونَا غَنَمًا قَالَ فَأَنَا أُعْطِيكُمْ ثَلَاثِينَ شَاةً فَقَبِلْنَا فَقَرَأْتُ عَلَيْهِ الْحَمْدُ لِلَّهِ سَبْعَ مَرَّاتٍ فَبَرَأَ وَقَبَضْنَا الْغَنَمَ قَالَ فَعَرَضَ فِي أَنْفُسِنَا مِنْهَا شَيْءٌ فَقُلْنَا لَا تَعْجَلُوا حَتَّى تَأْتُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَلَمَّا قَدِمْنَا عَلَيْهِ ذَكَرْتُ لَهُ الَّذِي صَنَعْتُ قَالَ وَمَا عَلِمْتَ أَنَّهَا رُقْيَةٌ اقْبِضُوا الْغَنَمَ وَاضْرِبُوا لِي مَعَكُمْ بِسَهْمٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ وَأَبُو نَضْرَةَ اسْمُهُ الْمُنْذِرُ بْنُ مَالِكِ بْنِ قُطَعَةَ وَرَخَّصَ الشَّافِعِيُّ لِلْمُعَلِّمِ أَنْ يَأْخُذَ عَلَى تَعْلِيمِ الْقُرْآنِ أَجْرًا وَيَرَى لَهُ أَنْ يَشْتَرِطَ عَلَى ذَلِكَ وَاحْتَجَّ بِهَذَا الْحَدِيثِ وَجَعْفَرُ بْنُ إِيَاسٍ هُوَ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ وَهُوَ أَبُو بِشْرٍ وَرَوَى شُعْبَةُ وَأَبُو عَوَانَةَ وَغَيْرُ وَاحِدٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ هَذَا الْحَدِيثَ","id":"Telah menceritakn kepada kami [Hannad], telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ja'far bin Iyas] dari [Abu Nadlrah] dari [Sa'id bin Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengutusku dalam suatu Sariyyah. Kemudian kami singgah pada suatu kaum dan meminta untuk dijamu, namun mereka tidak mau memberikan jamuan. Lalu pemimpin mereka terkena sengatan, maka kami pun segera mendatanginya. Mereka bertanya, \"Apakah diantara kalian ada yang bisa meruqyah dari sengatan kalajengking?\" Aku berkata, \"Ya, sayalah orangnya. Namun saya tidak akan meruqyah hingga kalian member seekor kambing untuk kami.\" Ia berkata, \"Aku akan memberikan tiga ekor kambing untuk kalian.\" Maka kami pun menyetujuinya, dan aku mulai meruqyah dengan membacakan, \"AL HAMDULILLAH\" sebanyak tujuh kali, hingga ia siuman dan kami pun langsung mengambil kambing tersebut. Namun di dalam hati kami timbul semacam keraguan akan tiga ekor kambing tersebut. Maka kami pun berkata, \"Janganlah kalian tergesa-gesa untuk memakannya, hingga kalian menemui Rasulullah shallallahu 'alaihi wasallam.\" Saat menemui Rasulullah shallallahu 'alaihi wasallam, maka aku langsung menceritakan apa yang telah aku perbuat. Kemudian beliau bersabda: \"Tidakkah kamu ketahui ia ia adalah benar-benar ruqyah? Ambillah kambing itu, dan berikanlah aku bagian darinya.\" Abu Isa berkata; Ini adalah hadits hasan. Abu Nadlrah namanya adalah Al Mundzir bin Malik bin Qutha'ah. Asy Syafi'i membolehkan bagi seorang mu'allim untuk mengambil upah atas pengajaran Al Qur`annya. Dan menurutnya, ia boleh memberikan persyaratan seperti itu dan ia berdalih dengan hadits ini. Ja'far bin Iyas adalah Ja'far bin Abu Wahsyiyyah yakni Abu Bisyr. [Syu'bah] dan [Abu 'Awanah] serta lebih dari satu orang perawi telah meriwayatkan hadits ini dari [Abu Al Mutawakkal] dari [Abu Sa'id]."},"1990":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو بِشْرٍ قَال سَمِعْتُ أَبَا الْمُتَوَكِّلِ يُحَدِّثُ عَنْ أَبِي سَعِيدٍأَنَّ نَاسًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرُّوا بِحَيٍّ مِنْ الْعَرَبِ فَلَمْ يَقْرُوهُمْ وَلَمْ يُضَيِّفُوهُمْ فَاشْتَكَى سَيِّدُهُمْ فَأَتَوْنَا فَقَالُوا هَلْ عِنْدَكُمْ دَوَاءٌ قُلْنَا نَعَمْ وَلَكِنْ لَمْ تَقْرُونَا وَلَمْ تُضَيِّفُونَا فَلَا نَفْعَلُ حَتَّى تَجْعَلُوا لَنَا جُعْلًا فَجَعَلُوا عَلَى ذَلِكَ قَطِيعًا مِنْ الْغَنَمِ قَالَ فَجَعَلَ رَجُلٌ مِنَّا يَقْرَأُ عَلَيْهِ بِفَاتِحَةِ الْكِتَابِ فَبَرَأَ فَلَمَّا أَتَيْنَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْنَا ذَلِكَ لَهُ قَالَ وَمَا يُدْرِيكَ أَنَّهَا رُقْيَةٌ وَلَمْ يَذْكُرْ نَهْيًا مِنْهُ وَقَالَ كُلُوا وَاضْرِبُوا لِي مَعَكُمْ بِسَهْمٍقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ صَحِيحٌ وَهَذَا أَصَحُّ مِنْ حَدِيثِ الْأَعْمَشِ عَنْ جَعْفَرِ بْنِ إِيَاسٍ وَهَكَذَا رَوَى غَيْرُ وَاحِدٍ هَذَا الْحَدِيثَ عَنْ أَبِي بِشْرٍ جَعْفَرِ بْنِ أَبِي وَحْشِيَّةَ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ وَجَعْفَرُ بْنُ إِيَاسٍ هُوَ جَعْفَرُ بْنُ أَبِي وَحْشِيَّةَ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad bin Al Mutsanna], telah menceritakan kepadaku [Abdush Shamad bin Abdul Warits], telah menceritakan kepada kami [Syu'bah], telah menceritakan kepada kami [Abu Bisyr] ia berkata, Aku mendengar [Abu Al Mutawakkil] menceritakan dari [Abu Sa'id] bahwasanya; Sekelompok orang dari sahabat Nabi shallallahu 'alaihi wasallam melewati suatu daerah di tanah Arab, namun mereka tidak menjamunya. Kemudian pemimpin daerah tersebut terkena sakit, sehingga mereka mendatangi kami seraya bertanya, \"Apakah kalian mempunyai obat?\" Kami menjawab, \"Ya. Akan tetapi kalian tidak memberikan jamuan untuk kami dan tidak pula menerima kami layaknya seorang tamu. Kami tidak akan memberikannya hingga kalian memberikan jamuan untuk kami.\" Lalu merekan pun memberikan jamuan sepotong daging kambing. Dan salah seorang dari kami membacakan surat Al Fatihah dan tuan mereka pun sembuh seketika. Ketika kami menemui Rasulullah shallallahu 'alaihi wasallam, kami pun menuturkan hal itu, lalu beliau bersabda: \"Siapa yang memberitahu kalian bahwa itu adalah ruqyah?\" Saat itu beliau tidak menyebutkan kalimat larangan. Dan beliau bersabda: \"Makanlah daging itu, dan berikanlah satu bagian untukku.\" Abu Isa berkata; Ini adalah hadits hasan shahih. Dan hadits ini lebih shahih dari haditsnya Al A'masy dari Ja'far bin Iyas. Dan seperti ini pula yang telah diriwayatkan oleh lebih dari satu perawi dari Abu Bisyr Ja'far bin Abu Wahsyiyyah dari Abu Al Mutawakkil dari Abu Sa'id. Ja'far bin Iyas adalah Ja'far bin Abu Wahsyiyyah."},"1991":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي خُزَامَةَ عَنْ أَبِيهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رُقًى نَسْتَرْقِيهَا وَدَوَاءً نَتَدَاوَى بِهِ وَتُقَاةً نَتَّقِيهَا هَلْ تَرُدُّ مِنْ قَدَرِ اللَّهِ شَيْئًا قَالَ هِيَ مِنْ قَدَرِ اللَّهِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ ابْنِ أَبِي خُزَامَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ وَقَدْ رُوِيَ عَنْ ابْنِ عُيَيْنَةَ كِلْتَا الرِّوَايَتَيْنِ فَقَالَ بَعْضُهُمْ عَنْ أَبِي خِزَامَةَ عَنْ أَبِيهِ و قَالَ بَعْضُهُمْ عَنْ ابْنِ أَبِي خِزَامَةَ عَنْ أَبِيهِ وَقَدْ رَوَى غَيْرُ ابْنِ عُيَيْنَةَ هَذَا الْحَدِيثَ عَنْ الزُّهْرِيِّ عَنْ أَبِي خِزَامَةَ عَنْ أَبِيهِ وَهَذَا أَصَحُّ وَلَا نَعْرِفُ لِأَبِي خِزَامَةَ غَيْرَ هَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar], telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Khuzamah] dari [bapaknya] ia berkata; Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, bagaimana menurutmu mengenai ruqyah yang sering kami gunakan, obat yang sering kami gunakan untuk berobat serta pelindung yang seringa kami pakai untuk berlindung, apakah hal itu dapat menolak taqdir Allah?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Bahkan hal itu termasuk dari taqdir Allah.\" Berkata Abu Isa: Ini merupakan hadits hasan shahih. Telah menceritakan kepada kami [Sa'id bin Abdurrahman], telah menceritakan kepada kami [Sufyan] dari [Zuhri] dari [Ibnu Abi khuzamah] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Dan kedua riwayat tersebut telah diriwayatkan dari Ibnu Uyainah. Maka sebagian mereka berkata; dari Abi Khuzaimah dari bapaknya, dan sebagian lagi berkata: Dari Ibnu Abi Khuzaimah dari bapaknya. Dan selain Ibnu Uyainah juga ada yang meriwayatkan hadits ini dari Zuhri dari Abi Khuzaimah dari bapaknya, namun hadits ini lebih shahih dan kami tidak mengetahui Ibnu Khuzaimah meriwayatkan selain hadits ini."},"1992":{"ar":"حَدَّثَنَا أَبُو عُبَيْدَةَ بْنُ أَبِي السَّفَرِ أَحْمَدُ بْنُ عَبْدِ اللَّهِ الْهَمْدَانِيُّ وَمَحْمُودُ بْنُ غَيْلَانَ قَالَا حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ مُحَمَّدِ بْنِ أَبِي عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَجْوَةُ مِنْ الْجَنَّةِ وَفِيهَا شِفَاءٌ مِنْ السُّمِّ وَالْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ سَعِيدِ بْنِ زَيْدٍ وَأَبِي سَعِيدٍ وَجَابِرٍ وَهَذَا حَدِيثٌ حَسَنٌ غَرِيبٌ وَهُوَ مِنْ حَدِيثِ مُحَمَّدِ بْنِ عَمْرٍو وَلَا نَعْرِفُهُ إِلَّا مِنْ حَدِيثِ سَعِيدِ بْنِ عَامِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو","id":"Telah menceritakan kepada kami [Abu Ubaidah bin Abu Safar Ahmad bin Abdullah Al Hamdani] dan [Mahmud bin Ghailan] keduanya berkata, Telah menceritakan kepada kami [Sa'id bin Amir] dari [Muhammad bin Abu Amru] dar [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Al 'Ajwah bersasal dari surga, di dalamnya mengandung kesembuhan untuk penyakit racun. Al Kam`ah dari Al Mann, airnya adalah kesembuhan bagi penyakit 'Ain.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Sa'id bin Zaid, Abu Sa'id dan Jabir. Dan ini adalah hadits hasan gharib, ia bersal dari haditsnya Muhammad bin Amr, kami tidak mengetahuinya kecuali dari haditsnya Sa'id bin Amir dari Muhammad bin Amr."},"1993":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا عُمَرُ بْنُ عُبَيْدٍ الطَّنَافِسِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ عَنْ سَعِيدِ بْنِ زَيْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Abu Kuraib], telah menceritakan kepada kami [Umar bin Ubaid Ath Thanafisi] dari [Abdul Malik bin Umair] dalam riwayat lain, telah menceritakan kepada kami [Muhammad bin Al Mutsanna], telah menceritakan kepada kami [Muhammad bin Ja'far], telah menceritakan kepada kami [Syu'bah] dari [Abdul Malik bin Umair] dari [Amr bin Hurais] dari [Sa'id bin Zaid] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Al Kam`ah (cendawan) berasah dari Al Mann, airnya mengandung kesembuhan bagi penyakit 'Ain.\" Abu Isa berkata; Ini adalah hadits hasan shahih."},"1994":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَبِي هُرَيْرَةَأَنَّ نَاسًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا الْكَمْأَةُ جُدَرِيُّ الْأَرْضِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكَمْأَةُ مِنْ الْمَنِّ وَمَاؤُهَا شِفَاءٌ لِلْعَيْنِ وَالْعَجْوَةُ مِنْ الْجَنَّةِ وَهِيَ شِفَاءٌ مِنْ السُّمِّقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Mu'adz bin Hisyam], telah menceritakan kepada kami [bapakku] dari [Qatadah] dari [Syahr bin Hausyab] dari [Abu Hurairah] bahwasanya; Sekelompok orang dari kalangan sahabat Nabi shallallahu 'alaihi wasallam berkata, \"Al Kam`ah adalah cacarnya orang-orang Anshar.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Al Kam`ah berasal dari Al Mann. Dan airnya mengandung kesembuhan bagi penyakit 'Ain. Air susu berasal dari surga, dan ia adalah obat untuk menghilangkan racun.\" Abu Isa berkata; Ini adalah hadits hasan."},"1995":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذٌ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ قَالَ حُدِّثْتُ أَنَّ أَبَا هُرَيْرَةَ قَالَأَخَذْتُ ثَلَاثَةَ أَكْمُؤٍ أَوْ خَمْسًا أَوْ سَبْعًا فَعَصَرْتُهُنَّ فَجَعَلْتُ مَاءَهُنَّ فِي قَارُورَةٍ فَكَحَلْتُ بِهِ جَارِيَةً لِي فَبَرَأَتْ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Mu'adz] Telah menceritakan kepada kami [bapakku] dari [Qatadah] ia berkata; Telah [diceritakan kepadaku] bahwasanya; [Abu Hurairah] berkata, \"Aku mengambil tiga, lima atau tujuh Akmu`, lalu aku meletakkan airnya di dalam botol, kemudian aku mencelakinya pada budak perempuan milikku, dan ia pun sembuh.\""},"1996":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذٌ حَدَّثَنَا أَبِي عَنْ قَتَادَةَ قَالَ حُدِّثْتُ أَنَّ أَبَا هُرَيْرَةَ قَالَالشُّونِيزُ دَوَاءٌ مِنْ كُلِّ دَاءٍ إِلَّا السَّامَقَالَ قَتَادَةُ يَأْخُذُ كُلَّ يَوْمٍ إِحْدَى وَعِشْرِينَ حَبَّةً فَيَجْعَلُهُنَّ فِي خِرْقَةٍ فَلْيَنْقَعْهُ فَيَتَسَعَّطُ بِهِ كُلَّ يَوْمٍ فِي مَنْخَرِهِ الْأَيْمَنِ قَطْرَتَيْنِ وَفِي الْأَيْسَرِ قَطْرَةً وَالثَّانِي فِي الْأَيْسَرِ قَطْرَتَيْنِ وَفِي الْأَيْمَنِ قَطْرَةً وَالثَّالِثُ فِي الْأَيْمَنِ قَطْرَتَيْنِ وَفِي الْأَيْسَرِ قَطْرَةً","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Mu'adz] Telah menceritakan kepada kami [bapakku] dari [Qatadah] ia berkata, Telah [diceritakan kepadaku] bahwasanya; [Abu Hurairah] pernah berkata, \"Asy Syuniz (habbatus sauda`) adalah obat untuk segala jenis penyakit, kecuali kematian.\" Qatadah berkata; Pada setiap harinya ia mengambil dua puluh satu biji dan meletakkannya pada sobekan kain lalu merendamnya. Kemudian setiap hari, ia memasukkannya ke dalam hidungnya. Dua tetes pada lubang hidung sebelah kanan dan setetes pada hidung yang kiri. Pada tetesan kedua, dua tetes untuk hidung sebelah kiri dan setetes pada lubah hidung bagian kanan. Kedua untuk kali yang ketiga, ia memasukkan dua tetes pada lubang hidung sebelah kanan, sedangkan sebelah kiri satu tetes."},"1997":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَمَهْرِ الْبَغِيِّ وَحُلْوَانِ الْكَاهِنِقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ","id":"Telah menceritakan kepada kami [Qutaibah], telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari [Abu Bakr bin Abdurrahman] dari [Abu Mas'ud Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam untuk mengambil keuntungan yang diperoleh dari anjing dan beliau juga melarang mahar yang diperoleh secara tidak halal serta hasil dari seorang dukun. Abu Isa berkata; Hadits ini adalah hasan shahih."},"1998":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَدُّوَيْهِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عِيسَى أَخِيهِ قَالَ دَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ عُكَيْمٍ أَبِي مَعْبَدِ الْجُهَنِيِّأَعُودُهُ وَبِهِ حُمْرَةٌ فَقُلْنَا أَلَا تُعَلِّقُ شَيْئًا قَالَ الْمَوْتُ أَقْرَبُ مِنْ ذَلِكَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَعَلَّقَ شَيْئًا وُكِلَ إِلَيْهِقَالَ أَبُو عِيسَى وَحَدِيثُ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ إِنَّمَا نَعْرِفُهُ مِنْ حَدِيثِ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى وَعَبْدُ اللَّهِ بْنُ عُكَيْمٍ لَمْ يَسْمَعْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَتَبَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ أَبِي لَيْلَى نَحْوَهُ بِمَعْنَاهُ قَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ عُقْبَةَ بْنِ عَامِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Madduwaih], telah menceritakan kepada kami [Ubaidullah bin Musa] dari [Muhammad bin Abdurrahman bin Abi Laila] dari saudaranya [Isa] ia berkata; Suatu ketika aku menjenguk [Abdullah bin Ukaim Abu Ma'bad Al Juhani] dan wajahnya berwarna kemerahan karena sakit, lantas kami pun berkata, \"Tidakkah engkau menggantungkan sesuatu (di lehermu untuk menyembuhkanmu).\" Ia menjawab, \"Kematian lebih dekat dari itu.\" Nabi shallallahu 'alaihi wasallam pernah bersabda: \"Barang siapa yang menggantungkan sesuatu (jampi atau mantra) dibadannya, maka Allah akan membiarkannya dengan jampi-jampinya.\" Abu Isa berkata; Hadits Abdullah bin Ukaim hanya kami ketahui dari haditsnya Muhammad bin Abdurrahman bin Abi Laila. Sedangkan Abdullah bin Ukaim tidak pernah mendengar dari Nabi shallallaahu 'alaihi wa sallam. Pada zaman Nabi dia berkata, \"Rasulullah shallallahu 'alaihi wasallam menuliskan kitab kepada kami.\" Telah menceritakan kepada kami [Muhammad bin Basysyar], telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Abu Laila] semisal dan semakna dengannya. Abu Isa berkata; Hadits semakna juga diriwayatkan dari Uqbah bin Amir."},"1999":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحُمَّى فَوْرٌ مِنْ النَّارِ فَأَبْرِدُوهَا بِالْمَاءِقَالَ أَبُو عِيسَى وَفِي الْبَاب عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ وَابْنِ عُمَرَ وَامْرَأَةِ الزُّبَيْرِ وَعَائِشَةَ وَابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Hannad], telah menceritakan kepada kami [Abu Al Ahwash] dari [Sa'id bin Masruq] dari [Abayah bin Rifa'ah] dari kakeknya [Rafi' bin Khadij] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya penyakit demam itu merupakan luapan dari panasnya api neraka, karena itu redakanlah ia dengan air.\" Abu Isa berkata; Hadits semakna juga diriwayatkan dari Asma` binti Abu Bakar dan Ibnu Umar, Istri Zubair, Aisyah dan Ibnu Abbas."},"2000":{"ar":"حَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْحُمَّى مِنْ فَيْحِ جَهَنَّمَ فَأَبْرِدُوهَا بِالْمَاءِحَدَّثَنَا هَارُونُ بْنُ إِسْحَقَ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو عِيسَى وَفِي حَدِيثِ أَسْمَاءَ كَلَامٌ أَكْثَرُ مِنْ هَذَا وَكِلَا الْحَدِيثَيْنِ صَحِيحٌ","id":"Telah menceritakan kepada kami [Harun bin Ishaq Al Hamdani], telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya penyakit demam itu merupakan luapan dari panasnya api neraka, karena itu redakanlah ia dengan air.\" Telah menceritakan kepada kami [Harun bin Ishaq] Telah menceritakan kepada kami [Abdah] dari [Hisyam bin Urwah] dari [Fathimah binti Al Mundzir] dari [Asma` binti Abu Bakar] dari Nabi Shallallahu 'alahi wa sallam semisalnya. Abu Isa berkata; Di dalam hadits Asma terdapat ungkapan yang lebih banyak dari ini. Dan dikatakan bahwa kedua hadits tersebut adalah shahih."}};
